-- Poems batch 131
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('87c814a0-5064-4ad6-b170-d550af83256b','擬水西寺東峯亭九詠 垂澗藤','梅堯臣','宋','宋诗','song-poetry','','[]','澗深連石壁，石上生長藤。',36,'全唐诗/poet.song.14000.json','["澗深連石壁，石上生長藤。", "孤猿來自熟，緣飲下復登。", "頼無樵人跡，且免束薪蒸。"]'),
('655145df-8641-4f29-a640-a3d058590371','擬水西寺東峯亭九詠 嶺上雲','梅堯臣','宋','宋诗','song-poetry','','[]','我來東峯下，遠見西嶺頭。',36,'全唐诗/poet.song.14000.json','["我來東峯下，遠見西嶺頭。", "白雲忽已合，向此偶遲留。", "人誰問何有，自可忘殷憂。"]'),
('b6636dc5-7858-415d-b270-3a1bb8e637d9','擬水西寺東峯亭九詠 林中翠','梅堯臣','宋','宋诗','song-poetry','','[]','萬木總柔翠，況復新晴時。',36,'全唐诗/poet.song.14000.json','["萬木總柔翠，況復新晴時。", "日色照欲動，山氣斂還遲。", "望之如何攬，舉袂隨風吹。"]'),
('184e4308-020a-44f7-bd37-afbb2e323838','擬水西寺東峯亭九詠 棲煙鳥','梅堯臣','宋','宋诗','song-poetry','','[]','斑斑遠林鳥，極目波煙中。',36,'全唐诗/poet.song.14000.json','["斑斑遠林鳥，極目波煙中。", "各識時早暮，不忘巢西東。", "推物得真意，吾將效陶公。"]'),
('6bb01dd2-6967-4016-9288-d275c1fac9b7','擬水西寺東峯亭九詠 古壁苔','梅堯臣','宋','宋诗','song-poetry','','[]','陰壁流暗泉，古苔長自好。',36,'全唐诗/poet.song.14000.json','["陰壁流暗泉，古苔長自好。", "不改春與秋，何如路傍草。", "空山正幽藹，浄綠無人掃。"]'),
('ea53f579-829f-44d0-a493-fed9fc2c51ad','擬水西寺東峯亭九詠 幽徑石','梅堯臣','宋','宋诗','song-poetry','','[]','緣溪去欲遠，磊砢忽礙行。',36,'全唐诗/poet.song.14000.json','["緣溪去欲遠，磊砢忽礙行。", "旁臨側身險，下忽寒流聲。", "幽客慣來往，同此猿鳥情。"]'),
('9b9a1b7f-542f-4906-87a6-cef288e32f07','擬水西寺東峯亭九詠 寒溪草','梅堯臣','宋','宋诗','song-poetry','','[]','青青色堪染，欲辨不知名。',36,'全唐诗/poet.song.14000.json','["青青色堪染，欲辨不知名。", "根陰託乳魚，水底抽新萌。", "康樂池上詠，獨與春夢成。"]'),
('e0070de4-a31a-47d5-a472-c1d28a42bca8','擬水西寺東峯亭九詠 陰崖竹','梅堯臣','宋','宋诗','song-poetry','','[]','背嶺斷崖下，老竹生扶疎。',36,'全唐诗/poet.song.14000.json','["背嶺斷崖下，老竹生扶疎。", "孤根石上引，勁節松不如。", "莫言霜雪多，終見綠有餘。"]'),
('2bd39d72-4ddb-41f7-8816-8b4a98167192','擬水西寺東峯亭九詠 臨軒桂','梅堯臣','宋','宋诗','song-poetry','','[]','山楹無惡木，但有綠桂叢。',36,'全唐诗/poet.song.14000.json','["山楹無惡木，但有綠桂叢。", "幽芳尚未歇，飛鳥銜殘紅。", "不見離騷人，憔悴吟秋風。"]'),
('8911e618-8a56-458f-90f0-6c857b7fc73a','依韻和達觀禪師還山後見寄','梅堯臣','宋','宋诗','song-poetry','','[]','雲歸在高嶺，人見是無心。',48,'全唐诗/poet.song.14000.json','["雲歸在高嶺，人見是無心。", "矯矯將棲鳥，遥遥傍故林。", "南方雖有暖，臘月易成陰。", "惟恐多風雪，幽期未可尋。"]'),
('c26007e5-2d4d-4cae-9e1e-c325f2ff64cd','九華隠士居陳生寄松管筆','梅堯臣','宋','宋诗','song-poetry','','[]','春松抽瘦梗，削束費長毫。',48,'全唐诗/poet.song.14000.json','["春松抽瘦梗，削束費長毫。", "雞距初含潤，龍鱗不自韜。", "嘗爲大夫後，欲寫伯夷高。", "一獲山家贈，令吾媿汝曹。"]'),
('accbcd00-a1d1-4d07-9f01-84c9bc0c9713','古柳','梅堯臣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','岸側古大柳，誰種臨長江。',180,'全唐诗/poet.song.14000.json','["岸側古大柳，誰種臨長江。", "中自出蠹蝎，百歲成枯腔。", "忽值漲流沒，槎牙綴旌幢。", "腹膚藏蛟龍，半夜雷砰韸。", "飛霆痕尚白，如斬馬陵龐。", "倏爾巨電至，萬弩聲裂缸。", "又爲狂風摧，所殘惟朽樁。", "卧幹越大鼎，絕臏不可扛。", "就爇以照漁，駭鱗一何厖。", "始知網罟細，未足禁突撞。", "隆準以脫去，城下徒焚降。", "我從洲上泊，昏曉睨船窗。", "始終覩變毀，欲賦挑殘釭。", "吾交評韓詩，險韻古莫雙。", "安得共詠此，但嗟各他邦。"]'),
('df711f9c-7c4f-4ce1-853c-85be0aec63c8','放鵲','梅堯臣','宋','宋诗','song-poetry','','[]','鵲爲禽之靈智兮，胡蹈機而不知。',159,'全唐诗/poet.song.14000.json','["鵲爲禽之靈智兮，胡蹈機而不知。", "爲庸皁以困束兮，固性命之將危。", "喜遠人之至止兮，始屢驗以如期。", "向何預覺兮，此何自昏。", "豈專心以謀食兮，昧目前之禍根。", "苟所履必慮患兮，莫若去人遠以圖存。", "屑餘秣以致死兮，誠咎爾而無恥。", "維羣鳴之苦傷兮，使吾心之測爾。", "予測孔孟兮爾自解則艱，皁聽予言兮釋爾而還。", "撫爾呪爾兮爾無甚頑，後誰恤爾兮拓彈方彎。"]'),
('2da9a6c5-1014-4f77-8208-1f0deb8d821e','聞西山虎','梅堯臣','宋','宋诗','song-poetry','','[]','猛虎畏白日，孤客莫夜行。',60,'全唐诗/poet.song.14000.json','["猛虎畏白日，孤客莫夜行。", "彼以不暴衆，此何獨忘生。", "饑必見人食，不食且無名。", "麋鹿能遠遁，安得逢怒獰。", "由人不由常，役役官有程。"]'),
('e27992a6-bf32-41d7-8045-5e0d7ee12316','凍禽','梅堯臣','宋','宋诗','song-poetry','','[]','高樹繞吾廬，薄暮煙氣重。',48,'全唐诗/poet.song.14000.json','["高樹繞吾廬，薄暮煙氣重。", "將棲立傍巢，已振窺落氄。", "有來同枿枝，亦各不偎擁。", "颼颼陰風寒，夜雪豈無恐。"]'),
('238182c3-2983-4b36-8663-869cddc1b050','登乾明院碧蘚亭','梅堯臣','宋','宋诗','song-poetry','','[]','餘喘不苟盡，順俗來飯僧。',48,'全唐诗/poet.song.14000.json','["餘喘不苟盡，順俗來飯僧。", "東嶺有上方，脩竹蔽觚棱。", "下有蒼石案，旁挂孤蔓藤。", "繫累向塵世，更住殊未能。"]'),
('3d2774df-7f9b-48f0-93d5-0fbae37c9ddf','隠靜遺枇杷','梅堯臣','宋','宋诗','song-poetry','','[]','五月枇杷實，青青味尚酸。',24,'全唐诗/poet.song.14000.json','["五月枇杷實，青青味尚酸。", "獼猴定撩亂，欲待熱應難。"]'),
('210b2229-a162-4082-8cb6-7e29945369f7','正月十日五更夢中','梅堯臣','宋','宋诗','song-poetry','','[]','今年花似去年新，去年人比今年老。',32,'全唐诗/poet.song.14000.json','["今年花似去年新，去年人比今年老。", "我勸厚地一杯酒，收拾白日莫苦早。"]'),
('2df4beaf-3cfa-4c48-a54d-3f35382f6a12','紅梅','梅堯臣','宋','宋诗','song-poetry','','[]','家住寒溪曲，梅先雜暖春。',48,'全唐诗/poet.song.14000.json','["家住寒溪曲，梅先雜暖春。", "學粧如小女，聚笑發丹唇。", "野杏堪同舍，山櫻莫與鄰。", "休吹江上笛，留伴庾園人。"]'),
('bf3af0e8-4d20-4c57-8022-4beb20aba08f','寄文鑒大士','梅堯臣','宋','宋诗','song-poetry','','[]','讀書夜寂冷無火，捲卷遂成摇膝吟。',64,'全唐诗/poet.song.14000.json','["讀書夜寂冷無火，捲卷遂成摇膝吟。", "始憶高僧將偈去，安知古寺託雲深。", "寒堂正睡遠鐘發，野鳥亂鳴殘月沉。", "明日呼兒整籃轝，欲煩重過小溪陰。"]'),
('e1cbc39d-9502-425b-8b15-7759f0b38f6f','海棠','梅堯臣','宋','宋诗','song-poetry','','[]','江燕入朱閤，海棠繁錦條。',48,'全唐诗/poet.song.14000.json','["江燕入朱閤，海棠繁錦條。", "醉生燕玉頰，瘦聚楚宮腰。", "曾未分香去，尤宜著意描。", "誰能共吹笛，樹下想前朝。"]'),
('1739596f-3356-4e5d-854f-bd5b944802a6','送餘干李少府','梅堯臣','宋','宋诗','song-poetry','','[]','作尉古來清，況於干越城。',48,'全唐诗/poet.song.14000.json','["作尉古來清，況於干越城。", "舟中雨新足，溪上水初生。", "蒼獺出還沒，素鷗飛且鳴。", "休將五色棒，欲取洛陽名。"]'),
('7ca09703-ced6-4a93-80be-da2f5f8b7db4','與二弟過溪至廣教蘭若','梅堯臣','宋','宋诗','song-poetry','','[]','溪水今尚淺，涉馬不及韉。',240,'全唐诗/poet.song.14000.json','["溪水今尚淺，涉馬不及韉。", "岸口出近郭，野徑通平田。", "行行渡小橋，决决響細泉。", "萬木蔭古殿，一燈明象筵。", "長廊顔頵碑，字體家法傳。", "空堂裴相真，白髯垂過咽。", "名跡兩不滅，豈獨畫與鎸。", "高僧鑿崖腹，建閣將雲連。", "秘此龍鸞迹，足使臣僕虔。", "脩竹間長松，森衛若被堅。", "是必神物護，禹穴空歲年。", "飯訖過山後，井傍携茗煎。", "探幽偶轉谷，忽視昭亭巔。", "蔓草不識名，步側時得牽。", "幽禽聲各異，可辨唯杜鵑。", "似驚俗客來，聒聒兩耳邊。", "弊廬隔城堞，畏暮遽言還。", "道逢張羅歸，鳥媒兼死懸。", "遂同山梁雉，令我復喟然。", "聊追一日事，書以爲短篇。"]'),
('47b88cd7-1603-48be-8cbd-a3f40087a9ee','晚坐北軒望昭亭山','梅堯臣','宋','宋诗','song-poetry','','[]','少客兩京間，熟游嵩與華。',120,'全唐诗/poet.song.14000.json','["少客兩京間，熟游嵩與華。", "歸來宛溪上，厭往昭亭下。", "何以厭昭亭，衰遲倦驅駕。", "況復慙詠歌，嘉辭前有謝。", "咀嚼在人口，甘美如食蔗。", "方同陶淵明，苦語近田舍。", "節行固不變，出處亦多怕。", "常防惡少年，豪橫使出胯。", "譬如故將軍，尚被亭長駡。", "不若守弊廬，讀書至中夜。"]'),
('acd4c033-3ab7-40fb-a646-877dd1ba3135','與諸弟及李少府訪廣教文鑒師','梅堯臣','宋','宋诗','song-poetry','','[]','山僧邀我輩，置酒比陶潛。',48,'全唐诗/poet.song.14000.json','["山僧邀我輩，置酒比陶潛。", "紫蕨老堪食，青梅酸不嫌。", "野蜂時入座，巖鳥或窺簷。", "薄暮未能去，前溪月似鎌。"]'),
('8d80187c-7a7b-40ba-894b-310f63503833','至廣教因尋古石盆寺','梅堯臣','宋','宋诗','song-poetry','','[]','古寺近田家，山尋石盆差。',48,'全唐诗/poet.song.14000.json','["古寺近田家，山尋石盆差。", "化蟲懸縊女，啼鸌響繅車。", "僧坐樹間石，馬行溪畔沙。", "野香無處辨，歸路傍城斜。"]'),
('7384d221-4f43-4125-8ea6-38770dc18bd4','傷何皆秀才','梅堯臣','宋','宋诗','song-poetry','','[]','高高空山木，枯死不中材。',72,'全唐诗/poet.song.14000.json','["高高空山木，枯死不中材。", "寧答厚地力，歲久爲朽灰。", "昂藏儒家子，五十殞蒿萊。", "空負執卷勤，明月不頷顋。", "一芥祿未及，九泉無復開。", "人世有若此，愚智曷論哉。"]'),
('1a58da21-56df-4aaf-9a9c-65f5f89bad31','觀王介夫蒙亭記因記題蒙亭','梅堯臣','宋','宋诗','song-poetry','','[]','吾年將五十，尚未暇讀易。',96,'全唐诗/poet.song.14000.json','["吾年將五十，尚未暇讀易。", "一聞蒙亭說，乃見適所適。", "維時明進退，豈不在泉石。", "野服製升越，山庖盛雞蹠。", "床頭龍唇琴，案上科斗籍。", "風物稍佳時，把酒會三益。", "況以兄爲郎，仕也人豈迫。", "垂之愛之深，自匪逢時客。"]'),
('40081f86-532a-4fdb-a2fd-b20595209f1d','亢陽和欲行舟者','梅堯臣','宋','宋诗','song-poetry','','[]','春秋書閔雨，乃見先王制。',120,'全唐诗/poet.song.14000.json','["春秋書閔雨，乃見先王制。", "有意在黎民，山川無不祭。", "今者望雲霓，青天絕纖翳。", "爲壇割舒鴈，盤血陳水汭。", "于時頗精虔，奠爵必親涚。", "向夕有微陰，掃然還復霽。", "吾聞先儒言，陽驕不能閉。", "此時繫穹旻，己力安所詣。", "宣王雲漢詩，曾不鑒上帝。", "恨無奡盪舟，空自思躍蜧。"]'),
('922f9f7b-4e8b-446f-abaf-c4b96ca0b9e7','黄鶑  其一','梅堯臣','宋','宋诗','song-poetry','','[]','內家初上翠微宮，樹裏窺人在半空。',32,'全唐诗/poet.song.14000.json','["內家初上翠微宮，樹裏窺人在半空。", "笑語漸高無約束，侍臣偷望向雲中。"]'),
('9361e1f5-7e00-451c-8114-be116bde1a13','黄鶑  其二','梅堯臣','宋','宋诗','song-poetry','','[]','西鄰少年今出遊，東家女兒未識羞。',32,'全唐诗/poet.song.14000.json','["西鄰少年今出遊，東家女兒未識羞。", "門前烏臼葉已暗，日暮問誰牆上頭。"]'),
('2f026825-d6ef-45b0-96b3-8cbb96337130','送懷賢上人歸隠靜兼寄達觀禪師','梅堯臣','宋','宋诗','song-poetry','','[]','適從山中來，復向山中去。',60,'全唐诗/poet.song.14000.json','["適從山中來，復向山中去。", "爲報山中人，莫厭山中住。", "近城塵土多，亂爾煙霞趣。", "野蜂銜漆汁，尚欲爲蔕固。", "息此可以安，其能忘我諭。"]'),
('bc015321-c2ea-447d-99ce-d63dfdcdcdf2','送瑞竹長老歸當塗因寄徐著作','梅堯臣','宋','宋诗','song-poetry','','[]','謝傅青山路，春來蔓草生。',48,'全唐诗/poet.song.14000.json','["謝傅青山路，春來蔓草生。", "樵蘇猶不入，瓶錫莫能行。", "朝上野船去，宿逢溪雨鳴。", "多應見康樂，曾重遠公名。"]'),
('f173ba5c-9f9b-48c7-8e95-008547a925f9','鶑','梅堯臣','宋','宋诗','song-poetry','','[]','桑間小婦好聲音，映葉穿枝意已深。',32,'全唐诗/poet.song.14000.json','["桑間小婦好聲音，映葉穿枝意已深。", "盡日呼郎郎不應，蕭蕭風雨到前林。"]'),
('a9b72a0b-1173-42a4-bf27-00d264e61c69','守宮','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞漢武帝，偶問東方朔。',24,'全唐诗/poet.song.14000.json','["嘗聞漢武帝，偶問東方朔。", "臣擬作龍呼，慙無頭上角。"]'),
('1bbe3c1b-b52e-4323-8e19-df43cf7c5122','夏園','梅堯臣','宋','宋诗','song-poetry','','[]','夏園甘果熟，日覺樹林稀。',24,'全唐诗/poet.song.14000.json','["夏園甘果熟，日覺樹林稀。", "休笑道傍李，無人摘自肥。"]'),
('8d4eb172-c43c-4833-957b-7ae39004e096','孔子廟震','梅堯臣','宋','宋诗','song-poetry','','[]','霹靂下虛殿，破楹非夢凶。',48,'全唐诗/poet.song.14000.json','["霹靂下虛殿，破楹非夢凶。", "昔嘗瞻畫袞，今實見升龍。", "隠隠雷聲散，疎疎霧氣從。", "予知仲尼廟，不是蓄乖慵。"]'),
('789ab154-b1b1-4ca6-b0c9-a033210c2e82','寄酬睦州晏殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','清潭吐明月，杳杳及吾廬。',48,'全唐诗/poet.song.14000.json','["清潭吐明月，杳杳及吾廬。", "流彩滿懷袖，託情非鳥魚。", "朝因南澗雨，暮入北畦鋤。", "豈不藉餘潤，況茲方飯蔬。"]'),
('87889c1e-54e9-4279-83ca-30d85cef4546','李仲求寄建溪洪井茶七品云愈少愈佳未知嘗何如耳因條而答之','梅堯臣','宋','宋诗','song-poetry','','[]','忽有西山使，始遺七品茶。',144,'全唐诗/poet.song.14000.json','["忽有西山使，始遺七品茶。", "末品無水暈，六品無沉柤。", "五品散雲脚，四品浮粟花。", "三品若瓊乳，二品罕所加。", "絕品不可議，甘香焉等差。", "一日嘗一甌，六腑無昏邪。", "夜枕不得寐，月樹聞啼鴉。", "憂來唯覺衰，可驗唯齒牙。", "動摇有三四，妨咀連左車。", "髮亦足驚疎，疎疎點霜華。", "乃思平生游，但恨江路賒。", "安得一見之，煑泉相與誇。"]'),
('dcfdee66-8b0b-48bd-92e7-f188082e4753','送闞令之潭州寧鄉','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋風逆水急，挂席飛鳥輕。',168,'全唐诗/poet.song.14000.json','["秋風逆水急，挂席飛鳥輕。", "三江去雖遠，一日行幾程。", "朝辭洞庭岸，暮抵巴陵城。", "長沙古建國，地狹賦薄征。", "邑宰愛民者，選薦豈非精。", "既曰處民上，固當知民情。", "民居篁竹間，山獠相雜并。", "教道苟未至，毫髮心起爭。", "太剛易斷折，太柔難搘撐。", "貴在得中道，於焉無近名。", "聞多不祥鳥，似鴞何足驚。", "遠方此爲常，慎勿心屏營。", "賈誼度湘水，爲文弔屈平。", "因君寄杯酒，爲我酹賈生。"]'),
('027148c0-8d64-40f4-84e6-2fe93450b0a5','乾明院碧鮮亭','梅堯臣','宋','宋诗','song-poetry','','[]','壞衣削髮遠塵垢，蛇祖龍孫生屋後。',96,'全唐诗/poet.song.14000.json','["壞衣削髮遠塵垢，蛇祖龍孫生屋後。", "不等渭川千戶侯，尺椽片瓦何嘗有。", "方丈東頭一畝餘，中軒四面無窗牖。", "青瓊作枝鈿爲葉，丹鳳未食蒼鼠走。", "細藤織榻白晝眠，寢濃鼻息如雷吼。", "世間百事不歷心，門外寒流徹溪口。"]'),
('323498e7-92f9-4e01-87ba-a049832d756c','得餘干李尉書錄示唐人于越亭詩因以寄題','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','餘水之于越之鄙，築基相對琵琶尾。',80,'全唐诗/poet.song.14000.json','["餘水之于越之鄙，築基相對琵琶尾。", "琵琶日日有秋聲，雁過洞庭風入葦。", "南斗戛湖波不起，長刀剡鋒碧耳耳。", "姱娥夜出在寒溪，青銅瑩磨光幾里。", "朝因吳客幅蒲輕，滿紙如蠶書可喜。"]'),
('1008b438-56a4-42d6-8a1e-5c5d838e8fab','南軒盆植重臺蓮移種池','梅堯臣','宋','宋诗','song-poetry','','[]','彤雲赤霧生紺房，朝霞變蕊朱粉光。',64,'全唐诗/poet.song.14000.json','["彤雲赤霧生紺房，朝霞變蕊朱粉光。", "白玉入泥不滿盎，羽蓋裛露明月璫。", "濁水一石亂蛙黽，鑿池五丈如斗方。", "萍根科斗得自在，荷芰明年出水央。"]'),
('e5e53a92-c02c-4b70-a509-bd37e074f7d5','朝天行','梅堯臣','宋','宋诗','song-poetry','','[]','大車高蓋徐方來，天子雙日延英開。',96,'全唐诗/poet.song.14000.json','["大車高蓋徐方來，天子雙日延英開。", "犀靴踏玉陞東陛，從臣賜對論宮市。", "諫官御史如指排，捧土未能障濁水。", "大夫言斡天關迴，黄門白望顔色死。", "始時暴奪何縱橫，有貨晝日不敢行。", "他時五方蛇當酒，誰道張郎臨井口。"]'),
('1713d636-f78f-420a-a88a-14880868a685','會勝院沃洲亭','梅堯臣','宋','宋诗','song-poetry','','[]','前溪夾洲後溪闊，風吹細浪龍鱗活。',64,'全唐诗/poet.song.14000.json','["前溪夾洲後溪闊，風吹細浪龍鱗活。", "孤亭一入野氣深，松上藤蘿籬上葛。", "葛花葛蔓無斷時，女蘿莫翦連古枝。", "當年吾叔讀書處，夜夜濕螢來復去。"]'),
('bf72224b-42d8-4aaa-bc9a-492632b7f87c','江南雜感','梅堯臣','宋','宋诗','song-poetry','','[]','樹頭巧婦棲，樹下秋蟲織。',48,'全唐诗/poet.song.14000.json','["樹頭巧婦棲，樹下秋蟲織。", "壞衣游子心，千里嘗相憶。", "蕩子脚出門，便作浮萍根。", "憂來憑五兆，拜樹賽黄豚。"]'),
('1f413916-d64a-49b7-a809-a5ff286bd9b3','依韻和達觀禪師山中見寄','梅堯臣','宋','宋诗','song-poetry','','[]','豶豕在塗龍在澤，豺狼食肉麝食柏。',160,'全唐诗/poet.song.14000.json','["豶豕在塗龍在澤，豺狼食肉麝食柏。", "蹄毛與角不對齒，啄觜兩足副以翮。", "既能閑閑住深谷，豈使于于佩鳴玉。", "水邊看虹山雨霽，夜與明月歸獨宿。", "門前重嶺後羣峯，石樓朱殿藏林中。", "銅絲緊轉轆轤響，絡緯秋老嚎西風。", "榮利淡薄無易此，彼飲甘醲茲飲水。", "暫將分別向喉舌，何異聲色亂眼耳。", "孔孟久歿言可師，千古布散葉與枝。", "今來閉戶自有趣，世上沄沄非我爲。"]'),
('9f0b1633-749c-4c74-84ff-cc18807ba0d5','送萬諤昌秀才','梅堯臣','宋','宋诗','song-poetry','','[]','志士不戀家，安能坐㕮咀。',48,'全唐诗/poet.song.14000.json','["志士不戀家，安能坐㕮咀。", "儒冠難徒行，馬骨瘦可數。", "後僕隔山陂，前林遇風雨。", "寒村夜宿時，寂默誰對語。"]'),
('888399c9-c690-41d2-a7ea-f6d53f7ce1fc','訪石子澗外兄林亭','梅堯臣','宋','宋诗','song-poetry','','[]','前日秋水漲，昨日秋水落。',84,'全唐诗/poet.song.14000.json','["前日秋水漲，昨日秋水落。", "偶來尋隠居，曾未乖宿諾。", "竹底除舊徑，藤蔓繫新彴。", "馬留岸傍樹，風掃林下籜。", "既能置魯酒，又復餉楚飵。", "誰知北南澗，照影似清洛。", "平生愛幽曠，斂迹誠非錯。"]'),
('b6f2373a-d9f6-4d5e-aff7-e3201feda7a5','八月二十七日夢與宋侍讀同賦泛伊水詩覺而錄之','梅堯臣','宋','宋诗','song-poetry','','[]','遨遊非昔時，輕舸偶同泛。',48,'全唐诗/poet.song.14000.json','["遨遊非昔時，輕舸偶同泛。", "山水心有慕，屢往如有欠。", "平生共好尚，飲食未嘗厭。", "茲日不言多，醉如春酒釅。"]'),
('24889085-52a2-4162-8ddd-947aae49351a','和端式上人十詠 幽谷泉','梅堯臣','宋','宋诗','song-poetry','','[]','幽谷有飛泉，入溪知幾里。',36,'全唐诗/poet.song.14000.json','["幽谷有飛泉，入溪知幾里。", "跳珠濺木葉，激雨霏巖趾。", "但無箕潁人，曾不吝洗耳。"]'),
('8b6bc295-0515-449a-be26-d52d05411d41','和端式上人十詠 古木陰','梅堯臣','宋','宋诗','song-poetry','','[]','古木少直枝，其下多曲影。',36,'全唐诗/poet.song.14000.json','["古木少直枝，其下多曲影。", "豈不愛高陰，奈此性所秉。", "千重葉薈翳，誰願憩日永。"]'),
('1644fa7e-ca96-4778-a2e0-794e6195ff3b','和端式上人十詠 寒溪石','梅堯臣','宋','宋诗','song-poetry','','[]','翠聳寒溪上，半隠寒松下。',36,'全唐诗/poet.song.14000.json','["翠聳寒溪上，半隠寒松下。", "水鳥立稜角，淵魚游穴罅。", "尋常置庭檻，瑣細不知價。"]'),
('525b0b27-b3e2-48b3-a942-6b2b8c16f33f','和端式上人十詠 孤汀蘋','梅堯臣','宋','宋诗','song-poetry','','[]','瀟湘歸去人，正值江南春。',36,'全唐诗/poet.song.14000.json','["瀟湘歸去人，正值江南春。", "始願逢拾羽，今乃見採蘋。", "寄語柳使君，莫恨日已曛。"]'),
('10659d45-247a-474e-a831-9a8e49897b43','和端式上人十詠 雲際鍾','梅堯臣','宋','宋诗','song-poetry','','[]','煙昏青櫟道，風急隔溪鍾。',36,'全唐诗/poet.song.14000.json','["煙昏青櫟道，風急隔溪鍾。", "征馬未及息，猛虎前有蹤。", "尋聲欲投宿，僮僕畏所逢。"]'),
('10c0b0d7-0bdb-443d-98ed-bb71fbad13b0','和端式上人十詠 垂崖鞭','梅堯臣','宋','宋诗','song-poetry','','[]','崖竹出石壁，根瘦懸青蛇。',36,'全唐诗/poet.song.14000.json','["崖竹出石壁，根瘦懸青蛇。", "磔髯露老節，斫骨點寒花。", "少年莫翦去，騎殺白鼻騧。"]'),
('d6e54759-8a58-464e-bd6e-d988b5fd0964','和端式上人十詠 天外峯','梅堯臣','宋','宋诗','song-poetry','','[]','天外一尺峯，國中千仞岳。',36,'全唐诗/poet.song.14000.json','["天外一尺峯，國中千仞岳。", "重雲不掩蔽，萬里見頭角。", "世人看遠碧，誰識産美璞。"]'),
('07e07686-6e29-4cda-a453-15392a65d05a','和端式上人十詠 秋原菊','梅堯臣','宋','宋诗','song-poetry','','[]','不爲潭上英，不助籬邊醉。',36,'全唐诗/poet.song.14000.json','["不爲潭上英，不助籬邊醉。", "獨占蘭杞鄰，原頭自榮悴。", "陶令與太鑿，逢人豈無意。"]'),
('c8f24b1c-cd81-4c7d-a18a-b0c47d46afcc','和端式上人十詠 漁舟火','梅堯臣','宋','宋诗','song-poetry','','[]','蘆洲一點明，知有漁人泊。',36,'全唐诗/poet.song.14000.json','["蘆洲一點明，知有漁人泊。", "江溟杳不分，誰方在高閣。", "是時孤雁去，應認光中落。"]'),
('50082abf-124c-4e04-bebb-1b38c0a31149','和端式上人十詠 春溪水','梅堯臣','宋','宋诗','song-poetry','','[]','春水冰欲開，傍岸已微釋。',36,'全唐诗/poet.song.14000.json','["春水冰欲開，傍岸已微釋。", "魚寒未動鱗，獸渡時有跡。", "篙師畏割舟，敲拉碎圭璧。"]'),
('1a9a59b5-8380-40f9-af58-630b8118092d','十月二十一日得許昌晏相公書','梅堯臣','宋','宋诗','song-poetry','','[]','哀憂向二年，朋戚誰與書。',60,'全唐诗/poet.song.14000.json','["哀憂向二年，朋戚誰與書。", "敢意大丞相，尺題傳義廬。", "從來鳳凰鳴，不厭寒竹疎。", "茂林多翔鳥，要路盛高車。", "窮巷一如此，江深無鯉魚。"]'),
('e856afb8-fb69-4939-aab5-adca4f780df1','訪施八評事','梅堯臣','宋','宋诗','song-poetry','','[]','施兄今七十，近郭隠茅廬。',48,'全唐诗/poet.song.14000.json','["施兄今七十，近郭隠茅廬。", "懶問齊民術，喜看莊叟書。", "竹間鳴澗水，原際見村墟。", "識盡窮通理，超然樂有餘。"]'),
('6168a715-58ab-4e02-a2c8-61da2a84c67b','贈陳無逸秀才','梅堯臣','宋','宋诗','song-poetry','','[]','良犬不取鼠，其人苦尤之。',72,'全唐诗/poet.song.14000.json','["良犬不取鼠，其人苦尤之。", "近識固未辨，善相又能知。", "在鹿忘守穴，挃足乃焉而。", "士有志功名，局縮秉書詩。", "憔悴未得展，磬折忽言卑。", "舉酒一以贈，願無羞爾爲。"]'),
('6109a3c7-aa6c-4ad6-8c99-e1f7a2469c9e','送田遵古秀才','梅堯臣','宋','宋诗','song-poetry','','[]','蹊。',74,'全唐诗/poet.song.14000.json','["蹊。", "既見游子發，登舟傍寒溪。", "沿江抵海澨，行陸至膠西。", "入門喜在顔，上堂拜阿㜷。", "四鄰持壺酒，雞蹠間豚蹄。", "親戚慶問畢，詩書速整齊。", "即有求賢詔，與子不久睽。"]'),
('e8b63387-10b2-4c75-bd02-ae2cac2a35f3','寄題刁景純環翠亭','梅堯臣','宋','宋诗','song-poetry','','[]','古臺數畝平崗連，莽蒼瘦竹生寒煙。',64,'全唐诗/poet.song.14000.json','["古臺數畝平崗連，莽蒼瘦竹生寒煙。", "蝦蟆不食海月在，夜久帖角迴嬋娟。", "今人莫論曾費築，昔人已往誰知年。", "三茅京峴必可望，終欲相與吟雲泉。"]'),
('d6161a22-b14c-4a24-a6cd-099525725714','題陳宰戲綵亭','梅堯臣','宋','宋诗','song-poetry','','[]','仕宦固已美，及親此其難。',72,'全唐诗/poet.song.14000.json','["仕宦固已美，及親此其難。", "況慕五綵戲，而奉興居安。", "翁喜君亦喜，翁餐君亦餐。", "嗷嗷園中禽，口哺心違丸。", "邑大歲幸稔，衆頼仁政寬。", "還思彼赤子，如恐君不歡。"]'),
('ab344c51-0246-4ce8-9ba9-7a63b06a6e4b','永慶僧舍松風亭','梅堯臣','宋','宋诗','song-poetry','','[]','誰按黄金徽，滿指清風度。',48,'全唐诗/poet.song.14000.json','["誰按黄金徽，滿指清風度。", "但聽松上聲，不知松間趣。", "野僧何所樂，樂此數株樹。", "寧邀俗客來，草綠澗西路。"]'),
('baf2be64-8241-4132-8f19-cbd25cfb4a32','寄松林長老','梅堯臣','宋','宋诗','song-poetry','','[]','大松五丈百歲餘，小松五尺前時種。',48,'全唐诗/poet.song.14000.json','["大松五丈百歲餘，小松五尺前時種。", "俱有堅完不朽心，莫以今輕古爲重。", "東溪一片寒玉光，夜挂高枝何所用。"]'),
('b8b4c003-fb99-4a18-bec8-5a1e8b6709f2','題松林院','梅堯臣','宋','宋诗','song-poetry','','[]','靜邃無塵地，青熒續焰燈。',48,'全唐诗/poet.song.14000.json','["靜邃無塵地，青熒續焰燈。", "木魚傳飯鼓，山衲見歸僧。", "野色寒多霧，溪痕夜閣冰。", "吾非謝康樂，獨往亦何能。"]'),
('b027f714-eda5-4e93-b43d-8a039ad5404a','永州守王公慥寄九巖亭記云此地疑是柳子厚所說萬石亭也因爲二百言以答願當留詠','梅堯臣','宋','宋诗','song-poetry','','[]','天地磨今古，賢愚爲埃塵。',240,'全唐诗/poet.song.14000.json','["天地磨今古，賢愚爲埃塵。", "草樹易變改，山川無故新。", "眷言零陵守，白髮駕朱輪。", "間來問遺老，俯跡哀昔人。", "昔人者誰歟，元和前放臣。", "下上窮幽荒，憔悴楚水濱。", "試觀當時記，圖寫未必真。", "最苦來黄溪，坐石數游鱗。", "有鳥大如鵠，東向立不踆。", "始買钴鉧潭，鄠杜難計緡。", "冉溪袁家洞，亂石多磷磷。", "深里與沸白，若盡無窮津。", "石渠連巖泓，菖蒲被其垠。", "窮勝得其詭，衆美誰齊均。", "西澗石爲底，豈無芹與蘋。", "澗崖如堂席，澗響如龍唇。", "折竹掃陳葉，羅榻同衆賓。", "其言粲星斗，百歲猶比晨。", "萬石乃淺近，尚可資覆巾。", "而況前所說，但恐煩鎸珉。"]'),
('29918585-d177-480c-8f56-11c00fce5dc7','答王君石遺包虎二軸','梅堯臣','宋','宋诗','song-poetry','','[]','老包曰岳岳生鼎，二人畫虎通神明。',160,'全唐诗/poet.song.14000.json','["老包曰岳岳生鼎，二人畫虎通神明。", "凡爲一虎不知價，鉅公貴士珍其名。", "死來年深搜索盡，何意好事識尤精。", "丹楓映坡茅葉白，雌者將乳雄坡行。", "細毛出肉不見跡，相顧猛氣都如生。", "忽聞持遺非素望，窮民展玩忘愁嬰。", "奇哉真是老包筆，世間空有黄金籯。", "因思前歲韓公子，亦贈尺紙圖生獰。", "傍題小子乃包鼎，此時偶得已可驚。", "借問吾鄉與天下，二包之美誰能并。"]'),
('6d7f8bca-bd0c-40aa-b1f4-0ed42ac736e5','潘樂二君對雪寄聲似欲予賦適方知之走筆奉呈','梅堯臣','宋','宋诗','song-poetry','','[]','南方今見雪，北客定思家。',48,'全唐诗/poet.song.14000.json','["南方今見雪，北客定思家。", "任凍不欺酒，競春先著花。", "樓高休厭上，山近未應遮。", "誰問窮居日，西窗壓竹斜。"]'),
('484accde-b5f2-4357-add1-4d466ad76108','過永慶院','梅堯臣','宋','宋诗','song-poetry','','[]','荒凉舊蘭若，古屋兩三重。',48,'全唐诗/poet.song.14000.json','["荒凉舊蘭若，古屋兩三重。", "庭下已無柏，澗邊唯有松。", "石堦生薜荔，香座缺芙蓉。", "化俗似禪衲，破來縫不縫。"]'),
('87f44f87-221b-4f5e-b69f-835086a492cc','雪中廖宣城寄酒','梅堯臣','宋','宋诗','song-poetry','','[]','輕舟泛泛昭亭灣，春雪漫漫昭亭山。',96,'全唐诗/poet.song.14000.json','["輕舟泛泛昭亭灣，春雪漫漫昭亭山。", "寒沙曲渚杳不辨，素鷗翔鷺空中還。", "宣城太守閔窮旅，雙壺貯醖兵吏頒。", "任從六花壅船戶，滿酌春色生衰顔。", "醒時但愛雲水好，醉後等與天地閑。", "世間取樂各有分，何必舞娥高髻鬟。"]'),
('14e5fe61-9266-4419-9622-af9b6256c9a4','翠竹亭','梅堯臣','宋','宋诗','song-poetry','','[]','種竹幾千个，結亭三四椽。',48,'全唐诗/poet.song.14000.json','["種竹幾千个，結亭三四椽。", "遊人多寂靜，啼鳥亦留連。", "酒有陶公愛，林希阮氏賢。", "我來歸路遠，躍馬古城邊。"]'),
('75e167ea-9c24-44ee-b666-333c061a2485','彩霓亭','梅堯臣','宋','宋诗','song-poetry','','[]','高出嶺頭樹，俯窺城下溪。',48,'全唐诗/poet.song.14000.json','["高出嶺頭樹，俯窺城下溪。", "半山飛急雨，舉手弄晴霓。", "曠望已無極，萬緣都與齊。", "自嗟來獨晚，征棹苦言西。"]'),
('74f4ae24-047f-4e26-8067-baf489c80396','留別樂和之','梅堯臣','宋','宋诗','song-poetry','','[]','雪消潭水綠，輕舸下灘時。',48,'全唐诗/poet.song.14000.json','["雪消潭水綠，輕舸下灘時。", "漸轉青山去，還將故國辭。", "野林看欲動，江燕欲逢遲。", "君語隨州體，余慙晚始知。"]'),
('0138c75d-2d0b-4aa8-ad9b-6a8743d42972','松風亭','梅堯臣','宋','宋诗','song-poetry','','[]','冉冉竹連澗，森森松蔭崖。',48,'全唐诗/poet.song.14000.json','["冉冉竹連澗，森森松蔭崖。", "始聞清吹度，似欲綠琴諧。", "莫識主人意，休論高士懷。", "春城百花發，薜荔上陰階。"]'),
('8d876a70-c351-4738-bd10-e912e6984780','留別乾明山主','梅堯臣','宋','宋诗','song-poetry','','[]','自余銜哀歸，不與人事接。',144,'全唐诗/poet.song.14000.json','["自余銜哀歸，不與人事接。", "兩至此飯僧，華宇何曄曄。", "大士邀我銘，吾學愧涉獵。", "强述殊不高，下筆曾未愜。", "豈意煩鎸刊，有似蟲鏤葉。", "徒將珉石蠹，枉壞亦已輙。", "又不虞後人，譏誚喙囁囁。", "今我將還朝，方丈一登躡。", "嶺竹與巖花，所植皆妥帖。", "羅列森翠戈，次第笑朱頰。", "乃知化平等，此意異蜂蝶。", "世人莫復問，江上鼓輕楫。"]'),
('dca0ffe6-7d8b-4859-9eee-e1330eec9d85','雪中懷廣教真上人','梅堯臣','宋','宋诗','song-poetry','','[]','蒼山去不遠，日日起寒雲。',48,'全唐诗/poet.song.14000.json','["蒼山去不遠，日日起寒雲。", "堂上看飛雪，水邊思練裙。", "銅缾生薄凍，桂火壓殘薰。", "欲往有餘興，林幽路不分。"]'),
('fa65f208-404e-4089-b827-f13d0526d39d','下赤山嶺過渡至石子澗別施八評事','梅堯臣','宋','宋诗','song-poetry','','[]','三年守廬次，兩迴來澗邊。',48,'全唐诗/poet.song.14000.json','["三年守廬次，兩迴來澗邊。", "臨塘愛魚樂，近竹見人賢。", "今我西歸日，逢君小隠年。", "重將車馬去，驚起野鷗眠。"]'),
('95dfbaba-adfe-4322-9b12-9f54a62d38f5','春日拜壠經田家','梅堯臣','宋','宋诗','song-poetry','','[]','田家春作日日近，丹杏破纇場圃頭。',64,'全唐诗/poet.song.14000.json','["田家春作日日近，丹杏破纇場圃頭。", "南嶺禽過北嶺叫，高田水入低田流。", "桑牙將綻霧露裛，蠶子未浴箱篚收。", "今我還朝固不遠，紫宸已夢瞻珠旒。"]'),
('9048ab23-7dbf-4b90-ad9f-3246b56601db','將行賽昭亭祠喜雨','梅堯臣','宋','宋诗','song-poetry','','[]','未生潭上雲，空望山中雨。',168,'全唐诗/poet.song.14000.json','["未生潭上雲，空望山中雨。", "湛湛陳桂樽，坎坎奏鼉鼓。", "蕭蕭靈風來，蹲蹲祝郎舞。", "莫言春作遲，但念寒灘阻。", "何當發泉源，綠水浸沙渚。", "不與農者期，自將舟人語。", "定作榜歌行，暮投丹湖浦。", "瞻祠草樹失，認嶺煙霞吐。", "平吞東南吳，遠带西北楚。", "川澤見坡陁，龍蛇蹙鱗膂。", "人經興寤歎，事往成前古。", "考碑何驗今，塗馬立空廡。", "余知骨相貧，豈敢望冥許。", "願乘溪流深，滂沛隨徹俎。"]'),
('0671e3a2-d388-4f1f-8f45-b2dd27bdf4e7','若訥上人彈琴','梅堯臣','宋','宋诗','song-poetry','','[]','祥哀已踰月，遇子彈鳴琴。',84,'全唐诗/poet.song.14000.json','["祥哀已踰月，遇子彈鳴琴。", "安得不成聲，子心異吾心。", "十日成笙歌，尼父非好音。", "先王禮有節，不可過於今。", "莫作風入松，懷壠情未任。", "一聞流水曲，歸思在溪陰。", "此焉吾所樂，目極送歸禽。"]'),
('20015e30-5e80-4d00-95d5-390c6b511f78','發昭亭','梅堯臣','宋','宋诗','song-poetry','','[]','春泥深一尺，車馬重重跡。',108,'全唐诗/poet.song.14000.json','["春泥深一尺，車馬重重跡。", "親舊各還城，山川空向夕。", "今朝水平岸，不畏舟礙磧。", "始隨湍漲發，已入青蒼壁。", "落日未逢人，孤村望來客。", "泱泱漫田流，青青被壠麥。", "欲霽鳩亂鳴，將耕杏先白。", "我無農畝懃，千里事行役。", "寄謝昭亭神，果不吝深澤。"]'),
('20e09e03-41e2-40ea-a24c-2c3ba1d9b28e','乘小舟訪松山法聰上人','梅堯臣','宋','宋诗','song-poetry','','[]','我從溪口來，正值山前雨。',48,'全唐诗/poet.song.14000.json','["我從溪口來，正值山前雨。", "濕衣逢梵宮，有僧善吳語。", "天寒蜜已空，軒靜竹可數。", "歸楫難久留，汀鷗自飛舞。"]'),
('06bd94a2-c2c4-4b05-8515-7829124f23a5','過雁洲','梅堯臣','宋','宋诗','song-poetry','','[]','船從雁洲北去，雁背春風亦歸。',28,'全唐诗/poet.song.14000.json','["船從雁洲北去，雁背春風亦歸。", "但見平沙綠水，䕡蒿荻笋方肥。"]'),
('1c8b65b5-8733-4f77-8810-163d9aa8416a','別達觀文鑒二大士','梅堯臣','宋','宋诗','song-poetry','','[]','雲衲山中來，畫橈江上發。',24,'全唐诗/poet.song.14000.json','["雲衲山中來，畫橈江上發。", "何日到山中，山花應未歇。"]'),
('a70134b9-2c84-4f0e-9896-5172cf5ef8ed','依韻和文鑒師贈別','梅堯臣','宋','宋诗','song-poetry','','[]','來見寒沙鳥，長隨上下波。',48,'全唐诗/poet.song.14000.json','["來見寒沙鳥，長隨上下波。", "乃知游宦跡，不似施松蘿。", "子語馬喻馬，吾吟柯伐柯。", "清江挂帆去，奈憶故山何。"]'),
('4f1da47f-0d0e-45b7-b4b9-7920b153897a','贈袁大監','梅堯臣','宋','宋诗','song-poetry','','[]','人以祿爲榮，當知身所重。',72,'全唐诗/poet.song.14000.json','["人以祿爲榮，當知身所重。", "祿榮身且勞，豈要權衡用。", "達人唯止足，曷顧百鍾俸。", "今朝西山歸，芝朮不須種。", "莊生逸老言，此必久已誦。", "矩法况自持，推年心可縱。"]'),
('efe7b6b3-879c-4927-98fb-d81ea7177a04','依韻和達觀禪師贈別','梅堯臣','宋','宋诗','song-poetry','','[]','平生少壯日，百事牽於情。',192,'全唐诗/poet.song.14000.json','["平生少壯日，百事牽於情。", "今年輒五十，所向唯直誠。", "既不慕富貴，亦不防巧傾。", "寧爲目前利，寧愛身後名。", "文史玩朝夕，操行蹈羣英。", "下不以傲接，上不以意迎。", "衆人欣立異，此心常自平。", "譬如先後花，結實秋共成。", "趙壹雖空囊，鄭子豈其卿。", "二人貧且隠，高譽動天京。", "我蹟固尚賤，我道未嘗輕。", "力遵仁義塗，曷畏萬里程。", "安能苟榮祿，擾擾復營營。", "近因喪已除，偶得存餘生。", "强欲活妻子，勉焉事徂征。", "徂征江浦上，鷗鳥莫相驚。"]'),
('e54117ea-0733-4ae6-a2de-8ced34f087f0','蕪湖阻風','梅堯臣','宋','宋诗','song-poetry','','[]','春風任惡花自笑，白浪不愁頭已白。',32,'全唐诗/poet.song.14000.json','["春風任惡花自笑，白浪不愁頭已白。", "戢戢大船江浦邊，崑崙五兩誰非客。"]'),
('63c67370-4d03-408f-9954-0bd85a34cd0c','依韻和達觀文鑒雨中見懷','梅堯臣','宋','宋诗','song-poetry','','[]','出浦候波平，石尤風未止。',48,'全唐诗/poet.song.14000.json','["出浦候波平，石尤風未止。", "密雨長蒲牙，輕泥隨燕子。", "寒侵遠客衣，岸起新痕水。", "各各欲還山，還山能幾里。"]'),
('ec71e6a9-ce96-4477-9fc1-f56aed9b5203','金陵與張十二傳師賞心亭飲','梅堯臣','宋','宋诗','song-poetry','','[]','但嗟識君遲，不恨春風惡。',48,'全唐诗/poet.song.14000.json','["但嗟識君遲，不恨春風惡。", "風惡舟未前，置酒共談謔。", "漁歌還浦頭，斜日下洲角。", "明朝渡江去，相望便成昨。"]'),
('6a9d9277-765e-47c5-9ed5-8b374dbec61b','阻風寄刁安國','梅堯臣','宋','宋诗','song-poetry','','[]','江風裂瓦鳴，浦口驚波作。',24,'全唐诗/poet.song.14000.json','["江風裂瓦鳴，浦口驚波作。", "君駕何不來，客心空寂寞。"]'),
('48301cb4-6307-463f-985d-c1116283187f','阻風秦淮令狐度支寄酒','梅堯臣','宋','宋诗','song-poetry','','[]','春風不獨開春木，能蹙浪花高似屋。',80,'全唐诗/poet.song.14000.json','["春風不獨開春木，能蹙浪花高似屋。", "江船百尾泊深灣，鐵纜千環繫長軸。", "遠客今朝愁未平，主人贈榼飲還足。", "前時共論酒可禁，急世救弊且勿速。", "我今正得杯中趣，效陶種秫置心曲。"]'),
('d27cd853-21da-4392-9840-ff1996e5a9c6','江上遇雷雨','梅堯臣','宋','宋诗','song-poetry','','[]','雷從燕尾來，雨到江心急。',72,'全唐诗/poet.song.14000.json','["雷從燕尾來，雨到江心急。", "挂帆中路時，望浦前舟入。", "聲喧釜豆裂，點疾盎蠒立。", "蕩遥魚鼈腥，恐懼兒女泣。", "稍聞人好語，出顧岸已及。", "蘆洲有同行，言唁氣吸吸。"]'),
('01fac054-aa63-4c01-a660-66bb280b0c1e','登瓜步山二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','瓜步山頭廟，堂因魏武興。',48,'全唐诗/poet.song.14000.json','["瓜步山頭廟，堂因魏武興。", "亡歸從赤壁，事去憶西陵。", "軍井藏雲杪，林根擁石稜。", "微風認江水，細甲幾千層。"]'),
('8a928e47-b27a-4923-bb57-8d2b659db9b0','登瓜步山二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','山上濃雲合，江南暴雨來。',48,'全唐诗/poet.song.14000.json','["山上濃雲合，江南暴雨來。", "將歸林下嶺，中路遇風雷。", "心速灣猶遠，行遲伴屢催。", "舟師添繫纜，兒女望人迴。"]'),
('3f02c3b6-d5e7-497f-8487-3519a1282ffd','啼禽','梅堯臣','宋','宋诗','song-poetry','','[]','盆繭未成絲，破褲勸可脫。',24,'全唐诗/poet.song.14000.json','["盆繭未成絲，破褲勸可脫。", "安知增羞顔，赤脛衣短褐。"]'),
('2857ed34-47f9-4299-89a3-dcc9d6869129','汴堤鶑','梅堯臣','宋','宋诗','song-poetry','','[]','古堤多長榆，落莢鵝眼小。',72,'全唐诗/poet.song.14000.json','["古堤多長榆，落莢鵝眼小。", "其下迅黄流，其上鳴黄鳥。", "安知舟中人，黑鬢日已少。", "千里歸大梁，玉笙聞䆗窕。", "終朝不成曲，幽響在林表。", "莫羨沙路行，金鞭馳裊裊。"]'),
('a68b28b9-f187-477f-ae45-d77c81116235','四月二十七日與王正仲飲','梅堯臣','宋','宋诗','song-poetry','','[]','我來自楚君自吳，相遇汎波銜舳艫。',128,'全唐诗/poet.song.14000.json','["我來自楚君自吳，相遇汎波銜舳艫。", "時時舉酒共笑樂，莫問罌盎有與無。", "醉憶曩同吾永叔，倒冠落佩來西都。", "是時豪快不顧俗，留守贈榼少尹俱。", "高吟持去擁鼻學，雅闋付唱纖腰姝。", "山東腐儒漫側目，洛下才子爭歸趨。", "自茲離散二十載，不復更有一日娛。", "如今舊友已無幾，歲晚得子欣爲徒。"]'),
('487012eb-7d34-4d57-928e-18f1719ffb95','四月二十八日記與王正仲及舍弟飲','梅堯臣','宋','宋诗','song-poetry','','[]','孟夏景苦長，與子舟中飲。',156,'全唐诗/poet.song.14000.json','["孟夏景苦長，與子舟中飲。", "酒行三四巡，病嘔聊就寢。", "仲氏又發霍，洞下忽焉甚。", "湯劑不能勝，悶絕口已噤。", "我嘔雖未平，驚走豈遑枕。", "叫號使呼醫，子怪亦莫諗。", "遽白何至斯，葛巾推小品。", "且尤食物間，膻腥失調飪。", "所餉惟豬雞，況此乏箘蕈。", "以子獨無恙，未必因滑瀋。", "稍覺陽脈回，慄膚猶瘮瘮。", "儻其遂不起，孰肯謂素稟。", "吾鄉千里遥，幸免成貝錦。"]'),
('d0196bd5-7fcc-41a2-b185-fc2aff8ce564','讀月石屏詩','梅堯臣','宋','宋诗','song-poetry','','[]','余觀二人作詩論月石，月在天上，石在山下，安得石上有月蹟。',178,'全唐诗/poet.song.14000.json','["余觀二人作詩論月石，月在天上，石在山下，安得石上有月蹟。", "至矣歐陽公，知不可詰不竟述，欲使來者默自釋。", "蘇子苦豪邁，何用强引犀角蚌蛤巧擘析。", "犀蛤動活有情想，石無情想已非的。", "吾謂此石之蹟雖似月，不能行天成紀曆。", "曾無纖毫光，不若燈照夕。", "徒爲頑璞一片圓，溫潤又不似圭璧。", "乃有桂樹獨扶疏，常娥玉兔了莫覓。", "無此等物豈可靈，秖以爲屏安足惜。", "吾嗟才薄不復詠，略評二詩庶有益。"]'),
('53897101-5495-4e88-b31a-25ebba955782','暴雨','梅堯臣','宋','宋诗','song-poetry','','[]','雲薄風回雨點麤，日腥土氣隨吸呼。',80,'全唐诗/poet.song.14000.json','["雲薄風回雨點麤，日腥土氣隨吸呼。", "蒸然襲汗猶揮珠，屋瓦裂響波生渠。", "森森斗覺凉侵膚，毛根癛瘮粟匝軀。", "已知燠寒變須臾，雷電不止投笑壺。", "槐端漏影日向晡，馬蹄莫惜行泥塗。"]'),
('c186f3c0-5cd9-4deb-ab3a-79872f5cfe52','和宋中道喜至次用其韻','梅堯臣','宋','宋诗','song-poetry','','[]','予從江南來，見子東浦榛。',288,'全唐诗/poet.song.14000.json','["予從江南來，見子東浦榛。", "問子何不治，子兄遊洛瀕。", "子素樂文字，而復養慈親。", "去年始陞朝，差差陪縉紳。", "今也與吾肩，行立笑語頻。", "未經鬢髮改，喜預班綴新。", "思如曩時會，浩飲不計巡。", "往謁持約史，文辭媿彬彬。", "謂將一乘粟，欲敵千箱囷。", "然而澤中蛇，時得龍一鱗。", "况復周孔教，幸逢舜禹辰。", "又究志所之，茲學豈不臻。", "誰其起予者，視子爲席珍。", "趨韓亦已工，比孟猶欠淳。", "慎勿驚怪奇，怪奇世多擯。", "吾慙遼東豕，未見西狩麟。", "汩汩塵泥間，曷辨玉與珉。", "昨來忽有知，所索非所循。", "使焉轉磨衡，安得目不眴。", "誠聞苑囿美，難遣麋鹿馴。", "自惟體衰苶，寧堪事艱辛。", "宜收蹭蹬迹，却返江湖濱。", "浸脛水活活，漫灘石磷磷。", "垂釣紅鬐登，舉袂白羽振。"]'),
('24f0268a-7ff0-4306-a0f0-afbe65b1f185','齊國大長公主挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','賢行聞當世，尊隆異故常。',48,'全唐诗/poet.song.14000.json','["賢行聞當世，尊隆異故常。", "每令夫結友，不爲子求郎。", "夜月初沉海，姑星忽殞潢。", "臨門親祖祭，悲吹起脩岡。"]'),
('acd9449b-9cb0-42c2-bbea-4ad57789b7ba','齊國大長公主挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','魯館當年盛，秦臺此日遥。',48,'全唐诗/poet.song.14000.json','["魯館當年盛，秦臺此日遥。", "龍歸終合劍，鳳去不聞簫。", "挽曲方傳薤，行輀競奠椒。", "空餘漢官屬，泣送馬如潮。"]'),
('a52c07cf-690b-46d1-a63b-d78f1c986b0a','招隠堂寄題樂郎中','梅堯臣','宋','宋诗','song-poetry','','[]','日哦招隠詩，日誦歸田賦。',60,'全唐诗/poet.song.14000.json','["日哦招隠詩，日誦歸田賦。", "未嘗見芸人，勇拋冠冕去。", "今聞緱山陰，身退效疏傅。", "一旦從犢車，歡言友田父。", "復來釣澗邊，誰問袁公路。"]'),
('bfaa6774-5a76-4cf4-8014-98dc2d4bb4db','貸米於如晦','梅堯臣','宋','宋诗','song-poetry','','[]','舉家鳴鵝雁，突冷無晨炊。',48,'全唐诗/poet.song.14000.json','["舉家鳴鵝雁，突冷無晨炊。", "大貧丐小貧，安能不相嗤。", "幸存顔氏帖，况有陶公詩。", "乞米與乞食，皆是前人爲。"]'),
('933a0ce8-5f3e-426c-950f-b4f91fa0d1c2','送渭州劉太保','梅堯臣','宋','宋诗','song-poetry','','[]','月黑見旄頭，芒角漸西向。',108,'全唐诗/poet.song.14000.json','["月黑見旄頭，芒角漸西向。", "八月邊草黄，胡人馬初壯。", "無奈我兵雄，方爲漢偏將。", "嘗聞登壇人，亦未免得喪。", "得爲凱歌還，鐃鼓喧亭障。", "千蹄使椎牛，百甕令設醠。", "喪乃軍之羞，節制由處上。", "進退從其呼，何能求必當。", "二事非己專，願思古挾纊。"]'),
('d55d932d-c8ff-459f-a951-3545e52886f4','送張推官洞赴晏相公辟','梅堯臣','宋','宋诗','song-poetry','','[]','送子居大梁，關中乃關外。',96,'全唐诗/poet.song.14000.json','["送子居大梁，關中乃關外。", "往者邊事繁，秦民被災害。", "今聞獨豐穰，逮堠無動旝。", "相公欲勤勞，請以臨都會。", "多選天下才，佐佑如何頼。", "决疑有全策，何必用蓍蔡。", "雖病君强行，寶刀仍喜带。", "豈是爲俗儒，空言事夸大。"]'),
('bc75f1d5-6afb-4db0-a4c1-fd1172eb3062','送張著作器宰蘄水','梅堯臣','宋','宋诗','song-poetry','','[]','予聞楚山竹，肉好髮亦勻。',60,'全唐诗/poet.song.14000.json','["予聞楚山竹，肉好髮亦勻。", "隴上風雪飽，石根莓苔皴。", "搜林翦橫吹，龍子愁水濱。", "作邑尚簡易，豈必蹈昔人。", "願爲季長賦，安用瑶與珉。"]'),
('9d7a7127-aaf7-464f-8fc6-2eeb93b3a749','和癭盃','梅堯臣','宋','宋诗','song-poetry','','[]','物以美好稱，或以醜惡用。',120,'全唐诗/poet.song.14000.json','["物以美好稱，或以醜惡用。", "美惡固無然，逢時乃亦共。", "棄則爲所輕，用則爲所重。", "道聞癭木器，愛賞互歌頌。", "定應初得之，買不論官俸。", "靧面生光輝，貯飲發狂縱。", "坐欲置於傍，行欲挈以從。", "其形何險怪，曾不因蓺種。", "凹凸本自然，出縮非鬭縫。", "薄才難究窮，詆訶茲實恐。"]'),
('7767bbf6-14db-4312-bb26-0d63b9de8c77','太廟致齋答韓舍人簡','梅堯臣','宋','宋诗','song-poetry','','[]','齋舍隔牆東，蕭蕭槐樹風。',48,'全唐诗/poet.song.14000.json','["齋舍隔牆東，蕭蕭槐樹風。", "聲顔雖不接，翰墨遽能通。", "未說凉堪飲，唯愁賦少工。", "此焉知素拙，試與問楊雄。"]'),
('d30bbf12-c0c7-4451-af03-b45d699c020c','送張著作孟侯宰上元','梅堯臣','宋','宋诗','song-poetry','','[]','天衢車馬跡，急若機上梭。',72,'全唐诗/poet.song.14000.json','["天衢車馬跡，急若機上梭。", "義雖平生篤，不越一再過。", "夫子累顧我，言歸泛長河。", "得邑美建業，風流猶可歌。", "依稀江令宅，秋草應更多。", "五題誰復詠，鍾蔣與嵯峨。"]'),
('a93e0cfd-d23b-4d4e-8d3a-d77c668c3466','劉原甫觀相國寺浄土楊惠之塑像吳道子畫又越僧鼓琴閩僧寫真予解其詫','梅堯臣','宋','宋诗','song-poetry','','[]','吾儕來都下，將踰三十春。',132,'全唐诗/poet.song.14000.json','["吾儕來都下，將踰三十春。", "不聞此畫塑，想子得亦新。", "茲寺臨大道，常多車馬塵。", "設如前日手，晦昧已惑人。", "曷分今與古，曷辯僞與真。", "閩緇圖鳳姿，越釋彈龍唇。", "但知五彩爛，徒謂五音淳。", "熟識商聲高，孰驚眸子神。", "不能評譜品，索玉翻得珉。", "二君才調高，言若羽翮振。", "將令尋常工，千歲傳不泯。"]'),
('820ad396-42d6-4f34-8276-1c68953fed13','依韻解中道如晦調','梅堯臣','宋','宋诗','song-poetry','','[]','二君嗜學者，不啻食飲貪。',168,'全唐诗/poet.song.14000.json','["二君嗜學者，不啻食飲貪。", "所得纔半語，已實猶雙南。", "推予當獨步，幸勿辭再三。", "可因憤悱發，莫爲頑鄙談。", "大雅固自到，建安殊未甘。", "哀哉彼屈宋，徒爾死湘潭。", "險句孰敢抗，似入虎穴探。", "辛勤不盈襜，况又劇采藍。", "誹訶蝟毛起，度量牛鼎函。", "人情何多嫉，機巧久已諳。", "莫問冠冕貴，自將詩書躭。", "興來聊詠懷，字密如排蠶。", "曹劉爲我駕，顔鮑爲我驂。", "爰視二子才，並驅應亦堪。"]'),
('1f215986-a84f-437e-9c87-f729065387f5','依韻和裴如晦秋懷','梅堯臣','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','老葉已足蠹，風振猶在柯。',72,'全唐诗/poet.song.14000.json','["老葉已足蠹，風振猶在柯。", "高高低低聲，切切感我多。", "不念四散飛，尖圓競相磨。", "當茲思再春，宛然同俟河。", "莫驚衡山雁，莫問洞庭波。", "徒聞漢武帝，獨有橫汾歌。"]'),
('9b0a7cb2-22c9-4cdf-96a2-772d4e5c4a7c','送張諷寺丞赴青州幕','梅堯臣','宋','宋诗','song-poetry','','[]','朝廷久清明，賢相出賢牧。',276,'全唐诗/poet.song.14000.json','["朝廷久清明，賢相出賢牧。", "賢牧又選賢，森森備官屬。", "是以邦政脩，良農播嘉穀。", "上無租賦逋，下有囷廩蓄。", "往者河朔饑，奔送劇鳬鶩。", "富公鎮青社，有來咸鞠育。", "病者調藥劑，起者飼饘粥。", "老稚四十萬，瘦骨生壯肉。", "鄉縣將遣歸，田園皆可復。", "爲之置長犂，爲之置黄犢。", "既完身上衣，又付橐中粟。", "庭下再拜辭，望城皆感哭。", "他人守一方，境內猶不足。", "至今趙魏間，食飲常酹祝。", "富公離山東，寇盜頗任觸。", "堂堂高平公，德業人所伏。", "幙府得才謀，螻蟻不勞撲。", "上體憂勤心，掃滅得神速。", "張侯三十餘，瑩若無玷玉。", "八字分濃眉，純漆點雙目。", "昨日奉辟書，氣貌寧近俗。", "言從必磊落，事果無出縮。", "他時爲書功，誰惜千毫禿。"]'),
('e4053860-6fdf-4da2-812b-82f211ae4b24','送徐秘校廬州監酒','梅堯臣','宋','宋诗','song-poetry','','[]','淮南秋物盛，稻熟蟹正肥。',48,'全唐诗/poet.song.14000.json','["淮南秋物盛，稻熟蟹正肥。", "况身爲酒官，醇酎飲不非。", "儻觀衆人醉，徒自使世譏。", "與君伯氏好，試以此言歸。"]'),
('9f77e86b-843e-4d7b-8634-c004cc3d8aa2','韓子華江南安撫','梅堯臣','宋','宋诗','song-poetry','','[]','韓侯出持節，志在撫黔黎。',192,'全唐诗/poet.song.14000.json','["韓侯出持節，志在撫黔黎。", "縣官負弩迎，刺史躍馬隨。", "千里宣德澤，煦如春風馳。", "寒潮不起浪，怗怗威馮夷。", "借問何致耳，試聽將所爲。", "立車呼父老，勞以哀矜詞。", "我從大明宮，天子親諭之。", "憂汝歲屢凶，吏不恤汝疲。", "已輸又索糴，囷橐無孑遺。", "此非陛下意，恐使汝輩疑。", "疾苦汝告我，不憚爲汝治。", "父老必喜拜，如餒得飼麋。", "我稱此大是，一一無不宜。", "南方二十州，歡聲無幼耆。", "壺漿擁大道，婦女闖短籬。", "行聞江漢間，復有宣王詩。"]'),
('037acea6-41b9-4ae1-95c5-595b0f3730c0','周仲章通判潤州','梅堯臣','宋','宋诗','song-poetry','','[]','昔過京口山，斷崖如鞏洛。',180,'全唐诗/poet.song.14000.json','["昔過京口山，斷崖如鞏洛。", "抱谷黄芹泥，百丈聳垠堮。", "山嶺與江面，地脈水可度。", "欲鑿無淺泉，孰云南土薄。", "君爲別乘去，便比北州樂。", "已免卑溼憂，仍離鴞鵩惡。", "況逢休明時，秋堞罷嚴柝。", "夜愛寒江潮，月臨甘露閣。", "置酒發浩歌，萬里波欲却。", "霜蟹肥可釣，水鱗活堪斫。", "縱飲不須休，未應滄海涸。", "終當笑楊雄，窮壁常寂寞。", "更知首陽人，薇蕨事亦錯。", "不若阮步兵，醉鞍伸兩脚。", "太守必吾徒，儻能時就酌。"]'),
('08db462f-ac13-4676-9208-fd3cd3c083fb','弟著作宰南陵','梅堯臣','宋','宋诗','song-poetry','','[]','新買紫騮馬，欲歸清弋江。',48,'全唐诗/poet.song.14000.json','["新買紫騮馬，欲歸清弋江。", "去彈琴雁獨，來認舄鳬雙。", "橐實收盈篚，濃醅熟滿缸。", "弟兄相憶否，風燭舊西窗。"]'),
('1cb0ab67-f444-46f7-a446-0c825f50360c','和江鄰幾有菊無酒','梅堯臣','宋','宋诗','song-poetry','','[]','種菊將飲酒，菊開酒無有。',84,'全唐诗/poet.song.14000.json','["種菊將飲酒，菊開酒無有。", "雖不負爾目，且已負爾口。", "昨日三四人，淡坐饑腹吼。", "徒與哦其傍，誰能置升斗。", "當時陶淵明，籬下望亦久。", "幸頼白衣人，不愧采盈手。", "悠然事頗同，必竟醉則否。"]'),
('8912b01e-3e96-4b58-9c3a-34f0373c2d51','五知堂','梅堯臣','宋','宋诗','song-poetry','','[]','履道坊中白家宅，五橋莊北晉公堂。',64,'全唐诗/poet.song.14000.json','["履道坊中白家宅，五橋莊北晉公堂。", "昔年二老曾相樂，今日五知名獨光。", "舉事是非都不問，接花時節暫能忙。", "清尊雅曲易爲厭，自有圖書列在傍。"]'),
('3fdb1127-019e-4364-a652-21c9578b334e','贈陳孝子庸','梅堯臣','宋','宋诗','song-poetry','','[]','康州水邊龍母墳，草樹蒙蒙起風雨。',144,'全唐诗/poet.song.14000.json','["康州水邊龍母墳，草樹蒙蒙起風雨。", "五色五蛇時往來，野鼠不穴墳上土。", "嗟哉異類猶厚親，豈彼人兮忘恃怙。", "果生陳子孝且仁，終日劬劬在民伍。", "天清天順感其和，嘉禾駢枝立如股。", "遐鄉歎慕爲爾鄰，太守欣言出吾部。", "中州士人傳以夸，照頑爍孽良有補。", "唯時火德君道明，粵南祝融孝所生。", "若然寧獨一陳生，築堠表廬從此數。"]'),
('fd35145a-0ac3-44d7-8917-1b4e912f3bb3','和原甫同鄰幾過相國寺浄土院因觀楊惠之塑吳道子畫聽越僧琴閩僧寫宋賈二公真','梅堯臣','宋','宋诗','song-poetry','','[]','青槐夾馳道，方轡下麒麟。',144,'全唐诗/poet.song.14000.json','["青槐夾馳道，方轡下麒麟。", "朅來游紺宇，歷玩同逡巡。", "吳畫與楊塑，在昔稱絕倫。", "深殿留舊迹，鮮逢真賞人。", "一見如宿遇，舉袂自拂塵。", "金碧發光彩，物象生精神。", "歲月雖已深，奇妙不愧新。", "驚嗟豈無意，振播還有因。", "乃知至精手，安得久晦堙。", "二僧感識別，請以己藝陳。", "或彈中散曲，或出丞相真。", "覽古仍獲今，未枉停車輪。"]'),
('44ca4541-88eb-49c1-9ec3-46c91e2459bb','李端明宅花燭席上賦','梅堯臣','宋','宋诗','song-poetry','','[]','百兩禮將陳，王家集上賓。',48,'全唐诗/poet.song.14000.json','["百兩禮將陳，王家集上賓。", "花光濃照席，燭豔暖迴春。", "已接冰壺潤，寧辭翠斝醇。", "自慙持短調，重對玉堂人。"]'),
('4a43166f-945d-4017-8821-a6c09efce59f','送李祠部知滑州','梅堯臣','宋','宋诗','song-poetry','','[]','自古重名器，未嘗輕授人。',48,'全唐诗/poet.song.14000.json','["自古重名器，未嘗輕授人。", "煌煌東郡守，燦燦兩朱輪。", "父祖繼居此，恩榮誰與鄰。", "秋風度河水，馬足不生塵。"]'),
('37ba9bbf-0d28-462d-b9da-64e5f3941b1e','送王正仲長官','梅堯臣','宋','宋诗','song-poetry','','[]','汴渠泝復沿，自可見遲速。',144,'全唐诗/poet.song.14000.json','["汴渠泝復沿，自可見遲速。", "來時遲有糧，去恨速無穀。", "有糧安計程，無穀不遑宿。", "霜高萬物枯，源水縮溪谷。", "黄流半泥沙，勢淺見蹙澳。", "千里東歸船，何日下清瀆。", "澹澹風雨寒，長汀嚎鴈鶩。", "將投孤戍遠，四顧危檣獨。", "强語慰妻孥，多虞頼僮僕。", "到家秫已收，綴樹橘始熟。", "折腰無慙陶，懷遺焉媿陸。", "我方羨子行，送望不移目。"]'),
('2e2f0bbc-c180-4e20-ad7f-562eaff5485d','和曹光道','梅堯臣','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.14000.json','["無正文。"]'),
('d059f4b0-a587-4944-8db2-cd6c5f4e0673','廨後木芙蓉','梅堯臣','宋','宋诗','song-poetry','','[]','託根地雖卑，凌霜花亦茂。',48,'全唐诗/poet.song.14000.json','["託根地雖卑，凌霜花亦茂。", "物稟固不遷，人情自爲陋。", "幸與時菊開，誰嗟發孤秀。", "楚人搴木末，已見離騷就。"]'),
('855a2ac1-7d83-408d-af70-e9652f11098a','傷驥','梅堯臣','宋','宋诗','song-poetry','','[]','駑驥同一輈，遲速能幾里。',48,'全唐诗/poet.song.14000.json','["駑驥同一輈，遲速能幾里。", "當其被問時，舉策數耳耳。", "馳騁心獨存，壓抑頭不起。", "空傳八駿名，未遇穆天子。"]'),
('d820102b-92fa-467b-b6b0-5818c74ac1ab','陳丞相燕息園','梅堯臣','宋','宋诗','song-poetry','','[]','少仕既勤勞，暮節念君息。',72,'全唐诗/poet.song.14000.json','["少仕既勤勞，暮節念君息。", "小車辭漢庭，緇衣賦衛國。", "廣園樹佳木，鳴鳥來野色。", "京水魚可緡，東陂雁可弋。", "豈不有秦聲，酒酣歌在側。", "寧同扶風人，自去北山北。"]'),
('31638196-c00b-460b-a49d-28e75c8083e2','依韻和普上人古琴見贈','梅堯臣','宋','宋诗','song-poetry','','[]','獨蠒絲爲絃，九竅珥爲軫。',60,'全唐诗/poet.song.14000.json','["獨蠒絲爲絃，九竅珥爲軫。", "彈風松颼颼，聽水流泯泯。", "欣者舉袖舞，悲者欲涕隕。", "若此輒動人，干時固能準。", "虞舜今在上，南薰思無盡。"]'),
('105d6d93-233a-436b-ab78-ca26c527b247','依韻和胡舍人見唁','梅堯臣','宋','宋诗','song-poetry','','[]','西垣閣老號文雄，辭體能兼兩漢風。',64,'全唐诗/poet.song.14000.json','["西垣閣老號文雄，辭體能兼兩漢風。", "絳帳舊生雖授學，灞陵歸將已無功。", "校文豈論居三上，賦分由來本下中。", "不恨早朝秋雨急，猶陪鴛鷺大明宮。"]'),
('25b69413-d779-4010-bc29-92dcbdf71749','題三教圓通堂','梅堯臣','宋','宋诗','song-poetry','','[]','處中最靈智，人與天地參。',96,'全唐诗/poet.song.14000.json','["處中最靈智，人與天地參。", "其間有佛老，曷又推爲三。", "共以圓通出，誠明自包含。", "排楹壓文礎，煥采塗朱藍。", "而將罝吾儒，復欲籠彼聃。", "二徒不自曉，恬若均笑談。", "越鳥不巢北，代馬不嘶南。", "固亦辨殊土，麟鷟唯時堪。"]'),
('9b69395a-55af-413b-a103-13935757656d','和中道秋宴','梅堯臣','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.14000.json','["無正文。"]'),
('c7aa748c-cc39-4736-9bf1-c76c5df849a7','設膾示坐客','梅堯臣','宋','宋诗','song-poetry','','[]','汴河西引黄河枝，黄流未凍鯉魚肥。',112,'全唐诗/poet.song.14000.json','["汴河西引黄河枝，黄流未凍鯉魚肥。", "隨鈎出水賣都市，不惜百金持與歸。", "我家少婦磨寶刀，破鱗奮鬐如欲飛。", "蕭蕭雲葉落盤面，粟粟霜蔔爲縷衣。", "楚橙作虀香出屋，賓朋競至排入扉。", "呼兒便索沃腥酒，倒腸飫腹無相譏。", "逡巡缾竭上馬去，意氣不說西山薇。"]'),
('10074392-2a09-4c88-a1a1-9c9cbcdc72ce','杜挺之新得和州將出京遺予薪芻豆','梅堯臣','宋','宋诗','song-poetry','','[]','魯公馬病不可出，陶令言拙徒扣門。',208,'全唐诗/poet.song.14000.json','["魯公馬病不可出，陶令言拙徒扣門。", "舉家食粥焉用怪，但願漉酒巾常存。", "長安侏儒勝方朔，水邊漂母哀王孫。", "王孫功名立四極，方朔詼談干至尊。", "我才不及三二子，摧藏自愧趨權閽。", "前時永叔寄秉粟，一秋已免憂朝昏。", "今君益之薪與菽，老馬病骨生精魂。", "昨聞新拜歷陽守，王國久客虱處褌。", "都水借船輕復淺，急趁寒汴流渾渾。", "耳清眼明見野色，一聽江鶴醒若噴。", "餘糧滯鈍不暇惜，均於朋契惟義惇。", "設如河涸膠在步，縣邑亦足供雞豚。", "却嗟我甑有時匱，莫與太倉黄鼠論。"]'),
('2e877661-6e58-47b0-a5d9-efc9cc4d25fe','江鄰幾邀食餛飩學書謾成','梅堯臣','宋','宋诗','song-poetry','','[]','老肌瘦腹喜食熱，况乃十月霜侵膚。',64,'全唐诗/poet.song.14000.json','["老肌瘦腹喜食熱，况乃十月霜侵膚。", "與君共貧君餉我，吹虀不學屈大夫。", "前時我膾斫赬鯉，滿坐驚睨卒笑呼。", "誠知舉筯意淺狹，一餐豈計有與無。"]'),
('76bad3e1-c7dc-4122-8804-262e3a6e204e','幽廟','梅堯臣','宋','宋诗','song-poetry','','[]','老狐依叢祠，妖橫起百怪。',108,'全唐诗/poet.song.14000.json','["老狐依叢祠，妖橫起百怪。", "巢梟助鳴聲，穴兔資狡膾。", "巫紿神靈言，俗奏飲食拜。", "三年空禱祈，萬疾無愈差。", "膻臊日已熾，疑畏誰敢懈。", "近者勇丈夫，發揭窟乃壞。", "始時驚其狂，今盡喜其快。", "尨茸毛尚存，獨使尾徒大。", "廟貌更一新，願以邪爲戒。"]'),
('c615c9f4-d99f-4b6d-bb32-bb7255abc59f','十月十八日','梅堯臣','宋','宋诗','song-poetry','','[]','霜梧葉盡枝影疎，井上青絲轉轆轤。',80,'全唐诗/poet.song.14000.json','["霜梧葉盡枝影疎，井上青絲轉轆轤。", "西廂舞娥豔如玉，東楯貴郎才且都。", "纏頭誰惜萬錢錦，映耳自有明月珠。", "一爲轆轤情不已，一爲梧桐心不枯。", "此心此情日相近，卷起飛泉注玉壺。"]'),
('e9a7693f-036d-4fac-badf-8c1b7c9f25b9','禁中瑞竹同本異莖','梅堯臣','宋','宋诗','song-poetry','','[]','孤竹二君子，聖人知獨清。',24,'全唐诗/poet.song.14000.json','["孤竹二君子，聖人知獨清。", "但將奇節並，何用首陽名。"]'),
('1288182e-6aed-4e4d-8f00-0848cef42949','依韻和集英殿秋宴','梅堯臣','宋','宋诗','song-poetry','','[]','殿幄陳金石，宮梧集鳳凰。',216,'全唐诗/poet.song.14000.json','["殿幄陳金石，宮梧集鳳凰。", "侍臣嚴虎帳，法衮被龍章。", "九穀初登稔，羣黎共樂康。", "宴盤犀作鎮，舞綴錦成行。", "玉椀盛冰滑，紗籠奏饌凉。", "廡深容小語，槐密漏微陽。", "庭立衛兼霍，坐尊蕭與張。", "清塵汲瑶井，泛宇藹天香。", "獸躍緣橦地，旗開踏鞠場。", "樓傳紅幘唱，簾隠內家粧。", "鴟攫曾無彈，蜂來悞有芳。", "門傍銅鑄馬，帝所翠爲觴。", "萬國趨王會，諸公佩水蒼。", "螭頭左史筆，陛楯半更郎。", "雅著明時樂，需言盛德光。", "添花慕平一，賜菊異元常。", "身已陪多士，心寧媿下鄉。", "薄才何所補，歌詠播殊疆。"]'),
('f85c6773-8a0d-4215-822c-72faebee56eb','書竄','梅堯臣','宋','宋诗','song-poetry','','[]','皇祐辛卯冬，十月十九日。',288,'全唐诗/poet.song.14000.json','["皇祐辛卯冬，十月十九日。", "御史唐子方，危言初造膝。", "曰朝有巨姦，臣介所憤嫉。", "願條一二事，臣職非妄率。", "巨姦丞相博，邪行世莫匹。", "曩時守成都，委曲媚貴昵。", "銀璫插左貂，窮臘使馳馹。", "邦媛將侈夸，中金賚十鎰。", "爲言寄使君，奇紋織纖密。", "遂傾西蜀巧，日夜急鞭抶。", "紅經緯金縷，排枓鬭八七。", "比比雙蓮花，篝燈戴心出。", "幾日成幾端，持行如鬼疾。", "明年觀上元，被服穩賢質。", "燦然驚上目，遽爾有薄詰。", "既聞所從來，佞對似未失。", "且云虔至尊，於妾豈能必。", "遂回天子顔，百事容丐乞。", "臣今得粗陳，狡獪彼非一。", "偷威與賣利，次第推甲乙。", "是惟陰猾雄，仁斷宜勇黜。", "必欲致太平，在列無如弼。", "弼亦昧平生，况臣不阿屈。", "臣言天下言，臣身寧自恤。"]'),
('3f89c89b-1a14-45d8-83ee-9c68461fdb83','紹巖上人寧親','梅堯臣','宋','宋诗','song-poetry','','[]','爾教禁足不出戶，盛夏畏蹈螻蟻蹤。',32,'全唐诗/poet.song.14000.json','["爾教禁足不出戶，盛夏畏蹈螻蟻蹤。", "赤日去省已亡律，曷若冠带共甘濃。"]'),
('f3868ac7-d0fd-4241-aa4c-c307fd90d788','送許州知錄王殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','霜花如鵠毛，萬里點枯槁。',48,'全唐诗/poet.song.14000.json','["霜花如鵠毛，萬里點枯槁。", "曉入蓬池道，寒侵蘇合袍。", "重來社櫟長，舊寄里門高。", "去事黄丞相，無辭執板勞。"]'),
('6e72da49-40ca-441d-9bbe-b503dd40fd82','慈氏院假山','梅堯臣','宋','宋诗','song-poetry','','[]','風濤舂斷越山骨，聚集奇險成千峯。',32,'全唐诗/poet.song.14000.json','["風濤舂斷越山骨，聚集奇險成千峯。", "碧甕爲潭立涎石，直疑巖底藏蛟龍。"]'),
('b3bcdb81-b8b7-45a9-841e-b05ba698ec09','夜與鄰幾持國歸','梅堯臣','宋','宋诗','song-poetry','','[]','紅塵夜不息，橫衢若煙霧。',48,'全唐诗/poet.song.14000.json','["紅塵夜不息，橫衢若煙霧。", "朝見車馬來，暮見車馬去。", "車中目炯炯，馬上情遽遽。", "交相知是誰，飛先無覓處。"]'),
('541263bf-c91b-4414-a434-f78adcbaf976','十月晦夢游嵩山明日訪宋中道見次道寄宿岳寺','梅堯臣','宋','宋诗','song-poetry','','[]','忽夢嵩峯下，同遊失姓名。',48,'全唐诗/poet.song.14000.json','["忽夢嵩峯下，同遊失姓名。", "山腰荒輦道，巖竇落泉聲。", "黑石文難辨，蒼苔蹟易成。", "他時傳洛詠，知是陸雲兄。"]'),
('93c9387c-779c-42c8-895c-08b637c413ed','十一月七日雪中聞宋中道與其內祥源觀燒香','梅堯臣','宋','宋诗','song-poetry','','[]','三日不相見，逢人問始知。',48,'全唐诗/poet.song.14000.json','["三日不相見，逢人問始知。", "同車侵朔雪，臨水拜靈龜。", "絮撲鴛鴦带，花團蛺蝶枝。", "如何東郭叟，足迹自穿綦。"]'),
('995abc24-227b-4284-84ad-26763a7d5e84','和江鄰幾詠雪二十韻','梅堯臣','宋','宋诗','song-poetry','','[]','十一月將雪，寒誰計有無。',240,'全唐诗/poet.song.14000.json','["十一月將雪，寒誰計有無。", "雲橫凍鵩翼，霰集泣蛟珠。", "萬里風爲使，千門玉作樞。", "縞衣來自鄭，濤鷺卷從吳。", "積甲聞熊耳，觀鵝入越都。", "庭槐高臃腫，屋蓋素模胡。", "騁巧能藏醜，論功解飾枯。", "巢禽皆白鳳，來獸必騶虞。", "遼俗休誇豕，燕丹久望烏。", "袒裘無壯臂，附火念焦臚。", "歌竹休王滿，餐毛活使蘇。", "亡羊何可問，別鶴不應孤。", "靡密同脂網，縈回似舞姝。", "漸深由片片，取重本銖銖。", "日月方收照，乾坤不辨隅。", "雖輕自相壓，更絜亦終渝。", "饑虎僵幽谷，游龍脫勁鬚。", "佳人調密蔗，公子擁貂狐。", "共是空囊客，曾非暖席儒。", "黄昏特過我，興與灞陵俱。"]'),
('4bab7bf5-a7ed-493e-8acb-b17da6753cd9','送張遂州','梅堯臣','宋','宋诗','song-poetry','','[]','華省名郎意若西，相如橋柱舊曾題。',64,'全唐诗/poet.song.14000.json','["華省名郎意若西，相如橋柱舊曾題。", "已將符節爲邦守，不畏關山入馬蹄。", "千里過秦看素滻，三年還蜀度青泥。", "里門錦綬何爲樂，外奉嚴君內阿㜷。"]'),
('513adec3-8682-45d5-a44a-fe302df98dfd','送周寺丞宰新鄭','梅堯臣','宋','宋诗','song-poetry','','[]','仲冬言徂征，曉月在環玦。',48,'全唐诗/poet.song.14000.json','["仲冬言徂征，曉月在環玦。", "京水生層冰，梅山見殘雪。", "縣庭槐已古，堂壁碑未缺。", "惟吾故交意，贈子以爲別。"]'),
('25e82b31-2375-42e1-8a89-ccf9fa371695','次韻和韓持國京師雪','梅堯臣','宋','宋诗','song-poetry','','[]','寒威無遠近，素色混高低。',216,'全唐诗/poet.song.14000.json','["寒威無遠近，素色混高低。", "玉路平何廣，天形浩莫倪。", "壓階寧辨玉，封谷不須泥。", "殄厲非乖候，資農必慰黎。", "大輸中府帛，雜有上公圭。", "星弁交光衆，珠旒動影迷。", "淩波妃度洛，銷鼎士烹齊。", "工鏤罇奇獸，鮮粧印女奚。", "簾開白羽扇，橋跨半輪霓。", "走吠生氂犬，姦埋縮殻蠵。", "力狂墀下馬，聲噤樹頭雞。", "團綴花爭發，燖庖羜已刲。", "獵人初逐跡，饑鳥未辭棲。", "凍酒誰能貰，危樓不厭躋。", "狐冰疑在耳，貍玉刻成蹄。", "可席纖腰舞，盈盤素手携。", "休傳上林雁，曾繫子卿題。", "願逐周王駿，瑶池勝越溪。"]'),
('305e0f52-1e3c-4fad-8b63-86d717516407','送余郎中知鄭州','梅堯臣','宋','宋诗','song-poetry','','[]','西接都門纔百里，壓城殘雪照牙旗。',64,'全唐诗/poet.song.14000.json','["西接都門纔百里，壓城殘雪照牙旗。", "風煙古是諸侯國，鴈鶩新來僕射陂。", "餽食且依當日具，鑄刑無改昔人爲。", "濃薰舊舍青綾被，不越常衙睡足時。"]'),
('42ed1a47-d295-4c0e-96b8-f7caeac19b32','送胡都官知潮州','梅堯臣','宋','宋诗','song-poetry','','[]','自昔揭陽郡，刺史惟韓侯。',120,'全唐诗/poet.song.14000.json','["自昔揭陽郡，刺史惟韓侯。", "韓侯初來時，問吏瀧水頭。", "到官諭鱷魚，夜失風雨湫。", "乃知抱正直，異類尚聽謀。", "潮雖處南粵，禮義無遐陬。", "勿言古殊今，唯在政教修。", "適聞豫章士，勇往登犀舟。", "不畏惡溪惡，疊鼓齊歌謳。", "遠持天子命，水物當自囚。", "更尋賢侯跡，書上揭陽樓。"]'),
('9de53d1b-7207-4cd5-81c6-f29bad18a8e8','送晏太祝之宣城監稅','梅堯臣','宋','宋诗','song-poetry','','[]','每愛昭亭傍，清灘石可數。',48,'全唐诗/poet.song.14000.json','["每愛昭亭傍，清灘石可數。", "兩岸脩竹林，孤城嚴晚鼓。", "自辨越人言，難廋楚鄉語。", "郭門春聚船，江賈無多取。"]'),
('e43d324e-acf8-43b0-b42f-8800fe9d28a4','送張正臣赴泰州幕','梅堯臣','宋','宋诗','song-poetry','','[]','敲冰冰未泮，塞河流玉段。',48,'全唐诗/poet.song.14000.json','["敲冰冰未泮，塞河流玉段。", "輕舸莫言遲，古城滄海畔。", "春皋蘭蕙茁，晚井魚蝦亂。", "時平無羽書，此樂異王粲。"]'),
('638ad521-1e84-4ba7-a703-eb5bbd071641','月下懷裴如晦宋中道','梅堯臣','宋','宋诗','song-poetry','','[]','九陌無人行，寒月浄如水。',120,'全唐诗/poet.song.14000.json','["九陌無人行，寒月浄如水。", "洗然天宇空，玉井東南起。", "我馬卧我庭，帖帖垂頸耳。", "霜花滿黑鬣，安欲致千里。", "我僕寢我廄，相背肖兩已。", "夜深忽驚魘，呼若中流矢。", "是時興我懷，顧影行月底。", "唯影與月光，舉止無猜毀。", "吾交有裴宋，心意月影比。", "尋常同語默，肯問世俗子。"]'),
('06904ffb-0602-4c82-8af7-77c00ac5c5ee','願嚏','梅堯臣','宋','宋诗','song-poetry','','[]','猛虎不獨宿，鴛鴦不隻棲。',74,'全唐诗/poet.song.14000.json','["猛虎不獨宿，鴛鴦不隻棲。", "虞舜遊蒼梧，帝子夜向瀟湘啼。", "時既禪禹妃亦老，老淚洒竹無高低。", "流根及筍駮紅蘚，此情乃與天地齊。", "我今齋寢泰壇下，侘傺願嚏朱顔妻。"]'),
('88600143-859a-40d7-ba43-b68416e02ec9','和司馬學士上辛祀事出郊寄馮學士','梅堯臣','宋','宋诗','song-poetry','','[]','侵曉度南薰，禁鍾猶可聞。',48,'全唐诗/poet.song.14000.json','["侵曉度南薰，禁鍾猶可聞。", "春郊微有霰，上苑稍藏雲。", "齋館人相望，官橋路已分。", "寧同鳥烏樂，翔集自成羣。"]'),
('b79793db-3e61-4c5b-be51-bc30ffd9611e','同蔡君謨江鄰幾觀宋中道書畫','梅堯臣','宋','宋诗','song-poetry','','[]','君謨善書能別書，宣獻家藏天下無。',272,'全唐诗/poet.song.14000.json','["君謨善書能別書，宣獻家藏天下無。", "宣獻既歿二子立，漆匣甲乙收盈厨。", "鍾王真蹟尚可覩，歐褚遺墨非因模。", "開元大曆名流夥，一一手澤存有餘。", "行草楷正大小異，點畫勁宛精神殊。", "坐中鄰幾素近視，最辨纖悉時驚吁。", "逡巡蔡侯得所得，索研鋪紙纔須臾。", "一掃一幅太快健，檀溪躍過瘦的顱。", "觀書已畢復觀畫，數軸江吳種稻圖。", "稻苗秧秧水拍拍，羣鷺矯翼人荷鋤。", "陂塍高下石籠密，竹樹參倚荆籬疎。", "大車立輪轉流急，小犢欺顧稚子驅。", "令人頻有故鄉念，春事況及蠶桑初。", "虎頭將軍畫列女，二十餘子拖裙裾。", "許穆夫人尤窈窕，因誦載馳誠起予。", "余無書性無田區，美人雖見身老癯。", "舉頭事事不稱意，不如倒盡君酒壺。"]'),
('a2421c7f-933d-4800-8727-29500ca5754c','上元夜雪有感','梅堯臣','宋','宋诗','song-poetry','','[]','去年昭亭陽，今夜苦風雪。',48,'全唐诗/poet.song.14000.json','["去年昭亭陽，今夜苦風雪。", "及雪在京城，宵燈亦將滅。", "石花廣袖輕，梅蕊新粧絜。", "怱怱競還家，陌上亂車轍。"]'),
('fd27e476-2ca6-4dab-b8c0-1136433f6cc7','上元雪','梅堯臣','宋','宋诗','song-poetry','','[]','春雪如蝴蝶，春燈如百花。',36,'全唐诗/poet.song.14000.json','["春雪如蝴蝶，春燈如百花。", "漫漫飛不已，愁殺千萬家。", "我今無復夢，擁被讀南華。"]'),
('83d31b12-d084-4bb4-9b4e-e5010cb04ad9','和宋中道元夕十一韻','梅堯臣','宋','宋诗','song-poetry','','[]','鼓聲闐闐衆戲屯，百仞太華臨端門。',176,'全唐诗/poet.song.14000.json','["鼓聲闐闐衆戲屯，百仞太華臨端門。", "端門兩廊多結綵，公卿士女爭來奔。", "接板連簾坐珠翠，簾疎不隔夭妍存。", "車駕適從馳道入，燈如撒星天向昏。", "赭衣已御鳳樓上，露臺宣看簇鈿轅。", "山前絳綃垂霧薄，火龍矯矯紅波翻。", "金吾不飭六街禁，少年追逐乘大宛。", "呼庖索醑鬭豐美，東市憧憧西市喧。", "持錢下數買歌笑，玉杓注飲琉璃盆。", "落然遺俗監主簿，夜對經史多討論。", "比諸豪俠乃自苦，明日苜蓿盈盤餐。"]'),
('dc2b00c1-bf29-43df-a96c-2bd39353a140','和原甫會靈讌集之什','梅堯臣','宋','宋诗','song-poetry','','[]','鳳皇非鷃匹，騏驥非駑攀。',204,'全唐诗/poet.song.14000.json','["鳳皇非鷃匹，騏驥非駑攀。", "自乏鎔質資，不數爐冶間。", "合於衆君子，百事無相關。", "豈期叨稱譽，藉已出瀛寰。", "昨聞競方駕，下直從道山。", "酒壺綴肴其，馬銜鏘玉環。", "上唾屈及賈，下吞崔與班。", "肯比豪華子，黄金邀舞鬟。", "遂來集靈宮，乃等逸士閑。", "養生曾昧術，四體幸無癏。", "池籞雖可樂，魚鳥鬧於闤。", "繞壇安石榴，何時拆朱殷。", "水疑蛟龍潛，雲想鸞鶴還。", "蕙圃秘且深，苔徑歷已艱。", "越樵得射鏑，秦洞迷童顔。", "杳杳頗起羨，區區空服綸。", "塵心儻一浣，石溜春潺潺。"]'),
('7c64083c-63a8-49ff-a1ad-f4d9051067f0','送李才元學士知廣安軍','梅堯臣','宋','宋诗','song-poetry','','[]','楊柳未堪折，柔條時倚風。',48,'全唐诗/poet.song.14000.json','["楊柳未堪折，柔條時倚風。", "朱輪過灞上，杜宇響褒中。", "危棧憎春雨，晴林發曉紅。", "不須言蜀政，當自學文翁。"]'),
('26510f43-f7f4-4f50-a974-a143b531fc15','送王推官宰上洛先歸關中','梅堯臣','宋','宋诗','song-poetry','','[]','跨馬獨歸日，春風隨度關。',48,'全唐诗/poet.song.14000.json','["跨馬獨歸日，春風隨度關。", "客裘將欲綻，社燕亦同還。", "洛水源邊邑，秦人隠處山。", "君家有鳬舄，切莫向雲間。"]'),
('e8c6c58b-26a3-4855-8224-a668b5ea04d3','送信安張從事吉甫兼寄白使君','梅堯臣','宋','宋诗','song-poetry','','[]','西洛故人少，世家今亦稀。',48,'全唐诗/poet.song.14000.json','["西洛故人少，世家今亦稀。", "憐君能及祿，過我苦言歸。", "游宦長城下，生涯舊國微。", "使君應借問，出處竟多違。"]'),
('b8745e8d-5b2a-41ac-89c7-604bffaba221','送懷州張從事仲賓','梅堯臣','宋','宋诗','song-poetry','','[]','行色在車馬，西亭新雨過。',48,'全唐诗/poet.song.14000.json','["行色在車馬，西亭新雨過。", "移家從上黨，佐幕向三河。", "皂莢林初暗，黄粱酒未和。", "七賢無復有，舊迹尚應多。"]'),
('20e41a2d-b88b-4f29-87bd-a3d668bb065a','正月二十二日江淮發運馬察院督河事於國門之外予訪之蔡君謨亦來蔡爲真草數幅馬以所用歙硯贈予','梅堯臣','宋','宋诗','song-poetry','','[]','江南硯工巧無比，深洞鎸斲黑蛟尾。',160,'全唐诗/poet.song.14000.json','["江南硯工巧無比，深洞鎸斲黑蛟尾。", "當心隠隠骨節圓，暗淡又若帖寒朏。", "樣傳孔子留廟堂，用稱右軍書棐几。", "皇皇御史從東來，役徒四萬如屯螘。", "春風擺撼桃杏醉，野亭置酒話亹亹。", "是時復有蔡中郎，筆法縱橫字瑰瑋。", "入門下馬索紙書，虬騰虎攫驚神鬼。", "主人得書不惜硯，贈予覓句題花卉。", "醉携惟恐失手墜，包以弋綈藏以篚。", "明朝聊記一時事，馳騁文章誠不韙。"]'),
('e0032d51-4241-47b4-8623-0b0b60eeaa5d','問洛上王宰訪商山青竹鞭','梅堯臣','宋','宋诗','song-poetry','','[]','蜀鞭雖紫多輕脆，最重商山節眼完。',32,'全唐诗/poet.song.14000.json','["蜀鞭雖紫多輕脆，最重商山節眼完。", "挂在蒼崖飽風雪，蘚花如漆試求看。"]'),
('9ab7ade7-b8b8-4d84-b23f-5972770fe534','正月二十四日同江鄰幾韓持國過師商廟','梅堯臣','宋','宋诗','song-poetry','','[]','大梁城西隅，競傳師商廟。',120,'全唐诗/poet.song.14000.json','["大梁城西隅，競傳師商廟。", "二墳在其傍，枯棘誰往弔。", "予嘗發夢寐，事已驗曩少。", "時逾二十春，偶過非素料。", "江韓寔並駕，寂默苦同調。", "下馬共羅拜，驚愚真可笑。", "致恭古賢人，且異媚近要。", "在昔魏公子，夷門尊隠燿。", "終知養松筠，曾不類蒿藋。", "我輩頗識公，虛名何所釣。"]'),
('b9567e2d-bfea-4aba-a678-b22ce0a11e8d','和李廷老家會飲','梅堯臣','宋','宋诗','song-poetry','','[]','四序豈常停，寒革春寖和。',144,'全唐诗/poet.song.14000.json','["四序豈常停，寒革春寖和。", "始愛衣裘輕，相與車馬過。", "車馬不畏遠，風埃不畏多。", "到門門有槐，槐上時鳥歌。", "時鳥歌猶澀，主人當謂何。", "南開石榴軒，中置飲酒蠃。", "食桉施黄金，饌炙厭白鵝。", "漢糟槎頭美，吳羹成咄呵。", "既醉或放言，抉莊引駘它。", "縱論或好辨，排墨同孟軻。", "日將薄虞淵，執策交相摩。", "欲去舉大白，酌我苦大苛。"]'),
('db0b38d4-a8ae-4132-836a-84f2514cf31c','正月二十七日江鄰幾杜挺之劉原甫貢甫韓持國邀飲於定力院','梅堯臣','宋','宋诗','song-poetry','','[]','昨日會飲我後至，誰欲比我爲王戎。',64,'全唐诗/poet.song.14000.json','["昨日會飲我後至，誰欲比我爲王戎。", "笑知卿輩意易敗，起誚便與俗物同。", "似過黄公酒壚下，嵇阮不見脩竹中。", "杳爾山河隔千里，此心正有古人風。"]'),
('c72b8f66-9cd2-4a87-b6a7-b884311350cb','送宋中道朝陵仍於西都省親','梅堯臣','宋','宋诗','song-poetry','','[]','西出虎牢關，南瞻園廟戟。',48,'全唐诗/poet.song.14000.json','["西出虎牢關，南瞻園廟戟。", "漢殿拜衣冠，魏臺嚴帳帟。", "春風石闕冷，曉氣田塗白。", "早晚下朱陵，先過洛陽陌。"]'),
('b0ec607d-31a4-407a-a4ae-3039a8781227','寄西京通判宋次道學士','梅堯臣','宋','宋诗','song-poetry','','[]','當時交友都無幾，欲問懽娛亦異今。',64,'全唐诗/poet.song.14000.json','["當時交友都無幾，欲問懽娛亦異今。", "花接上林新木變，水分清洛舊池深。", "嵯峨嵩色雲常在，窈窕宮牆草又侵。", "脩竹千竿白家寺，昔年題處可能尋。"]'),
('2dc23355-96e9-4e54-987a-e32a220c44b1','送晁殿丞鄭州簽判','梅堯臣','宋','宋诗','song-poetry','','[]','朝離泌水上，夕去野亭賒。',48,'全唐诗/poet.song.14000.json','["朝離泌水上，夕去野亭賒。", "走馬日銜樹，度河風卷沙。", "關雲來雨脚，陂岸長蒲芽。", "共被方爲樂，軍中莫摻撾。"]'),
('22ec9f87-dcf7-47a9-bf39-8e8e94faedf7','重送宋中道','梅堯臣','宋','宋诗','song-poetry','','[]','隴草陳根發，山櫻宿霧蒸。',48,'全唐诗/poet.song.14000.json','["隴草陳根發，山櫻宿霧蒸。", "將過周故宅，先下漢諸陵。", "栢道春經雨，官溝暗溜冰。", "蒓羹休定價，羊酪易爲勝。"]'),
('4b15975d-8f35-45ad-bff7-e68fd64dfe98','送涇州良原何鬲主簿','梅堯臣','宋','宋诗','song-poetry','','[]','春風入邊磧，二月沙草生。',48,'全唐诗/poet.song.14000.json','["春風入邊磧，二月沙草生。", "胡馬自偷牧，漢農寧廢耕。", "薄田刈晚穀，又餉防秋兵。", "縣版固當重，調輕無與程。"]'),
('2b634511-e446-45f1-8c9a-4f5dd7d3c315','依韻和永叔見寄','梅堯臣','宋','宋诗','song-poetry','','[]','春風約柳一片西，欲託鳥翼傳音稽。',320,'全唐诗/poet.song.14000.json','["春風約柳一片西，欲託鳥翼傳音稽。", "昨朝偶向東城去，草草又逢驄馬蹄。", "長髯御史威正峭，沙堤來坐氣吐霓。", "我乘小駟雖甚瘦，喜見驂馭猶解嘶。", "適聞南都接大尹，笑我出處今何迷。", "恥趨捷徑身已老，懲羹何用頻吹齏。", "蛟龍失水等蚯蚓，鱗角雖有辱在泥。", "困居廢井誰引手，豈得更望青雲梯。", "筆鋒勁發若强弩，餘力曾徹七重犀。", "倦禽雄雌不飽腹，日暮徒念還巢棲。", "大椿朝菌各有盡，此物何怪莊叟齊。", "誠知豪俠自快樂，東郊南陌競鬭雞。", "胸中有道無廣狹，包括宇宙在一稊。", "何時與公去穎尾，湖水漫漫如玻瓈。", "世間會合固不易，況乃仕宦多相睽。", "正似郵亭戀行者，未到止息空歌驪。", "我貧尚不給朝夕，焉得負郭置稻畦。", "筋骸幸且稍輕健，山水縱好無路躋。", "儻公他時買田宅，願以藜杖從招携。", "吾兒詩書不足教，亦以助力於耕犂。"]'),
('89e8581f-c036-42b9-9b4e-fc6554275542','東城送運判馬察院','梅堯臣','宋','宋诗','song-poetry','','["\u5fe7\u56fd\u5fe7\u6c11", "\u9001\u522b", "\u5199\u4eba", "\u53cb\u60c5"]','春風騁巧如翦刀，先裁楊柳後杏桃。',208,'全唐诗/poet.song.14000.json','["春風騁巧如翦刀，先裁楊柳後杏桃。", "圓尖作瓣得疏密，顔色又染燕脂牢。", "黄鸝未鳴鳩欲雨，深園靜墅聲嗷嗷。", "役徒開汴前日放，亦將决水歸河槽。", "都人傾望若焦渴，寒食已近溝已淘。", "何當黄流與雨至，雨深一尺水一篙。", "都水御史亦即喜，日夜順疾回輕舠。", "頻年吳楚歲苦旱，一稔未足生脂膏。", "吾願取之勿求羨，窮鳥困獸易遯逃。", "我今出城勤送子，沽酒不惜典弊袍。", "數途必向睢陽去，太傅大尹皆英豪。", "試乞二公評我說，萬分豈不益一毛。", "國給民蘇自有暇，東園乃可資遊遨。"]'),
('ebd93395-55c1-413f-8b00-bad03ef7794a','送知和州杜駕部','梅堯臣','宋','宋诗','song-poetry','','[]','桐花欲開時，羣噣爭哺兒。',120,'全唐诗/poet.song.14000.json','["桐花欲開時，羣噣爭哺兒。", "但求黄口飫，焉問丹穴饑。", "常山有四鳥，將飛昔已悲。", "中間忽殞逝，豈得安其枝。", "一飲必屢顧，每啄必遲遲。", "今朝竟矯翼，去向江之湄。", "銜芹不自食，欲遺孤與雌。", "此義實已重，莫爲梟所嗤。", "世俗多嫌忌，我胡爲此詩。", "此詩美孝悌，持贈杜挺之。"]'),
('3487a7d0-1d4a-4314-89bd-f74521a0bfe4','送劉郎中知廣德軍','梅堯臣','宋','宋诗','song-poetry','','[]','昔在少年時，辛勤事諸父。',240,'全唐诗/poet.song.14000.json','["昔在少年時，辛勤事諸父。", "諸父爲桃州，物宜皆可數。", "事君勤職貢，采茗先穀雨。", "劭農井田桑，科薅重鋤斧。", "城西大靈祠，措意初似禹。", "將通吳境河，身自同豕伍。", "期婦來餉時，壇上必鳴鼓。", "一爲烏所誤，愧恨去不覩。", "至今存遺堤，五丈立堅土。", "正如開轘轅，黄熊慙啟姥。", "功利欲及民，血食宜簋簠。", "祠後有高山，山頭多棟宇。", "此實諸父爲，禾麻可就俯。", "歲登有樂事，或亦作歌舞。", "賦詩當清明，解禊思洛浦。", "其言在黑石，往往被樂府。", "于今三十年，追想漸成古。", "公將乘朱輪，去問民疾苦。", "治術自有具，薄言無所補。", "缺將陳迹書，又且劇莽鹵。"]'),
('c48239de-a837-486a-b889-68c99a8c81b5','送洛南周寺丞','梅堯臣','宋','宋诗','song-poetry','','[]','將去洛南宰，日聞庭下松。',48,'全唐诗/poet.song.14000.json','["將去洛南宰，日聞庭下松。", "亂山歸四隠，舊墅隔三峯。", "狹谷車能入，春林雨易逢。", "地多椒與漆，貨必厚於農。"]'),
('1b4d1c85-0485-4819-b7d1-b21fd9b8c255','賦石昌言家五題 括蒼石屏','梅堯臣','宋','宋诗','song-poetry','','[]','括蒼黄石屏，樹如濃墨寫。',60,'全唐诗/poet.song.14000.json','["括蒼黄石屏，樹如濃墨寫。", "根深稱條葉，生意絕蕭灑。", "或聞造物手，立異先真假。", "指是龜溲摹，能同自然者。", "天下莫復言，物亦逢知寡。"]'),
('7351b70e-c8d8-4354-bf2c-2bc7f3524721','賦石昌言家五題 白石寒樹屏','梅堯臣','宋','宋诗','song-poetry','','[]','名畫不復生，古魂埋地底。',96,'全唐诗/poet.song.14000.json','["名畫不復生，古魂埋地底。", "技能無所發，騁巧嶄巖裏。", "纖纖掃蒼林，坡岸分迤邐。", "近可筆髮窺，遠若風霾起。", "遂令衆畫師，一點不可毀。", "我今會石家，飲酒酒復美。", "雖不見綠珠，見此差可喜。", "愁逢暴謔人，漬墨書不已。"]'),
('82a4dd37-a6a9-46cb-8975-f3f4c1616915','賦石昌言家五題 白鶻屏事於景仁','梅堯臣','宋','宋诗','song-poetry','','[]','雙睛射空眼角聳，筋爪入節韝絛垂。',176,'全唐诗/poet.song.14000.json','["雙睛射空眼角聳，筋爪入節韝絛垂。", "翅排霜刀毛綴甲，雪色愁突秋雲披。", "當時始得不知價，朝發海東夕九嶷。", "世爲奇俊玩不足，奪質移神歸畫師。", "而今推尚深堂上，燕雀屏絕寧來窺。", "畫師黄荃出西蜀，成都范君能具知。", "范云荃筆不取次，自養鷹鸇觀所宜。", "毰毛植立各有態，剜奇剔怪乃肯爲。", "尋常飼鷹多捕鼠，捕鼠往往驅其兒。", "其兒長大好飛走，其孫賣鼠迭又衰。", "范君語此亦有味，欲戒近習無他移。"]'),
('f6fd85b7-f3d8-4cc1-8ffd-23fb53495218','賦石昌言家五題 懷素草書','梅堯臣','宋','宋诗','song-poetry','','[]','往在河南佐王宰，王收書畫盈數車。',160,'全唐诗/poet.song.14000.json','["往在河南佐王宰，王收書畫盈數車。", "我於是時多所閱，如今過目無遯差。", "石君屏上懷素筆，盤屈瘦梗相交加。", "蒼虬入雲不收尾，卷起海水秋魚蝦。", "毫乾絹竭力未盡，山鬼突鬚垂髿髿。", "牽纏回環斷不斷，秋風枯蔓連蔕瓜。", "縱橫得意自奔放，體法豈計直與斜。", "客有臨書在屏側，豪强奪騎白鼻騧。", "超塵絕跡莫見影，競愛此家忘彼家。", "賞新匿舊世情好，射殺逢蒙亦可嗟。"]'),
('3fb70370-549b-4402-a0c7-14a941276450','賦石昌言家五題 蜀虎圖','梅堯臣','宋','宋诗','song-poetry','','[]','誰謂虎可縛，縛之自有術。',76,'全唐诗/poet.song.14000.json','["誰謂虎可縛，縛之自有術。", "孫生畫此繫在石，拏繩人立尾垂屈。", "墜身怒力欲脫時，顧眄生獰神氣出。", "江南包氏爲最精，毛質雖真猛難匹。", "蜀人不敢道知微，知微名重非今日。"]'),
('efb9f338-f4b4-4679-a262-c07e663b052d','送馬少卿知襄州','梅堯臣','宋','宋诗','song-poetry','','[]','荆州太守隨車雨，昨夜雲從峴首生。',64,'全唐诗/poet.song.14000.json','["荆州太守隨車雨，昨夜雲從峴首生。", "候吏莫辭弓箙重，春泥初著馬蹄輕。", "朝穿錦石江灘潤，暮入煙堤竹屋鳴。", "却嘆當年杜元凱，沉碑空愛異時名。"]'),
('1e966e1b-6e61-44b1-8dd8-786254b72a18','讀賢愚錄','梅堯臣','宋','宋诗','song-poetry','','[]','爲妹不傍貴，爲婦不慢貧。',48,'全唐诗/poet.song.14000.json','["爲妹不傍貴，爲婦不慢貧。", "爲母不縱情，三德今播人。", "胡翁與著錄，蘇倩爲書珉。", "比諸孟氏賢，義已同擇鄰。"]'),
('e17c47a2-8f7a-473f-a7bc-592b1d561a54','送張景純知邵武軍）','梅堯臣','宋','宋诗','song-poetry','','[]','賭却華亭鶴，圍棋未肯還。',48,'全唐诗/poet.song.14000.json','["賭却華亭鶴，圍棋未肯還。", "方爲剖符守，又近爛柯山。", "魚稻荆楊下，風煙楚越間。", "小君能賦詠，應得助餘閑。"]'),
('ac522a43-df34-4072-b2f3-94ad89e23533','送河內令孫偕兼懷太守晁子長','梅堯臣','宋','宋诗','song-poetry','','[]','去年同渡江，江上風雷惡。',56,'全唐诗/poet.song.14000.json','["去年同渡江，江上風雷惡。", "與君相後先，夜向蘆洲泊。", "君今作邑太行陽，八月黄河雁初落。", "漢家借寇吏正閑，到喜秋城罷嚴柝。"]'),
('e9b364d6-a801-4c91-8e86-fec51555a47c','送王待制知陝府','梅堯臣','宋','宋诗','song-poetry','','[]','東周尊夾輔，西漢重行春。',72,'全唐诗/poet.song.14000.json','["東周尊夾輔，西漢重行春。", "風化本從召，河山來自秦。", "選良出舊詔，出守必名臣。", "導從馳千騎，朱丹照兩輪。", "宴杯深畏卯，湖水浄連申。", "重見甘棠詠，爭傳樂府新。"]'),
('9de2aef6-9e6c-4c96-9817-01daba83f05d','送湖州太守章伯鎮','梅堯臣','宋','宋诗','song-poetry','','[]','一夜北山雲，吹作南湖雨。',48,'全唐诗/poet.song.14000.json','["一夜北山雲，吹作南湖雨。", "南湖迎使君，荷聲競笳鼓。", "頻年吳境旱，吳儂相聚語。", "今日見賢侯，魚蝦亦跳舞。"]'),
('1f976067-ae80-4d01-924a-b8598c6d4b57','送王伯初通判婺州','梅堯臣','宋','宋诗','song-poetry','','[]','隠侯沒來久，八詠無繼作。',72,'全唐诗/poet.song.14000.json','["隠侯沒來久，八詠無繼作。", "星宿少光芒，虹霓挂樓角。", "邇來數百年，才彥森臺閣。", "君平請是行，有意在巖壑。", "手持能賦筆，勢似强弩彍。", "會待東南風，芬然傳蕙若。"]'),
('6e30d642-ce59-4134-9f76-927487cc8325','送徐州簽判李廷評','梅堯臣','宋','宋诗','song-poetry','','[]','曩者初見君，同來許昌幕。',60,'全唐诗/poet.song.14000.json','["曩者初見君，同來許昌幕。", "今雖俱服除，獨得王粲樂。", "山東寇盜息，沛上風物博。", "主人況豪英，罇俎不落莫。", "行行無久留，歸向騏驎閣。"]'),
('a5b8419d-7dcc-49b3-b4a9-5ef94d1ee477','依韻和王中丞憶許州西湖','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','拍岸千尋水，陪京第一州。',120,'全唐诗/poet.song.14000.json','["拍岸千尋水，陪京第一州。", "艷光落日改，明月與人留。", "細浪差差蹙，深灣曲曲幽。", "跳鱗無限樂，春蔓不勝柔。", "晚下蛙爲吹，閑來葉作舟。", "亂禽喧後塢，急雨過西疇。", "負笱漁郎去，將雛燕子秋。", "跨橋尋島入，疏竇出城流。", "密樹能藏馬，晴沙自立鷗。", "緣何探景備，平昔從公遊。"]'),
('e83e81ca-450f-47af-b0b3-c244b9e109ba','自和','梅堯臣','宋','宋诗','song-poetry','','[]','忽思湖上趣，水闊似南州。',120,'全唐诗/poet.song.14000.json','["忽思湖上趣，水闊似南州。", "地接過從易，人閑取次留。", "絮輕遞吹卷，蒲嫩匝堤幽。", "落果知禽入，行莎覺履柔。", "蓮爲游女曲，藤繫野人舟。", "晚筍長過篠，春秧綠滿疇。", "賞心曾卜晝，望岫最宜秋。", "款款穿叢蝶，涓涓敗堰流。", "風埃無入座，笳鼓或驚鷗。", "下客林泉性，時能夢寐遊。"]'),
('6940af58-1918-447f-a850-602f251b25d8','觀史氏畫馬圖','梅堯臣','宋','宋诗','song-poetry','','[]','誰縫冰紈十二幅，畫出胡馬一百蹄。',144,'全唐诗/poet.song.14000.json','["誰縫冰紈十二幅，畫出胡馬一百蹄。", "胡人縱獵走且射，野牛駭怒頭角低。", "黄驄鐵騮白的顙，散作五花毛不齊。", "彎弓未發箭在手，二十五匹俱爭西。", "往聞胡瓌能畫馬，陰山七騎皆戎奚。", "或牽或立或仰視，閑暇意思如鳴嘶。", "風吹裘带旗脚展，沙草一向寒凄迷。", "鳳缾挈酒鞍挂獲，氊廬毳帳半隠堤。", "君之二圖誠亦好，若比瓌筆猶雲泥。"]'),
('1ae72d43-c414-46ba-9901-a71585466629','送顧中舍赴德順軍','梅堯臣','宋','宋诗','song-poetry','','[]','聞從壠坻去，壠坻多羌兵。',36,'全唐诗/poet.song.14000.json','["聞從壠坻去，壠坻多羌兵。", "明月共臨峽，風泉如哀箏。", "志士莫憶家，將軍亦儒生。"]'),
('da470769-141d-42f1-bf48-cdaa3b3a17f1','送畢郎中提點淮南茶場','梅堯臣','宋','宋诗','song-poetry','','[]','汴中春絮亂，淮上鮆魚時。',48,'全唐诗/poet.song.14000.json','["汴中春絮亂，淮上鮆魚時。", "順水疾奔馬，出都猶脫羈。", "拜親將已近，食膾不言遲。", "到日問茶事，徧山開幾旗。"]'),
('784a4a53-56d4-4fd6-ba34-aaab673c3953','三月二十五日喜雨','梅堯臣','宋','宋诗','song-poetry','','[]','初爲委吏承命書，是夜旱雨深一尺。',64,'全唐诗/poet.song.14000.json','["初爲委吏承命書，是夜旱雨深一尺。", "乃知窮困同草萊，隔歲焦枯有時滌。", "向聞乖龍池底藏，驅逐肯行須霹靂。", "今無雷電已滂然，好在三公莫憂責。"]'),
('e47861e8-5654-4388-90b9-ab0c7052d2d7','寄達觀禪師','梅堯臣','宋','宋诗','song-poetry','','[]','身在大梁塵土中，心思隠靜雲山裏。',32,'全唐诗/poet.song.14000.json','["身在大梁塵土中，心思隠靜雲山裏。", "忽聞乘柸江上歸，月下碧雞啼不已。"]'),
('241338a9-accd-4c9a-b397-3d4b6793ee94','送劉推官貢甫赴汝州','梅堯臣','宋','宋诗','song-poetry','','[]','苑路如繩直，郊亭一雨過。',48,'全唐诗/poet.song.14000.json','["苑路如繩直，郊亭一雨過。", "淺沙車轍穩，晴樹晝陰多。", "牧馬方鳴澤，芸瓜已滿坡。", "今聞從事去，試聽壤人歌。"]'),
('e73ffa4d-548a-4841-b8f7-a3ac301ebeb2','寄渭州劉太保求市堪乘穩駃馬','梅堯臣','宋','宋诗','song-poetry','','[]','有馬齒加疲且劣，欲求中駟問將軍。',32,'全唐诗/poet.song.14000.json','["有馬齒加疲且劣，欲求中駟問將軍。", "爲言身老趨朝熟，只要馴良不撓羣。"]'),
('093333bc-bc0b-415f-bb91-812fd40a208d','寄渭州經略王龍圖','梅堯臣','宋','宋诗','song-poetry','','[]','儒將一臨塞，虜塵無犯邊。',48,'全唐诗/poet.song.14000.json','["儒將一臨塞，虜塵無犯邊。", "卷旗瞻漢地，收馬入胡天。", "練卒朝營鼓，鳴箏夜峽泉。", "遥知玉關路，烽火不須傳。"]'),
('2b0f0e47-131e-4483-bcf1-b7f150d9e704','送王安之太博歸西京','梅堯臣','宋','宋诗','song-poetry','','[]','聞君夢慈親，手把青玉佩。',168,'全唐诗/poet.song.14000.json','["聞君夢慈親，手把青玉佩。", "循環念歸期，月已九弦晦。", "既寤心悁悁，面垢不暇頮。", "屈指必春還，忽焉朱火代。", "夢兆且差池，决去河可能。", "昨來理恩典，佐州令近塞。", "雁門適有乏，求往苦言礙。", "曰惟都督雄，豈付小邦倅。", "乃知仕宦難，分寸肯少貸。", "遂乞回洛陽，拜省慰憂愛。", "除補不應欺，聖時公道在。", "幸存舊郭園，重種滿畦菜。", "上爲北堂歡，間與良士對。", "此實賢者爲，贈行因以載。"]'),
('cbdcc392-c3a5-49bc-9285-d29bb3db47a8','寄致仕張郎中','梅堯臣','宋','宋诗','song-poetry','','[]','門榮世美高天下，身退心閑住洛陽。',64,'全唐诗/poet.song.14000.json','["門榮世美高天下，身退心閑住洛陽。", "畫鶴能同薛少保，愛書還比蔡中郎。", "花陰小酌呼鄰父，月下清吟掃石床。", "不問從來生計薄，題籤盈閣是家藏。"]'),
('fada0490-8104-4b65-927b-f685e657c360','送錢駕部知邛州','梅堯臣','宋','宋诗','song-poetry','','[]','細雨梅初熟，輕寒麥已秋。',48,'全唐诗/poet.song.14000.json','["細雨梅初熟，輕寒麥已秋。", "路危趨劍道，夢穩過刀州。", "秦栗非吳食，巴粳類越疇。", "當壚無復舊，試似長卿求。"]'),
('5fc8244a-1ee2-4a2c-9a94-877bc2ac3d44','文惠師贈新筍','梅堯臣','宋','宋诗','song-poetry','','[]','劉累死，龍不馴。',120,'全唐诗/poet.song.14000.json','["劉累死，龍不馴。", "世間士，不識真。", "有真物，實去人。", "或在山，亦隠鱗。", "或多孫，出水濱。", "奮雷轟轟萬里春，厚土坼裂窮蟄振。", "牙甲戢戢不可數，剗掘誰怕天公嗔。", "煑之桉酒美如玉，甘脆入齒饞流津。", "荆吳易得梁宋少，二年不食思無因。", "豈意今朝忽有遺，不忍獨饗呼吾鄰。"]'),
('1b1370ad-4dae-4571-a1a2-7d6af8e5677e','觀何君寶畫','梅堯臣','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','燕馬易畫，吳牛難圖。',366,'全唐诗/poet.song.14000.json','["燕馬易畫，吳牛難圖。", "馬骨隠細牛骨麤，馬毛厚密牛毛疎。", "麤疎必辨別，細密多模胡。", "乃知戴嵩筆，能出韓幹徒。", "幹馬精神在韁勒，嵩牛怒鬭無牽拘。", "昨日何家觀小軸，絹雖破爛色不渝。", "二頭相觴角競掎，前脚如跪後脚舒。", "尾株榻直脊膂蹙，筋力寫盡蹄腕殊。", "一勝一敗又苦似，勝者很逐敗者趨。", "卷窮赤印置小字，置字乃是陶尚書。", "尚書國初人，愛畫收幾厨。", "買時不惜金與帛，帛載牛車錢載馿。", "後世兒孫不能保，賣人窮市無須臾。", "凡目矜新不重故，千錢酬直皆笑愚。", "四牛遂爲何氏有，裝背入眼天下無。", "坐中吾儕趣已異，又喜玄女傳兵符。", "此本實稱閻令畫，下筆簡細容顔姝。", "三人鬼狀一牛首，八女二十美丈夫。", "黄帝中間蔭葩蓋，霞扇錯玳旌擁朱。", "冠服難知歲月遠，但見儀衛森清都。", "復觀鹿臺獨夫受，妲己不笑何由娛。", "酒池肉林騎行炙，剖心斮脛堪悲吁。", "數幅吳王宴西子，綵舟張樂當姑蘇。", "宮娥數百簇高下，鬒髻一一紅芙蕖。"]'),
('d7a7306d-06ee-4393-ab94-88f54bef6698','送任太博歸省西都','梅堯臣','宋','宋诗','song-poetry','','[]','人言少保持家謹，載見西京萬石君。',64,'全唐诗/poet.song.14000.json','["人言少保持家謹，載見西京萬石君。", "子舍今歸浣裙切，里門重戒下車勤。", "田園一一能爲計，僮僕訢訢亦有聞。", "我負洛陽山水久，試因行色寄嵩雲。"]'),
('d63bd222-ccbd-4e3b-ae9b-d0f5911180fb','送少卿張學士知洪州','梅堯臣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','朱旗畫舸一百尺，五月長江水拍天。',64,'全唐诗/poet.song.14000.json','["朱旗畫舸一百尺，五月長江水拍天。", "穩去先應望廬岳，暫來誰復見龍泉。", "閣經吏部重爲記，山識吳王舊鑄錢。", "往迹可尋軍事少，賸書遺逸附青編。"]'),
('ef1596ae-b7a8-4be9-8b1d-bf6ed244e000','觀楊之美畫','梅堯臣','宋','宋诗','song-poetry','','[]','天官乘車建朱旗，赤旛前亞風卷披。',240,'全唐诗/poet.song.14000.json','["天官乘車建朱旗，赤旛前亞風卷披。", "二龍緩駕蒼髯垂，印箱傍挈文籍隨。", "雙驂推軛如畏遲，行從冠服多威儀。", "水官自有真龍騎，兩佐並跨鯨尾螭。", "步趨羣吏怪眼眉，雲生海面無端涯。", "雷部處上相與期，人身獸爪負鼓馳。", "後有同類挾且搥，次執電鏡風囊吹。", "青蛇有角魚足鬐，上下引導神所施。", "地官既失不可知，此畫傳是閻令爲。", "設色鮮潤筆法奇，絹理膩滑雞子皮。", "吳生龍王多裂隳，八軸展玩忘晨炊。", "李成山水曉景移，黄荃花竹雀擁枝。", "韓幹馬本模搭時，神駿都失存毫氂。", "日高腹枵眼眥眵，邂逅獲見何言疲。", "厚謝主翁意不衰，他日飽目看無遺。"]'),
('d8840e55-8255-4a8a-97dc-5c7d25f06078','李審言遺酒','梅堯臣','宋','宋诗','song-poetry','','[]','大梁美酒斗千錢，欲飲常被饑窘煎。',208,'全唐诗/poet.song.14000.json','["大梁美酒斗千錢，欲飲常被饑窘煎。", "經時一滴不入口，漱齒費盡華池泉。", "昨日靈昌兵吏至，跪壺曾不候報箋。", "赤泥坼封傾瓦盎，母妻共嘗婢流涎。", "鄰家莆萄未結子，引蔓垂過高牆巔。", "當街賣杏已黄熟，獨堆百顆充盤筵。", "老年牙疎不喜肉，况乃下箸無腥羶。", "空腸易醉忽酩酊，倒頭夢到上帝前。", "賜臣蒼龍跨入月，不意正值姮娥眠。", "無人采顧傍玉兔，便取作腊下九天。", "拔毛爲筆筆如椽，狂吟一掃一百篇。", "其間長句寄東郡，東郡太守終始賢。", "切莫汲竭滑公井，留釀此醑時我傳。"]'),
('cd1c8197-a681-4c2a-8345-8dd2dc4f2a9d','送邵郎中知潭州','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','張鐃疊吹洞庭外，緣虎带刀蠻帥迎。',64,'全唐诗/poet.song.14000.json','["張鐃疊吹洞庭外，緣虎带刀蠻帥迎。", "且諭漢家綏撫厚，莫言湘守事權輕。", "木奴洲近霜包熟，斑竹林昏野鳥鳴。", "賈誼宅邊寒井在，暫留千騎漱餘清。"]'),
('c17cf30a-6255-49ae-b6f5-c4cab7ff38d3','送楊叔恬應北京辟','梅堯臣','宋','宋诗','song-poetry','','[]','昔時見子宛丘下，丞相待子知子賢。',88,'全唐诗/poet.song.14000.json','["昔時見子宛丘下，丞相待子知子賢。", "子於文字實贍博，海客謾估珠盈船。", "欲賣明月一寸魄，雖豪未肯售以錢。", "通都大邑忽辨寶，直取不犯驪龍涎。", "遂作照乘物，矜夸魏人前。", "從茲十二車，光彩生從先。"]'),
('8b8124d3-f70b-4804-87de-5cf70770d3f2','送洪州通判何太博先歸新淦','梅堯臣','宋','宋诗','song-poetry','','[]','拜官江上客，乘馬不乘船。',48,'全唐诗/poet.song.14000.json','["拜官江上客，乘馬不乘船。", "獨畏蛟龍浪，將歸風雨天。", "葛花侵野徑，源水入腴田。", "君住巴丘下，西山道路連。"]'),
('654c5179-5b70-4af8-983f-b75e5406d9d7','五月七日見賣瓠者','梅堯臣','宋','宋诗','song-poetry','','[]','老圃奪天時，馬通爲煦嫗。',60,'全唐诗/poet.song.14000.json','["老圃奪天時，馬通爲煦嫗。", "四月彼種瓜，五月此賣瓠。", "陽陂與糞壤，功力且異趣。", "瓜遲瓠何早，豈不同雨露。", "速利乃在人，爭先無晚暮。"]'),
('6dddede4-2b81-404f-9fda-3c90fbe269ef','和江鄰幾景德寺避暑','梅堯臣','宋','宋诗','song-poetry','','[]','垤蟻不應雨，鳴鳶不生風。',176,'全唐诗/poet.song.14000.json','["垤蟻不應雨，鳴鳶不生風。", "鬰氣若甑炊，初陽如火紅。", "裸膚汗交流，腯體膏將鎔。", "龍頭費挹酌，犢鼻强遮蒙。", "常畏俗物來，去避青蓮宮。", "廣堂鋪琉璃，高簷蔭梧桐。", "廊壁畫地獄，獄具鑊鋸舂。", "鐵城何焰焰，鐵床亦彤彤。", "誰知炮烙死活間，傳自西域黄面翁。", "正類人世苦此熱，聲利役使亡西東。", "京師貴賃幾椽舍，窮煎相似聒欲聾。", "屋頭朝爨作飲食，枕底夕艾驅蚊蟲。", "宜爾近巷江夫子，賦詩特壓塵土中。"]'),
('743611f4-4ac0-451e-9963-83f0ae1c70fc','送趙諫議知徐州','梅堯臣','宋','宋诗','song-poetry','','[]','鹿車幾兩馬幾匹，軫建朱幡騎彀弓。',64,'全唐诗/poet.song.14000.json','["鹿車幾兩馬幾匹，軫建朱幡騎彀弓。", "雨過短亭雲斷續，鶑啼高柳路西東。", "呂梁水注千尋險，大澤龍歸萬古空。", "莫問前朝張僕射，毬場細草綠蒙蒙。"]'),
('398badfc-cfe0-4b20-bf97-ab8b014a4d2e','送邵戶曹隨侍之長沙','梅堯臣','宋','宋诗','song-poetry','','[]','青袍會稽掾，采服湘江行。',48,'全唐诗/poet.song.14000.json','["青袍會稽掾，采服湘江行。", "水館魚方美，犀舟枕自清。", "鷓鴣啼欲雨，螮蝀見還晴。", "風土雖卑溼，醇醪可養生。"]'),
('5857a981-6181-4e5c-b331-99874fe06a20','晨起裴吳二直講過門云鳳閣韓舍人物故作五章以哭之  其一','梅堯臣','宋','宋诗','song-poetry','','[]','平生交友淚，又哭寢門前。',48,'全唐诗/poet.song.14000.json','["平生交友淚，又哭寢門前。", "魯叟不言命，楚人空問天。", "月沉滄海底，星隕太微邊。", "莫恨終埋沒，文章自可傳。"]'),
('bfda9825-a816-40fa-8555-5f0cb54f24a9','晨起裴吳二直講過門云鳳閣韓舍人物故作五章以哭之  其二','梅堯臣','宋','宋诗','song-poetry','','[]','使虜嘗專對，江湖謫幾年。',48,'全唐诗/poet.song.14000.json','["使虜嘗專對，江湖謫幾年。", "始看還近侍，遽此隔重泉。", "沃酒酒空滿，託詞詞謾傳。", "視予猶手足，莫怪獨潸然。"]'),
('189c03fa-ddc1-4239-9e5e-7c9a29e3eb1b','晨起裴吳二直講過門云鳳閣韓舍人物故作五章以哭之  其三','梅堯臣','宋','宋诗','song-poetry','','[]','算數曾無據，仁人亦莫聞。',48,'全唐诗/poet.song.14000.json','["算數曾無據，仁人亦莫聞。", "很愚多至老，蘭桂苦先焚。", "不竟千秋恨，還如萬里分。", "臨風一號慟，易散日邊雲。"]'),
('5c3f2a93-fb4f-43bd-92c2-4717001db257','晨起裴吳二直講過門云鳳閣韓舍人物故作五章以哭之  其四','梅堯臣','宋','宋诗','song-poetry','','[]','昨時賓晏地，今見繐緯遮。',48,'全唐诗/poet.song.14000.json','["昨時賓晏地，今見繐緯遮。", "棲室那因鵩，從杯不爲蛇。", "曾無越人術，意起漢臣嗟。", "明日東城陌，悲凉後部笳。"]'),
('7f9764f5-08ab-478a-b5e6-63f20bf6beef','晨起裴吳二直講過門云鳳閣韓舍人物故作五章以哭之  其五','梅堯臣','宋','宋诗','song-poetry','','[]','曉陌行車過，交相歎且驚。',48,'全唐诗/poet.song.14000.json','["曉陌行車過，交相歎且驚。", "荀龍聞一蛻，穆駿失全鳴。", "不復中書直，空餘左史成。", "緒言猶在耳，尚想見平生。"]'),
('b7fc422b-625b-4622-96ac-6a7fdb72fdd5','聞高平公殂謝述哀感舊以助挽歌三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','文章與功業，有志不能成。',48,'全唐诗/poet.song.14000.json','["文章與功業，有志不能成。", "嘗以隮高位，終然屈大名。", "遺風猶可見，逝水更無情。", "歸卜青烏壠，韓城苦霧平。"]'),
('de481383-3cbc-4070-a633-aa316051de99','聞高平公殂謝述哀感舊以助挽歌三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','京洛同逃酒，單袍跨馬歸。',48,'全唐诗/poet.song.14000.json','["京洛同逃酒，單袍跨馬歸。", "明朝各相笑，此分不爲稀。", "公既參鑪冶，予將事蕨薇。", "悲哀無以報，有涕向風揮。"]'),
('1f26ffd4-49df-47e1-bb7a-5cf8cc18b98c','聞高平公殂謝述哀感舊以助挽歌三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','一出屢更郡，人皆望酒壺。',48,'全唐诗/poet.song.14000.json','["一出屢更郡，人皆望酒壺。", "俗情難可學，奏記向來無。", "貧賤常甘分，崇高不解諛。", "雖然門館隔，泣與衆人俱。"]'),
('9add83f1-de28-45a3-9da4-d63a69e18078','歐陽郡太君挽歌二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','夫人有賢子，往歲謫夷陵。',48,'全唐诗/poet.song.14000.json','["夫人有賢子，往歲謫夷陵。", "欲使無愁鬰，怡然見寢興。", "外詞陽磊磊，內畏實兢兢。", "隮壽復終貴，共爲時所稱。"]'),
('a41d9220-d3ad-4a4f-849d-6bf824bbbc8c','歐陽郡太君挽歌二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','當時丈人歿，雖少守孤兒。',48,'全唐诗/poet.song.14000.json','["當時丈人歿，雖少守孤兒。", "以及成名譽，何嘗厭藿藜。", "暮年終饗福，陰騭不應欺。", "莫使碧江上，獨傳陶母碑。"]'),
('e5e3e3a4-ce58-427f-912a-fd817fc7b121','依韻和石昌言學士求鼠鬚筆之什鼠鬚鼠尾者前遺君謨今以松管代贈','梅堯臣','宋','宋诗','song-poetry','','[]','江南飛鼠拔長尾，勁健頗勝中山毫。',64,'全唐诗/poet.song.14000.json','["江南飛鼠拔長尾，勁健頗勝中山毫。", "其間又有蒼鼠鬚，入用不數南雞毛。", "二物緩急豈常獲，捕刺徒爾操蠻刀。", "舊藏已贈蔡夫子，報君松管何蕭騷。"]'),
('7af57be3-625c-4e6e-98da-fba283656bfb','邃隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','大梁車馬地，塵土飛百尺。',96,'全唐诗/poet.song.14000.json','["大梁車馬地，塵土飛百尺。", "賢愚走其間，朝暮不見迹。", "北望天波門，垣垣宗室宅。", "宗室令王孫，愛書輕玉帛。", "華宇何深沈，但聞列圖籍。", "曲房有窈窕，空自事眉額。", "體胖生粹和，安在處巖石。", "古來爲善樂，豈以歌鐘適。"]'),
('fbb4c278-4cc0-41ee-8dd9-896e88a24d9d','讀永叔所撰薛雲衛碣','梅堯臣','宋','宋诗','song-poetry','','[]','文章如塗金，光彩發美器。',48,'全唐诗/poet.song.14000.json','["文章如塗金，光彩發美器。", "所宜玉石間，模寫傳千祀。", "堅堅孝子心，森森柏庭閟。", "豈與石麒麟，原傍鬭蒼翠。"]'),
('23d519fd-750c-4a5d-8166-f675cc1fcef3','和石昌言以蜀牋南牋答松管之什','梅堯臣','宋','宋诗','song-poetry','','[]','青松抽幹龍鱗細，秋兔束毫雞距尖。',32,'全唐诗/poet.song.14000.json','["青松抽幹龍鱗細，秋兔束毫雞距尖。", "楊子擬經聊以贈，蜀麻江楮報何嫌。"]'),
('2d320c43-c281-406a-8ef4-f381e2a5867b','赤蟻辭送楊叔武廣南招安','梅堯臣','宋','宋诗','song-poetry','','[]','南方赤蟻大若象，潛荒穴洞人莫逢。',112,'全唐诗/poet.song.14000.json','["南方赤蟻大若象，潛荒穴洞人莫逢。", "天公合雨不决雨，從橫亂出將自封。", "侵疆凌壤壞城市，戰鬭億倍南柯雄。", "嘗聞穿山食此物，此物既大非常凶。", "張舌流涎莫可餌，枉啄不怕長戈舂。", "今令智者以智取，即見蚳醢傳太宮。", "因而使知禍福理，天子下令雲從龍。"]'),
('cb669fcc-a6b1-4147-964a-68c50b33ebbb','走筆戲邵興宗','梅堯臣','宋','宋诗','song-poetry','','[]','子魚一尾不曾有，又諾毘陵蒼鼠毫。',32,'全唐诗/poet.song.14000.json','["子魚一尾不曾有，又諾毘陵蒼鼠毫。", "細粒吳粳誰下咽，尖頭越管底能操。"]'),
('0266107b-3ae6-4fed-ac2e-8fa862361ebc','送李中舍襲之宰南鄭','梅堯臣','宋','宋诗','song-poetry','','[]','莫問褒中道路難，襄陽直上幾重灘。',64,'全唐诗/poet.song.14000.json','["莫問褒中道路難，襄陽直上幾重灘。", "蒼煙古柏漢高廟，落日荒茅韓信壇。", "出水槎頭一絲挂，穿虹雨脚兩橋殘。", "土風大抵如南國，期會先時俗自安。"]'),
('08a1f3ce-b19e-41b0-8153-8202770072bf','送王察推縝之鄧州','梅堯臣','宋','宋诗','song-poetry','','[]','昔向南陽憶洛陽，秋橙初熟半林黄。',64,'全唐诗/poet.song.14000.json','["昔向南陽憶洛陽，秋橙初熟半林黄。", "車過白水沙痕闊，鴈落鉗盧稻穟長。", "廢壘漢碑金刻字，古原秦冢石爲羊。", "太平羽檄何曾有，賓主相歡菊薦觴。"]'),
('a7060a65-10cd-4443-bbac-80e315dbe4db','戲酬高員外鯽魚','梅堯臣','宋','宋诗','song-poetry','','[]','天池鯽魚長一尺，鱗光鬣動楊枝磔。',80,'全唐诗/poet.song.14000.json','["天池鯽魚長一尺，鱗光鬣動楊枝磔。", "西城隠吏江東客，晝日馳來奪炎赫。", "冷氣射屋汗收額，便教斫膾傾大白。", "我所共樂仲與伯，羨君赴約笑啞啞。", "持扇已見飛鸞翮，欲往從之雲霧隔。"]'),
('630d8e1a-742b-48e3-b27b-ac7554cbb7c2','送何濟川學士知漢州','梅堯臣','宋','宋诗','song-poetry','','[]','丞相初得君，有志重儒術。',192,'全唐诗/poet.song.14000.json','["丞相初得君，有志重儒術。", "乃言天下士，徒此占清秩。", "遂懲衒鬻人，忝冒十八七。", "進君天祿閣，比衆爲第一。", "又薦王張韓，恬可與君匹。", "吾儕宜慙羞，空自預朝韠。", "欲歸無田園，强住枉歲日。", "值君乘高軒，西望函谷出。", "當時迎長卿，書史傳未悉。", "車馳及襁負，千萬今可詰。", "老農喜君來，田租不妄率。", "織婦喜君來，縑機當俟畢。", "府胥喜君來，督責去暴抶。", "疾苦無不求，前人唯法律。", "晝錦榮既浮，康民美方溢。", "真爲丈夫志，豈是名過實。"]'),
('0cdd78f3-eca9-4d56-bdce-42b4dc76602e','依韻和達觀師聞蟬','梅堯臣','宋','宋诗','song-poetry','','[]','飲餘晨露吸餘風，噪遍高枝爲俗聾。',32,'全唐诗/poet.song.14000.json','["飲餘晨露吸餘風，噪遍高枝爲俗聾。", "欲比伯夷清已甚，不餐周粟腹常空。"]'),
('0872e6ad-ba45-4da2-8868-825c9346ca14','西水門晚遇雨','梅堯臣','宋','宋诗','song-poetry','','[]','急雨射瓦瓦欲裂，猛吹驅熱熱斗歇。',48,'全唐诗/poet.song.14000.json','["急雨射瓦瓦欲裂，猛吹驅熱熱斗歇。", "西北日脚雲猶遮，東南樹頭虹未滅。", "燕子健翅翩翩時，蜻蜓困立塘蒲折。"]'),
('e85f6e3f-b03f-4c8b-8d49-67b612bc1b3a','依韻和杜相公謝蔡君謨寄茶','梅堯臣','宋','宋诗','song-poetry','','[]','天子歲嘗龍焙茶，茶官催摘雨前牙。',64,'全唐诗/poet.song.14000.json','["天子歲嘗龍焙茶，茶官催摘雨前牙。", "團香已入中都府，鬭品爭傳太傅家。", "小石冷泉留早味，紫泥新品泛春華。", "吳中內史才多少，從此蒓羹不足誇。"]'),
('a35fc01a-b7b1-4175-9e7f-ea964729b062','依韻和接花','梅堯臣','宋','宋诗','song-poetry','','[]','唯是圃人巧，非關元化偏。',48,'全唐诗/poet.song.14000.json','["唯是圃人巧，非關元化偏。", "折條違物理，遷豔得花權。", "美女嫁寒壻，醜株生極妍。", "世間多妄合，吾不謂之然。"]'),
('5b595d26-2dc4-47f3-ae86-abfd14edd099','送石昌言學士','梅堯臣','宋','宋诗','song-poetry','','[]','混混拍堤瓜蔓水，軒軒銜尾挂檣船。',64,'全唐诗/poet.song.14000.json','["混混拍堤瓜蔓水，軒軒銜尾挂檣船。", "使君東下只朝夕，父老走迎無後先。", "古堞秋耕拾銅鏃，長淮瀑雨入壕蓮。", "鳴猿舞鶴仍持去，不憶承明夜直眠。"]'),
('2ee69c3f-8024-456e-8268-f31675d32f9b','書南事','梅堯臣','宋','宋诗','song-poetry','','[]','大梁國南門，馹騎方騰趨。',132,'全唐诗/poet.song.14000.json','["大梁國南門，馹騎方騰趨。", "波波一何急，蠻寇圍番禺。", "番禺本無備，前頼魏大夫。", "大夫築子城，今得守以須。", "兵雖不滿萬，閉壁堪指呼。", "老幼轉木石，壯健操矛弧。", "廩庫得以完，日月不易圖。", "城中舊無井，魏鑿安轆轤。", "魏由飛語去，不使立外郛。", "古稱時有待，淺薄皆謂紆。", "曲突與爛額，看取報功殊。"]'),
('20bf88e1-03b3-4ce5-aa90-263b5a7b3a8e','送吳照鄰都官還江南','梅堯臣','宋','宋诗','song-poetry','','[]','霜前江水磨碧銅，岸背菱葉翹赤蟲。',64,'全唐诗/poet.song.14000.json','["霜前江水磨碧銅，岸背菱葉翹赤蟲。", "吳郎鬢絲生幾縷，不羞月上扶桑東。", "羞見清波照人影，去時黑髮吹春風。", "五年歸來婦應喜，從此不問西飛鴻。"]'),
('c179bf84-42fd-4f7b-9ee0-96ecefc9e497','馮子都詩','梅堯臣','宋','宋诗','song-poetry','','[]','黄金畫車屋，韋絮緣車輪。',168,'全唐诗/poet.song.14000.json','["黄金畫車屋，韋絮緣車輪。", "牽以五采絲，藉以刺繡茵。", "出入長信宮，晝夜將誰親。", "所親美且少，玉頰丹砂脣。", "殷羅縫輕襦，明珠攢緇巾。", "半醉卧車中，侍婢躡行塵。", "憶昔廣明亭，將軍愛憐頻。", "便房不使殉，易寵在茲辰。", "嗣侯喜驅逐，平樂多從賓。", "青絲穿五銖，累室貯百珍。", "歡與子都異，矯與子都均。", "用財糞土擲，吐氣日月踆。", "天地可齊久，禍患豈有因。", "秋風茂陵下，蒼蘚上騏驎。"]'),
('3f94e5b8-71f2-433f-9b8d-b1a6de3c7146','七月十六日赴庾直有懷','梅堯臣','宋','宋诗','song-poetry','','[]','白日落我前，明月隨我後。',120,'全唐诗/poet.song.14000.json','["白日落我前，明月隨我後。", "流光如有情，徘徊上高柳。", "高柳對寢亭，風影亂疎牖。", "我馬卧其傍，我僕倦搘肘。", "寂寂重門扃，獨念家中婦。", "乳下兩小兒，夜夜啼向母。", "問爺若箇邊，天性已見厚。", "不嗟羈枕孤，不愧棲禽偶。", "內有子相憶，外有月相守。", "何似長征人，沙塵聽刁斗。"]'),
('de430ee5-74f8-4ce0-81ef-921845f7b936','採芡','梅堯臣','宋','宋诗','song-poetry','','[]','蝟毛蒼蒼磔不死，銅盤矗矗釘頭生。',80,'全唐诗/poet.song.14000.json','["蝟毛蒼蒼磔不死，銅盤矗矗釘頭生。", "吳雞鬭敗絳幘碎，海蚌抉出真珠明。", "磨沙漉水莩殻滑，斫桂煮釜風波聲。", "齒如編貝嚼明月，曼倩不復饑腸鳴。", "莫論一斛貴與賤，堂上狼藉無由行。"]'),
('8c87ecfc-08f2-4b93-b2d2-407abed4724c','史氏南軒','梅堯臣','宋','宋诗','song-poetry','','[]','庭中碧石盎，上結三重山。',48,'全唐诗/poet.song.14000.json','["庭中碧石盎，上結三重山。", "飛光入酒盃，舞翠生髻鬟。", "竹林眠黄麞，莎徑欠白鷴。", "主人無倦情，窗戶不須關。"]'),
('4482d2cc-980a-4e68-aa6a-8382e9429720','送河北轉運使陳修撰學士','梅堯臣','宋','宋诗','song-poetry','','[]','河隍多宿兵，兵食固所須。',140,'全唐诗/poet.song.14000.json','["河隍多宿兵，兵食固所須。", "幸時不戰鬭，畜養安可無。", "古興十萬師，七十萬家輟耕鋤。", "今來歲調餉，且與往昔殊。", "不使民轉輓，但使民歸租。", "急緩實塞下，商賈以利趨。", "關西河東亦如此，軍食雖足民實虛。", "公乎抱長才，當有所畫謨。", "應不貸內府，重錦象牙明月珠。", "邊城預自足，寧待臨事諭。", "莫令漢庭臣，獨言桑大夫。"]'),
('36beacfd-3616-421f-8c88-90d38eda9012','奉和寄宣州廣教文鑒師','梅堯臣','宋','宋诗','song-poetry','','[]','秋池對門蓮子枯，野壁剝月蝸涎塗。',64,'全唐诗/poet.song.14000.json','["秋池對門蓮子枯，野壁剝月蝸涎塗。", "庭中兩株石楠樹，上有山鳥長相呼。", "當時聯巢接飛者，一落梁宋一海隅。", "扶桑日枝幾千尺，光彩不獨生陽烏。"]'),
('3596a8ae-a44e-4b3f-a278-0f784d96f0a1','送陸介夫學士通判秦州','梅堯臣','宋','宋诗','song-poetry','','[]','從來戎馬地，饗士日椎牛。',48,'全唐诗/poet.song.14000.json','["從來戎馬地，饗士日椎牛。", "介胄奉儒服，詩書參將謀。", "隴雲連塞起，渭水入關流。", "豈似瀛洲下，窮年事校讎。"]'),
('109e6ee5-d42b-450a-ad0a-b44128bd2fff','送徐君章秘丞知梁山軍','梅堯臣','宋','宋诗','song-poetry','','[]','蒼壁束江流，孤軍水上頭。',48,'全唐诗/poet.song.14000.json','["蒼壁束江流，孤軍水上頭。", "蛟龍驚鼓角，雲霧裛衣裘。", "午市巴姑集，危灘楚客愁。", "使君才筆健，當似白忠州。"]'),
('51f14635-7cc7-48fd-b857-3aa4ec50cac5','依韻和秋夜對月','梅堯臣','宋','宋诗','song-poetry','','[]','陳王苑裏望空虛，吳客風前憶具區。',64,'全唐诗/poet.song.14000.json','["陳王苑裏望空虛，吳客風前憶具區。", "橫閣漸看河影轉，繞枝還見鵲驚無。", "蟲催織婦機成素，露逼鮫人淚作珠。", "才比陶潛無用處，紗巾時任酒霑濡。"]'),
('4d0a201a-0531-4a04-a7a4-7fadce1f7dca','送令狐憲周度支知秀州','梅堯臣','宋','宋诗','song-poetry','','[]','鬢絲不是吳蠶吐，未到吳中已成縷。',128,'全唐诗/poet.song.14000.json','["鬢絲不是吳蠶吐，未到吳中已成縷。", "清腸無蠒自能生，窮愁便織連今古。", "論兵說劍三十秋，乃知功名難强取。", "往往橫遭年少輕，好在驅車海邊去。", "海邊郡民迎太守，黍作壺漿牛作脯。", "剩持鹽豉煮紫蒓，卵色椀寬光欲舞。", "試尋陸機舊時迹，畫舟烏榜穿平浦。", "秋草宅荒聞杜鵑，應暫徘徊解腰組。"]'),
('7b0a181a-5493-4ac0-ba2d-ecfc4d8d9e9a','寤寐謠','梅堯臣','宋','宋诗','song-poetry','','[]','日月晝夜明，中匿暗靄物。',304,'全唐诗/poet.song.14000.json','["日月晝夜明，中匿暗靄物。", "前世有奇疾，五日瞑未歿。", "大夫家臣懼，鵲來視之脈不汨。", "嘗聞秦繆公，奄奄往帝所，甚樂豈蒼卒。", "及乎七日寤，事與此無咈。", "果然踰二日，覺語汝忽忽。", "從帝游鈞天，天樂聲颺動心骨。", "有熊欲援我，我時不敢咄。", "帝命我射之，熊死羆來突。", "又射又死羆，帝喜笑嗢嗢。", "二笥皆有副，拜賜未及發。", "見兒在帝側，帝屬翟犬一。", "曰俟子壯與，雖得都未悉。", "復思古虞舜，勳德如白日。", "將以其胄女，而爲七世匹。", "是時董安于，受言藏既密。", "遂陳鵲所云，錫田嘉彼術。", "他日駕四牡，桓桓兵衛出。", "矯立道上人，不避從者叱。", "願言謁主君，見子光隘溢。", "請君去左右，且聞君始疾。", "臣實在帝傍，頗有良可詰。", "詰見我何爲，見君射熊羆，命中皆不失。", "是且曷謂然，晉難其可述。"]'),
('75d4c9a4-a3ad-4edc-8729-f62ac22d62f6','和曹光道風拔三檜','梅堯臣','宋','宋诗','song-poetry','','[]','飄風西北至，樹苦萬繂牽。',72,'全唐诗/poet.song.14000.json','["飄風西北至，樹苦萬繂牽。", "君家三古檜，繁根龍蛇纏。", "其固謂不拔，朱欄擁青塼。", "今同秀林木，摧倒誰復憐。", "安得百力士，扶持尚可全。", "慎勿伐作薪，豈無庭燎然。"]'),
('8fed9f0f-c552-4ad8-8b0e-4018a615a3e1','飲劉原甫家原甫懷二古錢勸酒其一齊之大刀長五寸半其一王莽時金錯刀長二寸半','梅堯臣','宋','宋诗','song-poetry','','[]','主人勸客飲，勸客無夭妍。',168,'全唐诗/poet.song.14000.json','["主人勸客飲，勸客無夭妍。", "欲出古時物，先請射以年。", "我料孔子履，久化武庫煙。", "固知陶氏梭，飛朱風雨天。", "世無軒轅鏡，百怪爭後先。", "復聞豐城劍，已入平津淵。", "聊讎二百載，儻有書畫傳。", "嗢呼纔十一，便可傾觥船。", "探懷發二寶，太公新室錢。", "獨行齊大刀，鎌形末環連。", "文存半辨齊，背有模法圓。", "次觀金錯刀，一刀平五千。", "精銅不蠹蝕，肉好鉤婉全。", "爲君舉酒盡，跨馬月娟娟。"]'),
('e2890412-5065-445c-82f2-b40684c59d25','送嘉州監押曹供奉','梅堯臣','宋','宋诗','song-poetry','','[]','舊友尹師魯，嘗作送子文。',48,'全唐诗/poet.song.14000.json','["舊友尹師魯，嘗作送子文。", "文存人已歿，行復我何云。", "平時爲郡尉，遐方宜撫軍。", "定過楊雄宅，野鶴自成羣。"]'),
('9fa89e5d-40a0-4c80-b903-4534eb0f94e6','答仲源太傅八日遺酒','梅堯臣','宋','宋诗','song-poetry','','[]','陶潛九月九，無酒望白衣。',72,'全唐诗/poet.song.14000.json','["陶潛九月九，無酒望白衣。", "何言先一日，雙榼忽我歸。", "借問遺酒誰，天宗分日暉。", "明當酌大斗，黄菊羔醅肥。", "李賀諸王孫，作詩字欲飛。", "聞多錦囊句，將報慙才微。"]'),
('b6bb01b2-021f-4bcc-b662-7e8a48456f70','送張生還和州','梅堯臣','宋','宋诗','song-poetry','','[]','山頭孤石望來久，天外行人今獨歸。',32,'全唐诗/poet.song.14000.json','["山頭孤石望來久，天外行人今獨歸。", "藥囊自有留生術，不管淮南木葉飛。"]'),
('b9d8ec97-a40c-4f30-b77e-e63fd8846664','李康靖少傅夫人挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','九月秋風急，三川苦霧迷。',48,'全唐诗/poet.song.14000.json','["九月秋風急，三川苦霧迷。", "卜邙新隧啟，度鞏短簫齊。", "寶劍知終合，靈蟾已隕西。", "松門來會葬，車馬幾千蹄。"]'),
('1673a54b-1758-42ca-a14c-bf638a0bf87f','李康靖少傅夫人挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','板輿曾至鄭，靈輤此歸周。',48,'全唐诗/poet.song.14000.json','["板輿曾至鄭，靈輤此歸周。", "行哭人增慕，凝茄月正秋。", "九原開祔穴，故土覆新丘。", "歲晏寒松下，茅苫孝子留。"]'),
('356af491-b384-4805-86fb-58c0e621e42f','送韓文饒寺丞宰蕭山','梅堯臣','宋','宋诗','song-poetry','','[]','吳會未探穴，廣陵先看潮。',48,'全唐诗/poet.song.14000.json','["吳會未探穴，廣陵先看潮。", "橫江百馬怒，卷海萬鼙囂。", "舟楫凌湍發，魚龍接浪跳。", "薄言增勇氣，少當舉山瓢。"]'),
('84d8ef01-3d89-4715-9e8b-92b1b673adc3','蔡君謨示古大弩牙','梅堯臣','宋','宋诗','song-poetry','','[]','黄銅弩牙金錯花，銀闌線齒如排沙。',128,'全唐诗/poet.song.14000.json','["黄銅弩牙金錯花，銀闌線齒如排沙。", "上立準度可省括，箭溝三道前直窊。", "其度四寸寸五刻，鋈光歷歷無纖差。", "蔡侯出此問誰得，往年客遺來瑯琊。", "瑯琊築城穿厚壤，既獲磨洗爭傳誇。", "莫知歲月孰製作，精妙近世應難加。", "發機高下在分刻，今人妄射功仍賒。", "願侯擬之起新法，勿使邊兵死似麻。"]'),
('5fc9a451-cb5d-4d99-a40e-d0f2c6c61d26','和劉原甫省中新菊','梅堯臣','宋','宋诗','song-poetry','','[]','華省切星斗，沉沉嚴燕房。',120,'全唐诗/poet.song.14000.json','["華省切星斗，沉沉嚴燕房。", "秋風茂陵孫，種菊爛生光。", "天晴蝴蝶飛，上下舞雙黄。", "劉郎才筆豪，移榻吟在傍。", "日晚吏已散，殘景上粉牆。", "有酒無飲伴，掇英襟裾香。", "還思陶淵明，棄官歸柴桑。", "東籬獨此物，盈把恨無觴。", "頼有白衣來，好事遺壺漿。", "適意各一時，豈乏同舍郎。"]'),
('ae19c244-0d20-4bba-bc14-954db2ac4d3a','依韻和仲源獨夜吟','梅堯臣','宋','宋诗','song-poetry','','[]','秋鴻聲澀秋絃苦，塗金博山煙夜吐。',32,'全唐诗/poet.song.14000.json','["秋鴻聲澀秋絃苦，塗金博山煙夜吐。", "寂歷虛堂燈暈生，誰人共聽西窗雨。"]'),
('70cceaf5-3edc-4036-9661-27296324de4b','寄題周敦美琨瑶洞','梅堯臣','宋','宋诗','song-poetry','','[]','仙人采玉驅雄龍，列山剖璞青腔空。',144,'全唐诗/poet.song.14000.json','["仙人采玉驅雄龍，列山剖璞青腔空。", "因邃爲堂曲爲室，石乳溜壁光玲瓏。", "僊歸龍去草樹長，蔽翳不復人蹤通。", "指疆買墅下峯下，洗斸務欲險怪窮。", "蛇鱗鹿跡尚莫到，安問樵老諸牛童。", "古今未得君獨得，萬景付與由天公。", "何當歸來斂頭角，任從寶氣生白虹。", "陰溪淺水菖蒲綠，下有蝦蟆雙眼紅。", "及時佐酒斫兩股，勿使更入明月中。"]'),
('eeb59803-07e0-4a64-99b9-db387f3ca6a1','許生南歸','梅堯臣','宋','宋诗','song-poetry','','[]','大盤小盤堆明珠，海估眩目迷精麤。',112,'全唐诗/poet.song.14000.json','["大盤小盤堆明珠，海估眩目迷精麤。", "斗量入貢由掇拾，未必一一疵纇無。", "不貢亦自有光價，此等固知魚目殊。", "許生懷文頗所似，暫抑安用頻增吁。", "倚門老母應日望，霜前稻熟舂紅稃。", "歸來爛炊多釀酒，洗蕩幽憤傾盆盂。", "九卿有命不愁晚，朱邑當年是嗇夫。"]'),
('1c0635ea-affa-4ac7-a6d7-955583711938','得沙苑榅桲戲酬','梅堯臣','宋','宋诗','song-poetry','','[]','蒺藜已枯天馬歸，嫩蠟籠黄霜冒榦。',32,'全唐诗/poet.song.14000.json','["蒺藜已枯天馬歸，嫩蠟籠黄霜冒榦。", "不比江南楂柚酸，橐駝載與吳人看。"]'),
('54cba0f3-e8a7-4d90-9474-8ff59e64bb17','寄題杭州廣公法喜堂','梅堯臣','宋','宋诗','song-poetry','','[]','淘青研朱畫屋梁，黄漆柏障連曲房。',64,'全唐诗/poet.song.14000.json','["淘青研朱畫屋梁，黄漆柏障連曲房。", "日暉月色不須照，了了自可窺毫芒。", "夕陰花斂似欲病，飛鳥不驚烏帽郎。", "深山窮谷謾幽僻，喜得吳儂是藥囊。"]'),
('d1c403ec-75e4-4e09-9617-3f3f2a49492a','題滿公僧錄西明軒','梅堯臣','宋','宋诗','song-poetry','','[]','赤萍纔落鄧林外，青銅半磨傍露明。',64,'全唐诗/poet.song.14000.json','["赤萍纔落鄧林外，青銅半磨傍露明。", "飛光斜入了不隔，坐卧一榻琉璃平。", "西方古胡黄金質，貝葉傳寫烏行橫。", "謂曉此教居此軒，滿壁圖畫遥峯生。"]'),
('0761b71f-775d-43d5-8435-2bdcd5ee4d0c','寄題撫州戴秀才息心亭','梅堯臣','宋','宋诗','song-poetry','','[]','蒼蒼開幽林，峯嶺日相對。',48,'全唐诗/poet.song.14000.json','["蒼蒼開幽林，峯嶺日相對。", "雲歸垂衣纓，泉落響環珮。", "仕宦雖有負，耳目得以貸。", "俯仰宇宙中，晏然維進退。"]'),
('e9b31d86-fc79-4051-8784-34f050c21b31','送臨江軍監軍李太博','梅堯臣','宋','宋诗','song-poetry','','[]','三江卑溼地，北客宦游稀。',48,'全唐诗/poet.song.14000.json','["三江卑溼地，北客宦游稀。", "霧氣多成雨，雲蒸易損衣。", "白醪燒甕美，黄雀下田肥。", "未辨殊方語，山歌半是非。"]'),
('df96aeb7-9815-4a70-92e6-df499ca548ee','道損司門前日過訪別且云計程二月到郡正看暗惡海棠頗見太守風味因爲詩以送行','梅堯臣','宋','宋诗','song-poetry','','[]','蜀州海棠勝兩川，使君欲賞意已猛。',64,'全唐诗/poet.song.14000.json','["蜀州海棠勝兩川，使君欲賞意已猛。", "春露洗開千萬株，燕脂點素攢細梗。", "朝看不足暮秉燭，何暇更尋桃與杏。", "青泥劍棧將度時，跨馬莫辭霜氣冷。"]'),
('7e24dc4e-bd04-4e64-9d7a-8cd743ce6be5','送雪竇長老曇穎','梅堯臣','宋','宋诗','song-poetry','','[]','朝從雪竇請，暮卷雲衲輕。',48,'全唐诗/poet.song.14000.json','["朝從雪竇請，暮卷雲衲輕。", "莫問居士病，自從他方行。", "吳霜點髭根，海烏隨衆迎。", "安隠彼道場，萬事都忘情。"]'),
('0b020757-7543-4d79-9fd5-90adfa3c0f69','送襄邑知縣杜君懿太博','梅堯臣','宋','宋诗','song-poetry','','[]','霜落水未落，令君將度河。',48,'全唐诗/poet.song.14000.json','["霜落水未落，令君將度河。", "農耕休叱耒，女織罷鳴梭。", "赤幘驅亭長，丹砂挈印窠。", "無慙浚儀政，才比陸雲多。"]'),
('9e68022c-029f-46fe-b3dd-589625b81b07','送晉原喬主簿','梅堯臣','宋','宋诗','song-poetry','','[]','太守登車時，我病不能出。',108,'全唐诗/poet.song.14000.json','["太守登車時，我病不能出。", "遥期玩海棠，度險馬屢叱。", "唯畏行邁遲，惡欲及春日。", "何爲愛此花，曾非桃杏匹。", "生紅濃復淺，瘦蔕脩且密。", "湖傍幾十樹，雕盤擁新漆。", "酒傾瑠璃盆，月上歡未畢。", "縣官同遠宦，簿領無督詰。", "刻意詠芳菲，追補李杜失。"]'),
('6df12e0d-3ce5-4acb-9dcb-22496ae40f74','十一月十三日病後始入倉','梅堯臣','宋','宋诗','song-poetry','','[]','曾非雀與鼠，何彼大倉爲。',48,'全唐诗/poet.song.14000.json','["曾非雀與鼠，何彼大倉爲。", "狐裘破不溫，黄狗補其皮。", "霜花逐落月，綴在枯槁枝。", "予年過五十，瘦寢冰生肌。"]'),
('a7897fbe-c004-4d3d-9b7e-d13fd00b5806','閔尚衣盜褲','梅堯臣','宋','宋诗','song-poetry','','[]','昔聞廉叔度，能使民多褲。',84,'全唐诗/poet.song.14000.json','["昔聞廉叔度，能使民多褲。", "多褲非或貪，持新不忘故。", "嗟嗟亦王官，奚自門閥汙。", "中府中紋綾，袖之呼馬去。", "左右即其私，邀索乃就捕。", "三公出死狗，訓導能有素。", "今同竊鈇者，見爾皆此趣。"]'),
('56e32de6-6389-40e2-82b4-a4b7c3eb2e8a','胡夫人挽歌','梅堯臣','宋','宋诗','song-poetry','','[]','已哉胡夫人，其壽七十餘。',60,'全唐诗/poet.song.14000.json','["已哉胡夫人，其壽七十餘。", "其子哀母死，一夕髭皓如。", "髭白髮亦白，長號守茅廬。", "扶棺埋吳雲，來會傾市墟。", "誰復向寒月，卧冰求鯉魚。"]'),
('14934930-a361-4dbe-973c-450684347f45','裴直講得潤州通判周仲章鹹豉遺一小缾','梅堯臣','宋','宋诗','song-poetry','','[]','金山寺僧作鹹豉，南徐別乘馬不肥。',48,'全唐诗/poet.song.14000.json','["金山寺僧作鹹豉，南徐別乘馬不肥。", "大梁貴人與年少，紅泥罌盎鳥歸飛。", "我今老病寡肉食，廣文先生分遺微。"]'),
('a5ee7d23-24ab-4cc5-8b9a-ff212d1d3aaa','贈裴直講水梨二顆言太尠答吳柑三顆以爲多走筆呈之','梅堯臣','宋','宋诗','song-poetry','','[]','綠橘似甘來太學，大梨如水出咸陽。',32,'全唐诗/poet.song.14000.json','["綠橘似甘來太學，大梨如水出咸陽。", "莫將多少爲輕重，試擘霜包幾瓣香。"]'),
('2314fb1b-728b-4926-9a42-0c69200ba46e','送樂職方知泗州','梅堯臣','宋','宋诗','song-poetry','','[]','長堤凍柳不堪折，窮臘使君單騎行。',64,'全唐诗/poet.song.14000.json','["長堤凍柳不堪折，窮臘使君單騎行。", "蘇合輕裘霜莫犯，銅牙大弩吏先迎。", "山旁楚賈連檣泊，水上禹書寒磬清。", "試向郡樓東北望，煙波千里月臨城。"]'),
('d918e83b-ece1-4b1a-8353-f980ce37dff6','和劉原甫十二月十日試墨','梅堯臣','宋','宋诗','song-poetry','','[]','海神不朝雪不作，大梁塵土蔽天高。',80,'全唐诗/poet.song.14000.json','["海神不朝雪不作，大梁塵土蔽天高。", "道傍牛喘復誰問，佛寺吹螺空唱嚎。", "相公跪香恬且佚，陛下減膳心焦勞。", "因君試墨偶有激，勇辭壯筆揮長刀。", "予無奈何亦思飲，飲竭甖甕從餔糟。"]'),
('d102b67e-ec71-44d0-979c-4a4405801908','十二月十三日喜雪','梅堯臣','宋','宋诗','song-poetry','','[]','三日朔風吹暗沙，蛟龍卷起噴成花。',80,'全唐诗/poet.song.14000.json','["三日朔風吹暗沙，蛟龍卷起噴成花。", "花飛萬里奪曉月，白石爛堆愁女媧。", "大明廣庭踏朝駕，雉尾不掃黏宮靴。", "宮中才人承聖顔，捧觴稱壽呼南山。", "三公免責百姓喜，斗酒十千誰復慳。"]'),
('69729e5e-edc3-4c54-b9c5-f1c54200a830','送劉職方知汾州','梅堯臣','宋','宋诗','song-poetry','','[]','西河風俗厚，尚翅古所聞。',48,'全唐诗/poet.song.14000.json','["西河風俗厚，尚翅古所聞。", "子夏有遺廟，干木有遺墳。", "太守下車日，當先此二君。", "不必汾水上，秋風看雁羣。"]'),
('9774afd9-1ba5-4992-819b-d9f7942bfcbf','十三日雪後晚過天漢橋堤上行','梅堯臣','宋','宋诗','song-poetry','','[]','隄上殘風雪，橋邊盛酒樓。',48,'全唐诗/poet.song.14000.json','["隄上殘風雪，橋邊盛酒樓。", "據鞍衰意盡，倚檻艷歌留。", "海月開金鑑，河冰卧玉虬。", "當年洛陽醉，偏憶董糟丘。"]'),
('48372cbb-8a62-4362-a7c1-036b6a3b51da','送崔黄臣殿丞之任廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','驊駒西行四千里，直度經橋百尋水。',96,'全唐诗/poet.song.14000.json','["驊駒西行四千里，直度經橋百尋水。", "石上菖蒲未見花，蒙頂茶牙初似觜。", "采時應憶故園春，故園開焙亦思人。", "其間杜鵑不中聽，掩耳聊看錦雉馴。", "青崖鞭垂瘦蛇尾，仙人掐節隨鱗起。", "斫取他年跨馬歸，劍棧秦山多折箠。"]'),
('a98e7eff-130e-411e-8f4c-60918697be38','十九日出曹門見水牛拽車','梅堯臣','宋','宋诗','song-poetry','','[]','只見吳牛事水田，只見黄犂負車軛。',64,'全唐诗/poet.song.14000.json','["只見吳牛事水田，只見黄犂負車軛。", "今牽大車同一羣，又與騾馿走長陌。", "卬頭闊步塵蒙蒙，不似緩耕泥洦洦。", "一一夜眠頭向南，越鳥心腸誰辨白。"]'),
('cf5e49d4-647b-49a4-9284-c4b59a6dd9b0','二十一日同韓持國陳和叔騏驥院遇雪往李廷老家飲予暮又赴劉原甫招與江鄰幾謝公儀飲','梅堯臣','宋','宋诗','song-poetry','','[]','雪游如梨園，風撼梨花落。',288,'全唐诗/poet.song.14000.json','["雪游如梨園，風撼梨花落。", "驊騮驤首時，杳杳聞天樂。", "樓觀何參差，仙居倚寥廓。", "羣朋思飲酒，飲舉北斗杓。", "公子邀以歸，躍馬度城郭。", "鵠毳拂輕裘，蛟珠亂疎箔。", "少年氣若虹，屢起鄱陽謔。", "壯語士膽開，狂訶僮指愕。", "間或美笑言，又或跪酬酢。", "或如猿狙跳，或類虎豹攫。", "或廋秦客辭，或縱灌夫惡。", "盃盂或遷擲，履舄或攙錯。", "稍看雲容披，斜漏日光薄。", "馭僕整轡銜，庖人困羹臛。", "還家歷南市，燈燭已煜爚。", "入門見妻孥，未暇問何若。", "劉侯遽相招，登堂羅綽約。", "往往奏清歌，時時更大噱。", "江翁唱渭城，嘹唳華亭鶴。", "半夜蜘蛛喜，微然見無著。", "主人倍歡欣，勸客如傾壑。", "我時已大醉，盞至不解却。", "還思一日喧，靜坐無適莫。", "書作異時談，竹林何愧怍。"]'),
('4bcb9a4c-820d-4dc0-ab6b-b6d298dbe4f5','吳太博遺柑子','梅堯臣','宋','宋诗','song-poetry','','[]','太學先生欺綠橘，吳興才士與黄柑。',48,'全唐诗/poet.song.14000.json','["太學先生欺綠橘，吳興才士與黄柑。", "黄柑似日勝崖蜜，带葉初擎翠竹籃。", "還料楚王曾未識，徒將萍實詫江南。"]'),
('86956895-37a4-4c80-a4a9-51ed17037750','和普公賦東園十題 擷芳亭','梅堯臣','宋','宋诗','song-poetry','','[]','結宇東園中，種花待春風。',36,'全唐诗/poet.song.14000.json','["結宇東園中，種花待春風。", "口歌金縷衣，手折枝上紅。", "今日映綠髮，他年羞青銅。"]'),
('84518123-e39e-4041-846c-5c9566ea9ecd','和普公賦東園十題 清心堂','梅堯臣','宋','宋诗','song-poetry','','[]','寂寞外物亂，境清心亦清。',36,'全唐诗/poet.song.14000.json','["寂寞外物亂，境清心亦清。", "彼皆居深谷，此獨處重城。", "夷齊食薇蕨，千古首陽名。"]'),
('18a90d0d-9f8d-4fb9-9dc4-a9c61790e781','和普公賦東園十題 石筍','梅堯臣','宋','宋诗','song-poetry','','[]','削出青山根，峭立碧玉圭。',36,'全唐诗/poet.song.14000.json','["削出青山根，峭立碧玉圭。", "不作湘竹老，不染帝子啼。", "不爲盤中蔬，豈與煙茁齊。"]'),
('29373447-e723-4ba0-b21f-2793e27e93c2','和普公賦東園十題 待月亭','梅堯臣','宋','宋诗','song-poetry','','[]','明月過三五，飛出滄海遲。',36,'全唐诗/poet.song.14000.json','["明月過三五，飛出滄海遲。", "佳人望清夜，隔樹光離離。", "不須磔蝦蟆，寒魄自有虧。"]'),
('2a746132-d040-4c1e-8112-fd21f5d194da','和普公賦東園十題 虛白堂','梅堯臣','宋','宋诗','song-poetry','','[]','空堂絕纖塵，虛靜自生白。',36,'全唐诗/poet.song.14000.json','["空堂絕纖塵，虛靜自生白。", "長風吹月東，窗戶如不隔。", "漆園茲趣深，赤水珠難索。"]'),
('d6e230d4-341c-4ce1-aa5b-1bd6c59b4a44','和普公賦東園十題 假山','梅堯臣','宋','宋诗','song-poetry','','[]','太山不可歷，石齒齧人足。',36,'全唐诗/poet.song.14000.json','["太山不可歷，石齒齧人足。", "聊集怪與奇，蒼蒼都在目。", "何須引寒流，平地作溪谷。"]'),
('d2b862aa-c2c3-45cd-9678-7cb696327483','和普公賦東園十題 書齋','梅堯臣','宋','宋诗','song-poetry','','[]','聖賢有事業，皆在經籍中。',36,'全唐诗/poet.song.14000.json','["聖賢有事業，皆在經籍中。", "已愛牙作籤，可輕山賜銅。", "還來讀詩禮，不用辨魚蟲。"]'),
('3276bbca-dfa5-4e2a-b686-c56b8e5cccd7','和普公賦東園十題 小池','梅堯臣','宋','宋诗','song-poetry','','[]','小池依小山，山晴翠光入。',36,'全唐诗/poet.song.14000.json','["小池依小山，山晴翠光入。", "無容羣蛙鳴，間有孤鶴立。", "曾不起波瀾，石郵風自急。"]'),
('999756fa-1b2e-45bf-9299-d4b2b24a1e34','和普公賦東園十題 紫竹','梅堯臣','宋','宋诗','song-poetry','','[]','西南産脩竹，色異東筠綠。',36,'全唐诗/poet.song.14000.json','["西南産脩竹，色異東筠綠。", "裁簫映檀脣，引枝宜鳳宿。", "移從幾千里，不改生幽谷。"]'),
('ad2760be-8cee-469d-bcd1-1d45efa9a15e','和普公賦東園十題 山茶','梅堯臣','宋','宋诗','song-poetry','','[]','紅蘤勝朱槿，越丹看更大。',36,'全唐诗/poet.song.14000.json','["紅蘤勝朱槿，越丹看更大。", "臘月冒寒開，楚梅猶不奈。", "曾非中土有，流落思江外。"]'),
('1d395791-770d-4a83-9426-8f518ae148a2','除夜雪','梅堯臣','宋','宋诗','song-poetry','','[]','擊鼓人驅鬼，漫天雪送寒。',48,'全唐诗/poet.song.14000.json','["擊鼓人驅鬼，漫天雪送寒。", "臘從今日盡，花作舊年看。", "著樹多還墮，隨風積更乾。", "明朝預王會，畏濕兩梁冠。"]'),
('5cd7485e-ae6a-46f4-aeee-8277811554ad','和吳沖卿元會','梅堯臣','宋','宋诗','song-poetry','','[]','千官車馬閶闔來，晝漏始上閶闔開。',224,'全唐诗/poet.song.14000.json','["千官車馬閶闔來，晝漏始上閶闔開。", "峨峨左右升龍進，昨夜雪飛雲作堆。", "殿前冠劍魚鱗立，東風入仗旗脚迴。", "黄鍾一奏寶扇掩，玳簾卷起香霧排。", "鳴梢未盡霹靂響，翠輦已退黄金階。", "聖人端冕御法座，大樂旅作聲和諧。", "羣公抃蹈丹墀下，尚書奏瑞四夷懷。", "乘輿却入更衣閤，通天絳袍陞玉榻。", "百拜稱觴萬歲聞，兩廊賜食簪裾匝。", "曲傳大定舞綴疎，波旋烟斂飭宮車。", "衛官解嚴多士退，日光停午氣象舒。", "吳君才筆天下傑，歸來作詩傳石渠。", "石渠祕邃無凡愚，石渠酬唱皆嚴徐。", "我慙短學復在後，收拾掇棄聊以書。"]'),
('02e305a7-d8a4-4fc6-80e1-6722693b62ab','元日','梅堯臣','宋','宋诗','song-poetry','','[]','頻年無入閤，今日預朝元。',48,'全唐诗/poet.song.14000.json','["頻年無入閤，今日預朝元。", "丹陛發金奏，侍臣稱玉罇。", "旗旌摇細仗，雲霧啟千門。", "却出蒼龍闕，衣冠萬馬屯。"]'),
('b30e5107-89cd-40ba-a34c-a3ae7aa405a5','依韻和仲源暮冬見寄','梅堯臣','宋','宋诗','song-poetry','','[]','曾未學黄庭，衰顔已可驚。',48,'全唐诗/poet.song.14000.json','["曾未學黄庭，衰顔已可驚。", "詩能如阮籍，評不愧鍾嶸。", "玉軫調初美，冰壺想更清。", "兔園風雪甚，還聽鴈來聲。"]'),
('a329937a-ff75-41b9-b028-286cd0a6a555','送韓子文寺丞通判瀛州','梅堯臣','宋','宋诗','song-poetry','','[]','常聞河間守，介直天下無。',60,'全唐诗/poet.song.14000.json','["常聞河間守，介直天下無。", "選才才且殊，鐵網收珊瑚。", "珊瑚得亦難，鐵網取亦劬。", "况茲戎馬郊，爲貳維多謨。", "新春度滹沲，冰上少馳驅。"]'),
('0c46e040-8d85-4790-b09a-3143cc733b7f','十七日和原甫風花偶書','梅堯臣','宋','宋诗','song-poetry','','[]','風花不戀枝，脫萼亂翻飛。',40,'全唐诗/poet.song.14000.json','["風花不戀枝，脫萼亂翻飛。", "自學空中雪，寧同垣上衣。", "繞庭回旋久無著，衆鳥爭銜何處歸。"]'),
('a939ed55-ef1b-4441-a6b6-a925d5f237e3','貽妄怒','梅堯臣','宋','宋诗','song-poetry','','[]','飲食無遠近，所美貴甘𨍥。',84,'全唐诗/poet.song.14000.json','["飲食無遠近，所美貴甘𨍥。", "南方食蝦蟆，密捕向清畎。", "齒咀口且諱，聞語輒忿喘。", "此物何醜惡，猶勝螺螄蜆。", "西蜀亦取之，水田名穀犬。", "彼士不爲慙，吳人休獨愐。", "豈須若中州，牛羊烹大臠。"]'),
('22130ac2-5426-4695-a4d1-523f6d731706','十六日會靈火','梅堯臣','宋','宋诗','song-poetry','','[]','章聖皇帝興三宮，三宮鼎峙何崇崇。',160,'全唐诗/poet.song.14000.json','["章聖皇帝興三宮，三宮鼎峙何崇崇。", "天聖七年六月尾，玉清始災壇宇空。", "于今二十有五載，上元後夜星軫中。", "乃聞會靈五殿火，丹焰徹天明月紅。", "千楹萬棟一夕盡，赤煙奔突西南風。", "先時二日車駕幸，爲民祈福輸清衷。", "大臣驕蹇不從祀，岳靈不歆爲不恭。", "若此示變猶影響，宜鑒陛下無惰容。", "神非怒乙遂及甲，天意警聖不警凶。", "不獨洪水累堯德，堯仁未忍流驩共。"]'),
('bcfe9c39-f7c4-48f4-a1ff-57635054d6aa','送潘司封知解州','梅堯臣','宋','宋诗','song-poetry','','[]','鹽池暗湧蚩尤血，紅波爛爛陽烏熱。',96,'全唐诗/poet.song.14000.json','["鹽池暗湧蚩尤血，紅波爛爛陽烏熱。", "岸旁遺老記南風，五月滿畦吹作雪。", "白徑嶺上橐駞鳴，太行山中騏驥苶。", "古人射利今人同，行商不困何由設。", "朱轓太守自東來，先世大夫留故轍。", "是非取與應不移，秦人休衒張儀舌。"]'),
('3635148c-94ea-4c51-80f1-89d45e57bf48','飲酒呈鄰幾原甫','梅堯臣','宋','宋诗','song-poetry','','[]','天地不爭行，日月不爭明。',156,'全唐诗/poet.song.14000.json','["天地不爭行，日月不爭明。", "晝夜自顯晦，冬春自枯榮。", "夸父逐日死，共工觸天傾。", "二子不量力，空有千古名。", "寄語賢與愚，何嘗見長生。", "我願會良友，醉顔日常赬。", "東海爲酒罇，五湖爲杯羹。", "海罄湖且竭，盡倒爲解酲。", "苟死不復知，苟生徒牽情。", "項籍乘牛車，馳上廣武城。", "强梁取秦鹿，慷慨猶爲輕。", "歸來卧酒家，豈得慙公卿。", "樂亦但如此，舉世任營營。"]'),
('d1784d5a-e78f-4d1c-9828-86cca118751d','寄渭州經略王龍圖','梅堯臣','宋','宋诗','song-poetry','','[]','西城橐駞來賀蘭，入貢美玉天可汗。',88,'全唐诗/poet.song.14000.json','["西城橐駞來賀蘭，入貢美玉天可汗。", "蕭關夜開月團團，彈箏古峽鳴哀湍。", "前將軍，不擐甲，取大官。", "今將軍，能撫士，尚盤桓。", "河西五郡兵氣完，駿馬躍棧無箭瘢。", "我嗟乘劣不受鞍，焉得乞與都人看。"]'),
('ce43395d-9e2f-48fb-98c3-2af783f975ba','二十一日雪中赴宿懷鄰幾原甫','梅堯臣','宋','宋诗','song-poetry','','[]','正月東都雪，多於舊臘時。',48,'全唐诗/poet.song.14000.json','["正月東都雪，多於舊臘時。", "酒賓臨迥閣，野雀集枯枝。", "馬向西城度，花從上苑遲。", "劉郎與江叟，相對定爭棋。"]'),
('1d489479-3bd0-470c-881a-5a4f266c7b1e','送永興通判薛虞部','梅堯臣','宋','宋诗','song-poetry','','[]','灰宮盜玉秦樓空，南山不老天無窮。',80,'全唐诗/poet.song.14000.json','["灰宮盜玉秦樓空，南山不老天無窮。", "蘚碑剝爛少文字，雨耕拾寶牛蹄中。", "其旁築城聚貔虎，黄土岌嶪如削銅。", "西州吏人氣吐虹，摧鱗斂角聽相公。", "少年別乘勤爾躬，幙府甚盛瓊瑶叢。"]'),
('125320f1-960c-45df-8d05-b9582d586c37','送宣州簽判馬屯田兼寄知州邵司勳','梅堯臣','宋','宋诗','song-poetry','','[]','寒溪翠拖碧玉带，蒼山晴卧蛻骨龍。',128,'全唐诗/poet.song.14000.json','["寒溪翠拖碧玉带，蒼山晴卧蛻骨龍。", "水邊苦竹抽肥笋，石上老蕨拳紫茸。", "泊船繫纜宿明鏡，昭亭廟古攢瘦松。", "陰風雨電潭心起，雲遮北嶺如墨濃。", "田秧浸綠白鷺立，內史出喜嘉賓從。", "昔時謝公來賽神，蘭肴作椒金作鍾。", "聯詩姓何名已失，板蠹粉落蟲鳥蹤。", "我鄉復傳召南化，磨鏤黑石君亦逢。"]'),
('83a5f3d8-ff10-4f05-8c96-f09eb99adf7d','觀拽龍舟懷裴宋韓李','梅堯臣','宋','宋诗','song-poetry','','[]','截春流，築沙坻。',168,'全唐诗/poet.song.14000.json','["截春流，築沙坻。", "拽龍舟，過天池。", "尾矯矯，角岐岐。", "千夫推，萬鱗隨。", "驚鴻鵠，沉魚龜。", "春三月，輕服時。", "薄水殿，習水嬉。", "馬特特，來者誰。", "魏公子，人不窺。", "車轔轔，集其涯。", "邯鄲倡，士交馳。", "銀缾索酒傾玻瓈，用錢如水贈舞兒。", "却入上苑看鬭雞，擊毬彈金無不爲。", "適聞天子降玉輦，當門虎脚看大旗。", "春風吹花入行幄，紅錦百尺爭蛟螭。", "雲蓋迴，綵纜維，明年結客觀未遲。"]'),
('dabe68d1-5631-46fb-96f9-900aebb8576b','二月四日雪','梅堯臣','宋','宋诗','song-poetry','','[]','前日春風初擺條，昨夜雪飛深一尺。',96,'全唐诗/poet.song.14000.json','["前日春風初擺條，昨夜雪飛深一尺。", "北帝及臘不行令，東皇發煦遭爾厄。", "侵時奪氣四時錯，欲問上天何不責。", "天高地厚語難通，俛首下土徒叩額。", "或言莫信難可聞，鶴鳴至微猶不隔。", "休問天，問顔蹠。", "休看花，看壟麥。"]'),
('fb35d565-ec4d-4721-af12-e73e6cd2c59f','答劉原甫','梅堯臣','宋','宋诗','song-poetry','','[]','生平多交友，常恨會遇稀。',120,'全唐诗/poet.song.14000.json','["生平多交友，常恨會遇稀。", "每念相笑語，昨是今或非。", "重惜向時游，出處苦乖違。", "從今儻有酒，莫問梨栗微。", "前夕呼我飲，遣奴來扣扉。", "暗犯風雪往，醉脫冠服歸。", "夜來新霽月，清吐萬里輝。", "劉郎戴幅巾，江叟披褐衣。", "相過無百步，誰虞竊訶譏。", "三家若循環，但知具甘肥。"]'),
('223186a2-17e2-4d7c-b230-625992206d8a','聞語十方璉長老','梅堯臣','宋','宋诗','song-poetry','','[]','舊居廬嶽寺，新化給孤園。',48,'全唐诗/poet.song.14000.json','["舊居廬嶽寺，新化給孤園。", "還享國人供，應無塵事喧。", "有來聽喻筏，一悟見吹幡。", "不憶爐峯下，臨溪看飲猿。"]'),
('fcf0946a-e1a5-467b-a3cb-dee3989cb2b3','十一日垂拱殿起居聞南捷','梅堯臣','宋','宋诗','song-poetry','','[]','二月雪飛雞狗狂，錦衣走馬回大梁。',144,'全唐诗/poet.song.14000.json','["二月雪飛雞狗狂，錦衣走馬回大梁。", "入奏邕州破蠻賊，絳袍玉座開明堂。", "腰佩金魚服金带，榻前拜跪稱聖皇。", "一朝嚴氣變和氣，初令漏泄飛四方。", "將軍曰青才且武，先斬逗撓兵後强。", "從來儒帥空賣舌，未到已愁茆葉黄。", "徘徊嶺下自稱疾，詔書切責仍勉當。", "因人成功喜受賞，親戚便擬封侯王。", "昔日苦病今不病，銅鼓棄擲無鏢鎗。"]'),
('c20aa6d0-cbdf-4581-a803-1bca7d9d49cd','十五日雪三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','寒令奪春令，六花侵百花。',48,'全唐诗/poet.song.14000.json','["寒令奪春令，六花侵百花。", "塘冰膠燕觜，野水澀芹牙。", "擁柱輕於絮，吹墀浄若沙。", "乳禽饑啄木，誰悞撥琵琶。"]'),
('d91a4f63-8378-4b19-94ae-52b485b65162','十五日雪三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','新雷奮蛇甲，密雪鬭鵝毛。',48,'全唐诗/poet.song.14000.json','["新雷奮蛇甲，密雪鬭鵝毛。", "正欲裁輕縠，重令著弊袍。", "沙泉流復凍，煙萼坼還韜。", "只待鄰醅熟，微聲聽酒槽。"]'),
('66a55f49-a619-41bf-9a60-36fff0a6e5d1','十五日雪三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','春風九十日，一半已銷磨。',48,'全唐诗/poet.song.14000.json','["春風九十日，一半已銷磨。", "準擬看花少，依稀詠雪多。", "官車猶戴炭，菢鵲不離窠。", "向此興都盡，戴家誰復過。"]'),
('2c1a61d2-85a7-4006-80ba-eed4170047e0','聞密賜','梅堯臣','宋','宋诗','song-poetry','','[]','朝聞政府賀捷回，夕賜明月五千枚。',64,'全唐诗/poet.song.14000.json','["朝聞政府賀捷回，夕賜明月五千枚。", "巍巍聖皇德所該，廟略付與何有哉。", "况未覆穴翦渠魁，宜先戰士老與孩。", "傾肝瀝膽謝不敏，豈可便恃張良才。"]'),
('a3c50364-300b-40d9-a46d-c4409b007725','送衛真宰晏寺丞罷長安','梅堯臣','宋','宋诗','song-poetry','','[]','捨琴辭苦縣，解劍入函關。',48,'全唐诗/poet.song.14000.json','["捨琴辭苦縣，解劍入函關。", "鵲報遠人至，馬衝春雨還。", "荒榛郊北囿，葱翠國南山。", "歸見蕭何政，條令舊鎬間。"]'),
('4874221b-d731-4f81-9b42-0df62beb55b2','江鄰幾饌鰌','梅堯臣','宋','宋诗','song-poetry','','[]','泥鰌魚之下，曾不享佳賓。',72,'全唐诗/poet.song.14000.json','["泥鰌魚之下，曾不享佳賓。", "又嫌太健滑，治洗煩庖人。", "煎炙亦苦腥，未嘗輒向脣。", "江侯昔南官，家膳無此珍。", "昨日邀我餐，下筯勝紫鱗。", "乃知至賤品，唯在調甘辛。"]'),
('5ef827d2-bb99-4e02-a9c8-9ff64458bfd5','淘渠','梅堯臣','宋','宋诗','song-poetry','','[]','開春溝，畎春泥。',100,'全唐诗/poet.song.14000.json','["開春溝，畎春泥。", "五步掘一塹，當途如壞堤。", "車無行轍馬無蹊，遮截門戶雞犬迷。", "屈曲措足高復低，芒鞋苔滑雨凄凄。", "老翁夜行無子携，眼昏失脚非有擠。", "明日尋者爾瘦妻，手提幼女哭嘶嘶。", "金吾司街務欲齊，不管人死獸顛啼。"]'),
('c377b4f0-fbf7-4b5a-bb08-afd7a8913423','蓬生麻中','梅堯臣','宋','宋诗','song-poetry','','[]','麻畦無曲本，蓬質有樛莖。',72,'全唐诗/poet.song.14000.json','["麻畦無曲本，蓬質有樛莖。", "所託脩仍直，安能縱復橫。", "擇鄰聞舊母，益友記諸生。", "蕭艾從茲遠，蒿萊不可并。", "何嗟蔣詡徑，孰念衛人行。", "儻匪緣其地，秋風廣漠驚。"]'),
('c716b04c-fb75-4a56-a14c-96da002e53fe','賣鹿角魚','梅堯臣','宋','宋诗','song-poetry','','[]','水中龍，角而足。',64,'全唐诗/poet.song.14000.json','["水中龍，角而足。", "海小魚，角矗矗。", "不擬龍，乃擬鹿。", "譬彼蝸，抗蠒犢。", "漬以鹹鹵久且醭，持賣都市參鼎餗。", "此人何苦厭豬羊，甘爾臭味不飽腹。"]'),
('ebd49321-b53e-4ae9-a819-486891d0abaf','夜與原甫江家步歸','梅堯臣','宋','宋诗','song-poetry','','[]','丹砂漆盤盛井水，冷浸半坼山櫻花。',64,'全唐诗/poet.song.14000.json','["丹砂漆盤盛井水，冷浸半坼山櫻花。", "始見春色不奈喜，黄昏招飲夜還家。", "劉郎居南我居北，陌上泥開天正黑。", "風吹蠟燭燒未明，素絲作履惜不得。"]'),
('2a739745-4d1e-4566-a1ee-fdb7584c4212','高陽關射亭','梅堯臣','宋','宋诗','song-poetry','','[]','星弧射狼夜夜張，角弓備寇不可忘。',64,'全唐诗/poet.song.14000.json','["星弧射狼夜夜張，角弓備寇不可忘。", "將軍屯師古關下，不尚武力何由强。", "日與官兵來會此，弓須射硬箭射長。", "更如羿中九烏斃，獨見杲杲明扶桑。"]'),
('8ad33d2c-fb6c-4542-a43f-94669c4bd163','京師逢賣梅花五首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','此土只見看杏蕊，大梁亦復賣梅花。',32,'全唐诗/poet.song.14000.json','["此土只見看杏蕊，大梁亦復賣梅花。", "此心還似庾開府，不惜金錢買取誇。"]'),
('f838f18d-ff03-4a10-884a-61112a9b3226','京師逢賣梅花五首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','驛使前時走馬迴，北人初識越人梅。',32,'全唐诗/poet.song.14000.json','["驛使前時走馬迴，北人初識越人梅。", "清香莫把荼䕷比，只欠溪頭月下杯。"]'),
('006fcc24-a704-493e-8d5d-0e69cb7c1380','京師逢賣梅花五首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','憶在鄱君舊國傍，馬穿脩竹忽聞香。',32,'全唐诗/poet.song.14000.json','["憶在鄱君舊國傍，馬穿脩竹忽聞香。", "偶將眼趁蝴蝶去，隔水深深幾樹芳。"]'),
('01f08ecc-cadc-4f57-9a55-2fce8ec87469','京師逢賣梅花五首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','曾見竹籬和樹夾，高枝斜引過柴扉。',32,'全唐诗/poet.song.14000.json','["曾見竹籬和樹夾，高枝斜引過柴扉。", "對門獨木危橋上，少婦髻鬟猶戴歸。"]'),
('b5f72df7-6a0a-424a-a783-837ebf020731','京師逢賣梅花五首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','此去吾鄉二千里，不看素萼兩三年。',32,'全唐诗/poet.song.14000.json','["此去吾鄉二千里，不看素萼兩三年。", "移根種子誰辛苦，上苑偷來值幾錢。"]'),
('19123b1b-1eb6-4b71-a4ed-fb0c17b4eaa6','三月五日欲訪宋中道遇雪而止','梅堯臣','宋','宋诗','song-poetry','','[]','蝴蝶飛時雪鬭輕，滿街撩亂得人驚。',32,'全唐诗/poet.song.14000.json','["蝴蝶飛時雪鬭輕，滿街撩亂得人驚。", "欲尋宋子東城去，馬畏春泥不敢行。"]'),
('17bf02c6-f487-4937-a951-f324d34d321d','觀文丁右丞挽辭二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','預政公槐亞，談經帝席陳。',48,'全唐诗/poet.song.14000.json','["預政公槐亞，談經帝席陳。", "儉恭齊國相，清浄漢廷人。", "去夢嘗爲蝶，遺文不解麟。", "一聞車馬幸，豐賜及孤臣。"]'),
('ddfc2935-42f4-4f06-b46d-4d649bc1ae23','觀文丁右丞挽辭二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','春風百花發，露挽九原歸。',48,'全唐诗/poet.song.14000.json','["春風百花發，露挽九原歸。", "白馬悲鳴駐，黄鸝下上飛。", "壠邊新柏盛，門外弔人稀。", "獨見東牀客，攀車淚濕衣。"]'),
('d9d35a1f-9646-44db-8167-f58016033624','廷老傳沛語戲作','梅堯臣','宋','宋诗','song-poetry','','[]','夷門市裏侯嬴老，公子時能釋禮過。',32,'全唐诗/poet.song.14000.json','["夷門市裏侯嬴老，公子時能釋禮過。", "莫問孟嘗招致客，薛中遺俗尚應多。"]'),
('81c99f1a-a1df-4c3f-92bd-7afa69dd673a','送胥平叔寺丞赴洛','梅堯臣','宋','宋诗','song-poetry','','[]','單車細馬出虎牢，春雲黕黕百舌嚎。',96,'全唐诗/poet.song.14000.json','["單車細馬出虎牢，春雲黕黕百舌嚎。", "穀雨已近花欲盡，秉燭夜飲朝坐曹。", "因君重思昔日歡，醉筆狂掃嵩丘高。", "于今零落二十載，縱在各各歎二毛。", "試採上陽何首烏，刮切仍致苦竹刀。", "俗情相望亦異此，競欲折筍籠含桃。"]'),
('cda58bb6-1781-4911-b87a-6b0771f16870','送婺州通判徐殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','疾湍怒蛟龍，不畏東風逆。',48,'全唐诗/poet.song.14000.json','["疾湍怒蛟龍，不畏東風逆。", "沄沄奔長淮，千里在咫尺。", "辭梁始及晨，過宋尚未夕。", "南州豈難到，何處淹行迹。"]'),
('8ed55849-ae2e-4e4e-8f26-1d7192e21f8c','三月十日韓子華招飲歸成','梅堯臣','宋','宋诗','song-poetry','','[]','清明曉赴韓侯家，自買白杏丁香花。',112,'全唐诗/poet.song.14000.json','["清明曉赴韓侯家，自買白杏丁香花。", "雀眼塗金銀蔑籠，貯在當筵呼舞娃。", "舞娃取捧笑向客，不顧插壞新烏紗。", "朝來我舍報生子，賀勸大白浮紅霞。", "酒狂有持梧桐板，暴謔一似鄱陽槎。", "袒裼擊鼓禰處士，當時偶脫猛虎牙。", "褊衷不容又何益，鸚鵡洲上空蒹葭。"]'),
('51317ce3-4c49-4cdc-b58d-fcaa1016b471','送下第親舊','梅堯臣','宋','宋诗','song-poetry','','[]','花開風雨惡，坐見紛紛落。',60,'全唐诗/poet.song.14000.json','["花開風雨惡，坐見紛紛落。", "明日結子時，又復有脫萼。", "莫嗟樹漸老，樹老子亦著。", "共愛西枝繁，不數東枝弱。", "他年會有春，却看西枝薄。"]'),
('c01b212c-4d5e-4653-8f4f-d229af5d6327','燕','梅堯臣','宋','宋诗','song-poetry','','[]','一避吳宮火，千年楚屋春。',48,'全唐诗/poet.song.14000.json','["一避吳宮火，千年楚屋春。", "翅迎風雨健，聲入戶庭頻。", "掠水過長渚，銜蟲落覆塵。", "休將漢皇后，故故比輕身。"]'),
('46f45870-eba5-4720-9453-a73a5a616cf0','雨','梅堯臣','宋','宋诗','song-poetry','','[]','春雲易成雨，一日幾迴陰。',48,'全唐诗/poet.song.14000.json','["春雲易成雨，一日幾迴陰。", "燕濕飛猶快，花寒色更深。", "邀車愁客遠，盤馬畏泥侵。", "向晚晴光吐，西窗綠影臨。"]'),
('337bcd2d-afb3-40a1-b6e2-7504bc79943f','晴','梅堯臣','宋','宋诗','song-poetry','','[]','風掃天如鑑，雲開日似萍。',48,'全唐诗/poet.song.14000.json','["風掃天如鑑，雲開日似萍。", "苑花猶带濕，蔬甲已微青。", "蝶翅粉應薄，塘漘波更渟。", "尋春不惜醉，莫笑髮星星。"]'),
('37b82624-217e-4e0e-aafa-333b7533b3b6','送胡公疎之金陵','梅堯臣','宋','宋诗','song-poetry','','[]','綠蒲作帆一百尺，波浪疾飛輕鳥翮。',128,'全唐诗/poet.song.14000.json','["綠蒲作帆一百尺，波浪疾飛輕鳥翮。", "瓜步山傍夜泊人，石頭城邊舊遊客。", "月如冰輪出海來，江波千里無物隔。", "自古有恨洗不盡，于今萬事何由白。", "依稀可記鮑家詩，寂寞休尋江令宅。", "楊花正飛鮆魚多，良膾舉酒謝河伯。", "但令甘肥日飽腹，誰用麒麟刻青石。", "去舸已快風亦便，寧同步兵哭車軛。"]'),
('e4ab9cdb-c758-4042-8352-850194c8d677','送裴虞部知信州','梅堯臣','宋','宋诗','song-poetry','','[]','攢青歷歷正面山，刺史日坐雲屏間。',64,'全唐诗/poet.song.14000.json','["攢青歷歷正面山，刺史日坐雲屏間。", "楚人竟掘水精璞，漢女買作月珮環。", "時惟産寶不重穀，願當化俗無棄菅。", "往辭丞相相有言，物景清絕何由攀。"]'),
('fae2e2ef-cc06-4e1f-8be2-f8bde441dbe6','送李推官之岳州','梅堯臣','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','崑崙燕子五兩竿，霧露薄水平湖寒。',80,'全唐诗/poet.song.14000.json','["崑崙燕子五兩竿，霧露薄水平湖寒。", "風帆美滿八百里，夕從岳陽樓上看。", "魚跳鷺立月鉤下，星斗爛爛垂欄干。", "羽書不到罇俎裏，蠻兵况去荆楚安。", "試尋燕公舊賦筆，磨圭刻碧獨可完。"]'),
('3ebba787-3d52-4abe-8119-51341cc028cd','和和之南齋畫壁歌','梅堯臣','宋','宋诗','song-poetry','','[]','終南下臨長安城，峻欄高檻黄金嬴。',160,'全唐诗/poet.song.14000.json','["終南下臨長安城，峻欄高檻黄金嬴。", "嵩山亦近洛陽陌，鮮車怒馬一日程。", "大梁平廣匝千里，不見雲峯來眼底。", "其間自有高趣人，掃室呼工巖壑啟。", "初疑巨靈勇擘華，不比將軍能聚米。", "暗雨輕煙滿室中，塵事如脂一朝洗。", "又將餘力作脩竹，石上數莖風撼玉。", "葉斜枝亞寒聲盡，節老根獰生意足。", "何須踐苔眠綠陰，然後始爲嵇阮公。", "三賢歌詠已見意，舞女不須頻整簪。"]'),
('5587d0ad-73ac-4855-acd9-deac1b187e64','嫣婦','梅堯臣','宋','宋诗','song-poetry','','[]','黄金一丸入雲端，羣貧望逐滿長安。',64,'全唐诗/poet.song.14000.json','["黄金一丸入雲端，羣貧望逐滿長安。", "衆人爲貴嫣不惜，棄擲如泥資彈射。", "藏身葉底有能鳴，辜負春風拖兩翮。", "不飛上天訴至珍，幾人辛勤揀砂石。"]'),
('e0702ce6-4a1f-44bd-8ba0-a42141344c64','送端式歸漳州','梅堯臣','宋','宋诗','song-poetry','','[]','來居天王都，常夢苦竹溪。',60,'全唐诗/poet.song.14000.json','["來居天王都，常夢苦竹溪。", "乃識高僧趣，不爲利物迷。", "海燕乘華屋，區區竟銜泥。", "安知矯翼鷗，豈類斷尾雞。", "性同而質殊，何必莊指齊。"]'),
('e7a1e19d-d2af-4541-8356-8708e80aa478','送黄殿丞通判潤州','梅堯臣','宋','宋诗','song-poetry','','[]','前年江州飛火龍，樓殿化盡山將鎔。',80,'全唐诗/poet.song.14000.json','["前年江州飛火龍，樓殿化盡山將鎔。", "今聞榱棟復華壯，大閣渠渠出波上。", "南徐別乘簡且閑，下馬岸傍呼畫舫。", "永日江風不畏人，檝師猱獰欺白浪。", "衣上京塵莫厭多，斗擻中流雲在望。"]'),
('26901116-7ef3-47dd-836a-414ed4f9ddd7','揀花','梅堯臣','宋','宋诗','song-poetry','','[]','紫絲暈粉綴蘚花，綠羅布葉攢飛霞。',80,'全唐诗/poet.song.14000.json','["紫絲暈粉綴蘚花，綠羅布葉攢飛霞。", "鶑舌未調香萼醉，柔風細吹銅梗斜。", "金鞍結束果下馬，低枝不礙無闌遮。", "長陵小市見阿姊，濃薰馥郁升鈿車。", "莫輕貧賤出閭巷，迎入漢宮人自誇。"]'),
('4fe94ced-e902-40bb-8139-ef535deb3ee8','次韻和端式見贈','梅堯臣','宋','宋诗','song-poetry','','[]','不爲阮步兵，發詠怨朝陽。',84,'全唐诗/poet.song.14000.json','["不爲阮步兵，發詠怨朝陽。", "不學屈大夫，行吟思搴芳。", "其雨豈無時，細佩空自香。", "吾道不苟合，我懷固有常。", "江南一畝宅，近在句溪旁。", "仁宦且如此，夢寐安敢忘。", "以子諭言多，重歌木桃章。"]'),
('3ae8c6b9-f253-47a9-964b-8a5211505891','楊公藴之華亭宰','梅堯臣','宋','宋诗','song-poetry','','[]','月徑千里大，中有神娥宮。',108,'全唐诗/poet.song.14000.json','["月徑千里大，中有神娥宮。", "宮旁種玉桂，柯葉垂瓏瓏。", "蝦蟆穴其根，出輒氣墨蒙。", "光魄縱復吐，血赤如頑銅。", "不知從何時，更使人蹤通。", "年年折桂枝，寬少尚易充。", "今年拗都盡，禿株立童童。", "株禿莫爾攀，墮雲雙手空。", "歸來走海上，買鶴問吳翁。"]'),
('0ff2d177-a6cc-4dd9-a79f-b239d1bbd318','端午前保之太傅遺水墨扇及酒','梅堯臣','宋','宋诗','song-poetry','','[]','畫扇雙酒壺，置前兵吏立。',48,'全唐诗/poet.song.14000.json','["畫扇雙酒壺，置前兵吏立。", "言將國匠奇，重以風義執。", "樹石冰上看，山河月中入。", "便持菖蒲飲，不畏青蠅及。"]'),
('cf8044f8-bebe-4bf8-b93f-2cf034d47c94','送汝陰宰孫寺丞','梅堯臣','宋','宋诗','song-poetry','','[]','艑郎唱櫓燕尾下，潁水落日蛇鱗生。',64,'全唐诗/poet.song.14000.json','["艑郎唱櫓燕尾下，潁水落日蛇鱗生。", "綠蒲被岸漁網舉，黄鳥啄葚繰車鳴。", "吏無詬租官正來，不借魴鱮與吏烹。", "饋吏人情見里黨，官非喜慢知官清。"]'),
('d73ac1f9-39b0-488a-8087-ed4fb6b595b3','和曇穎師四明十題 雪竇山','梅堯臣','宋','宋诗','song-poetry','','[]','重雲不藏春，深竇常有雪。',36,'全唐诗/poet.song.14000.json','["重雲不藏春，深竇常有雪。", "曉月號松猿，晴壁挂海霓。", "終恍無心人，區區佩環玦。"]'),
('19fb2daa-052e-420d-93fb-f48463ec0164','和曇穎師四明十題 龍隠潭','梅堯臣','宋','宋诗','song-poetry','','[]','老龍戀潭窟，不雨亦不雲。',36,'全唐诗/poet.song.14000.json','["老龍戀潭窟，不雨亦不雲。", "吐涎出溪滑，吹腥隔林聞。", "疾雷驅未去，魚鼈競紛紛。"]'),
('2af3981e-3e96-49ae-877f-4a86a12adbd4','和曇穎師四明十題 含珠林','梅堯臣','宋','宋诗','song-poetry','','[]','山爲驪龍蟠，谷作驪龍顋。',36,'全唐诗/poet.song.14000.json','["山爲驪龍蟠，谷作驪龍顋。", "珠樹存其間，誰採明月來。", "何須循海隅，笑蚌未成胎。"]'),
('3eae44a7-af7f-4952-b449-fbab3c205d92','和曇穎師四明十題 偃蓋亭','梅堯臣','宋','宋诗','song-poetry','','[]','既將茅覆簷，復有松爲蓋。',36,'全唐诗/poet.song.14000.json','["既將茅覆簷，復有松爲蓋。", "五里入山時，憩此得寒籟。", "曾無康樂游，但見雲衲會。"]'),
('e555a8ac-8bc2-4a1b-8574-c6fa5913c208','和曇穎師四明十題 雲外庵','梅堯臣','宋','宋诗','song-poetry','','[]','山僧好寂靜，入雲恨不深。',36,'全唐诗/poet.song.14000.json','["山僧好寂靜，入雲恨不深。", "峯間一雨昏，林表孤燈沉。", "往來有猿狖，呼嘯自成音。"]'),
('ffafd3c6-bfe1-4e1e-9b27-f955a8d1cc36','和曇穎師四明十題 石筍峯','梅堯臣','宋','宋诗','song-poetry','','[]','巨石如龍孫，聳聳煙霧裏。',36,'全唐诗/poet.song.14000.json','["巨石如龍孫，聳聳煙霧裏。", "明明落溪口，納納喧灘齒。", "何當助齋盂，菌蕃徒爲美。"]'),
('73586519-d71e-4ed0-9de0-8f5af875953c','和曇穎師四明十題 宴坐巖','梅堯臣','宋','宋诗','song-poetry','','[]','心危身亦危，衽席尚顛墜。',36,'全唐诗/poet.song.14000.json','["心危身亦危，衽席尚顛墜。", "如何巖石上，來坐自安意。", "能諭死生間，無論寤與寐。"]'),
('27990fbc-ad7e-4c16-99e6-a7ed56695e2a','和曇穎師四明十題 三層瀑','梅堯臣','宋','宋诗','song-poetry','','[]','山頭出飛瀑，落落鳴寒玉。',36,'全唐诗/poet.song.14000.json','["山頭出飛瀑，落落鳴寒玉。", "再落至山腰，三落至山足。", "欲引煑春山，僧房架刳竹。"]'),
('681a334d-392b-41ac-a017-44478fb91234','和曇穎師四明十題 丹山洞','梅堯臣','宋','宋诗','song-poetry','','[]','山無鳳皇飛，洞有仙人跡。',36,'全唐诗/poet.song.14000.json','["山無鳳皇飛，洞有仙人跡。", "蝙蝠大如鴉，莓苔遍上屐。", "自慙無道骨，安問緣雲客。"]'),
('b7e0c8fc-49a3-4310-a57c-5946a9a96620','和曇穎師四明十題 獅子巖','梅堯臣','宋','宋诗','song-poetry','','[]','巖形若狻猊，不能千里走。',36,'全唐诗/poet.song.14000.json','["巖形若狻猊，不能千里走。", "豈無鳥獸羣，當假風雷吼。", "寄謝棲息人，想像真妄有。"]'),
('47bf31be-1a1b-4859-a10f-f6b6fe932cde','依韻和原甫省中松石畫壁','梅堯臣','宋','宋诗','song-poetry','','[]','山林與城闕，事物不相對。',120,'全唐诗/poet.song.14000.json','["山林與城闕，事物不相對。", "唯聞秉道義，所處無內外。", "趨煩而毀靜，此理乃俗輩。", "昔有天下賢，喜得名筆會。", "買粉塗南牆，松石生屋內。", "石怪如舂濤，松偃如起籟。", "畫來二十年，數偶未輒愛。", "罕親憑按顔，但覩抱犢背。", "雖當省闥嚴，晦昧欲何頼。", "今逢茂陵人，獨唱亦豪邁。"]'),
('528b4be2-a15e-4f5c-9ca0-8f32e1c5cb2d','依韻和原甫廳壁錢諫議畫蟹','梅堯臣','宋','宋诗','song-poetry','','[]','諫議吳王孫，特畫水物具。',48,'全唐诗/poet.song.14000.json','["諫議吳王孫，特畫水物具。", "至今圖寫名，不減南朝顧。", "濃淡一以墨，螯殻自有度。", "意將輕蔡謨，殆被蟛蜞誤。"]'),
('f9e213c9-95ce-4445-ae36-bd33f1d9cd84','依韻和原甫廳壁許道寧山水云是富彥國作判官時畫','梅堯臣','宋','宋诗','song-poetry','','[]','山情水思半軒間，試問來居有底閑。',32,'全唐诗/poet.song.14000.json','["山情水思半軒間，試問來居有底閑。", "唯有才高方暇佚，無論歲月自能攀。"]'),
('dbdfedb9-58db-4eb4-a47a-997d13f5270e','依韻和劉原甫見寄','梅堯臣','宋','宋诗','song-poetry','','[]','憶昔游臨汝，于時太守賢。',144,'全唐诗/poet.song.14000.json','["憶昔游臨汝，于時太守賢。", "山尋順風處，城得豢龍遷。", "民頸纍纍大，池荷一一圓。", "周碑嗟缺矣，少室望嶄然。", "羸馬居人後，歸禽落我先。", "事還如響答，老去若波旋。", "賦分都應定，元功豈得偏。", "不須天以問，自可鑒於前。", "王粲今方樂，邊韶舊好眠。", "漢官聊擲彩，梵學競通禪。", "語道滔滔是，論情往往牽。", "平生二三友，南睇不勝悁。"]'),
('24a28da3-beaf-4e02-a82b-485091b1510b','醉和范景仁賦子華東軒樹次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','樹影落東牆，影微人已醉。',24,'全唐诗/poet.song.14000.json','["樹影落東牆，影微人已醉。", "休看枝上綠，但對眉間翠。"]'),
('86de03d9-afa0-498a-9652-1f899c54e06f','五月十四日與子華自內中歸','梅堯臣','宋','宋诗','song-poetry','','[]','君注起居同左史，我爲委吏退延和。',32,'全唐诗/poet.song.14000.json','["君注起居同左史，我爲委吏退延和。", "共經南陌東風急，側帽偷看意已多。"]'),
('4a5caffb-bc51-46f2-be57-cd66630fcd48','送傅越石都官歸越州待闕','梅堯臣','宋','宋诗','song-poetry','','[]','越客舟從真定至，夜夜鏡湖生夢寐。',112,'全唐诗/poet.song.14000.json','["越客舟從真定至，夜夜鏡湖生夢寐。", "曉度吳江百尺船，洗眼重看會稽翠。", "買臣負薪樵徑荒，伯鸞賃舂苔臼棄。", "綠橘黄柑带葉收，白粳紫蟹侵霜饋。", "食蟹易美粳易飽，綠橘佐酒柑佐醉。", "莫論仕宦遠與近，布袍練袍何所利。", "君恬不忍乞丐爲，且返故廬聊以遲。"]'),
('5a3442a9-83e7-4c25-9b53-85d372bbd624','吳沖卿出古飲鼎','梅堯臣','宋','宋诗','song-poetry','','[]','精銅作鼎土不蝕，地下千年蘚花冪。',112,'全唐诗/poet.song.14000.json','["精銅作鼎土不蝕，地下千年蘚花冪。", "腹空鳳卵留藻文，足立三刀刃微直。", "左耳可執口可斟，其上兩柱何對植。", "從誰發掘歸吳侯，來助雅飲歡莫極。", "又荷君家主母賢，翠羽胡琴令奏側。", "絲聲不斷玉箏繁，繞樹黄鸝鳴不得。", "我雖衰苶爲之醉，玩古樂今人未識。"]'),
('1eef4024-1007-44c9-8d07-68fe1d71c4ab','二十四日江鄰幾邀觀三館書畫錄其所見','梅堯臣','宋','宋诗','song-poetry','','[]','五月秘府始暴書，一日江君來約予。',208,'全唐诗/poet.song.14000.json','["五月秘府始暴書，一日江君來約予。", "世間難有古畫筆，可往共觀臨石渠。", "我時跨馬冒熱去，開厨發匣鳴鑰魚。", "羲獻墨迹十一卷，水玉作軸光疏疏。", "最奇小楷樂毅論，永和題尾付官奴。", "又看四本絕品畫，戴嵩吳牛望青蕪。", "李成寒林樹半枯，黄荃工妙白兔圖。", "不知名姓貌人物，二公對弈旁觀俱。", "黄金錯鏤爲投壺，粉障復畫一病夫。", "後有女子執巾裾，床前紅毯平圍爐。", "床上二姝展氍毹，繞床屏風山有無。", "畫中見畫三重鋪，此幅巧甚意思殊。", "孰真孰假丹青模，世事若此還可吁。"]'),
('1c508d99-4f00-4fe3-bf92-b27e3b083879','依韻吳沖卿祕閣觀逸少墨蹟','梅堯臣','宋','宋诗','song-poetry','','[]','奇哉王右軍，下筆若神聖。',192,'全唐诗/poet.song.14000.json','["奇哉王右軍，下筆若神聖。", "長戈與伏弩，無不從號令。", "賢豪雖林立，帖斂孰敢競。", "師徒氣揚揚，龍虎旗正正。", "勝聲塞宇宙，自昔無此盛。", "赫赫猶至今，瑣瑣曷云並。", "崇崇中秘書，濟濟士游泳。", "墨寶收盈厨，來觀遇已橫。", "始知前人蹟，鎸多自失勁。", "紙素儻未壞，萬古傳莫竟。", "一從歸人間，夢寐不能更。", "但媿將短才，輒爾接高詠。", "何羞趙壹窮，自有鍾嶸評。", "嘗聞曹將軍，尚諳賦競病。", "我生羣俊末，貧賤亦足慶。", "文成終媿君，鉛刀值枯梗。"]'),
('5f4af5a9-aea0-415f-a81f-c62c4aa1c237','同江鄰幾龔輔之陳和叔登吹臺有感','梅堯臣','宋','宋诗','song-poetry','','[]','在昔梁惠王，築臺聚歌吹。',60,'全唐诗/poet.song.14000.json','["在昔梁惠王，築臺聚歌吹。", "笙簫無復聞，黄土化珠翠。", "當時秦兵强，今亦歸厚地。", "我與諸賢良，舉酒莫言醉。", "曾誰問孟軻，空自有仁義。"]'),
('9176fd98-d31e-489b-90bc-4609a2549cc9','逢羊','梅堯臣','宋','宋诗','song-poetry','','[]','牧人垂長髯，驅羊從北道。',60,'全唐诗/poet.song.14000.json','["牧人垂長髯，驅羊從北道。", "老羝壓大羣，毛比長髯好。", "暮歸同一欄，朝出不擇草。", "既肥當用烹，從羝羝獨保。", "狡誘以全軀，角尾徒爲老。"]'),
('bffd1f4f-257c-40a6-8043-9020242df07c','依韻和張中樂寺丞見贈','梅堯臣','宋','宋诗','song-poetry','','[]','朝車走轔轔，暮車走𨌠𨌠。',144,'全唐诗/poet.song.14000.json','["朝車走轔轔，暮車走𨌠𨌠。", "黄埃蔽車輪，赤日爍車屋。", "靡論遠與近，安問疎與熟。", "賢愚各有求，往返相磨轂。", "我馬不出門，我蹟亦以跼。", "心慕中樂賢，道義聞且宿。", "其言清而新，其貌古不俗。", "書可到二王，辯可折五鹿。", "往見未爲勞，定交然後篤。", "惠詩何勁敏，對敵射銅鏃。", "穿楊有舊手，驚雀無全目。", "强酬非所當，宜將弓矢速。"]'),
('05bd2983-e75f-41d8-aabe-01930853f543','依韻和原甫對月見邀不至','梅堯臣','宋','宋诗','song-poetry','','[]','每愛孔北海，罇中常不空。',48,'全唐诗/poet.song.14000.json','["每愛孔北海，罇中常不空。", "今無酒與客，唯有月兼風。", "遠色曾何隔，微凉亦已同。", "更期三五夕，靜坐接談叢。"]'),
('f0697d68-6d0c-47c0-9260-c9b8fba984cf','依韻和原甫月夜獨酌','梅堯臣','宋','宋诗','song-poetry','','[]','月下馬蹄休擾擾，夜凉蟲響競囂囂。',64,'全唐诗/poet.song.14000.json','["月下馬蹄休擾擾，夜凉蟲響競囂囂。", "一杯獨飲愁何有，孤榻無人膝自摇。", "北斗柄高天漸轉，小冠簪冷髮微凋。", "誰知靜對頹然影，竟夕幽懷豈易聊。"]'),
('d6047036-fb32-4361-af6c-574912e5b953','依韻和原甫早赴紫宸朝待旦假寐','梅堯臣','宋','宋诗','song-poetry','','[]','月落西樓露氣寒，大明將謁望清班。',64,'全唐诗/poet.song.14000.json','["月落西樓露氣寒，大明將謁望清班。", "燭房猶照衣冠上，漏舍欲爲魚鳥間。", "入仗采旗開日月，在庭公衮儼雲山。", "我慙一似朝宗水，亦得隨流到海還。"]'),
('df9f7d30-8f37-42e1-bc32-43c8bd1cfc8e','依韻和原甫新置盆池種蓮花菖蒲養小魚數十頭之什','梅堯臣','宋','宋诗','song-poetry','','[]','瓦盆貯斗斛，何必問尺尋。',72,'全唐诗/poet.song.14000.json','["瓦盆貯斗斛，何必問尺尋。", "菖蒲未見花，蓮子未見心。", "小鮮不足烹，安用芎餌沉。", "戶庭雖云窄，江海趣已深。", "襲香而玩芳，嘉賓會如林。", "寧思千里游，鳴櫓上清涔。"]'),
('0c419625-6a71-4e5e-a328-977157bfc2a9','送施屯田提點銅場兼相度嶺外鹽入虔吉','梅堯臣','宋','宋诗','song-poetry','','[]','江西采銅山未竭，南越熬波海將結。',128,'全唐诗/poet.song.14000.json','["江西采銅山未竭，南越熬波海將結。", "主人貪利不畏刑，白日持兵逾盜竊。", "銅私鑄器鹽奪商，死共吏爭蛇鬭穴。", "姦豪乘勢倚蠻陬，劫掠聚徒成蟻垤。", "今雖驅翦嶺下平，尚恐根存更生孽。", "因擇健才通便民，付職與權將有設。", "秋香亭上共爲賓，却作主人殊少悅。", "徂東走北十五年，只有山川看不別。"]'),
('05b4512d-32bd-4d1e-9da3-aed42b58606b','依韻和江鄰幾癸巳六月十日同刁吳韓楊飲范景仁家晚赴館宿覩吳興太守章伯鎮題壁記辛卯仲秋初吉九月十一日十月二十二日十二月十一日壬辰二月一日館直慨然有感','梅堯臣','宋','宋诗','song-poetry','','[]','江翁多感槩，飲散來直廬。',156,'全唐诗/poet.song.14000.json','["江翁多感槩，飲散來直廬。", "題蹤有舊友，連蹇常與渠。", "昨歸天祿下，念昔悲有餘。", "未久復外補，安能戀清虛。", "得請向苕霅，幽懷寄禽魚。", "高城浸湖光，面面當紅蕖。", "晚乘畫舫游，四坐羅輕裾。", "數杯已酩酊，萬事應破除。", "不愛趨時近，不恤與世疎。", "百歲且過半，冉冉將焉如。", "誰慕八十叟，猶在磻溪漁。", "嗟哉再宿夕，乃自仲秋初。", "清談固隔絕，可見壁上書。"]'),
('68f43be3-14e4-47bb-bff2-06231988f641','送林大年寺丞宰蒙城先歸餘杭逋之姪孫','梅堯臣','宋','宋诗','song-poetry','','[]','東方有奇士，隠德珠在淵。',96,'全唐诗/poet.song.14000.json','["東方有奇士，隠德珠在淵。", "川壑爲之媚，草樹爲之妍。", "歿來十五載，獨見諸孫賢。", "煌煌出仕途，皎皎如淮蠙。", "今爲蒙城宰，歸問浙江船。", "何時渡楊子，夜入明月邊。", "有舄不化鳬，有琴何用絃。", "真趣還自得，治民唯力田。"]'),
('a4f260b9-ee5b-4032-bbf1-2593f34ea1c9','依韻和原甫六月八日曉雨','梅堯臣','宋','宋诗','song-poetry','','[]','侵曉忽飛雨，颯然戶庭凉。',72,'全唐诗/poet.song.14000.json','["侵曉忽飛雨，颯然戶庭凉。", "滴堦初聞聲，濯樹暗有香。", "吹燭焰閃閃，鳴雞濕昂昂。", "稍已便衣冠，喜氣眉宇翔。", "安然如涸魚，呴沫久已望。", "塵纓自可潔，何必念滄浪。"]'),
('0aa964e4-7c38-4b00-9e96-2713dd32a63b','送余中舍知漢州德陽','梅堯臣','宋','宋诗','song-poetry','','[]','匹馬易爲秣，單車長是輕。',48,'全唐诗/poet.song.14000.json','["匹馬易爲秣，單車長是輕。", "秋風來棧道，宿雨度關城。", "石上樹林暗，山根江水明。", "桐花鳳何似，歸日爲將行。"]'),
('16dd194a-5e62-46e8-a46e-0b482b864937','勉裴如晦','梅堯臣','宋','宋诗','song-poetry','','[]','裴侯失嬰兒，心腸如焚煎。',60,'全唐诗/poet.song.14000.json','["裴侯失嬰兒，心腸如焚煎。", "愛玩白玉玦，墜地不復全。", "收拾見顔色，瑩澈猶自妍。", "鳳皇生九雛，一卵破易捐。", "况多令男子，拭淚慰目前。"]'),
('8adfbc5e-dd82-4855-b51b-28f5cd854025','送謝寺丞知餘姚','梅堯臣','宋','宋诗','song-poetry','','[]','姚江千里海汐應，山井亦與江潮通。',64,'全唐诗/poet.song.14000.json','["姚江千里海汐應，山井亦與江潮通。", "秋來魚蟹不知數，日日舉案將無窮。", "高堂有親甘可養，下舍有弟樂可同。", "縣民舊喜諸郎政，芻力莫媿今爲翁。"]'),
('4aa76f8d-8e1e-421c-a3a7-2ee6b96958f8','與蔣祕別二十六年田棐二十年羅拯十年始見之','梅堯臣','宋','宋诗','song-poetry','','[]','我今五十二，常苦離別煎。',264,'全唐诗/poet.song.14000.json','["我今五十二，常苦離別煎。", "屈指數離別，正去一半年。", "三君異出處，相見有後先。", "蔣最會遇早，羅倍晚於田。", "仕宦比我遲，官資居我前。", "此亦漫輕量，無限歸荒埏。", "所喜笑語同，各驚顔貌遷。", "髮有霜華侵，目有蜘蛛懸。", "有酒易以醉，有奚徒用妍。", "醒來念功名，病螾希蜿蜒。", "安得有園廬，寬閒近林泉。", "養魚數千頭，種薤三四廛。", "餘蔬皆稱此，嘉果植亦然。", "既無俗造請，窮冬事高眠。", "囷貯白粳稻，酒沽青銅錢。", "飯過引數杯，令兒誦嘉篇。", "仰首看赤日，區區隨天旋。", "朝見出滄海，莫見入虞淵。", "畢竟將何窮，磨滅愚與賢。", "億億萬萬載，筋骨非玉堅。", "桐棺三寸厚，在昔誰免焉。", "去去欲及時，嗟嗟無由緣。"]'),
('731fce20-9c06-483a-a079-6343e719a654','別三十弟彥臣','梅堯臣','宋','宋诗','song-poetry','','[]','朝辭都城裏，暮止汴堤頭。',24,'全唐诗/poet.song.14000.json','["朝辭都城裏，暮止汴堤頭。", "滿目非相親，寂默對河流。"]'),
('24c94ccc-1023-4387-90ef-b062c04eb180','依韻和雪竇山曇穎長老見寄','梅堯臣','宋','宋诗','song-poetry','','[]','處山無厭山，林鳥正關關。',48,'全唐诗/poet.song.14000.json','["處山無厭山，林鳥正關關。", "月入潭心白，花明谷口閒。", "采薪能自至，流水不知還。", "聞欲觀滄海，高峯峻亦攀。"]'),
('946a061b-fcdd-4de3-ba54-622145bc6bcf','送余中舍監韶州錢監','梅堯臣','宋','宋诗','song-poetry','','[]','孤青水上石，片白蒼梧雲。',48,'全唐诗/poet.song.14000.json','["孤青水上石，片白蒼梧雲。", "虞舜不可見，簫韶不可聞。", "君爲漢錢官，鑿山取銅鑛。", "韶石不生銅，留爲千古景。"]'),
('491d978c-0b77-46ad-9fe7-2f672a586378','七夕詠懷','梅堯臣','宋','宋诗','song-poetry','','[]','織女無恥羞，年年嫁牽牛。',120,'全唐诗/poet.song.14000.json','["織女無恥羞，年年嫁牽牛。", "牽牛苦娶婦，娶婦不解留。", "來往一夕光，奕奕河漢秋。", "輕傳人世巧，未知何時休。", "喜鵲頭無毛，截雲駕車輈。", "老鴉少斟酌，死欲同造舟。", "明月不到曉，是夜曲如鈎。", "天意與物理，注錯將何求。", "嘗聞阮家兒，犢鼻竹竿頭。", "人生自有分，豈媿曝衣樓。"]'),
('598c72c3-1fe6-43cb-a9ec-e921abc39363','韓子華遺冰','梅堯臣','宋','宋诗','song-poetry','','[]','六月侍臣方賜冰，我賦得之從友朋。',80,'全唐诗/poet.song.14000.json','["六月侍臣方賜冰，我賦得之從友朋。", "開盤一見水玉璞，置坐百步無青蠅。", "熱膚收汗起疹粟，不有消渴同茂陵。", "杜子每思赤脚踏，韓老嘗苦如甑烝。", "慙無二公才與學，享此足與俗輩矜。"]'),
('6e811770-1048-49a1-9354-d83719e04f6d','依韻和原甫置酒蘭菊間','梅堯臣','宋','宋诗','song-poetry','','[]','置酒蘭菊間，賓主適所適。',120,'全唐诗/poet.song.14000.json','["置酒蘭菊間，賓主適所適。", "權豪自炎炎，下上走役役。", "茲時况休沐，良可會朋戚。", "流俗務趨喧，寧思事閑寂。", "我輩豈其愚，歡言無吝色。", "相與舉盃盂，高歌不知夕。", "秋花未黄紫，秋雲多淡白。", "但知沉醉歸，莫顧有吏責。", "冠紼身外物，儻來安足惜。", "吾貧喜從游，幸免挂錢僻。"]'),
('28c006fd-610d-4d93-95ed-28f9b30879ae','觀書','梅堯臣','宋','宋诗','song-poetry','','[]','山陽女子大字書，不比常流事梳洗。',48,'全唐诗/poet.song.14000.json','["山陽女子大字書，不比常流事梳洗。", "親傳筆法中郎孫，妙作蠶頭魯公體。", "試寫麻牋滑似苔，墨蛟矯矯秋潭底。"]'),
('6b6b9769-41b8-42a4-a2b8-73199c751134','送仲和師歸雪竇兼簡穎禪師','梅堯臣','宋','宋诗','song-poetry','','[]','野鉢歸松下，將親聞道師。',24,'全唐诗/poet.song.14000.json','["野鉢歸松下，將親聞道師。", "風沙不堪寄，霜笴自相宜。"]'),
('bca96f72-2853-41f5-b6b7-37b452d5dc0d','二十二日起居退聞宣三館諸公觀瑞蓮','梅堯臣','宋','宋诗','song-poetry','','[]','來朝十二旒，將出未央殿。',72,'全唐诗/poet.song.14000.json','["來朝十二旒，將出未央殿。", "微聞嘉蓮開，獨許侍臣見。", "嘉蓮其如何，層樓擁霞片。", "玉輦下天泉，日昃不知倦。", "恩魚應亦喜，跳沫珠欲濺。", "誰憐與衆歸，博士臣疏賤。"]'),
('96d0c6c8-4cd3-43f9-87ab-746440dd5481','依韻吳沖卿秋蟲','梅堯臣','宋','宋诗','song-poetry','','[]','梧桐葉未老，露滴玉井牀。',204,'全唐诗/poet.song.14000.json','["梧桐葉未老，露滴玉井牀。", "秋蟲如里胥，促織何苦忙。", "苒苒機上絲，入夜爲鼠傷。", "織婦中夕起，投梭重徊徨。", "那聞草根聲，膏入然肝腸。", "天子固明聖，措意如陶唐。", "下民唯力穡，不見田疇荒。", "豈知裒斂人，督責務健强。", "所以機中女，心鬭日月光。", "年年租稅在，聒耳信已常。", "哀哉四海人，無不由此戕。", "吳侯當廳時，靜坐愛初凉。", "方將同佳人，歡樂舉杯觴。", "繁鳴雜螇螰，感愴情不皇。", "况蒙朝家恩，兄弟登俊良。", "意慮宜恤物，以慰衆所望。", "今者秋蟲篇，不異七月章。"]'),
('ee1502de-89a1-42f0-ab32-94a76fe02ff8','陌上二女','梅堯臣','宋','宋诗','song-poetry','','[]','素手搴冪䍦，柔纖明春荑。',48,'全唐诗/poet.song.14000.json','["素手搴冪䍦，柔纖明春荑。", "轉眄動桂葉，陽語啟瓠犀。", "阿姊金盛珠，阿妹繅籍圭。", "吹香襲行路，豈獨下蔡迷。"]'),
('fa0cb8bc-f0ad-4e45-a842-38015b939ef5','無悔','梅堯臣','宋','宋诗','song-poetry','','[]','婦人未四十，容貌已改前。',60,'全唐诗/poet.song.14000.json','["婦人未四十，容貌已改前。", "男年踰五十，嗜欲固自偏。", "勿以色敵心，色衰心易遷。", "勿以愛恃久，愛移久多愆。", "明鏡知惡看，何須妬嬋娟。"]'),
('9dcbd7c2-1951-4f52-bc45-02d08dfc6055','弔瑞新和尚','梅堯臣','宋','宋诗','song-poetry','','[]','示化何悲戚，俱焚只衲衣。',48,'全唐诗/poet.song.14000.json','["示化何悲戚，俱焚只衲衣。", "已隨原火盡，空見野雲飛。", "寫影誰方丈，栽松舊翠微。", "當年渡江鉢，弟子獨將歸。"]'),
('6ebee74b-e7e7-4774-9725-19188c416bbe','依韻和吳沖卿新葺南齋','梅堯臣','宋','宋诗','song-poetry','','[]','移病新秋厭直廬，自將僮僕治前除。',64,'全唐诗/poet.song.14000.json','["移病新秋厭直廬，自將僮僕治前除。", "已栽楚客江邊草，不學嚴陵瀨上魚。", "紅穗拂欄何蒨粲，綠叢無水亦蕭疎。", "從今有月君須飲，況與朋親共舍居。"]'),
('68577984-bfc5-487d-a783-2424a7f03a05','江鄰幾遷居','梅堯臣','宋','宋诗','song-poetry','','[]','聞君遷新居，應比舊居好。',60,'全唐诗/poet.song.14000.json','["聞君遷新居，應比舊居好。", "復此假布囊，家具何草草。", "我貧無囊假，來僮笑欲倒。", "所笑還往人，生計不足道。", "非用僮僕知，雖貧自懷寶。"]'),
('54556cbd-8838-498e-af19-56a36b59850f','依韻答宋中道','梅堯臣','宋','宋诗','song-poetry','','[]','朝迴思見子，疲馬不及換。',288,'全唐诗/poet.song.14000.json','["朝迴思見子，疲馬不及換。", "入門呼僮僕，雞犬屢鳴嚾。", "中厨尚青煙，知未畢晨爨。", "曾不留我餐，忍餒固已慣。", "一接道德言，塵坌洗鄽閈。", "復出新錄書，令人再三歎。", "史漢抉精深，文字光粲粲。", "雖然饑腸鳴，躭讀忽忘肝。", "乃慙素所學，掇拾得淺懦。", "窮年誦讀人，呷呷類鵝鸛。", "較量功實倍，要捷未能半。", "麤行與細注，健筆凌東觀。", "天馬萬里行，筋骨在蹄腕。", "不知始何時，方冊已盈案。", "譬如涉大海，只見波漫漫。", "嗟哉勤且敏，固合處文翰。", "九閽未蹟歷，重雲若蔽扞。", "蓬瀛咫尺間，將度石橋斷。", "昔爲蛟龍騰，今爲野鼠竄。", "我亦失其宜，朝出不暇盥。", "碌碌倉廩爲，區區升斗筭。", "褊衷誠未堪，欲說慮辭曼。", "强希高遠蹤，終作俗嵬喚。", "家匱兒女大，裙襦不遮骭。"]'),
('31a3239e-1d4c-4caf-a340-4e7f1c1b71bc','聞刁景純侍女瘧已','梅堯臣','宋','宋诗','song-poetry','','[]','前時君家飲，不見吹笛姬。',132,'全唐诗/poet.song.14000.json','["前時君家飲，不見吹笛姬。", "君言彼娉婷，病瘧久屢治。", "隔日作寒熱，經時銷膏脂。", "醫師尤飲食，冷滑滯在脾。", "次聞有鬼物，水火陰以施。", "乃因道士逐，實得鬼所爲。", "手洒桃枝湯，足學夏禹馳。", "呵叱出門牆，勿復顧嘔遺。", "今雖病且已，皮骨尚尫羸。", "豈暇理舊曲，未能畫蛾眉。", "當期重相見，風月臨前墀。"]'),
('3ad6b427-d276-4369-be36-bff4f9a68d13','景純以侍兒病期與原甫月圓爲飲','梅堯臣','宋','宋诗','song-poetry','','[]','古龍水底鳴素秋，江雲不飛江賈愁。',184,'全唐诗/poet.song.14000.json','["古龍水底鳴素秋，江雲不飛江賈愁。", "金陵舊族天祿游，家有善笛能娛侯。", "憶侯前年罷姑孰，自買蘄州飽霜竹。", "腮肥頂瘦裁青玉，鑽鑿商聲五音足。", "牛渚磯邊夜泊時，平波不起月中吹。", "老魚跳舞龜出泥，雌蛟怨泣雄鼉悲。", "新還中都人罕知，交親奏酒隔簾幃。", "丹脣一發妙響馳，醉客欲見寧非癡。", "昨夜劉郎辭玉巵，主人勤謝當勿疑。", "渠今纏瘧尚苦羸，他日海蟾圓未遲。", "圓未遲，凉肝脾。", "畏肝熱，生腦脂。", "生脛脂，不得窺。"]'),
('f40a3345-6d87-4125-a867-377bd0098118','永濟倉書事','梅堯臣','宋','宋诗','song-poetry','','[]','神武立四極，收兵銷衆豪。',120,'全唐诗/poet.song.14000.json','["神武立四極，收兵銷衆豪。", "輸糧來萬國，積庾下千艘。", "貔虎肥於豢，麒麟老向槽。", "中州無殍餓，南土竭脂膏。", "黄鼠羣何畏，青鳩啄且嚎。", "古梁生菌耳，朽堵出蠐螬。", "樹腹懸蛇蛻，絲窠挂鳥毛。", "塵埃雖自汨，朱墨亦能操。", "直宿愁風雨，經年弊褐袍。", "仲尼猶作吏，我輩勿爲勞。"]'),
('fa0aec0a-ee2d-4e66-8595-449c1c25d02a','依韻和磁守王幾道屯田暑夜懷寄','梅堯臣','宋','宋诗','song-poetry','','[]','地厚天青冥，故交榮謝并。',72,'全唐诗/poet.song.14000.json','["地厚天青冥，故交榮謝并。", "何當一壺酒，以昔相與傾。", "君今二千石，未往戀山楹。", "山楹夜對月，孤懷豈忘情。", "貴者幾何逝，賤者幾何生。", "夏簟且安寢，明星上東城。"]'),
('4ac9dc67-54b3-41ce-9eb0-e6a2a9604425','依韻和孫侔鴈蕩二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','海邊巉絕有蒼山，怪怪奇奇物象閑。',64,'全唐诗/poet.song.14000.json','["海邊巉絕有蒼山，怪怪奇奇物象閑。", "百丈素流珠噴薄，千重紅樹火回環。", "遠尋僧寺石屏下，時遇野人雲屋間。", "今日京華見君說，便思輕舸出東關。"]'),
('756d494f-6893-44a5-b413-cebbc6b1b35f','依韻和孫侔鴈蕩二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','鴈蕩高高路莫通，銜蘆秋翼入雲峯。',64,'全唐诗/poet.song.14000.json','["鴈蕩高高路莫通，銜蘆秋翼入雲峯。", "山頭水闊不見影，巖下沙平時有蹤。", "千仞柱天何斂閃，萬工揮筆漫輕濃。", "葛巾蠟屐未能著，空羨青蒼重復重。"]'),
('93d404d8-eba1-4511-9c97-889f2bfd25df','赴刁景純招作將進酒呈同會','梅堯臣','宋','宋诗','song-poetry','','[]','日光如鎔金，湧上滄海流。',216,'全唐诗/poet.song.14000.json','["日光如鎔金，湧上滄海流。", "一朝復一朝，鑄出萬古愁。", "大鑪石破碎，世事安得休。", "明月只照夜，時時如屈鉤。", "常娥與玉兔，擣藥何所瘳。", "大患不自治，更被蝦蟆偷。", "我思天地間，二物最取尤。", "措置尚若此，細故曷用憂。", "著書欲傳道，未必如孔丘。", "當時及後代，見薄彼耽周。", "功名信難立，德行徒自脩。", "勞勞於我生，蔕挂同贅疣。", "不如聽鄰笛，就其舉盃甌。", "笛不煩教養，酒不煩取求。", "從今醉至春，從夏醉至秋。", "勿禁雞㹠魚，間薦鶉雁鳩。", "况多南方物，鹹腥美咽喉。", "計較無以過，試共阮籍謀。"]'),
('19c3eeb3-56d8-4629-97a0-e42605d8c72a','薛簡肅夫人挽詞四首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','蕭公當貴日，小吏引輕軒。',48,'全唐诗/poet.song.14000.json','["蕭公當貴日，小吏引輕軒。", "四德有遺美，六親無異言。", "立孤傳世嗣，垂範在閨門。", "澮水終歸柎，秋雲逐去魂。"]'),
('816bf837-776d-4165-bfe3-5210cfd47a25','薛簡肅夫人挽詞四首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞求子婿，不似怒甘公。',48,'全唐诗/poet.song.14000.json','["嘗聞求子婿，不似怒甘公。", "莫以昔人比，皆爲當世雄。", "家聲新慶續，國禮舊恩隆。", "必與齊姜墓，千秋壠樹同。"]'),
('5e8585ef-8438-4afe-bb9b-c53670b3544a','薛簡肅夫人挽詞四首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','冠劍將朝去，常知好直言。',48,'全唐诗/poet.song.14000.json','["冠劍將朝去，常知好直言。", "戒辭猶可託，先見久應存。", "瑩白冰兼玉，清芬蕙與蓀。", "堂塗從此閉，何日卜丘原。"]'),
('b28581b2-df93-4328-8c84-f66b1de9721e','薛簡肅夫人挽詞四首  其四','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','美合周詩播，魂先岱嶽歸。',48,'全唐诗/poet.song.14000.json','["美合周詩播，魂先岱嶽歸。", "空堂遷舊榻，素月照靈衣。", "珠翠香沉匣，丹青影挂幃。", "百年親戚淚，併作露霏霏。"]'),
('12926c58-e1f9-4f0b-bc67-9151220291af','送淮南提刑孫學士','梅堯臣','宋','宋诗','song-poetry','','[]','淮南木老霜欲飛，順令恐縱諸侯威。',64,'全唐诗/poet.song.14000.json','["淮南木老霜欲飛，順令恐縱諸侯威。", "命書纔出邸掾竭，已見衣繡車迎歸。", "樂莫我聽筵莫迓，清如蟾蜍夜吐暉。", "不須久作平反吏，自合橫經親帝闈。"]'),
('ca2e9569-9e95-4fda-af41-42e08020c216','送孫學士知太平州','梅堯臣','宋','宋诗','song-poetry','','[]','慈姥山上瘦龍孫，堪爲笙簫奉玉罇。',128,'全唐诗/poet.song.14000.json','["慈姥山上瘦龍孫，堪爲笙簫奉玉罇。", "使君來教後堂樂，江雲江月能迎門。", "門外青山謝家宅，當時池館無復存。", "乃知取歡須及早，富貴只是乘華軒。", "我踰五十作委吏，塵土汨汨嗟馳奔。", "有吹亦如賣餳者，安得鳳凰下崑崙。", "君今雖不苦稱意，尚驅文弩彯朱幡。", "嚴助昔除二千石，久勞侍從誠爲煩。"]'),
('19bc77d6-bfe0-4c7e-a269-c03d726988ad','送楊明叔通判越州','梅堯臣','宋','宋诗','song-poetry','','[]','知子心中光皪皪，不作秋蟫緣簡策。',128,'全唐诗/poet.song.14000.json','["知子心中光皪皪，不作秋蟫緣簡策。", "八月乘風入會稽，鏡湖細浪魚吹白。", "新除戚里外諸侯，况喜上賓開右席。", "明月樓中吸玉笙，青山影裏森朱戟。", "禹穴淵深入地流，秦望峯高插天碧。", "朝暮樵溪不見人，往來梅市空餘迹。", "墨池科斗作蝦蟆，道士鵝羣誰更易。", "摩滅應多著者稀，但游莫用論今昔。"]'),
('bc8e385f-36d5-4811-90b4-d57abf920f8d','依韻和睢陽杜相公答蔡君謨新體飛草書','梅堯臣','宋','宋诗','song-poetry','','[]','丹砂篆印發題封，雲母屏開照耀中。',64,'全唐诗/poet.song.14000.json','["丹砂篆印發題封，雲母屏開照耀中。", "漠漠蛟綃吹入紙，翹翹蠆髮卷隨風。", "新番自與鴻都異，舊法唯應堊帚同。", "丞相報詩何處問，清泠池上雁能通。"]'),
('7ba55978-6f79-4915-978d-845dab1e5915','翠羽辭','梅堯臣','宋','宋诗','song-poetry','','[]','秦女乘鸞遺翠羽，落在人間與風舞。',208,'全唐诗/poet.song.14000.json','["秦女乘鸞遺翠羽，落在人間與風舞。", "風休不歸誰作主，此郎拾取裝金縷。", "郎家主婦愛且憐，繫向裙腰同出處。", "朝來鄰里偶經過，方朔鄒枚爭欲覩。", "主人重客苦留連，急走鈿車令去取。", "酒巡未匝掩閤扉，忽已聞歸報鸚鵡。", "重勻朱粉臨鏡臺，促息不停催出戶。", "正抱琵琶穩繫絛，輥作輕雷攏作雨。", "自解彈成啄木聲，豈唯能寫胡人語。", "醉眼流波入鬢時，絃慢邀郎緊絃柱。", "身柔柱澀郎力微，欲倩傍人頻顧主。", "主何磊落風味多，就請上賓無不許。", "相疎情遠誰稱渠，畫撥當胸客當去。"]'),
('452b8f8a-4b3a-4168-83d5-f3c19e4e3708','擬詠懷','梅堯臣','宋','宋诗','song-poetry','','[]','西北有龍淵，東南有天池。',72,'全唐诗/poet.song.14000.json','["西北有龍淵，東南有天池。", "天池鳥名鵬，昔在北溟嬉。", "龍能安故淵，變化不可知。", "豈效彼運徒，翼如浮雲垂。", "荒淫啟朱宮，道德處茅茨。", "何爲後世士，常以尼父悲。"]'),
('f546a513-60b1-4053-9a3b-cb859fd9363f','八月三日詠原甫庭前林檎花','梅堯臣','宋','宋诗','song-poetry','','[]','秋蠹無完葉，疎叢有瘁莖。',48,'全唐诗/poet.song.14000.json','["秋蠹無完葉，疎叢有瘁莖。", "偶來庭樹下，重看露葩榮。", "衆自守常理，獨開偏見情。", "從今數霜月，結子尚能成。"]'),
('114fcdfd-dff4-42a6-a1e2-6df4ac4ed70a','送河陽通判張寺丞從富公辟','梅堯臣','宋','宋诗','song-poetry','','[]','張公愛神鍔，佩服近玉麟。',60,'全唐诗/poet.song.14000.json','["張公愛神鍔，佩服近玉麟。", "又拭華陰土，光彩一以新。", "百里無惡獸，千里無冤人。", "今朝欲何之，去去延平津。", "應當出匣飛，騰波决秋旻。"]'),
('5c8cf646-bd0b-4fa8-89a1-ae37c48c0ce6','送淮南轉運李學士君錫','梅堯臣','宋','宋诗','song-poetry','','[]','王都重兵廩，命使總八方。',192,'全唐诗/poet.song.14000.json','["王都重兵廩，命使總八方。", "淮南舟車衝，三楚籠利長。", "惟時有才彥，數計等桑羊。", "八月賜詔行，朱斾插大航。", "汴湍入秋漲，東鼓下鏜鏜。", "今日發大梁，明朝過睢陽。", "睢陽授經地，父老認道旁。", "同業八十人，或貴或爲郎。", "先生歿大官，弟子無荷囊。", "乃知詩書傳，要在明三綱。", "隋末聞仲淹，來學去佐唐。", "唐初稱名臣，鮮及杜與房。", "親見慕義人，專門起輝光。", "我聞房杜流，已顯惟王張。", "雲漢幾萬里，星宇爭耀芒。", "歸來立螭頭，莫愛魚稻鄉。"]'),
('8801a796-1f64-4cf2-ae3f-bd7cc9f7291b','重送楊明叔','梅堯臣','宋','宋诗','song-poetry','','[]','君將會稽去，舊蹟可以嬉。',252,'全唐诗/poet.song.14000.json','["君將會稽去，舊蹟可以嬉。", "予因狀其美，贈子臨路岐。", "子不以爲樂，但願有以規。", "噫吾豈無說，畏子未及裨。", "既求不語子，吾曷忍子欺。", "前年子渡淮，夜泊洪澤湄。", "有鬼稱使者，來告風波期。", "子時再拜謝，乃被鄰船嗤。", "逡巡鬼復至，復附船家兒。", "怒彼慢嗤士，明當使驚危。", "船兒傍舷迴，走若一足夔。", "翌日各解舟，出浦風動旗。", "子獨乘安流，彼受橫浪吹。", "此事非子傳，焉得他人知。", "昨逢令弟藴，備述果不疑。", "越俗素重鬼，慎勿啟其私。", "子口有仁義，子腹有書詩。", "子嘗談王道，怪語固未宜。", "近聞蘇才翁，問子辟者誰。", "得非外戚侯，子怒已豎眉。", "今我儻得罪，甘與蘇同之。"]'),
('341f9714-3a43-40ef-b0d6-e881b678b1c1','送董傳秀才之汝陰','梅堯臣','宋','宋诗','song-poetry','','[]','社燕已歸盡，秋鶑猶繞林。',48,'全唐诗/poet.song.14000.json','["社燕已歸盡，秋鶑猶繞林。", "久爲梁國客，不起灞陵心。", "徒步赴朋館，遠遊無橐金。", "江君丈人意，莫入楚鄉深。"]'),
('c8e55b42-4995-45c4-a270-18ebad3bca09','送張子野屯田知渝州','梅堯臣','宋','宋诗','song-poetry','','[]','舊居苕溪上，久客咸陽東。',72,'全唐诗/poet.song.14000.json','["舊居苕溪上，久客咸陽東。", "歸來得虎符，馳馬向巴中。", "歌將聽巴人，舞欲教渝童。", "况嘗善秦聲，樂彼渝人風。", "忠州白使君，竹枝辭頗工。", "行當繼其美，貢葛勿怱怱。"]'),
('41f60332-867b-4925-b66d-e010f90640fb','送楊子充知資陽縣','梅堯臣','宋','宋诗','song-poetry','','[]','家近古臨邛，聞多木蘭樹。',96,'全唐诗/poet.song.14000.json','["家近古臨邛，聞多木蘭樹。", "其人襲芳馨，乃有相如賦。", "成名三十年，始見列鴛鷺。", "出爲資陽長，秋鬢已點素。", "天子愛黔黎，歸與蜀民諭。", "當時同洛陽，過半作丘墓。", "屈指今所存，無如君最故。", "唯酒可餞行，不飲車空駐。"]'),
('919626ad-58eb-4cc1-8a4c-6ef4f9b89bbc','送司馬學士君實通判鄆州','梅堯臣','宋','宋诗','song-poetry','','[]','君家世典史，君復續祖爲。',108,'全唐诗/poet.song.14000.json','["君家世典史，君復續祖爲。", "蘭臺未成書，汶陽從已知。", "將行我何贈，一誦溪堂詩。", "聞彼多蒲魚，可助鼎與巵。", "在昔阮嗣宗，初赴東平時。", "醉扶乘蹇馿，圖畫猶可披。", "今見國門外，徒馭不驅馳。", "十里馬一歇，五里車一脂。", "不得同雁羣，相送過寒陂。"]'),
('20ccab5a-c168-4c7b-888a-58c8f3d77a9a','送陳殿丞知韶州','梅堯臣','宋','宋诗','song-poetry','','[]','韶州使君行，請問韶石名。',72,'全唐诗/poet.song.14000.json','["韶州使君行，請問韶石名。", "傳聞古帝舜，石上奏九成。", "鳳皇爲之下，朱鳥不復鳴。", "舊祠亡玉琯，四序安得平。", "至今南方熱，臘月裘服輕。", "事外共廢酒，曲江風物清。"]'),
('7f3934f7-414c-40a8-88bd-8c54d66501c9','寄岳州孫屯田','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','從來洞庭好，都在岳陽樓。',48,'全唐诗/poet.song.14000.json','["從來洞庭好，都在岳陽樓。", "明月一千里，寒光三萬秋。", "年華有時盡，風物不知休。", "太守憐予句，應如沈隠侯。"]'),
('574a7b5a-20ae-424f-b24a-f019f8d91d3b','大愚','梅堯臣','宋','宋诗','song-poetry','','[]','大愚不量能，品藻輒己出。',60,'全唐诗/poet.song.14000.json','["大愚不量能，品藻輒己出。", "朝以軻爲同，暮以丘爲匹。", "其人豈鷹雀，鳩鴿化五日。", "指鹿危二世，師歆造新室。", "雖云詐力尚，終自殞斧鑕。"]'),
('d662d73e-bedc-4067-b638-1162cf0d4ecf','送邵不疑謫邵武','梅堯臣','宋','宋诗','song-poetry','','[]','不嗟遷謫遠，所惜去非遲。',48,'全唐诗/poet.song.14000.json','["不嗟遷謫遠，所惜去非遲。", "國法何嘗重，君恩亦已慈。", "飛鴻因雨急，寒葉未霜危。", "江上多新釀，青帘亞竹籬。"]'),
('559403fc-aec8-4bd9-bb31-ad0200bad0f0','送孫應之推官赴鄆州','梅堯臣','宋','宋诗','song-poetry','','[]','重別心意衰，輕別心意壯。',48,'全唐诗/poet.song.14000.json','["重別心意衰，輕別心意壯。", "行車將漸遥，依依獨長望。", "晚風生微寒，脫葉飛汶上。", "何當發談笑，把酒半鬰盎。"]'),
('35e77653-dd4b-43aa-b367-874412849505','寧陵阻風雨寄都下親舊','梅堯臣','宋','宋诗','song-poetry','','[]','晝夜風不止，寒樹嚎未休。',288,'全唐诗/poet.song.14000.json','["晝夜風不止，寒樹嚎未休。", "人言雨殺風，雨急風未柔。", "獨扶慈母喪，淚與河水流。", "河水有冬竭，淚泉長在眸。", "予生五十二，再解官居憂。", "昨者母疾亟，骨肉相聚愁。", "橐中無一錢，緩急何可求。", "母當臨終時，囑我貧莫羞。", "隨宜具棺斂，厚貸壓人頭。", "死事定無益，生償且無由。", "泣涕聽母言，心腸如剜鉤。", "小子雖不令，長養恩曷酬。", "旦夕期速平，後事勿預謀。", "願母强藥食，更延百千秋。", "固云莫望我，我魂已飛遊。", "語畢忽奄逝，撫膺呼裂喉。", "未能一物備，迷亂將安投。", "艱窘見風義，乃有令朋儔。", "致賻或錢帛，最力李與劉。", "禁省及石渠，奠助日不周。", "裴楊乞銘蓋，文篆古復遒。", "潭饒兩大艦，朝索暮泛浮。", "哀憐荷君子，才德慙未脩。", "三日違大梁，兩宿此遲留。"]'),
('85403a95-efad-430b-ba1e-977d9407aaf4','新霜感','梅堯臣','宋','宋诗','song-poetry','','[]','前日衣上露，今日衣上霜。',120,'全唐诗/poet.song.14000.json','["前日衣上露，今日衣上霜。", "我母魂何之，膏火麋我腸。", "隔棺三寸地，如在萬里鄉。", "嚎呼不聞聲，飲食空置傍。", "昔時憂我寒，縫衣紉線長。", "線長必絮厚，要與風霜當。", "又每恐我饑，羹臛自調嘗。", "此身內外間，莫得頃刻忘。", "舉衣不忍著，舉筯不下吭。", "一念百感生，欲問天蒼蒼。"]'),
('0ffcb223-d70a-42fa-9c17-c8b2a9d3d415','過淮','梅堯臣','宋','宋诗','song-poetry','','[]','侍親數數來浮汴，護櫬迢迢復渡淮。',64,'全唐诗/poet.song.14000.json','["侍親數數來浮汴，護櫬迢迢復渡淮。", "旨蓄曾無御寒具，細君唯有隠居釵。", "月銜遠入魚銜浪，潮退長汀蚌閣崖。", "素服華顛色相似，青銅不忍見形骸。"]'),
('03cd2f84-ab05-4113-bfce-bdfb14f46691','淮陰','梅堯臣','宋','宋诗','song-poetry','','[]','天下滔滔久厭秦，英雄蛇鼠竄荆榛。',32,'全唐诗/poet.song.14000.json','["天下滔滔久厭秦，英雄蛇鼠竄荆榛。", "少年豪橫知多少，不及沙頭一婦人。"]'),
('a09647e2-d249-4ad8-8f82-b8f7c90e7ff9','桫欏樹','梅堯臣','宋','宋诗','song-poetry','','[]','桫欏古樹常占歲，在昔曾看北海碑。',32,'全唐诗/poet.song.14000.json','["桫欏古樹常占歲，在昔曾看北海碑。", "今日四方俱大稔，不知榮悴向何枝。"]'),
('aff07843-edbf-49af-85ad-423f4287fdcc','就野人買兔','梅堯臣','宋','宋诗','song-poetry','','[]','霜濃草白兔初肥，蒼鶻調拳獵犬携。',32,'全唐诗/poet.song.14000.json','["霜濃草白兔初肥，蒼鶻調拳獵犬携。", "剩付錢刀買庖餗，不須緣徑更求蹄。"]'),
('fb1299b7-ee59-4d63-84e1-31e672850fab','使風船','梅堯臣','宋','宋诗','song-poetry','','[]','清淮直上水連天，坐看高帆後復前。',32,'全唐诗/poet.song.14000.json','["清淮直上水連天，坐看高帆後復前。", "自是乘風有遲速，不由人力愛爭先。"]'),
('7d4028b0-6ee8-4175-8498-15fe057e6637','淮陰侯廟','梅堯臣','宋','宋诗','song-poetry','','[]','韓信未遇時，忍饑坐垂釣。',132,'全唐诗/poet.song.14000.json','["韓信未遇時，忍饑坐垂釣。", "歸來淮陰市，又復逢惡少。", "使之出胯下，一市皆大笑。", "龍蛇忽雲騰，蛭螾豈能料。", "亡命乃爲將，出奇還破趙。", "用兵不患多，所向孰敢摽。", "功名塞天地，翦刈等蒿藋。", "於今千百年，水上見孤廟。", "鷺銜葭下魚，相呼尚鳴叫。", "高皇四海平，有酒不共釂。", "古來稱英雄，去就可以照。"]'),
('e1980064-41dc-4be8-a5d3-030aab4103d2','又平律一首','梅堯臣','宋','宋诗','song-poetry','','[]','漢家天下將，廟古像公圭。',48,'全唐诗/poet.song.14000.json','["漢家天下將，廟古像公圭。", "百戰自忘楚，一時空王齊。", "鄉人奏簫鼓，舟子賽豚雞。", "不改寒潮水，朝平暮復低。"]'),
('852690c1-60c5-46aa-b366-95ab246f6ee2','入滿浦','梅堯臣','宋','宋诗','song-poetry','','[]','馬頭攙岸斗，燕尾泊船齊。',48,'全唐诗/poet.song.14000.json','["馬頭攙岸斗，燕尾泊船齊。", "風送寒潮急，雲藏晚日低。", "逢人多楚語，問客煑吳雞。", "難覓枚臯宅，倉葭處處迷。"]'),
('9b45e6a8-d601-403e-8554-05e9bf298fdc','許發運待制見過夜話','梅堯臣','宋','宋诗','song-poetry','','[]','許公運國儲，歲入六百萬。',180,'全唐诗/poet.song.14000.json','["許公運國儲，歲入六百萬。", "上莫究所來，下莫有剝怨。", "十年無纖乏，功利潛亦建。", "昨除侍從官，聊爲磨世鈍。", "比於以舌得，此豈愧物論。", "較量多少間，未足數劉晏。", "大計苟窘費，曷不使預筭。", "欲倍即能倍，但勿惑謗訕。", "擾民可以奪，食官可以竄。", "要付與權衡，一切出果斷。", "嗚呼任智力，長短固有限。", "制財猶制兵，太甚則生亂。", "公譬淮陰侯，多多有益辦。", "我今聽其談，夜去爲扼腕。", "書之俟采詩，咨訪不可緩。"]'),
('4d66d0af-beee-465a-9428-c76ad6bde6d1','登泰山日觀峯','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','晨登日觀峯，海水黄金鎔。',84,'全唐诗/poet.song.14000.json','["晨登日觀峯，海水黄金鎔。", "浴出車輪光，隨天行無蹤。", "正視刺我目，攢集如劍鋒。", "照曜萬物興，磨滅萬物凶。", "草木既無命，必聞石間松。", "當時一避雨，安得大夫封。", "人而苟不遇，抱簡誦六龍。"]'),
('6b2b041c-3d6c-4b27-962d-2d585061d098','重過瓜步山','梅堯臣','宋','宋诗','song-poetry','','[]','魏武敗忘歸，孤軍處山頂。',144,'全唐诗/poet.song.14000.json','["魏武敗忘歸，孤軍處山頂。", "雖鄰江上浦，鑿巖山巔井。", "豈是欲勞兵，防患在萌穎。", "我昔常登臨，徘徊愛晴景。", "片雨西北來，風雷變俄頃。", "疾行下危磴，屨脫不及整。", "霑濡入舟中，幼子喜抱頸。", "問我適何之，衣濕不太冷。", "昨暮泊其陽，月黑夜正永。", "雁從沙際鳴，旅枕自耿耿。", "平明夾櫓去，廟樹聳寒嶺。", "舉首生白雲，飄摇水中影。"]'),
('18d8e981-6e3d-4c82-be70-373c8ea88293','發長蘆江口','梅堯臣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','篙師柂工相整衣，龍女廟中來宰豨。',64,'全唐诗/poet.song.14000.json','["篙師柂工相整衣，龍女廟中來宰豨。", "野祝擊鼓降神語，老鴉銜肉上樹飛。", "長江無風平似削，兩櫓夾舸行將歸。", "南國山川都不改，傷心慈姥舊時磯。"]'),
('034d0718-6f45-4ec3-8487-d28be299a2e3','龍女祠祈順風','梅堯臣','宋','宋诗','song-poetry','','[]','龍母龍相依，風雲隨所變。',68,'全唐诗/poet.song.14000.json','["龍母龍相依，風雲隨所變。", "舟人請予往，出廟旗脚轉。", "旗指西南歸，飛帆疾流電。", "長蘆江口發平明，白鷺洲前已朝膳。", "竹根杯珓不欺人，世間然諾空當面。"]'),
('260483e9-161c-41a9-a88d-074b814bbaba','西施','梅堯臣','宋','宋诗','song-poetry','','[]','濺濺溪流散，苒苒石髮開。',84,'全唐诗/poet.song.14000.json','["濺濺溪流散，苒苒石髮開。", "一朝辭浣沙，去上姑蘇臺。", "歌舞學未穩，越兵俄已來。", "門上子胥目，吳人豈不哀。", "層宮有麋鹿，朱顔爲土灰。", "水邊同時伴，貧賤猶摘梅。", "食梅莫厭酸，禍福不我猜。"]'),
('0c5408e9-80b3-4b84-b0aa-88235e1018bb','金陵三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','恃險不能久，六朝今已亡。',48,'全唐诗/poet.song.14000.json','["恃險不能久，六朝今已亡。", "山形象龍虎，宮地牧牛羊。", "江上鷗無數，城中草自長。", "臨流邀月飲，莫挂一毫芒。"]'),
('bc175b3f-0362-43fa-8524-3e6ac22fbf1c','金陵三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','金陵逢曉雪，撩亂逗雲來。',48,'全唐诗/poet.song.14000.json','["金陵逢曉雪，撩亂逗雲來。", "已失烏衣巷，還成白玉臺。", "山盤猶隠見，江轉似昭回。", "一聽高樓笛，依稀認落梅。"]'),
('2d0b7358-9de2-4270-b77c-a36f671aeb94','金陵三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','每入秦淮口，風波更不憂。',48,'全唐诗/poet.song.14000.json','["每入秦淮口，風波更不憂。", "重看後庭樹，還起舊時愁。", "故老都無有，遺蹤莫可求。", "何人能識意，白鷺在寒洲。"]'),
('632a5cd2-b5d8-4d14-9f56-e51f6df9a361','丫頭石','梅堯臣','宋','宋诗','song-poetry','','[]','丫頭石雖斷，文字未全訛。',48,'全唐诗/poet.song.14000.json','["丫頭石雖斷，文字未全訛。", "年筭赤烏近，書疑黄象多。", "幾時經霹靂，異代見干戈。", "更與千秋看，松煤定費摩。"]'),
('19f5b140-160c-483f-90cf-88f58415a19b','漫書','梅堯臣','宋','宋诗','song-poetry','','[]','蒲葵兩錢扇，漫寫未嫌輕。',24,'全唐诗/poet.song.14000.json','["蒲葵兩錢扇，漫寫未嫌輕。", "老媼持將去，無端色不平。"]'),
('1e39fb7e-d1b7-47d9-91c4-e2ec9e85813a','閔冢','梅堯臣','宋','宋诗','song-poetry','','[]','盜發廣陵冢，及扉開石樞。',132,'全唐诗/poet.song.14000.json','["盜發廣陵冢，及扉開石樞。", "中環走徹道，高闊可通車。", "五尺銅鑄人，執兵冠服朱。", "壁石刻位號，列侍幽宮隅。", "殿將將軍屬，侍郎常侍俱。", "啟棺見其尸，鬢斑顔未渝。", "白璧十雙藉，雲母一尺鋪。", "黄金塞耳鼻，千歲不腐枯。", "生爲貴與富，死與人未殊。", "後世逢暴禍，雖久將焉如。", "堯舜及周孔，豈不固形軀。"]'),
('8e45a859-6b3f-4dea-a190-cbe6b60846fd','雪中發江寧浦至采石','梅堯臣','宋','宋诗','song-poetry','','[]','泊舟斫枯葭，歊火爇岸傍。',120,'全唐诗/poet.song.14000.json','["泊舟斫枯葭，歊火爇岸傍。", "冒嶺雲冥濛，漫江雪飛揚。", "拖冰脩網澀，出水朱鬐殭。", "曠然起遠懷，風旗轉危檣。", "千帆共辭浦，攙錯逆水翔。", "落星始前瞻，瞬目已後相。", "鮆魚何時來，楊花吹茫茫。", "沙草不可辨，雁立知汀長。", "山頭化石婦，忽變素質光。", "豈復願聞笛，莫逢桓野王。"]'),
('d403945b-dc8e-4717-b56d-59a1daa813dd','登采石山上廣濟寺','梅堯臣','宋','宋诗','song-poetry','','[]','船從山下過，直上見僧軒。',48,'全唐诗/poet.song.14000.json','["船從山下過，直上見僧軒。", "繫纜當磯石，緣崖到寺門。", "短籬遮竹瀁，危路踏松根。", "却看滄江底，帆歸煙外昏。"]'),
('e78670bc-c973-42ff-a68c-80828a3a24e0','效阮步兵一日復一日  其一','梅堯臣','宋','宋诗','song-poetry','','[]','一日復一日，一朝復一昏。',72,'全唐诗/poet.song.14000.json','["一日復一日，一朝復一昏。", "來新去成故，俯仰變凉溫。", "有貴則有賤，未若賤常存。", "騂牛慕孤㹠，黄犬悲東門。", "禍福相爲基，損益不復言。", "吾祖入吳市，應龍非伏轅。"]'),
('825bbab0-41de-48f3-8dc6-3d8a5f34baa8','效阮步兵一日復一日  其二','梅堯臣','宋','宋诗','song-poetry','','[]','一日復一日，一晨復一夕。',84,'全唐诗/poet.song.14000.json','["一日復一日，一晨復一夕。", "四序相盛衰，三辰運光魄。", "下上有常理，憂患何時易。", "先爛泣金燃，先焚歎薪積。", "但願遠世網，焚爛不能責。", "麒麟出非時，未免西狩獲。", "鷗鳥浮洪波，心已預海客。"]'),
('62f0ced0-67e5-46dc-9792-41d91bb39b87','阻風宿大信口','梅堯臣','宋','宋诗','song-poetry','','[]','東梁如印蠶，西梁如游魚。',168,'全唐诗/poet.song.14000.json','["東梁如印蠶，西梁如游魚。", "二山夾大江，早暮潮吸噓。", "解舟辭姑熟，速欲還吾廬。", "風逆未可前，泊浦近煙墟。", "波中事網罟，乘月多夜挐。", "冰灘聚鳴雁，霜葭正疎疎。", "是時昴畢中，曠渺天地虛。", "靜坐人已眠，我慮久洗如。", "自起取美酒，獨酌邀蟾蜍。", "蟾蜍射白光，入盞亦躊躕。", "醉來不解舞，欲攬常娥袪。", "昔對謫仙人，此意復在予。", "既醒裂尺素，立作數行書。", "寄與青山冢，精靈其有諸。"]'),
('0f78c212-e0bf-4218-980b-9cc36cf1cbe2','早發大信口','梅堯臣','宋','宋诗','song-poetry','','[]','犬吠知船解，村墟尚閉門。',48,'全唐诗/poet.song.14000.json','["犬吠知船解，村墟尚閉門。", "霜泥黏纜尾，冰水閣潮痕。", "撇撇鸊鵜去，纖纖舴艋昏。", "梅湖到不遠，寄信向田園。"]'),
('28bc3f72-b60a-4f14-b33c-fd4685653d86','黄池月中共酌得池字','梅堯臣','宋','宋诗','song-poetry','','[]','將歸謝公郡，喜見阮家兒。',48,'全唐诗/poet.song.14000.json','["將歸謝公郡，喜見阮家兒。", "但對月和水，那能酒似池。", "衰形疑鏡照，葆鬢怯霜吹。", "宿雁不堪託，鄉人知未知。"]'),
('8450b774-4969-4cef-83e2-be98e4bda1bd','泊昭亭山下得亭字','梅堯臣','宋','宋诗','song-poetry','','[]','雪中峯午午，潭上樹亭亭。',48,'全唐诗/poet.song.14000.json','["雪中峯午午，潭上樹亭亭。", "久作大梁客，貧留小阮醒。", "灘愁江舸澀，祠信楚巫靈。", "日暮渡頭立，山歌不可聽。"]'),
('4fa5af71-4d31-4e50-88e2-746d05496c68','送鹽官劉少府古賢','梅堯臣','宋','宋诗','song-poetry','','[]','我祖南昌尉，時危棄去仙。',48,'全唐诗/poet.song.14000.json','["我祖南昌尉，時危棄去仙。", "劉郎從宦日，天子治平年。", "燥茗山中火，熬波海上煙。", "吳民不爲盜，唯此撓君權。"]'),
('267c05e7-f61f-4b6e-ac0f-2014ece8afc5','太師杜相公篇章真草過人遠甚而特奬後進流於詠言輒依韻和','梅堯臣','宋','宋诗','song-poetry','','[]','杜詩嘗說少陵豪，祖德兼誇翰墨高。',64,'全唐诗/poet.song.14000.json','["杜詩嘗說少陵豪，祖德兼誇翰墨高。", "蘇李爲奴令侍席，鍾王北面使持毫。", "郊麟作瑞唯逢趾，天馬能行不辨毛。", "一誦東山零雨句，無心更學楚離騷。"]'),
('e49b7853-bf2f-409e-ab69-27f7af5fd601','依韻和簽判都官昭亭謝雨迴廣教見懷','梅堯臣','宋','宋诗','song-poetry','','[]','賽雨何從事，高情苦愛山。',48,'全唐诗/poet.song.14000.json','["賽雨何從事，高情苦愛山。", "謝公聯句後，惠遠過溪間。", "笑處巖相答，歸時酒在顔。", "端憂守窮巷，無力共躋攀。"]'),
('1f543c8a-3852-406e-bf5b-f6bd70e05bc9','依韻和吳正仲屯田重臺梅花詩','梅堯臣','宋','宋诗','song-poetry','','[]','桃花已滿秦人洞，杏樹猶存董奉祠。',32,'全唐诗/poet.song.14000.json','["桃花已滿秦人洞，杏樹猶存董奉祠。", "莫怪寒梅獨多葉，只緣樂府有新詩。"]'),
('83779494-f231-4b1e-a6ab-4046d9a8896c','讀吳正仲重臺梅花詩','梅堯臣','宋','宋诗','song-poetry','','[]','楚梅何多葉，縹蔕攢瓊瑰。',72,'全唐诗/poet.song.14000.json','["楚梅何多葉，縹蔕攢瓊瑰。", "常惜歲景盡，每先春風開。", "龍沙雪爲友，青女霜作媒。", "託根邇廟堂，結子助鼎鼒。", "吳侯本吳人，筆力高崔嵬。", "但詠同姓木，予非梁棟材。"]'),
('7447f770-4f10-4935-a05b-9aa3e2408ff1','依韻和正仲重臺梅花','梅堯臣','宋','宋诗','song-poetry','','[]','芳梅何蒨蒨，素葉吐層層。',192,'全唐诗/poet.song.14000.json','["芳梅何蒨蒨，素葉吐層層。", "近臘寒猶勁，先春氣已承。", "冷香傳去遠，靜豔密還增。", "有意常欺雪，無功合鏤冰。", "早煙籠玉暖，凍雨浴脂凝。", "漢女新粧薄，燕姬瘦骨稜。", "壓枝唯恐折，簇萼似難勝。", "神物終來護，江鄉未解矜。", "獨奇心豈欲，寄遠客何曾。", "不見黄鸝度，寧防粉蝶凌。", "月光臨更好，谿水照偏能。", "畫軸開雲霧，宮刀翦綵繒。", "都無筆可衒，莫信巧堪憑。", "丹杏塵多雜，夭桃俗所稱。", "故林嘗渴望，大庾更愁登。", "重和陽春曲，聲辭猥媿仍。"]'),
('b6120698-6944-498f-81db-058db1a0b9b0','正仲見贈依韻和答','梅堯臣','宋','宋诗','song-poetry','','[]','平生好書詩，一意在抱槧。',240,'全唐诗/poet.song.14000.json','["平生好書詩，一意在抱槧。", "既無鈌雲劍，身世遭黮黭。", "恥游公相門，甘自守恬淡。", "妻孥每寒饑，內愧劇剜憯。", "時頼二三友，乞米慰窮慘。", "雖然情懷惡，亦未廢誦覽。", "如負會稽辱，欲雪效嘗膽。", "作文持與人，百不得一頷。", "聖猶嗜好殊，獨取菖蒲歜。", "我愚希六義，將使鬼神感。", "譬彼捕長黥，區區只持窨。", "青天挂虹霓，踴跂不可擥。", "太華五千仞，妄學巨靈撼。", "幸且同蛙黽，近樂在井坎。", "蒼髮况種種，存非衛髦髧。", "吳侯琅玕姿，而來視亂菼。", "鳳皇五色毛，曷羨未翅蝻。", "染夏有正采，安用此淺黲。", "乃知叔度陂，萬頃見澄澹。", "孟軻患爲師，薄劣亦何敢。"]'),
('a6e5adcd-6cf4-4b05-9761-8dacbeccc994','正仲往靈濟廟觀重臺梅','梅堯臣','宋','宋诗','song-poetry','','[]','玉盤疊捧溪女歸，魚鱗作室待水婓。',80,'全唐诗/poet.song.14000.json','["玉盤疊捧溪女歸，魚鱗作室待水婓。", "竹間山鬼入夜啼，古廟久閉誰啟扉。", "屈原憔悴江之圻，芙蓉木蘭託興微。", "賈誼未召絳灌擠，香草嘉禾徒菲菲。", "曾無半辭助訶譏，國風幸頼相因依。"]'),
('c6167cd0-e978-45c5-b63c-06e17bbc0a3e','依韻和昭亭山廣教院文鑑大士喜予往還','梅堯臣','宋','宋诗','song-poetry','','[]','山暖春煙重，林昏古寺藏。',96,'全唐诗/poet.song.14000.json','["山暖春煙重，林昏古寺藏。", "谿流過曉漲，嶺樹見新行。", "馬去侵雲蹟，風來襲野芳。", "禪衣頻斗藪，蠟屐莫趨蹌。", "飛鼠時過擲，饑禽或下頏。", "憑欄何所適，望堞正相當。", "捧膳溪童絜，銜花鹿女香。", "登臨無險絕，不似畏巖牆。"]'),
('b4c10ec0-cb84-44ad-8c6d-661816af364b','依韻答達觀禪師穎公','梅堯臣','宋','宋诗','song-poetry','','[]','霜露每懷感，江山空復情。',48,'全唐诗/poet.song.14000.json','["霜露每懷感，江山空復情。", "老便林室靜，坐厭巷童聲。", "盡日都無語，逢人亦强迎。", "浮生過半百，安用此虛名。"]'),
('5c42e813-fd0e-4929-a1ab-37478424d99a','題姑蘇邵氏園居','梅堯臣','宋','宋诗','song-poetry','','[]','積水夫差國，閒居魯叟心。',48,'全唐诗/poet.song.14000.json','["積水夫差國，閒居魯叟心。", "石科雲起潤，城角竹連陰。", "燕入池塘晚，花開島嶼深。", "應當效疏傅，不惜橐中金。"]'),
('8e42afe9-e616-42bd-8cde-7175151a29bc','嘗正仲所遺撥醅','梅堯臣','宋','宋诗','song-poetry','','[]','屈原自著漁父篇，餔糟不及漁父賢。',112,'全唐诗/poet.song.14000.json','["屈原自著漁父篇，餔糟不及漁父賢。", "世無功名多浪死，劉伶阮籍于今傳。", "邇來獨酌邀明月，唯有青山李謫仙。", "謫仙歿後幾百年，市樓日沽千萬錢。", "沉湎豈少當道眠，文字不見空月圓。", "吳均之孫何我憐，雙壺貯醅持置前。", "豈乏阮李詩與瘨，淺飲强對春風妍。"]'),
('a25b2c7f-8c1d-494b-b762-333f501bda4b','依韻和正仲寄酒因戲之','梅堯臣','宋','宋诗','song-poetry','','[]','上字黄封誰可識，偷傳王氏法應真。',64,'全唐诗/poet.song.14000.json','["上字黄封誰可識，偷傳王氏法應真。", "清淮始變醅猶薄，句水新來味更醇。", "欲擬比酥酥少色，曾持勸客客何人。", "紅梅雖是吾家物，老去無心一醉春。"]'),
('ed9575a6-1937-4e4e-bb9e-86a05081f5cb','春雨','梅堯臣','宋','宋诗','song-poetry','','[]','春雨𩅨𩅨鳴百舌，林花淡淡洗燕脂。',32,'全唐诗/poet.song.14000.json','["春雨𩅨𩅨鳴百舌，林花淡淡洗燕脂。", "眼前耳底催人殺，不醉三杯大是癡。"]'),
('29980e1b-c36f-45b2-adca-c1225905df4f','春夜聞雨','梅堯臣','宋','宋诗','song-poetry','','[]','風味正不寢，驟來寒氣增。',48,'全唐诗/poet.song.14000.json','["風味正不寢，驟來寒氣增。", "簷斜滴野籜，窗缺摇春燈。", "孺子睡中語，歸人行未能。", "前溪波暗長，定已沒灘稜。"]'),
('58f8917b-18f0-4ef9-96e0-afc57b415984','早春田行','梅堯臣','宋','宋诗','song-poetry','','[]','風雪雙羊路，梅花溪上村。',48,'全唐诗/poet.song.14000.json','["風雪雙羊路，梅花溪上村。", "鳥呼知木暖，雲濕覺山昏。", "婦子來陂下，囊壺置樹根。", "予非陶靖節，老去愛田園。"]'),
('538db647-908c-4d6a-ba9e-f55a097674ae','依韻和馬都官春日憶西湖寄陸生','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','時望前湖倚玉梯，雲山橫絕路東西。',64,'全唐诗/poet.song.14000.json','["時望前湖倚玉梯，雲山橫絕路東西。", "只知遠目窮芳草，不見高人在曲隄。", "畫榼尋春應醉去，舊朋懷昔欲魂迷。", "海邊燕子來無數，願託雙飛寄短題。"]'),
('ea0e33c2-7fb5-4265-a297-2b968b675fdf','送志來上人往姑蘇謁元曹','梅堯臣','宋','宋诗','song-poetry','','[]','折取東橋柳，青青向故人。',48,'全唐诗/poet.song.14000.json','["折取東橋柳，青青向故人。", "欲知問館處，要識舊溪春。", "旋洒銅缾水，休霑野寺塵。", "吳門逢隠者，必是漢名臣。"]'),
('741f4751-1acf-4e39-9bcb-9ad62f8c68fc','溫成皇后挽詞','梅堯臣','宋','宋诗','song-poetry','','[]','鞏洛園陵啟，函關鹵部聞。',48,'全唐诗/poet.song.14000.json','["鞏洛園陵啟，函關鹵部聞。", "素車迎紫氣，靈襪度青雲。", "歌欲傳長恨，人將問少君。", "明年賀元日，無復繡衣薰。"]'),
('fb370b36-0907-49d1-aa05-a61c4ed4d293','和真上人萬松亭虎窺泉','梅堯臣','宋','宋诗','song-poetry','','[]','南岡新路平，東嶺新亭成。',96,'全唐诗/poet.song.14000.json','["南岡新路平，東嶺新亭成。", "嶺上松萬株，嶺下泉一泓。", "松未龍鱗老，泉曾虎跡行。", "虎去豈不渴，松今豈不生。", "泉無百尺繩，安見甘與清。", "松無百歲人，安見千丈榮。", "道人能喻道，莫使世人驚。", "我來開醉眼，不似阮步兵。"]'),
('a3bb0dcb-9150-455e-a3de-7012479f12c5','種碧映山紅於新墳','梅堯臣','宋','宋诗','song-poetry','','[]','年年杜鵑啼，口滴枝上赤。',36,'全唐诗/poet.song.14000.json','["年年杜鵑啼，口滴枝上赤。", "今同萇弘血，三歲化爲碧。", "因移新冢傍，顔色照松柏。"]'),
('1b292416-4b5c-40ab-85e7-0241a0cae596','邵郎中姑蘇園亭','梅堯臣','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','公愛樂天池上篇，買池十畝皆種蓮。',160,'全唐诗/poet.song.14000.json','["公愛樂天池上篇，買池十畝皆種蓮。", "薄城萬竿竹㛹娟，藤纜繫橋青板船。", "折腰大菱不直錢，鵁鶄鸂鶒沙際眠。", "水從太湖根底穿，月出洞庭山上圓。", "公歸與客相留連，秋風鶴唳春杜鵑。", "班鱸斫膾紅縷鮮，紫豉煑蒓香味全。", "我思白傅在三川，吳船雖有吳饌偏。", "當時九老各華顛，裴令來過吟復聯。", "至今怪石存舊鎸，七葉樹蔭黄金田。", "羨公有子勝昔賢，高門通車千萬年。"]'),
('7ee5a35e-cfe0-449a-a0b1-deb883555a7d','與正仲屯田遊廣教寺','梅堯臣','宋','宋诗','song-poetry','','[]','春灘尚可涉，不惜濺衣裾。',48,'全唐诗/poet.song.14000.json','["春灘尚可涉，不惜濺衣裾。", "古寺入深樹，野泉鳴暗渠。", "酒盃參茗具，山蕨間盤蔬。", "落日還城郭，人方带月鋤。"]'),
('99ada568-b428-4607-9347-aabbe2d480ce','哭謝公儀學士','梅堯臣','宋','宋诗','song-poetry','','[]','道路傳聞日，驚嗟尚復疑。',48,'全唐诗/poet.song.14000.json','["道路傳聞日，驚嗟尚復疑。", "疾因勤學得，命不與人期。", "賈誼年傷少，相如恨見遲。", "向來公輔器，看取李家知。"]'),
('f46bbf94-5c34-4742-b00e-4f603f6cfe21','依韻和王介甫兄弟舟次蕪江懷寄吳正仲','梅堯臣','宋','宋诗','song-poetry','','[]','楚客連檣泊晚風，吳人江畔醉無窮。',64,'全唐诗/poet.song.14000.json','["楚客連檣泊晚風，吳人江畔醉無窮。", "少陵失意詩偏老，子厚因遷筆更雄。", "貫口信潮千里至，平沙落日一時紅。", "知君兄弟才名大，我愧白頭遼水東。"]'),
('75790919-1419-484e-af4b-29ffcefe861e','依韻和吳季野馬上口占','梅堯臣','宋','宋诗','song-poetry','','[]','溪頭三月草菲菲，城畔春游惜醉稀。',32,'全唐诗/poet.song.14000.json','["溪頭三月草菲菲，城畔春游惜醉稀。", "莫信杜鵑花上鳥，人歸猶道不如歸。"]'),
('8fd24fbf-8a4d-4e4f-9373-d32c43eb45a0','邵考功遺鮆魚及鮆醤','梅堯臣','宋','宋诗','song-poetry','','[]','已見楊花撲撲飛，鮆魚江上正鮮肥。',32,'全唐诗/poet.song.14000.json','["已見楊花撲撲飛，鮆魚江上正鮮肥。", "早知甘美勝羊酪，錯把蒓羹定是非。"]'),
('7e326443-e937-4fee-843f-db6b2247b938','昨於發運馬御史求海味馬已歸闕吳正仲忽分餉黄魚鱟醤鮆子因成短韻','梅堯臣','宋','宋诗','song-poetry','','[]','前欲淮南求海物，緘書未發報還臺。',32,'全唐诗/poet.song.14000.json','["前欲淮南求海物，緘書未發報還臺。", "陸機黄耳何時至，罌品分傳事按杯。"]'),
('ffc92ad6-b0ba-483b-9508-99b95821fde0','正仲答云鱟醤乃是毛魚耳走筆戲之','梅堯臣','宋','宋诗','song-poetry','','[]','折却毛魚一品資，吳郎聲屈向吾詩。',32,'全唐诗/poet.song.14000.json','["折却毛魚一品資，吳郎聲屈向吾詩。", "若論鮆子無從著，冤氣衝喉未可知。"]'),
('2c0b8ef7-a0c5-4e97-9404-55f94f328a06','春日東齋','梅堯臣','宋','宋诗','song-poetry','','[]','剝剝禽敲竹，薰薰日照花。',48,'全唐诗/poet.song.14000.json','["剝剝禽敲竹，薰薰日照花。", "耳中無俗聽，眼底有閑誇。", "迸筍過幽草，吹香到別家。", "吾懷方自得，切莫問生涯。"]'),
('8d0bb958-e520-4f41-b521-77ce65077e03','吳正仲遺新茶','梅堯臣','宋','宋诗','song-poetry','','[]','十片建溪春，乾雲碾作塵。',48,'全唐诗/poet.song.14000.json','["十片建溪春，乾雲碾作塵。", "天王初受貢，楚客已烹新。", "漏泄關山吏，悲哀草土臣。", "捧之何敢啜，聊跪北堂親。"]'),
('946325cb-3f14-4cb9-9e84-e3064ce7a5e8','閑居','梅堯臣','宋','宋诗','song-poetry','','[]','讀易忘饑倦，東窗盡日開。',48,'全唐诗/poet.song.14000.json','["讀易忘饑倦，東窗盡日開。", "庭花昏自斂，野蝶晝還來。", "謾數過籬笋，遥窺隔葉梅。", "唯愁車馬入，門外起塵埃。"]'),
('cc12c4c6-dfc8-4720-bb68-c94573ea62c6','依韻和季野見招','梅堯臣','宋','宋诗','song-poetry','','[]','悲憂如路去無程，靖節終朝酒自傾。',32,'全唐诗/poet.song.14000.json','["悲憂如路去無程，靖節終朝酒自傾。", "苦苦來招爲醉伴，西山不使伯夷清。"]'),
('4eb1d99f-8700-4b10-9d5e-4f931b1aa11d','依韻馬都官宿縣齋','梅堯臣','宋','宋诗','song-poetry','','[]','常愛陶潛遠世緣，阮家仍有竹㛹娟。',32,'全唐诗/poet.song.14000.json','["常愛陶潛遠世緣，阮家仍有竹㛹娟。", "夜深風撼蕭蕭響，誰憶北窗人正眠。"]'),
('773af2d0-9fc8-4df1-9272-07659af0905a','吳正仲見訪迴日暮必未晚膳因以解嘲','梅堯臣','宋','宋诗','song-poetry','','[]','永日無車馬，閑坊有竹鄰。',48,'全唐诗/poet.song.14000.json','["永日無車馬，閑坊有竹鄰。", "雨中烏帽至，門外綠苔新。", "不殺雞爲具，堪題鳳向人。", "山公識墨在，知我舊來貧。"]'),
('44222856-c46c-4c28-9221-5a6cc448a13a','昭亭潭上別弟','梅堯臣','宋','宋诗','song-poetry','','[]','從來潭上別，先賽故山祠。',48,'全唐诗/poet.song.14000.json','["從來潭上別，先賽故山祠。", "却入舟中飲，無令盞盡遲。", "須拚一日醉，便作數年期。", "落日馬嘶急，岸傍人散時。"]'),
('d4cc854d-008f-4f99-a5ad-177c15e8e2b4','夢後得宋中道書','梅堯臣','宋','宋诗','song-poetry','','[]','宵夢宋子語，晝得宋子書。',132,'全唐诗/poet.song.14000.json','["宵夢宋子語，晝得宋子書。", "書意與夢語，曾不異往初。", "昔我遭家難，逢子亦在廬。", "我南君大梁，千里非隔疎。", "念處天地中，天地猶一車。", "日月爲兩轂，星辰隨徐徐。", "晝夜轉不已，載之將焉如。", "冉冉趨死鄉，萬古曾無餘。", "其間乃有夢，覺實夢何虛。", "何虛亦何實，及盡皆同墟。", "身世既若此，合離休歎諸。"]'),
('58a2b2eb-d7d0-4a5f-bdfb-7d135dfeea73','送吳季野太博移蜀靈泉先至輦','梅堯臣','宋','宋诗','song-poetry','','[]','葦箔蠶齊老，桑林葉更生。',48,'全唐诗/poet.song.14000.json','["葦箔蠶齊老，桑林葉更生。", "楚禽多異響，蜀棧未堪行。", "客散岸傍席，馬還溪上城。", "過都當有問，爲語欲巖耕。"]'),
('d6fc70bf-ad95-40f6-9b07-ca1cd8d02dc6','至和元年四月二十日夜夢蔡紫微君謨同在閣下食櫻桃蔡云與君及此再食矣夢中感而有賦覺而錄之','梅堯臣','宋','宋诗','song-poetry','','[]','朱櫻再食雙盤日，紫禁重頒四月時。',64,'全唐诗/poet.song.14000.json','["朱櫻再食雙盤日，紫禁重頒四月時。", "滉朗天開雲霧閣，依稀身在鳳皇池。", "味兼羊酪何由敵，豉下蒓羹不足宜。", "原廟薦來應已久，黄鶑猶在最深枝。"]'),
('2960d478-f0b0-432f-8e8e-b6171c158630','依韻和吳正仲赤目見寄','梅堯臣','宋','宋诗','song-poetry','','[]','尋常不病眼，青白看人多。',48,'全唐诗/poet.song.14000.json','["尋常不病眼，青白看人多。", "暫見朱成碧，難逢扁與和。", "金篦舊說在，訶子古方磨。", "我自苦風痹，思君那得過。"]'),
('100c463a-f7e3-4d5a-8775-43e50c7345df','雨燕','梅堯臣','宋','宋诗','song-poetry','','[]','雨燕去還來，銜蟲爲雛食。',48,'全唐诗/poet.song.14000.json','["雨燕去還來，銜蟲爲雛食。", "雄雌濕已倦，梁棟冷並息。", "緣礎蚍蜉羣，拾餕蜻蜓翼。", "穀粟滿京囷，任從黄雀得。"]'),
('21287cfc-169e-41df-ad70-39b232e8aa21','夏蟲','梅堯臣','宋','宋诗','song-poetry','','[]','物久必自化，化之猶騫騰。',48,'全唐诗/poet.song.14000.json','["物久必自化，化之猶騫騰。", "當看厠中蛆，去作盤上蠅。", "飛聲既混雞，歛迹何疑冰。", "寄言漆園吏，已知鵾與鵬。"]'),
('8d7e9b67-a616-4727-be84-eea912ad3e50','秋風篇','梅堯臣','宋','宋诗','song-poetry','','[]','秋風白虎嘷，長庚光如刀。',252,'全唐诗/poet.song.14000.json','["秋風白虎嘷，長庚光如刀。", "水源縮竅穴，木根潛脂膏。", "啄實已細毳，齧枯皆豎毛。", "鬼啼竹籬梢，月黑爲朋曹。", "小兒莫畏聲，破管偶值遭。", "挂掇青紅蕡，拆剖皺刺韜。", "熟墜存虛房，瘦歛由失薅。", "西吹幾萬里，乃起東海濤。", "衡舂困龜魚，白沫丘岳高。", "原揚爛屋茅，岸裂樅船篙。", "貧門易𦵧藉，遠遊難撐操。", "驅雲失巫宮，迸雨入楚壕。", "攪空神兵發，穿窟乖龍逃。", "唯恐五色石，女媧補不牢。", "擺落缺西北，赤子何熬熬。", "常娥近天箕，學簸不學溞。", "欲使糠粃盡，撼死千歲桃。", "王母不敢訴，倚日黄人豪。", "自與穆天子，終朝醉酕醄。", "後得漢武帝，述以再種勞。", "因之來橫汾，作辭心切忉。"]'),
('8894a7a3-02c7-4160-ab76-4a3a47bf4947','秋雨篇','梅堯臣','宋','宋诗','song-poetry','','[]','秋雨一向不解休，連昏接晨終窮秋。',184,'全唐诗/poet.song.14000.json','["秋雨一向不解休，連昏接晨終窮秋。", "梅生不量仰天問，神官夜夢言語周。", "日月是天之兩目，忽然生瞖無藥瘳。", "只知淚滴爲赤子，赤子豈悞天公憂。", "天公哭𩅨𩅨，洒涕落九州。", "地祇不敢安，泥潦已沒頭。", "乃因從容詰神官，后稷今在帝所不。", "從前后稷知稼穡，曾以筋力親田疇。", "曷不告帝且輟泣，九穀正熟容其收。", "早時不泣此時泣，憂民欲活反扼喉。", "神官發怒髭奮虬，下士小臣安預謀。", "恐然驚覺汗交流，樹上已聽呼雌鳩。"]'),
('a350d111-eec3-4557-9777-fda151546640','中秋月下懷永叔','梅堯臣','宋','宋诗','song-poetry','','[]','有朋無明月，秉燭光强致。',108,'全唐诗/poet.song.14000.json','["有朋無明月，秉燭光强致。", "有月無樂朋，獨醉顔易醉。", "往年過廣陵，公欣來我值。", "期玩秋蟾圓，靜掃庭下地。", "復邀高陽公，賸作詩準備。", "特特乃多違，後池風雨至。", "一夜看石屏，怛吟無逸氣。", "今宵皓如晝，千里嗟離異。", "固知理難并，把酒遥相寄。"]'),
('20c5ee3a-99b8-4537-8027-b461e59768da','聞永叔出守同州寄之','梅堯臣','宋','宋诗','song-poetry','','[]','冕旒高拱元元上，左右無非唯唯臣。',64,'全唐诗/poet.song.14000.json','["冕旒高拱元元上，左右無非唯唯臣。", "獨以至公持國法，豈將孤直犯龍鱗。", "茱萸欲把人留楚，苜蓿方枯馬入秦。", "訪古尋碑可銷日，秋風原上足麒麟。"]'),
('d35b9576-14e3-467b-932f-1e42c67dbb2c','九日陪京東馬殿院會疊嶂樓','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','誰言天去遠，山上有樓臺。',48,'全唐诗/poet.song.14000.json','["誰言天去遠，山上有樓臺。", "峯色引谿色，共入茱萸杯。", "行當登泰山，雲掃日月開。", "栢烏與城烏，兩處休鳴哀。"]'),
('a35c3a98-60e9-4944-b971-79aaf94b8eb4','酒病自責呈馬施二公','梅堯臣','宋','宋诗','song-poetry','','[]','李白死宣城，杜甫死耒陽。',84,'全唐诗/poet.song.14000.json','["李白死宣城，杜甫死耒陽。", "二子以酒敗，千古留文章。", "我無文章留，何可事杯觴。", "況承先子戒，宜不著口嘗。", "昔聞有田竇，以此相滅亡。", "禮飲不在多，歡飲不在荒。", "二公方逢時，安得入醉鄉。"]'),
('a7039bc3-8c11-4fdc-af1b-bd6fbb85d2f1','宣城馬御史酒闌一夕而西因以寄之御史嘗留老馬與予僕','梅堯臣','宋','宋诗','song-poetry','','[]','三更醉下陵陽峯，平明溪上去無蹤。',80,'全唐诗/poet.song.14000.json','["三更醉下陵陽峯，平明溪上去無蹤。", "叉牙鐵鎖謾橫絕，濕櫓不驚潭底龍。", "斷腸吳姬指如筍，欲剝玉棐將何從。", "短翎水鴨飛不遠，那經細雨山重重。", "却顧舊埒老病馬，塵沙歷盡空龍鍾。"]'),
('74a2a4de-9749-406f-a63a-ce3639056205','詠懷','梅堯臣','宋','宋诗','song-poetry','','[]','西方有鳥鼠，生死同穴居。',60,'全唐诗/poet.song.14000.json','["西方有鳥鼠，生死同穴居。", "物理固不測，孰言飛走殊。", "雄雌豈相匹，飲啄豈相須。", "一爲枝上鳴，一爲莽下趨。", "苟合而異嚮，世道當何如。"]'),
('b0509b80-7e2d-4c27-a239-9cdd111a9b73','答沖雅上人遺草書并詩','梅堯臣','宋','宋诗','song-poetry','','[]','經月不出戶，堂上多綠苔。',132,'全唐诗/poet.song.14000.json','["經月不出戶，堂上多綠苔。", "忽有方外客，衣披稻畦來。", "來從青山下，手把紈素裁。", "筆草數行字，瘦蛇起春雷。", "渴墨未散霧，屈角麟欲開。", "裝爲兩大軸，置我并瓊瑰。", "懶瞋長鬚奴，挂壁不掃埃。", "智永與懷素，其名久崔嵬。", "師今繼此學，入神在徘徊。", "未料輒以我，便比和羹梅。", "我心常苦酸，得姓何可能。"]'),
('71e8b099-74e5-43e8-b215-3b3b030630c6','讀吳季野芝草篇','梅堯臣','宋','宋诗','song-poetry','','[]','阮生存詠懷，美彼曜朱堂。',60,'全唐诗/poet.song.14000.json','["阮生存詠懷，美彼曜朱堂。", "一榮不復枯，五色異衆芳。", "衆芳發朝露，俄以歛夕陽。", "丹莖起瓦礫，又匪媚棟梁。", "此稟由至和，君子要有常。"]'),
('c9883735-7823-4bc9-82e5-260b84784eba','送吳季野','梅堯臣','宋','宋诗','song-poetry','','[]','贈言必有規，無規固無言。',60,'全唐诗/poet.song.14000.json','["贈言必有規，無規固無言。", "强言苟無補，何異秋蟲喧。", "君行蜀道難，不厭治輕軒。", "母歿未歸土，女長未出門。", "誰能力爲此，勞苦游牆藩。"]'),
('d304b1f0-e457-4a1a-ae6b-14eda0722de5','袁大監挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','昔罷宣城守，將歸尚撫予。',48,'全唐诗/poet.song.14000.json','["昔罷宣城守，將歸尚撫予。", "殷勤爲開徑，慘愴遂登車。", "告老聞還楚，遺榮喜效疏。", "西山忽埋玉，松露助漣如。"]'),
('901d6c5c-630f-4987-9bb1-106622cf4606','袁大監挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','西蜀何夫子，濡毫作冢銘。',48,'全唐诗/poet.song.14000.json','["西蜀何夫子，濡毫作冢銘。", "遼遼傳耳目，炳炳若丹青。", "罷市知遺愛，存祠識舊形。", "生芻莫能置，江闊底滄溟。"]'),
('4064fa81-d609-4376-b597-874c965b1fd6','袁大監挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','不向斗牛望，已聞風雨哀。',48,'全唐诗/poet.song.14000.json','["不向斗牛望，已聞風雨哀。", "沉埋太阿劍，毀折豫章材。", "百鍊飽於鍛，九層誰起臺。", "平生嗟泯泯，逝水詎重來。"]'),
('b1adb121-7f57-4506-97b2-1920758a3cd4','籬上牽牛花','梅堯臣','宋','宋诗','song-poetry','','[]','楚女霧露中，籬上摘牽牛。',72,'全唐诗/poet.song.14000.json','["楚女霧露中，籬上摘牽牛。", "花蔓相連延，星宿光未收。", "采之一何早，日出顔色休。", "持置梅鹵間，染薑奉盤羞。", "爛如珊瑚枝，惱翁牙齒柔。", "齒柔不能食，粱肉坐爲讎。"]'),
('525f828b-bf60-45fa-98c6-342a84983d70','吳正仲同諸賓泛舟歸池上','梅堯臣','宋','宋诗','song-poetry','','[]','輕舟與客歸，竹下閑棋局。',48,'全唐诗/poet.song.14000.json','["輕舟與客歸，竹下閑棋局。", "煮鱟吳味新，篘醪楚釀熟。", "風吹山雨來，冷射膚生粟。", "醉昏笑語同，不看西齋錄。"]'),
('c1589ef2-e412-4b52-a060-b5353d351ece','吳季野話撫州潛心閣','梅堯臣','宋','宋诗','song-poetry','','[]','高閣潛心所，圖書曝蠹收。',48,'全唐诗/poet.song.14000.json','["高閣潛心所，圖書曝蠹收。", "青山隨宅轉，遠水向門流。", "迤邐看無厭，潺湲聽不休。", "一聞秦洞說，便欲泛漁舟。"]'),
('003ae540-d2cc-42f0-81ab-bdadb2473003','詠懷  其一','梅堯臣','宋','宋诗','song-poetry','','[]','一身頭面間，所用蓋有長。',96,'全唐诗/poet.song.14000.json','["一身頭面間，所用蓋有長。", "兩耳主於聰，兩目主於光。", "維鼻主於嗅，維舌主於嘗。", "以耳辨黑白，以目分宮商。", "以鼻識酸鹹，以舌聞嗅香。", "各各反爾用，安得無悲傷。", "此能而兼彼，自勞由不量。", "寄言世上人，欣欣蹈其常。"]'),
('ba91bb9a-d674-46ab-b639-5813bcbcf3d5','詠懷  其二','梅堯臣','宋','宋诗','song-poetry','','[]','東方有野父，禳田一豚蹄。',48,'全唐诗/poet.song.14000.json','["東方有野父，禳田一豚蹄。", "復操一盂酒，祝穀滿吾棲。", "百金請救兵，所欲奢所齎。", "彼何滑稽生，仰天獨笑齊。"]'),
('0dc3c568-645a-46bb-ba11-2a60014b34b7','詠懷  其三','梅堯臣','宋','宋诗','song-poetry','','[]','自余居田里，未免病與貧。',84,'全唐诗/poet.song.14000.json','["自余居田里，未免病與貧。", "常把神農書，每以藥物親。", "處方猶持法，義比君使臣。", "但恨無餘資，豈及療我鄰。", "筆頭不中書，聊可備急人。", "昨日除吏來，吾邦爲長民。", "欲溺復燃灰，敗筆前已陳。"]'),
('e52e5ac2-e599-4083-93d2-c34ebff46723','詠懷  其四','梅堯臣','宋','宋诗','song-poetry','','[]','風驅暴雨來，雷聲出雲背。',84,'全唐诗/poet.song.14000.json','["風驅暴雨來，雷聲出雲背。", "若决千仞溪，追奔下天鎧。", "堂堂亞夫軍，吳楚不足碎。", "旱氣沃原田，煩蒸洗闤闠。", "深料生注射，聚沫猶壅礙。", "青葱草樹鮮，斷歿虹霓在。", "向晚留霽暉，天容染新黛。"]'),
('62090ff2-8124-4763-a3fa-fc855bcc7e40','送人入都下','梅堯臣','宋','宋诗','song-poetry','','[]','梁雖千里近，楚隔九江深。',48,'全唐诗/poet.song.14000.json','["梁雖千里近，楚隔九江深。", "卑濕嗟猶劇，炎蒸老不禁。", "高懷雲出沒，寄信鳥浮沉。", "君去逢親舊，微吟亦見心。"]'),
('94f8c1a8-0a02-44c9-8944-14ec83784262','送毛祕校罷宣城主簿被薦入補令','梅堯臣','宋','宋诗','song-poetry','','[]','良驥不必大，騰羈已超邁。',96,'全唐诗/poet.song.14000.json','["良驥不必大，騰羈已超邁。", "良弓不待寒，調弦自勁快。", "宣城古大邑，聽訟易聾聵。", "君能抉其塞，宰與民共頼。", "自當割雞用，刃必無鈍敗。", "嘗聞開元時，令長多賜戒。", "戒石今尚存，世異事不背。", "以此贈行行，無酒勿我怪。"]'),
('f3eb3e94-4bad-4de5-84ce-877cbbfa541b','鴨脚子','梅堯臣','宋','宋诗','song-poetry','','[]','魏帝昧遠圖，於吳求鬭鴨。',84,'全唐诗/poet.song.14000.json','["魏帝昧遠圖，於吳求鬭鴨。", "乃爲吳人料，重玩志已陿。", "江南有嘉樹，脩聳入天插。", "葉如欄邊跡，子剝杏中甲。", "持之奉漢宮，百果不相壓。", "非甘復非酸，淡苦衆所狎。", "千里競賫貢，何異貴爭啑。"]'),
('93b17cc5-4b0f-4eee-8af0-d3a409679129','八月十五日夜東軒','梅堯臣','宋','宋诗','song-poetry','','[]','隔竹已見月，清光度谿來。',72,'全唐诗/poet.song.14000.json','["隔竹已見月，清光度谿來。", "移影上素壁，與我相徘徊。", "是夜正中秋，天地霧露開。", "人疑玉兔出，藥仵不生埃。", "嫦娥倚冰輪，豔色若自媒。", "他夕豈不好，物意爲之摧。"]'),
('eee30871-baa4-40ba-b531-c6f089bd4a43','送楊辯青州司理','梅堯臣','宋','宋诗','song-poetry','','[]','儒者服襃衣，氣志輕王公。',84,'全唐诗/poet.song.14000.json','["儒者服襃衣，氣志輕王公。", "一落該網中，折節長俯躬。", "山東多豪士，片言不可窮。", "青土饒嘉棗，無以人鈍蒙。", "彼知南楚輕，强始必弱終。", "矯志合其情，乃是吾徒通。", "行當問友生，爲我舉杯空。"]'),
('f62a0616-311b-4f4e-9e02-7dbabb8ea064','隠靜山訪懷賢上人不遇','梅堯臣','宋','宋诗','song-poetry','','[]','松上垂青蔓，蒲根瀉碧泉。',24,'全唐诗/poet.song.14000.json','["松上垂青蔓，蒲根瀉碧泉。", "高僧來不見，却返五峯前。"]'),
('0913b860-6cbb-4d04-a2b0-4eb423763e1c','游隠靜山','梅堯臣','宋','宋诗','song-poetry','','[]','心存名山久，積歲未及遊。',240,'全唐诗/poet.song.14000.json','["心存名山久，積歲未及遊。", "將過值風雨，路不通馬牛。", "丁壯四五人，籃轝時更休。", "轉谷逢煙火，下隰多田疇。", "偃穟黄壓畝，刈麻東盈丘。", "始覺山門深，長松如騰虬。", "直上百餘尺，蒼髯葉脩脩。", "五峯迎人來，冷逼臺殿秋。", "石泉出雲中，引入舍下流。", "緣源至巖口，巖底魚可鉤。", "天昏碧溪去，果熟青猿偷。", "草樹不盡識，自起詩人羞。", "濺濺澗水淺，苒苒菖蒲稠。", "菖蒲花已晚，菖蒲茸尚柔。", "靈根采九節，試共野僧求。", "逡巡能致之，衰疾無甚憂。", "昔聞有釋子，渡江用杯浮。", "棲心向茲地，埋骨在林陬。", "駁陰漏斜光，徒欲窮巔幽。", "夜還南陵郭，幾落猛虎喉。"]'),
('f000a01d-a2d2-431f-91e8-852dbf7848d9','路詠','梅堯臣','宋','宋诗','song-poetry','','[]','五里十里銷磨盡，千蹄萬蹄來往蹤。',32,'全唐诗/poet.song.14000.json','["五里十里銷磨盡，千蹄萬蹄來往蹤。", "古今不是不經歷，踏破青山重復重。"]'),
('c2f7509d-b2aa-4aab-8746-f8c2662c70f6','次韻和吳正仲以予往南陵見寄兼惠新醖早蟹','梅堯臣','宋','宋诗','song-poetry','','[]','我念仲氏疾，走轂不暇膏。',216,'全唐诗/poet.song.14000.json','["我念仲氏疾，走轂不暇膏。", "久處田園閒，風日慣犯冒。", "暮過春穀溪，亭長或前勞。", "乃心在手足，豈得事請造。", "邑僚相哀憐，曾未曰簡傲。", "朝夕論藥品，況是素所好。", "頗能識精麤，固靡窮突奧。", "吾親日倚戶，西首只待報。", "不知羸苶劇，飲餌須諭導。", "既平憂已寬，勝境思一到。", "原田經秋霖，步履畏宿潦。", "山中趣多幽，松下浄不掃。", "言歸尚泥塗，雲綻喜暫曝。", "還將奉談笑，近已逢問耗。", "入門得寄詩，欲覽整白帽。", "酒壺及霜蟹，致釀知談操。", "豈同里中俗，唯罪往不告。", "醉來夜揮毫，明月爲絕倒。"]'),
('8056328c-4065-42cd-aac5-4e3093c79ccd','書席語送馬御史','梅堯臣','宋','宋诗','song-poetry','','[]','天意漫漫物自供，聞香能至是喧蜂。',32,'全唐诗/poet.song.14000.json','["天意漫漫物自供，聞香能至是喧蜂。", "野人割蜜不須盡，留與寒脾作御冬。"]'),
('d77e9e86-3dd8-47fc-a9cb-c7892a672ced','送李南玉','梅堯臣','宋','宋诗','song-poetry','','[]','小人貧於資，君子貧於時。',156,'全唐诗/poet.song.14000.json','["小人貧於資，君子貧於時。", "小人富於貨，君子富於辭。", "貧雖同寒饑，富不同路岐。", "彼富歿則已，此富名不移。", "丈夫事百變，未死安可期。", "明明趨財利，莫卹前人嗤。", "舉家如春蠶，仰食不可遲。", "況念宿債窘，何愧賤士爲。", "買臣嘗負薪，相如猶滌巵。", "君思此二人，信吾言不欺。", "邇者有趙壹，窮憤自興詩。", "乘驥抱美玉，樂與和未知。", "古來鮮逢遇，後世無苦悲。"]'),
('9476e831-76a9-4cb3-927a-52b93803717d','代書寄鴨脚子於都下親友','梅堯臣','宋','宋诗','song-poetry','','[]','予指老無力，不能苦多書。',72,'全唐诗/poet.song.14000.json','["予指老無力，不能苦多書。", "書苟過百字，便覺筋攣拘。", "京都多豪英，往往處石渠。", "作書未可周，寄聲亦已疎。", "後園有嘉果，遠贈當鯉魚。", "中雖聞尺素，加餐意何如。"]'),
('a9b6d984-ae8f-471d-b015-2a26ff89ff38','秋日家居','梅堯臣','宋','宋诗','song-poetry','','[]','移榻愛晴暉，翛然世慮微。',48,'全唐诗/poet.song.14000.json','["移榻愛晴暉，翛然世慮微。", "懸蟲低復上，鬭雀墮還飛。", "相趁入寒竹，自收當晚闈。", "無人知靜景，苔色照人衣。"]'),
('47372548-c0e7-47b8-904b-bfcaaf2997b4','昭亭別施度支','梅堯臣','宋','宋诗','song-poetry','','[]','昭亭送客地，來往四十年。',48,'全唐诗/poet.song.14000.json','["昭亭送客地，來往四十年。", "常視松端日，每稽潭上船。", "風移虎旗脚，寒入牛童肩。", "待訪名山去，相期廬阜前。"]'),
('881e9a6d-1e5d-4f1d-a48c-2f467bafe288','潘歙州話廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','潘侯話廬山，落落尤可伏。',192,'全唐诗/poet.song.14000.json','["潘侯話廬山，落落尤可伏。", "初云江上來，遠見雲中瀑。", "捨舟到雲外，觀瀑已巖麓。", "往往逢平田，攢攢愛深木。", "竹門懸徑微，源水陰藤覆。", "坐石浸兩骹，炎膚起芒粟。", "夕陽穿萬峯，高下相出縮。", "尋常杳不分，但被煙嵐畜。", "絕頂水底花，開謝向淵腹。", "風力豈能加，日氣豈能𣋉。", "攬之不可得，滴瀝空在掬。", "夜昏投僧居，孤燈望溪曲。", "忽聞清磬音，漸近幽林屋。", "止侯休多談，已滿我心目。", "懷游二十年，夢寐今固熟。", "何當借輕舠，一往如飛鶩。"]'),
('3d7637eb-fe66-4088-8fa2-0b82611c89b4','秋日村行','梅堯臣','宋','宋诗','song-poetry','','[]','谿霧晝又收，山村夜初晦。',48,'全唐诗/poet.song.14000.json','["谿霧晝又收，山村夜初晦。", "饑禽來往飛，遠樹清紅碎。", "原上楚牛童，屋頭吳婦碓。", "雞肥酒已熟，野老邀同輩。"]'),
('c1eadd86-5140-4280-9162-6f6835bdc173','吳正仲遺蛤蜊','梅堯臣','宋','宋诗','song-poetry','','[]','紫緣常爲海錯珍，吳鄉傳入楚鄉新。',32,'全唐诗/poet.song.14000.json','["紫緣常爲海錯珍，吳鄉傳入楚鄉新。", "罇前已奪蟹螯味，當日蒓羹枉對人。"]'),
('a8397e18-36fa-46ca-9c99-c7cdb242f678','送潘歙州','梅堯臣','宋','宋诗','song-poetry','','[]','一見新安守，便若新安江。',108,'全唐诗/poet.song.14000.json','["一見新安守，便若新安江。", "洞澈物不隔，演漾心所降。", "遠指治所山，已入鄰齋窗。", "捧輿登南嶺，策馬懷舊邦。", "養親將爲壽，傾甘抱玉缸。", "觀軍將勞士，臠肥堆羊腔。", "下車談詩書，上世擁旄幢。", "勿窺淵游鱗，無吠夜驚尨。", "他日聞課第，天下誰能雙。"]'),
('b191ef6d-b480-4aea-8247-48d202c6823d','馬都官行之惠黄柑荔枝醋壺','梅堯臣','宋','宋诗','song-poetry','','[]','染霜胡甘熟，烘日荔枝美。',75,'全唐诗/poet.song.14000.json','["染霜胡甘熟，烘日荔枝美。", "橘柚未爲精，葡萄安可擬。", "郭生始能贊，魏文何謬比。", "二果皆世珍，乃遺及賤士。", "而復副醇{酉盆}，或乞自諸己。", "豈唯享遠味，終得爲直矣。"]'),
('4e2586ac-2a26-450b-ad61-0007990cbc21','前以甘子詩酬行之既食乃綠橘也頃年襄陽人遺甘予辨是綠橘今反自笑之','梅堯臣','宋','宋诗','song-poetry','','[]','昔辨荆州悞，今爲越叟迷。',24,'全唐诗/poet.song.14000.json','["昔辨荆州悞，今爲越叟迷。", "黄甘與綠橘，正似珷玞圭。"]'),
('106f2ed8-d7b1-4149-a3c0-15fc4dc636b1','新安潘侯將行約游山門寺予以濘淖遂止因爲詩以見懷','梅堯臣','宋','宋诗','song-poetry','','[]','蒼山自爲門，呀豁異鎸鑱。',84,'全唐诗/poet.song.14000.json','["蒼山自爲門，呀豁異鎸鑱。", "路通石壁盡，潦起田穟陷。", "傍嶺有結廬，潛潭浄於鑑。", "聞之固欲往，久雨濕泥埿。", "莫陪太守車，然諾豈誑賺。", "遥遥橋上去，望望馬猶站。", "畏滑不肯行，非關惜韉䪌。"]'),
('f9d0e776-3254-45b8-b788-837e6818d64d','依韻自和送詩寄潘歙州','梅堯臣','宋','宋诗','song-poetry','','[]','潘侯擅詩筆，五色神授江。',108,'全唐诗/poet.song.14000.json','["潘侯擅詩筆，五色神授江。", "世家有大勳，佐舜同厖降。", "子孫逢太平，少小事書窗。", "源流本慷慨，吐論皆經邦。", "量猶函牛鼎，吾徒媿罌缸。", "開口必典實，省腹唯空腔。", "作者過我門，應笑無戟幢。", "窮老在弊廬，何異守戶尨。", "有心希買交，白璧無一雙。"]'),
('5a772ebb-d604-4936-8922-43524aa03854','避爲師依韻答李獻甫','梅堯臣','宋','宋诗','song-poetry','','[]','蛟龍養鬐鬛，當在浩浩潯。',48,'全唐诗/poet.song.14000.json','["蛟龍養鬐鬛，當在浩浩潯。", "虎豹養文采，當在巍巍岑。", "我無太山高，我無滄海深。", "斗水與堆阜，恐未慰此心。"]'),
('14a3a5b4-5c16-4528-9a8a-fe9095e1153a','送李逢原','梅堯臣','宋','宋诗','song-poetry','','[]','禰衡負其才，沉沒鸚鵡洲。',108,'全唐诗/poet.song.14000.json','["禰衡負其才，沉沒鸚鵡洲。", "李白負其才，飄落滄江頭。", "後亦多效此，才薄空覊囚。", "文章本濟時，反不能自周。", "吾嘗戒吾曹，慎勿異爾流。", "臧倉毀孟軻，桓魋迫聖丘。", "雖云推之天，未免皇皇求。", "吾今重子學，無力薦公侯。", "行當思吾言，非教子佞柔。"]'),
('f4633995-83ad-46ba-be41-9569657a8a39','重送李逢原歸蘇州','梅堯臣','宋','宋诗','song-poetry','','[]','吳客歸從楚，霜華著馬蹄。',48,'全唐诗/poet.song.14000.json','["吳客歸從楚，霜華著馬蹄。", "倦童持弊橐，呼艇過寒谿。", "索寞區中飯，依稀日午雞。", "張儀猶舌在，不必愧於妻。"]'),
('d43dd635-83b6-46a1-9718-51374b5315f5','黄國博遺銀魚乾二百枚','梅堯臣','宋','宋诗','song-poetry','','[]','乾若會稽筍，色比荆州銀。',48,'全唐诗/poet.song.14000.json','["乾若會稽筍，色比荆州銀。", "熟宜煨栗火，飲助擁爐人。", "低陰欲飛雪，酒微生頰熱。", "海上使方來，多饟不爲餮。"]'),
('352fc1ae-e073-41c4-85fb-bb5f01cad0f7','三和寄潘歙州','梅堯臣','宋','宋诗','song-poetry','','[]','昔固聞陸海，今復有潘江。',108,'全唐诗/poet.song.14000.json','["昔固聞陸海，今復有潘江。", "文章吞時英，光芒瞻星降。", "如游太室陽，仰見玉女窗。", "高才生大國，試政來遠邦。", "道傍一相顧，冰壺臨瓦缸。", "逸驥美豐肉，老䍽慙瘦腔。", "藻詠答下俚，玉鈴鏘寶幢。", "尋言不悟言，自笑趁塊尨。", "終知將門豪，射雕常貫雙。"]'),
('148801d1-e7b6-4bd7-8a2b-39d161027acc','送天台李令庭芝','梅堯臣','宋','宋诗','song-poetry','','[]','吾聞天台久，未見天台狀。',120,'全唐诗/poet.song.14000.json','["吾聞天台久，未見天台狀。", "去海知幾里，去天知幾丈。", "峯嶺隠與出，巖壑背與向。", "雲雷反在下，泉瀑反在上。", "幽深無窮窺，杳渺無窮望。", "至險可悸慄，至怪可駭喪。", "石橋彎長弓，跨絕絃未放。", "當時白道猷，平步入青嶂。", "去爲六百石，亦見志所尚。", "子欲廣異聞，可以一尋訪。"]'),
('511de44a-02f6-46ed-a14f-cdeb03682213','李令將行返遺以茶','梅堯臣','宋','宋诗','song-poetry','','[]','宏詞郎，姑蘇住，千千蚨母絲繩度。',64,'全唐诗/poet.song.14000.json','["宏詞郎，姑蘇住，千千蚨母絲繩度。", "誰將爲壽不肯收，上馬慨然如脫兔。", "獨持茶丳過江來，已把贈人空手去。", "雨雪綏綏出楚關，我無魯酒徒相顧。"]'),
('26894486-bb92-4ff1-b9ec-f6d65f8f9f27','十一月十二日賽昭亭神','梅堯臣','宋','宋诗','song-poetry','','[]','冷雨凝雪未成雪，潭空魚寒歸石穴。',96,'全唐诗/poet.song.14000.json','["冷雨凝雪未成雪，潭空魚寒歸石穴。", "長篙扣穴倩鯉魚，寄信山頭來奠設。", "魚傳水鳥飛上山，山木槎槎乾吹咽。", "旋灰起角巫鼓鳴，漆俎銅盤顫牲血。", "瑟琶嘈嘈神降言，福汝祐汝無災蘗。", "西向啐飲東向迴，谿心却望山崔嵬。"]'),
('86a0d634-9185-4f50-96c9-3e0ef92e511d','依韻和吳正仲冬至','梅堯臣','宋','宋诗','song-poetry','','[]','流光冉冉即衰遲，物趣迴環似轉規。',64,'全唐诗/poet.song.14000.json','["流光冉冉即衰遲，物趣迴環似轉規。", "長景已知今日至，孤懷不比少年時。", "阻陪上閤鴛鸞後，且與南州父老期。", "況有舂禾新酒熟，百分休放手中巵。"]'),
('12dd7219-09a5-4067-a42b-9a4dfdbc24cd','施君挽歌','梅堯臣','宋','宋诗','song-poetry','','[]','哀鐸悽悽裏，銘旌杳杳中。',48,'全唐诗/poet.song.14000.json','["哀鐸悽悽裏，銘旌杳杳中。", "澗雲銷繐帳，山雨入蒿官。", "世路行來久，泉途去莫窮。", "素吟應共葬，飲韻在松風。"]'),
('0a0dc90a-f477-48c0-93b7-4aef522c6226','涇尉徐絳於其廨得魯公破碑二十六字近又於碑陰得二十八字寄予及吳正仲正仲有詩答亦答之','梅堯臣','宋','宋诗','song-poetry','','[]','顔公忠血化爲碧，顔公奇筆留在石。',320,'全唐诗/poet.song.14000.json','["顔公忠血化爲碧，顔公奇筆留在石。", "十存三四復不完，完者椎模少稜壁。", "許昌斷碣稱最佳，已經田火侵鉤畫。", "今復涇山好事人，別識偶得從糞礫。", "青天雲破星辰明，牽牛半沒河敘白。", "日來翻覆又覩字，久苦堙埋窟螻蟈。", "碑身上下亡八九，況乃龜蚨與螭額。", "不知歲月紀述由，真卿二字如新蹟。", "蠶頭缺齾燕尾斷，斬玉摧金競𦵧藉。", "顔公名與喬嶽齊，置在窮鄉猶棄擲。", "孤城野鬼多神靈，守此隳殘應自惜。", "不虞發掘出幽沉，泣雨霏霏愁向夕。", "氈敲墨刷將寄誰，不付驚弦付鸞翮。", "鸞飛萬里徧八荒，豈止持傳吳楚客。", "中郎有孫能此書，要官木刻輸金帛。", "方爲大尹雖少閑，得之究玩如轂炙。", "我鬢蓬然兩眼花，欲學辛勤定無益。", "人生愛留身後名，□□立勳書史冊。", "□□終知有磨滅，至剛可銷堅可折。", "欲圖億載安所設，世上轉頭方耳熱。"]'),
('2d4f0f42-a11a-41a5-ab16-58bac1f6b994','杜和州寄新醅吳正仲云家有海鮮約予携往就酌逡巡又云幙中有會且罷此飲','梅堯臣','宋','宋诗','song-poetry','','[]','淮南寄我玉醅酒，白蚶海月君家有。',64,'全唐诗/poet.song.14000.json','["淮南寄我玉醅酒，白蚶海月君家有。", "欲持就味明日期，窮羹易覆已反手。", "從事開筵不可辭，燕脂秀臉羅前後。", "長頸善謳須賸謳，只恐老來歡意休。"]'),
('ab8a3750-98dc-4ebf-aebb-6243bc0b0778','依韻答吳正仲罷飲','梅堯臣','宋','宋诗','song-poetry','','[]','君辭予家傾蟻醅，自有嘉味須持來。',64,'全唐诗/poet.song.14000.json','["君辭予家傾蟻醅，自有嘉味須持來。", "青篾絡缾方出戶，紅粧侑席已邀杯。", "窮愁一飲猶關分，側望羣賢不可陪。", "靜坐紙窗無所得，只將文字眼前堆。"]'),
('c915d3da-9e54-44a9-94d0-b3a3a61df71d','送王景憲奉職','梅堯臣','宋','宋诗','song-poetry','','[]','清羸將家子，苦節自寒儒。',48,'全唐诗/poet.song.14000.json','["清羸將家子，苦節自寒儒。", "四壁我何有，一錢君亦無。", "下灘船自急，聞雁日將晡。", "行愛青山口，人煙事網罛。"]'),
('29043e36-97ec-4e08-8767-0b67009ae136','讀毛祕校新詩','梅堯臣','宋','宋诗','song-poetry','','[]','毛公明於詩，其系宜善續。',36,'全唐诗/poet.song.14000.json','["毛公明於詩，其系宜善續。", "前示五長篇，大須傾幾曲。", "豈特元和間，咳唾成珠玉。"]'),
('948b6e6f-accd-48cd-b8db-dc11ac3fae9b','送允從上人還廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山高雲在下，諸壑藏半空。',60,'全唐诗/poet.song.14000.json','["山高雲在下，諸壑藏半空。", "千重萬重翠，正望落日中。", "不知野僧歸，石徑寒易通。", "松間無人掃，隕葉如斷鬉。", "獨行逢暮寒，衣裂溪上風。"]'),
('9301cbd8-9839-45df-86b6-069f04f04325','依韻諸公尋靈濟重臺梅','梅堯臣','宋','宋诗','song-poetry','','[]','梅要山傍水次栽，非同弱柳近章臺。',64,'全唐诗/poet.song.14000.json','["梅要山傍水次栽，非同弱柳近章臺。", "重重葉葉花依舊，歲歲年年客又來。", "雖愛千枝競繁密，還嗟短髮已衰頹。", "郎官博士留車騎，擁蔽脩篁爲斫開。"]'),
('4510fe4e-02bb-40c1-b04e-66456552474f','和正仲再和罷飲','梅堯臣','宋','宋诗','song-poetry','','[]','吳味期君强飲開，楚醅因我破愁來。',64,'全唐诗/poet.song.14000.json','["吳味期君强飲開，楚醅因我破愁來。", "何言合美將虛館，却憶爭妍就捧杯。", "夜霰已先庭雪集，單衣難與毳裘陪。", "踐盟幾欲驅車去，塵事無端日日堆。"]'),
('7bcdeda8-93fd-4fbc-b0db-80e11b53979a','和韻三和戲示','梅堯臣','宋','宋诗','song-poetry','','[]','笭箐畫蛤瓦缸醅，海若淮壖各寄來。',64,'全唐诗/poet.song.14000.json','["笭箐畫蛤瓦缸醅，海若淮壖各寄來。", "將學時人鬭牛飲，還從上客舞娥杯。", "蓬蒿自有蔣生樂，珠翠寧容鄭氏陪。", "莫計暄寒與風雪，古來黄土北邙堆。"]'),
('ddb679dc-e84a-4ab4-a4c5-f86b87242c90','嘉雪應祈呈權郡通判','梅堯臣','宋','宋诗','song-poetry','','[]','臘近冬殘雲未合，江南青壠麥休肥。',32,'全唐诗/poet.song.14000.json','["臘近冬殘雲未合，江南青壠麥休肥。", "誰將太守隨車雨，一夜從風作雪飛。"]'),
('be9c08e7-fa55-45a6-a5da-c3d16f3c8ade','依韻四和正仲','梅堯臣','宋','宋诗','song-poetry','','[]','四和還如九酘醅，更醇更美未嫌來。',64,'全唐诗/poet.song.14000.json','["四和還如九酘醅，更醇更美未嫌來。", "相逢莫作兩般眼，一飲不辭三百杯。", "嵇阮當時無俗慮，山王雖貴亦能陪。", "如今世態尤堪薄，只把官資滿眼堆。"]'),
('356eac8b-bfaf-4e02-914f-a60b84dcbe96','雪','梅堯臣','宋','宋诗','song-poetry','','[]','朔雲生晚雨，臘霰集狂風。',48,'全唐诗/poet.song.14000.json','["朔雲生晚雨，臘霰集狂風。", "不數花多出，安知天更工。", "漫階夜已積，萬物曉初蒙。", "誰憶新豐酒，乘馿灞水東。"]'),
('62ac3e26-b29b-44d1-8a6d-d1b9180be47c','依韻和郭祥正秘校遇雨宿昭亭見懷','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君乘瘦馬來，骨竦毛何長。',96,'全唐诗/poet.song.14000.json','["君乘瘦馬來，骨竦毛何長。", "下馬與我語，滿屋聲琅琅。", "一誦廬山高，萬景不得藏。", "出沒望林寺，遠近數鳥行。", "鬼神露怪變，天地無炎凉。", "設令古畫師，極意未能詳。", "誦說冒雨去，夜宿昭亭傍。", "明朝有使至，寄多驚俗章。"]'),
('7c2c0564-a1e3-4f56-b1bf-2980e3855d46','採石月贈郭功甫','梅堯臣','宋','宋诗','song-poetry','','[]','採石月下聞謫仙，夜披錦袍坐釣船。',112,'全唐诗/poet.song.14000.json','["採石月下聞謫仙，夜披錦袍坐釣船。", "醉中愛月江底懸，以手弄月身翻然。", "不應暴落饑蛟涎，便當騎魚上九天。", "青山有冢人謾傳，却來人間知幾年。", "在昔熟識汾陽王，納官貰死義難忘。", "今觀郭裔奇俊郎，眉目真似攻文章。", "死生往復猶康莊，樹穴探環知姓羊。"]'),
('0cb207e6-f841-41a5-9d53-849a66d2e70e','依韻和郭秘校苦寒','梅堯臣','宋','宋诗','song-poetry','','[]','噫風鳴悲鳶鳴哀，雨霰枯木爲之摧。',64,'全唐诗/poet.song.14000.json','["噫風鳴悲鳶鳴哀，雨霰枯木爲之摧。", "昭亭山頭野火滅，海水夜凍迷蓬萊。", "燭籠以爪自掩耳，酒盞生冰拈不起。", "陶潛棄官屋無米，兒嚎妻啼付鄰里。"]'),
('e3d4999c-0ce6-424b-9e0c-05124638277c','依韻和郭秘校昭亭山偶作','梅堯臣','宋','宋诗','song-poetry','','[]','知君棄官後，江上尋名山。',120,'全唐诗/poet.song.14000.json','["知君棄官後，江上尋名山。", "心既慣世內，迹欲還人間。", "昭亭忽來過，覽古興長歎。", "野寺拂塵壁，丹陽已斕斒。", "殿角虛寶鐸，微風聲珊珊。", "遺像與筆蹟，始得觀裴顔。", "淺井何泠泠，前溪何潺潺。", "幽幽隨猿鳥，渾渾忘區寰。", "裂裳不爲媿，餌芝不爲難。", "坐對寒雨中，松上孤鶴還。"]'),
('8aee1008-619d-4b7c-a724-f031af945216','送郭功甫還青山','梅堯臣','宋','宋诗','song-poetry','','[]','來何遲遲去何勇，羸馬寒僮肩竦竦。',96,'全唐诗/poet.song.14000.json','["來何遲遲去何勇，羸馬寒僮肩竦竦。", "昨日棄爲梅福官，扁舟早勝大夫種。", "負經不厭關山遥，訪我猶將歲月恐。", "得言會意若秋鷹，反翅歸飛輕飽氄。", "明朝到家年始開，椒花壽酒期親捧。", "何當交臂須强行，莫作區區事丘壠。"]'),
('23bf9560-6465-496a-8fae-9327665e46fb','送鄧生','梅堯臣','宋','宋诗','song-poetry','','[]','哀哀彼鄧子，扶柩歸長沙。',48,'全唐诗/poet.song.14000.json','["哀哀彼鄧子，扶柩歸長沙。", "朝暮哭失聲，驚聒牆上鴉。", "飛去復飛還，相與棲水涯。", "卜葬不當緩，早晚能到家。"]'),
('84b9d07f-6e1f-41bc-bf7e-676ccee18ccc','送才上人還雪竇寄達觀禪師','梅堯臣','宋','宋诗','song-poetry','','[]','春雪滿簑笠，海邊先燕歸。',48,'全唐诗/poet.song.14000.json','["春雪滿簑笠，海邊先燕歸。", "千林新改葉，百衲舊來衣。", "谿水從何至，山雲自解飛。", "報言巖下客，齋鉢筍應肥。"]'),
('7f621bd2-3200-4c4a-931f-33cf00da2f4c','樂椽自淮南迴示新詩','梅堯臣','宋','宋诗','song-poetry','','[]','淮南歷覽還宣城，囊多嘉句何冰清。',80,'全唐诗/poet.song.14000.json','["淮南歷覽還宣城，囊多嘉句何冰清。", "入門先叫十年兄，袖中大卷持來評。", "我雖暗愚眼不盲，要識合如劉長卿。", "舉頭不言笑且驚，此兄議論頗稱情。", "我亦感君知我名，阮籍從呼作老兵。"]'),
('6ca488a1-1a38-4cb7-ac60-44ef394ff2fd','蘇州曹琰虞部浩然堂','梅堯臣','宋','宋诗','song-poetry','','[]','姑蘇臺上麋鹿嚎，夫差城中樓觀高。',80,'全唐诗/poet.song.14000.json','["姑蘇臺上麋鹿嚎，夫差城中樓觀高。", "荒榛盡已付明月，萬古憤怒空秋濤。", "吳亡越霸能幾日，後世擾擾猶鴻毛。", "孟軻善養浩然氣，充塞天地無饑嗷。", "慕而爲堂亦有意，不學屈子成離騷。"]'),
('a1e1b425-b59b-4ce1-ae1e-25ba4cbcf974','紅梅篇','梅堯臣','宋','宋诗','song-poetry','','[]','昨夜輕雷起風雨，芍藥紅牙竹欄土。',142,'全唐诗/poet.song.14000.json','["昨夜輕雷起風雨，芍藥紅牙竹欄土。", "南庭梅花如杏花，東家殘朱塗頰䩉。", "萼爲裳衣蕊爲組，枝爲高居幹爲戶。", "蛺蝶未生蜂未來，赤身掩斂無金縷。", "終然有子當助傅說羹，落亦不學飛燕皇后迴風舞。", "此意又笑麻姑與王母，勾引何人擗麟脯。", "是非方朔謾漢武，只知此桃不知語。", "樹不著口數，而今言之已莫補，放我渾丹鳳皇羽。"]'),
('6606040b-035a-41a7-834a-53dd811c7066','依韻和吳正仲聞重梅已開見招','梅堯臣','宋','宋诗','song-poetry','','[]','難開密葉不因寒，誰翦鵝兒短羽攢。',64,'全唐诗/poet.song.14000.json','["難開密葉不因寒，誰翦鵝兒短羽攢。", "猶是去年驚目豔，不知從此幾人觀。", "重重好蕊重重惜，日日攀枝日日殘。", "我爲病衰方止酒，願携茶具作清歡。"]'),
('58e69a4a-53e5-4ed2-81b6-a54c5f4dc30a','寄送吳公明屯田通判秦州','梅堯臣','宋','宋诗','song-poetry','','[]','一聞春禽婆餠焦，竹林山木生蕭條。',80,'全唐诗/poet.song.14000.json','["一聞春禽婆餠焦，竹林山木生蕭條。", "憶君將向洛門去，胡馬無塵塞路遥。", "將軍本是漢丞相，玉帳坐辨牙旗梟。", "白面書生有肝膽，少年曾過咸陽橋。", "今雖老病由廬巷，爲報緩制秦兵驕。"]'),
('57ab51d2-0c9f-461c-9cf0-8e93d35ab580','吳正仲求紅梅接頭','梅堯臣','宋','宋诗','song-poetry','','[]','君家梅溪上，但見梅花白。',48,'全唐诗/poet.song.14000.json','["君家梅溪上，但見梅花白。", "我家家樹紅，求枝寄歸客。", "翦接如交情，本末不相隔。", "明年舉酒時，醉頰生微赤。"]'),
('918d8742-eccd-48d1-bb44-9bb9bdff280a','初聞蛙','梅堯臣','宋','宋诗','song-poetry','','[]','朝開南籬梅，暮聞北池蛙。',48,'全唐诗/poet.song.14000.json','["朝開南籬梅，暮聞北池蛙。", "何時科斗生，草根已吐牙。", "只畏草葉長，其下可隠蛇。", "游子且勿行，科斗成蝦蟆。"]'),
('653031be-a2f0-40ce-afd1-2bbe22f7ffaf','百舌','梅堯臣','宋','宋诗','song-poetry','','[]','一冬常噤默，乘春何多舌。',60,'全唐诗/poet.song.14000.json','["一冬常噤默，乘春何多舌。", "蒼毛無文章，尖啄苦騰說。", "曉升高高樹，百鳥言漏泄。", "只未學鳳皇，有亦學不徹。", "傷哉古辯士，往往遭車裂。"]'),
('446a7e64-1ccc-44fd-a192-a6b0bffa446e','萬表臣報山傍有重梅花葉又繁諸君往觀之','梅堯臣','宋','宋诗','song-poetry','','[]','前時見多葉，曾何數尋常。',36,'全唐诗/poet.song.14000.json','["前時見多葉，曾何數尋常。", "今見葉又多，移賞南澗陽。", "寄言莫苦恃，更多殊未央。"]'),
('f1f35e8c-b930-477d-944a-c93ad6edaa18','去臘隠靜山僧寄榧樹子十二本柏樹子十四本種於新墳','梅堯臣','宋','宋诗','song-poetry','','[]','棐柏移皆活，風霜不變青。',48,'全唐诗/poet.song.14000.json','["棐柏移皆活，風霜不變青。", "冢垣雖闃寂，田客每丁寧。", "不待爲書几，常流作鬼庭。", "東邊夾路少，更致儻能令。"]'),
('a5248f55-a6b4-4447-8a44-952053ccfcbb','新除廣東常平之節感恩書懷','楊萬里','宋','宋诗','song-poetry','','[]','已愧雙旌古晉陵，更堪一節古羊城。',64,'全唐诗/poet.song.140000.json','["已愧雙旌古晉陵，更堪一節古羊城。", "偶逢舊治年頻熟，忽署新銜手尚生。", "山與君恩誰是重，身如秋葉不勝輕。", "向來百鍊今繞指，一寸丹心白日明。"]'),
('957b5ed5-a0e7-444e-acd7-abd8d28bbd69','芥齏','楊萬里','宋','宋诗','song-poetry','','[]','茈薑馨辣最佳蔬，孫芥芳辛不讓渠。',64,'全唐诗/poet.song.140000.json','["茈薑馨辣最佳蔬，孫芥芳辛不讓渠。", "蟹眼嫩湯微熟了，鵝兒新酒未醒初。", "棖香醋釅作三友，露葉霜芽知幾鋤。", "自笑枯腸成破甕，一生只解貯寒葅。"]'),
('cf493a07-6f09-4669-b76d-1e921e9c178b','正月將晦繁星滿天','楊萬里','宋','宋诗','song-poetry','','[]','兔冷蟾寒不出時，羣仙無睡尚遊嬉。',32,'全唐诗/poet.song.140000.json','["兔冷蟾寒不出時，羣仙無睡尚遊嬉。", "可憐深夜無燈火，碧玉枰前暗著棋。"]'),
('bf5d95b7-a9f5-453f-b1cc-7012e5d07d09','辭滿代者未至','楊萬里','宋','宋诗','song-poetry','','[]','一麾來此恰三年，到得終更分外難。',32,'全唐诗/poet.song.140000.json','["一麾來此恰三年，到得終更分外難。", "老眼看燈渾作暈，愁心得酒不成歡。"]'),
('82f7a8b2-fe87-4821-b60f-1e9f4cf1b6d7','試毗陵周壽墨池樣筆','楊萬里','宋','宋诗','song-poetry','','[]','舊來雞距說宣城，近來墨池說毗陵。',168,'全唐诗/poet.song.140000.json','["舊來雞距說宣城，近來墨池說毗陵。", "不知阿誰喜柔懦，毛穎只今泥樣軟。", "筆頭政要挽千鈞，渠自無力隨人轉。", "兔尖如針利如錐，方能幻出抉石猊。", "少年免冠已秃鬢，老去種種將奚爲。", "就中周壽差可意，銳頭將軍殊解事。", "銛鋒不用洮州礪，剛腸頗學汲都尉。", "先生焚香坐明窗，中書奮髯蝟毛張。", "願翻墨汁詩戰場，先生一揮十萬行。", "梅花微笑看在旁，吾詩雖非雲錦章，中有梅花玉雪香。"]'),
('c0494995-2e8f-4b70-8712-2b9436621ee8','春寒初晴','楊萬里','宋','宋诗','song-poetry','','[]','峭寒穿屋透衣裘，欺得詩人兩鬢秋。',32,'全唐诗/poet.song.140000.json','["峭寒穿屋透衣裘，欺得詩人兩鬢秋。", "從此莫教三日暖，花開花落却成愁。"]'),
('5195b247-1144-489f-b455-1cfa17cc1fcd','柳色','楊萬里','宋','宋诗','song-poetry','','[]','春到四經旬，元來未見春。',24,'全唐诗/poet.song.140000.json','["春到四經旬，元來未見春。", "柳條將軟碧，爭獻上番新。"]'),
('dd640a7f-be25-4a78-aa0a-fdf7573ad971','行圃二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','摘杞搜枯梗，攀花脫脆包。',24,'全唐诗/poet.song.140000.json','["摘杞搜枯梗，攀花脫脆包。", "蝶呈新樣粉，柳送隔城梢。"]'),
('acfc3a9d-70b7-430b-9b8a-b2bcf2e74275','行圃二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','澹天薄日倦春遊，蒼檜叢篁引逕幽。',32,'全唐诗/poet.song.140000.json','["澹天薄日倦春遊，蒼檜叢篁引逕幽。", "忽有小風人未覺，薺花無數總摇頭。"]'),
('43e5fe49-7908-4f54-9411-bafaca14035a','春半聞歸雁','楊萬里','宋','宋诗','song-poetry','','[]','春光深淺沒人知，我正南歸雁北歸。',32,'全唐诗/poet.song.140000.json','["春光深淺沒人知，我正南歸雁北歸。", "頭上一聲如話別，一生長是背人飛。"]'),
('782e71ca-45bf-4c3c-b125-ffa6f5766724','毗陵辭滿出舍添倅廳','楊萬里','宋','宋诗','song-poetry','','[]','小住丞廳更一旬，客魂先入故鄉春。',32,'全唐诗/poet.song.140000.json','["小住丞廳更一旬，客魂先入故鄉春。", "未離鼓角聲中夢，已是譙門外面人。"]'),
('355d630f-7cad-459c-8ffe-2c92c316ca46','寓倅廳寒夜不寐','楊萬里','宋','宋诗','song-poetry','','[]','不堪斜雨打虛窗，只願晴陽送曉光。',64,'全唐诗/poet.song.140000.json','["不堪斜雨打虛窗，只願晴陽送曉光。", "自是老人眠不著，近來春夜幾曾長。", "樓頭吹動梅花曲，夢裏猶疑燕寢香。", "道是官居如客舍，等閑一宿兩年强。"]'),
('16664263-0e95-4f4e-977e-8d0296bc6c8b','春望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春光放盡百花房，開到林檎與海棠。',32,'全唐诗/poet.song.140000.json','["春光放盡百花房，開到林檎與海棠。", "青却子城千樹柳，高枝猶有一梢黄。"]'),
('8822d186-0659-46e1-80db-7840b30e12b6','春望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','掠削嬌雲放嫩晴，三朝五日即清明。',32,'全唐诗/poet.song.140000.json','["掠削嬌雲放嫩晴，三朝五日即清明。", "垂楊幸自風流殺，莫著啼烏只著鶑。"]'),
('0d3290b6-2390-49a0-a83c-4cad16e1216d','送醫家孟宗良漢卿','楊萬里','宋','宋诗','song-poetry','','[]','醫家者流多盧人，亦如許靖浪得名。',136,'全唐诗/poet.song.140000.json','["醫家者流多盧人，亦如許靖浪得名。", "有眼何曾識內經，有手何曾赦方兄。", "一丸足可殺一命，却道良醫逢死病。", "荆溪此輩端不稀，向來吾兒命如絲。", "孟君談笑能起死，吾兒更生一彈指。", "我今挂帆上江西，君來送我別荆溪。", "贈別只有七字詩，千萬珍重慰相思。", "它年荆溪說神醫，非吾孟君更阿誰，倉公華佗何必奇。"]'),
('155eca6c-b4cd-4125-a0db-f3ad4ae128d8','遊翟園三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','花枝劣相絓人衣，蜂子顛狂觸面皮。',32,'全唐诗/poet.song.140000.json','["花枝劣相絓人衣，蜂子顛狂觸面皮。", "一巷海棠千架錦，兩堤楊柳萬窩絲。"]'),
('cdee6b07-5931-444a-b66b-774193afe63b','遊翟園三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','柔風軟日斬新晴，釅白嬌紅鼎盛春。',32,'全唐诗/poet.song.140000.json','["柔風軟日斬新晴，釅白嬌紅鼎盛春。", "借問主人何處去，春光分付守園人。"]'),
('5a3d8ed4-283d-4026-afcb-e16df14c8c1f','遊翟園三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','翟園從此即相辭，園裏春歸我亦歸。',32,'全唐诗/poet.song.140000.json','["翟園從此即相辭，園裏春歸我亦歸。", "蜂踏殘花容易落，蝶隨數片往來飛。"]'),
('26cd20a1-dd42-4855-b340-93eb511e8ef9','上印有日代者未至','楊萬里','宋','宋诗','song-poetry','','[]','不是新人不肯來，天教老子小徘徊。',32,'全唐诗/poet.song.140000.json','["不是新人不肯來，天教老子小徘徊。", "坐看桃李繽紛落，等得酴醾爛熳開。"]'),
('10976fa8-cb8e-4743-847f-2b99f80809b8','初離常州夜宿小井清曉放船三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','攔街父老不教行，出得東門已一更。',32,'全唐诗/poet.song.140000.json','["攔街父老不教行，出得東門已一更。", "一事新來偏可意，夢中聞打放船鉦。"]'),
('e68c182f-2b9d-4e7a-9bc0-06cb51db8956','初離常州夜宿小井清曉放船三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','晨炊只煮野蔬湯，更揀鮮魚買一雙。',32,'全唐诗/poet.song.140000.json','["晨炊只煮野蔬湯，更揀鮮魚買一雙。", "病眼未能禁曉日，西窗莫閉閉東窗。"]'),
('284fe72f-43d7-4a32-9fb6-345a1175f672','初離常州夜宿小井清曉放船三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','春旱愁人是去年，如今說著尚心酸。',32,'全唐诗/poet.song.140000.json','["春旱愁人是去年，如今說著尚心酸。", "篙師莫遣船遲著，見說蘇州好牡丹。"]'),
('e5390bc4-a9a6-46a9-b918-445419b3b09f','雨中遠望惠山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','準擬歸時到未遲，歸時不到悔來時。',32,'全唐诗/poet.song.140000.json','["準擬歸時到未遲，歸時不到悔來時。", "惠山不識空歸去，枉與常州作住持。"]'),
('6f1dea09-a98c-4c03-b197-460c4a9458bd','雨中遠望惠山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','詩人也是可憐生，不及穿雲渡水僧。',32,'全唐诗/poet.song.140000.json','["詩人也是可憐生，不及穿雲渡水僧。", "不是惠山看不見，只教遥見不教登。"]'),
('67816057-bcda-4a38-9713-30435f767c9b','酌惠山泉瀹茶','楊萬里','宋','宋诗','song-poetry','','[]','錫作諸峰玉一涓，麯生堪釀茗堪煎。',32,'全唐诗/poet.song.140000.json','["錫作諸峰玉一涓，麯生堪釀茗堪煎。", "詩人浪語元無據，却道人間第二泉。"]'),
('3dbf92a9-3850-4b82-b811-aaf212f322b7','舟中雨望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨裏船中只好眠，不堪景物妬人閑。',32,'全唐诗/poet.song.140000.json','["雨裏船中只好眠，不堪景物妬人閑。", "岩如玉案平鋪却，飣餖真山作假山。"]'),
('488f2a5b-696d-410d-8200-5501814a7e49','舟中雨望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','船窗深閉懶看書，獨倚船門撚白鬚。',32,'全唐诗/poet.song.140000.json','["船窗深閉懶看書，獨倚船門撚白鬚。", "雨共長河織青錦，金錢暈上滴真珠。"]'),
('ec5ac016-d220-449d-9637-d712fd7c7785','曉經潘葑','楊萬里','宋','宋诗','song-poetry','','[]','油窗著雨光不濕，東風忽轉西風急。',64,'全唐诗/poet.song.140000.json','["油窗著雨光不濕，東風忽轉西風急。", "篷聲蕭蕭河水澀，牽船不行人却立。", "雨中篙師風墮笠，潘葑未到眼先入。", "岸柳垂頭向人揖，一時喚入誠齋集。"]'),
('62c1b1f5-03be-41ae-bc89-fe6fc8b835a1','惠山雲開復合','楊萬里','宋','宋诗','song-poetry','','[]','二年常州不識山，惠山一見開心顔。',96,'全唐诗/poet.song.140000.json','["二年常州不識山，惠山一見開心顔。", "只嫌雨裏不子細，髣髴隔簾青玉鬟。", "天風忽吹白雲坼，翡翠屏開倚南極。", "政緣一雨染山色，未必雨前如此碧。", "看山未了雲復還，雲與詩人偏作難。", "我船自向蘇州去，白雲穩向山頭住。"]'),
('71409c0b-496b-45b4-9ada-e615d2880ddf','泊舟無錫雨止遂游惠山','楊萬里','宋','宋诗','song-poetry','','[]','天教老子不空回，船泊山根雨頓開。',32,'全唐诗/poet.song.140000.json','["天教老子不空回，船泊山根雨頓開。", "歸去江西人問我，也曾一到惠山來。"]'),
('1e139c52-e5df-4c72-ac97-d10b3e5da8cd','出惠山遥望橫山','楊萬里','宋','宋诗','song-poetry','','[]','三日橫山反覆看，殷勤送我惠山前。',32,'全唐诗/poet.song.140000.json','["三日橫山反覆看，殷勤送我惠山前。", "常州更在橫山外，只望橫山已杳然。"]'),
('197544ae-c4ad-4c17-a28e-4e11a83d93b5','舟過望亭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','常州盡處是望亭，已離常州第四程。',32,'全唐诗/poet.song.140000.json','["常州盡處是望亭，已離常州第四程。", "柳線絆船知不住，却教飛絮送儂行。"]'),
('69600f8e-3e97-4cc9-9b33-6bce776bdf07','舟過望亭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨罷風回花柳晴，忽然數點打窗聲。',32,'全唐诗/poet.song.140000.json','["雨罷風回花柳晴，忽然數點打窗聲。", "遊蜂誤入船窗裏，飛去飛來總是情。"]'),
('73a3010b-d006-4040-90bb-715d0c61d26c','舟過望亭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','此去蘇州半日期，歸心長是覺船遲。',32,'全唐诗/poet.song.140000.json','["此去蘇州半日期，歸心長是覺船遲。", "一村樹暗知何處，兩岸草青無了時。"]'),
('e98769a2-9a24-44e1-be18-2b23d9d8842f','將近許市望見虎丘','楊萬里','宋','宋诗','song-poetry','','[]','許市人家遠樹前，虎丘山色夕陽邊。',32,'全唐诗/poet.song.140000.json','["許市人家遠樹前，虎丘山色夕陽邊。", "石橋分水入別港，茅屋垂楊仍釣船。"]'),
('c74ec225-2884-477d-a0fa-c1c3ead63040','舟中晚酌二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','竹陵春酒絕清嚴，解割詩腸快似鎌。',32,'全唐诗/poet.song.140000.json','["竹陵春酒絕清嚴，解割詩腸快似鎌。", "雪藕逢暄偏覺爽，鵝梨欲爛不勝甜。"]'),
('9be97caf-bd70-437a-b379-fc5dfa07889e','舟中晚酌二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一日寒暄自不同，繡簾下却護輕風。',32,'全唐诗/poet.song.140000.json','["一日寒暄自不同，繡簾下却護輕風。", "楊花可是多情思，飛入船中落酒中。"]'),
('8fc9a24d-21e0-4237-8e4b-167d0e2b856e','泊船百花洲登姑蘇臺二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','二月盡頭三月初，繫船楊柳拂菰蒲。',32,'全唐诗/poet.song.140000.json','["二月盡頭三月初，繫船楊柳拂菰蒲。", "姑蘇臺上斜陽裏，眼度靈巖到太湖。"]'),
('b8b02d6e-ad6a-4467-a58c-a340d09ee22c','泊船百花洲登姑蘇臺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','客裏逢春了不知，牡丹剩買十來枝。',32,'全唐诗/poet.song.140000.json','["客裏逢春了不知，牡丹剩買十來枝。", "東風動地從渠惡，吹盡楊花無可吹。"]'),
('809e57d8-53c8-4906-a963-18cfe8a9fc2e','舟中小雨','楊萬里','宋','宋诗','song-poetry','','[]','漠漠輕寒粟曉膚，酴醾半落牡丹初。',64,'全唐诗/poet.song.140000.json','["漠漠輕寒粟曉膚，酴醾半落牡丹初。", "顛風無頼難拘管，小雨多情爲破除。", "半世光陰行路裏，一年春事客愁餘。", "浙西尚遠江西在，何日章江買白魚。"]'),
('921cf6f6-0c46-4e6f-9466-c151e28060ca','從范至能參政游石湖精舍坐間走筆二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','孤塔鷗邊迥，千巖鏡裏看。',48,'全唐诗/poet.song.140000.json','["孤塔鷗邊迥，千巖鏡裏看。", "折花倩人插，摘葉護窗寒。", "不是無相識，相從却是難。", "歸舟望精舍，已在白雲端。"]'),
('397fed53-f90a-448b-9470-816a66580448','從范至能參政游石湖精舍坐間走筆二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','震澤分波入，垂虹隔水看。',48,'全唐诗/poet.song.140000.json','["震澤分波入，垂虹隔水看。", "何須小風起，生怕牡丹寒。", "政坐諸峰好，端令落筆難。", "催人理歸棹，落日許無端。"]'),
('8dd64b24-3849-4155-907e-7484c468e656','夜飲周同年權府家','楊萬里','宋','宋诗','song-poetry','','[]','老趁漁船泊館娃，月明夜飲故人家。',32,'全唐诗/poet.song.140000.json','["老趁漁船泊館娃，月明夜飲故人家。", "春風吹酒不肯醒，嚼盡酴醾一架花。"]'),
('f74f26a9-80b5-4c66-9807-87100c74ca5c','再登垂虹亭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','紅塵不解送詩來，身在煙波句自佳。',32,'全唐诗/poet.song.140000.json','["紅塵不解送詩來，身在煙波句自佳。", "銀漢光中有詩客，玉虹背上曳芒鞋。"]'),
('4b884671-4c16-4e74-a750-220daccfcb9d','再登垂虹亭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','宿酲作惱未惺鬆，一對湖光酒病空。',32,'全唐诗/poet.song.140000.json','["宿酲作惱未惺鬆，一對湖光酒病空。", "身到吳中無好處，三年兩度上垂虹。"]'),
('c6e0e1a2-6823-447c-a88a-c7c748012498','再登垂虹亭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','長年三老不須催，且據胡牀未擬回。',32,'全唐诗/poet.song.140000.json','["長年三老不須催，且據胡牀未擬回。", "白晝驚人星滿地，日光碎處萬波來。"]'),
('c2bd8cb7-6fb8-4bba-a699-e492cb1c524b','已過吳江阻風上湖口二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','五日姑蘇一醉中，醉中看盡牡丹紅。',32,'全唐诗/poet.song.140000.json','["五日姑蘇一醉中，醉中看盡牡丹紅。", "阻風只怕松江渡，過了松江却阻風。"]'),
('eacd7abe-2686-4cb5-adee-a5264493d932','已過吳江阻風上湖口二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','南風捲水入湖去，落盡波痕不復回。',32,'全唐诗/poet.song.140000.json','["南風捲水入湖去，落盡波痕不復回。", "更被綱船礙歸舫，一船過盡一船來。"]'),
('6fcfd194-4f7a-4da7-83d5-e2627f1f3996','夜泊平望終夕不寐三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','船中新熱睡難成，聽盡漁舟掠水聲。',32,'全唐诗/poet.song.140000.json','["船中新熱睡難成，聽盡漁舟掠水聲。", "不分兩窗窗外月，如何不爲別人明。"]'),
('85bd56d1-a5b5-427d-8bea-02f3591f65a6','夜泊平望終夕不寐三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','櫻桃湖裏月如霜，偏照征人寸斷腸。',32,'全唐诗/poet.song.140000.json','["櫻桃湖裏月如霜，偏照征人寸斷腸。", "醉裏不知家尚遠，夢回忽覺路初長。"]'),
('3bc0ebe6-57b4-4d10-b867-78a5b501fec1','夜泊平望終夕不寐三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一生行路便多愁，落得星星兩鬢秋。',32,'全唐诗/poet.song.140000.json','["一生行路便多愁，落得星星兩鬢秋。", "數盡歸程到家了，此身猶未出蘇州。"]'),
('cf740469-25c7-4981-bc6f-da44d62b22c1','小泊梅堰登明孝寺','楊萬里','宋','宋诗','song-poetry','','[]','泊船梅堰日微昇，一逕深深喚我登。',32,'全唐诗/poet.song.140000.json','["泊船梅堰日微昇，一逕深深喚我登。", "隨分垂楊兼老檜，備員野寺更殘僧。"]'),
('b08d7209-c27e-4c02-bdb6-35b03a379e65','湖州三里橋取道德清','楊萬里','宋','宋诗','song-poetry','','[]','浙西只欠到湖州，三里橋頭轉却舟。',32,'全唐诗/poet.song.140000.json','["浙西只欠到湖州，三里橋頭轉却舟。", "不到湖州妨底事，不如元不到橋頭。"]'),
('97ecb26e-8659-472a-9670-7ed360ec1fb9','宿湖甫山','楊萬里','宋','宋诗','song-poetry','','[]','夜泊湖甫山，綠楊護危堤。',132,'全唐诗/poet.song.140000.json','["夜泊湖甫山，綠楊護危堤。", "迅雷將殘雨，似猛竟復微。", "曉月解風纜，熟睡初不知。", "起來問宿處，千山翠相圍。", "霽峰有剩謁，旭溪無停輝。", "遠樹蘆外出，若與船爭馳。", "多情東林塔，寸步不相離。", "後送欣已遠，前迎復在茲。", "不知塔意厚，爲復船行遲。", "誰能仆此塔，庶不淹吾歸。", "獨感夜來雨，政作朝涼資。"]'),
('788ef489-1fd5-492b-b803-2ee26af1a3be','過霅川大溪','楊萬里','宋','宋诗','song-poetry','','[]','菰蒲際天青無邊，只堪蓮蕩不堪田。',112,'全唐诗/poet.song.140000.json','["菰蒲際天青無邊，只堪蓮蕩不堪田。", "中有一溪元不遠，摺作三百六十灣。", "政如綠錦地衣上，玉龍盤屈於其間。", "前船未轉後船隔，前灣望得到不得。", "及至前灣到得時，只與後灣纔咫尺。", "朝來已度數百縈，問知德清猶半程。", "老夫乍喜櫂夫悶，管有到時君莫問。"]'),
('b56e1df7-6ce2-40d5-b1b9-5449d58820e3','霅溪','楊萬里','宋','宋诗','song-poetry','','[]','道場山背是吳興，只不教人到德清。',32,'全唐诗/poet.song.140000.json','["道場山背是吳興，只不教人到德清。", "霅水相留別無計，却將溪曲暗添程。"]'),
('8461a5ab-c81a-4ad7-8b90-e88800b94340','春盡舍舟餘杭雨後山行二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','前夕船中索簟眠，今朝山下覺衣單。',32,'全唐诗/poet.song.140000.json','["前夕船中索簟眠，今朝山下覺衣單。", "春歸便肯平平過，須做桐花一信寒。"]'),
('c5c5ec18-108c-4255-b784-8f6c3048b62c','春盡舍舟餘杭雨後山行二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','樹樹低桑不要梯，溪溪新漲總平堤。',32,'全唐诗/poet.song.140000.json','["樹樹低桑不要梯，溪溪新漲總平堤。", "杜鵑知我歸心急，林外飛來頭上啼。"]'),
('a2ddf0f9-1c2f-42df-9636-cc029fb10203','新竹','楊萬里','宋','宋诗','song-poetry','','[]','東風弄巧補殘山，一夜吹添玉數竿。',32,'全唐诗/poet.song.140000.json','["東風弄巧補殘山，一夜吹添玉數竿。", "半脫錦衣猶半著，籜龍未信沒春寒。"]'),
('8d0a56fb-f300-433e-a3c9-ea484273804e','轎中絕句','楊萬里','宋','宋诗','song-poetry','','[]','雪洗林花頰，金挼隴麥髯。',24,'全唐诗/poet.song.140000.json','["雪洗林花頰，金挼隴麥髯。", "捲簾雙眼遠，隔樹一峰尖。"]'),
('fd0abebb-5007-4d8b-b362-632d85718acb','晨炊白昇山','楊萬里','宋','宋诗','song-poetry','','[]','千峰爲我旋生妍，我爲千峰一灑然。',64,'全唐诗/poet.song.140000.json','["千峰爲我旋生妍，我爲千峰一灑然。", "雲掠石崖啼鳥樹，雨添山澗落花泉。", "心知僮僕多饑色，目斷茅簷半穗煙。", "只道晨炊食無肉，竹根斤筍兩三錢。"]'),
('7830ec08-4108-450e-97da-e0675b5f1b16','晚憩富陽二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','苕溪到得富春灘，度綠穿青半日間。',32,'全唐诗/poet.song.140000.json','["苕溪到得富春灘，度綠穿青半日間。", "未出浙西心已喜，眼中初見浙東山。"]'),
('6c8efcc4-1a33-4618-a902-a6d89aaf8035','晚憩富陽二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','春餘客裏政無聊，忽報潮頭雪樣高。',32,'全唐诗/poet.song.140000.json','["春餘客裏政無聊，忽報潮頭雪樣高。", "急喚清空竹陵酒，旋嘗梅子與櫻桃。"]'),
('367aeb51-4e64-4a32-8801-dc3212a7b15a','富陽登舟待潮回文','楊萬里','宋','宋诗','song-poetry','','[]','山接江清江接天，老人漁釣下前灘。',32,'全唐诗/poet.song.140000.json','["山接江清江接天，老人漁釣下前灘。", "寒潮晚到風無定，船泊小灣春日殘。"]'),
('6417285f-3e62-4d47-b256-cd172b068118','小舟晚興四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','篛篷舊屋雨聲乾，蘆䕠新簷暖日眠。',32,'全唐诗/poet.song.140000.json','["篛篷舊屋雨聲乾，蘆䕠新簷暖日眠。", "枕底席邊俱綠水，脚根頭上兩青天。"]'),
('a7944203-5e16-4ed9-a578-b04e0d6fd096','小舟晚興四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','人在非晴非雨天，船行不浪不風間。',32,'全唐诗/poet.song.140000.json','["人在非晴非雨天，船行不浪不風間。", "坐來堪喜還堪恨，看得南山失北山。"]'),
('198eed71-422d-4476-b9a6-bf00d40ac2c9','小舟晚興四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','潮痕初落水猶肥，雨點纔來已復微。',32,'全唐诗/poet.song.140000.json','["潮痕初落水猶肥，雨點纔來已復微。", "半濕岸沙危欲落，牽船稚子去如飛。"]'),
('fea8968d-6c98-4b12-9151-155555a8d17f','小舟晚興四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','一船在後忽攙前，前後篙師各粲然。',32,'全唐诗/poet.song.140000.json','["一船在後忽攙前，前後篙師各粲然。", "山入春來肥更秀，向人依舊聳寒肩。"]'),
('cb6a15b8-f58a-4387-bef0-de19ebfedd5e','明發窄溪晚次嚴州','楊萬里','宋','宋诗','song-poetry','','[]','夕照落帆烏石灘，朝來解纜窄溪邊。',32,'全唐诗/poet.song.140000.json','["夕照落帆烏石灘，朝來解纜窄溪邊。", "篙師好語君知否，一日風行兩日船。"]'),
('e1c6dc45-01a4-4d7f-a0bb-cc4522ef37b7','過橫山塔下','楊萬里','宋','宋诗','song-poetry','','[]','六年三度過蘭溪，總是殘春首夏時。',32,'全唐诗/poet.song.140000.json','["六年三度過蘭溪，總是殘春首夏時。", "最感橫山山上塔，迎人東去送人西。"]'),
('da590c11-d891-4f21-a901-9c73508ee0d4','過金臺天氣頓熱三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江雲山翠借朝涼，晚日晴波挾暑光。',32,'全唐诗/poet.song.140000.json','["江雲山翠借朝涼，晚日晴波挾暑光。", "舊說長江無六月，暮春已自不禁當。"]'),
('b5aa8a1d-26f0-480e-903f-08a22518d322','過金臺天氣頓熱三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','日曬船篷四面炊，幾時却得出船時。',32,'全唐诗/poet.song.140000.json','["日曬船篷四面炊，幾時却得出船時。", "江西未到何須恨，且到三衢也自奇。"]'),
('56f33d46-61f9-42f0-a668-a473af401c1b','過金臺天氣頓熱三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','入到船中氣鬰蒸，出來船外日侵陵。',32,'全唐诗/poet.song.140000.json','["入到船中氣鬰蒸，出來船外日侵陵。", "綠波欲沸清何在，青蓋張來似不曾。"]'),
('dcc95431-84e2-4719-8537-57bc3c08d8c1','宿潭石步','楊萬里','宋','宋诗','song-poetry','','[]','三更無月天正黑，電光一掣隨霹靂。',128,'全唐诗/poet.song.140000.json','["三更無月天正黑，電光一掣隨霹靂。", "雨穿天心落篷脊，急風橫吹斜更直。", "疎篷穿漏濕床席，波聲打枕一紙隔。", "夢中驚起眠不得，攬衣危坐三嘆息。", "行路艱難非不歷，平生不曾似今夕。", "天公嚇客惡作劇，不相關白出不測。", "收風拾雨猝無策，如何乞得東方白。", "垂頭縮脚正偪仄，忽然頭上復一滴。"]'),
('de51c0c1-c1f3-4a44-ba6d-2d1cc5bb26bb','過安仁市得風挂帆二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','明發山溪一雨餘，昨來暑氣半分無。',32,'全唐诗/poet.song.140000.json','["明發山溪一雨餘，昨來暑氣半分無。", "何人道是三衢遠，挂起東風十幅蒲。"]'),
('d4f4f318-ef77-4dbd-a919-1ea2eed12621','過安仁市得風挂帆二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','西望柯山正蔚藍，衢州只在此山南。',32,'全唐诗/poet.song.140000.json','["西望柯山正蔚藍，衢州只在此山南。", "却愁路盡風猶剩，回納清風與破帆。"]'),
('02121c44-ba25-4fbf-8219-55f2ae80e65b','舟中戲題','楊萬里','宋','宋诗','song-poetry','','[]','花處青山柳處溪，新來宿處舊曾炊。',32,'全唐诗/poet.song.140000.json','["花處青山柳處溪，新來宿處舊曾炊。", "到家失却行程曆，只檢西歸小集詩。"]'),
('23bba9b2-cb81-437e-80e8-cf2feebe0405','上章戴灘','楊萬里','宋','宋诗','song-poetry','','[]','脫巾枕手仰哦詩，醉上諸灘總不知。',32,'全唐诗/poet.song.140000.json','["脫巾枕手仰哦詩，醉上諸灘總不知。", "回看他船上灘苦，方知它看我船時。"]'),
('ece2c511-67fc-4730-a030-be1bfc203a96','三月二十七日送春絕句','楊萬里','宋','宋诗','song-poetry','','[]','只餘三日便清和，儘放春歸莫恨他。',32,'全唐诗/poet.song.140000.json','["只餘三日便清和，儘放春歸莫恨他。", "落盡千花飛盡絮，留春肯住欲如何。"]'),
('9a345ff2-f153-4d82-851e-3e60e4d51220','春盡感興','楊萬里','宋','宋诗','song-poetry','','[]','春事匆匆掠眼過，落花寂寂奈愁何。',64,'全唐诗/poet.song.140000.json','["春事匆匆掠眼過，落花寂寂奈愁何。", "故人南北音書少，野渡東西芳草多。", "筍借一風爭作竹，燕分數子別成窠。", "青燈白酒長亭夜，不勝孤舟兀綠波。"]'),
('2e8da284-cfb7-4a65-8af4-ae12d4238765','四月一日三衢阻雨二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','無朝無夕雨翻盆，村北村南水接天。',32,'全唐诗/poet.song.140000.json','["無朝無夕雨翻盆，村北村南水接天。", "斷却市橋君莫笑，前頭野渡更無船。"]'),
('4c846bbc-d130-425f-8edd-0be6886b70e0','四月一日三衢阻雨二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','小詩苦雨當雲牋，寄似南風一問天。',32,'全唐诗/poet.song.140000.json','["小詩苦雨當雲牋，寄似南風一問天。", "漏得銀河乾見底，却將什麽作豐年。"]'),
('582d9c29-9f6e-4a14-ba47-6103f254293a','明發三衢三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','拔盡新秧插盡田，出城一眼翠無邊。',32,'全唐诗/poet.song.140000.json','["拔盡新秧插盡田，出城一眼翠無邊。", "不關雨水愁行客，政是年年雨水天。"]'),
('fb854bb1-f6ba-4052-a162-e510b6a03c3e','明發三衢三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','衝風破雨正愁人，愁得心情沒半分。',32,'全唐诗/poet.song.140000.json','["衝風破雨正愁人，愁得心情沒半分。", "風處吹來好消息，諸峰放散夜來雲。"]'),
('f63587bb-60cc-4f02-af66-0683c7513910','明發三衢三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雲欲開時又不開，問天覓陣好風催。',32,'全唐诗/poet.song.140000.json','["雲欲開時又不開，問天覓陣好風催。", "雨無多落泥偏滑，溪不勝深岸故頹。"]'),
('67c258fe-556d-4cf5-b009-7a4d304e938e','插秧歌','楊萬里','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u519c\u6751", "\u5199\u4eba\u8bd7"]','田夫拋秧田婦接，小兒拔秧大兒插。',64,'全唐诗/poet.song.140000.json','["田夫拋秧田婦接，小兒拔秧大兒插。", "笠是兜鍪蓑是甲，雨從頭上濕到胛。", "喚渠朝餐歇半霎，低頭折腰只不答。", "秧根未牢蒔未匝，照管鵝兒與雛鴨。"]'),
('fb8d4bda-6b81-4736-974f-dd7c11328073','明發平坦市','楊萬里','宋','宋诗','song-poetry','','[]','花霏滋曉寒，葉哢新野聽。',120,'全唐诗/poet.song.140000.json','["花霏滋曉寒，葉哢新野聽。", "萬象宿雨餘，潔齋無欠浄。", "霽曦耿欲吐，遠峰忽復暝。", "林廬居者誰，戶與碧山映。", "薔薇上木末，不架得初性。", "彼卧晏未興，我征漂靡定。", "悁然懷吾廬，花竹幽更盛。", "茲焉獨足羨，自視不差勝。", "顧瞻江之西，心速路逾夐。", "似聞前溪水，盡還舊沙徑。"]'),
('024bf0b1-f3ca-4899-a880-d153d30b75b0','晨炊江山縣驛','楊萬里','宋','宋诗','song-poetry','','[]','聞道常山水壯哉，問途何惜小紆回。',32,'全唐诗/poet.song.140000.json','["聞道常山水壯哉，問途何惜小紆回。", "平生不到江山縣，臨老須教作一來。"]'),
('7d51c86e-9241-4310-bf6e-62d419be9fae','過景星山山頂一石孤立又名突星山','楊萬里','宋','宋诗','song-poetry','','[]','山頭孤立玉竛𥪁，天上何年墮景星。',32,'全唐诗/poet.song.140000.json','["山頭孤立玉竛𥪁，天上何年墮景星。", "四面萬峰非不峻，如何只是一峰青。"]'),
('ac86b228-e78d-4080-a234-12a24117f38b','江山道中蠶麥大熟三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','衢信中央兩盡頭，蠶麰今歲十分收。',32,'全唐诗/poet.song.140000.json','["衢信中央兩盡頭，蠶麰今歲十分收。", "穗初黄後枝無綠，不但麥秋桑亦秋。"]'),
('19c12e1f-2c46-4708-b8b0-666ae51b4204','江山道中蠶麥大熟三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','黄雲割露幾肩歸，紫玉炊香一飯肥。',32,'全唐诗/poet.song.140000.json','["黄雲割露幾肩歸，紫玉炊香一飯肥。", "却破麥田秧晚稻，未教水牯卧斜暉。"]'),
('6be78317-4dcd-4aac-97ff-a3de27facaa3','江山道中蠶麥大熟三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','新晴戶戶有歡顔，曬繭攤絲立地乾。',32,'全唐诗/poet.song.140000.json','["新晴戶戶有歡顔，曬繭攤絲立地乾。", "却遣繰車聲獨怨，今年不及去年閑。"]'),
('baffba86-f3cf-46be-b9de-00aff7ceb47e','午憩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嫩綠桐陰夾道遮，爛紅野果壓枝斜。',32,'全唐诗/poet.song.140000.json','["嫩綠桐陰夾道遮，爛紅野果壓枝斜。", "日烘細草香無價，況有三枝兩朶花。"]'),
('aed080da-2b93-451b-96ac-0d0abe285c20','午憩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','晴邊雨後麥秋時，風色輕輕日色微。',32,'全唐诗/poet.song.140000.json','["晴邊雨後麥秋時，風色輕輕日色微。", "已隔深溪仍蘸水，却教人折野薔薇。"]'),
('925b4bed-5145-4653-99e5-275245c475a7','過髦塘渡','楊萬里','宋','宋诗','song-poetry','','[]','雪浪無堅岸，金沙有退痕。',48,'全唐诗/poet.song.140000.json','["雪浪無堅岸，金沙有退痕。", "斷橋猶半板，漱樹欲枯根。", "爲問新來漲，今年第幾番。", "昨來愁此渡，已濟不堪論。"]'),
('701cf49d-0e5d-4562-b160-0f199ce5918c','江郎峰三石山在江山縣南三十五里禮賢鎮望之極正里人又呼爲郎峰','楊萬里','宋','宋诗','song-poetry','','[]','走徧名山脚不停，見渠令我眼偏明。',32,'全唐诗/poet.song.140000.json','["走徧名山脚不停，見渠令我眼偏明。", "郎峰好處端何似，筍剝三竿紫水精。"]'),
('05c41108-15f0-4665-a58e-4c1a0ee96669','轎中望泛仙山','楊萬里','宋','宋诗','song-poetry','','[]','上却籃輿卷却簾，曉寒旋索熟衣添。',32,'全唐诗/poet.song.140000.json','["上却籃輿卷却簾，曉寒旋索熟衣添。", "孤松已自三千丈，更在仙山第一尖。"]'),
('3dcf4b78-a298-4d4f-b100-cf29db38eef2','度小橋','楊萬里','宋','宋诗','song-poetry','','[]','危橋度中半，深溪動人心。',48,'全唐诗/poet.song.140000.json','["危橋度中半，深溪動人心。", "欲返業至此，將進眩下臨。", "已涉尚回顧，溪水知幾深。", "誰能大此橋，以安往來人。"]'),
('a4564311-f25b-4831-a9c4-695362baaf88','小憩二龍爭珠蓋兩長嶺夾一圜峰故名自此出官路入山路云','楊萬里','宋','宋诗','song-poetry','','[]','田路直復縈，肩輿斜還正。',132,'全唐诗/poet.song.140000.json','["田路直復縈，肩輿斜還正。", "如何晴三日，猶自滑一徑。", "缺岸有危踐，方軫無穩興。", "不跌先獨驚，稍坦深自慶。", "肯信坐者安，不及行者病。", "昨來九軌塗，可思不可更。", "忽逢兩蒼虬，爭此一照乘。", "頗欲問故老，雙爭誰孤勝。", "水聲亂人語，一辭無真聽。", "輕風泛秧疇，衆綠久未定。", "崎嶇從此始，辛苦何時竟。"]'),
('4621ec95-cded-4e90-9877-708ae70c51f5','早炊楊家塘','楊萬里','宋','宋诗','song-poetry','','[]','枯樹藤爲葉，遥峰石作鬟。',48,'全唐诗/poet.song.140000.json','["枯樹藤爲葉，遥峰石作鬟。", "如何每行路，不勸自加餐。", "浙界殘零處，江東咫尺間。", "炊煙戀茅店，飛出却飛還。"]'),
('99eb69f9-fd2e-492b-ace0-ca6d7cdf62f3','四月四日午初出浙東界入信州永豐界','楊萬里','宋','宋诗','song-poetry','','[]','外面千峰合，中間一逕通。',48,'全唐诗/poet.song.140000.json','["外面千峰合，中間一逕通。", "日光自摇水，天靜本無風。", "村酒渟春綠，林花倦午紅。", "莫欺山堠子，知我入江東。"]'),
('84e388c2-f5e1-4ced-8095-f8c35de102d5','過蘇巖','楊萬里','宋','宋诗','song-poetry','','[]','仰望蒼巖高更深，巖中佳處著禪林。',32,'全唐诗/poet.song.140000.json','["仰望蒼巖高更深，巖中佳處著禪林。", "瓊泉萬仞峰頭落，一滴泉聲一醒心。"]'),
('8814c132-b4ff-48d6-914f-ce59d0f938b0','松陰小憩','楊萬里','宋','宋诗','song-poetry','','[]','不但先生倦不蘇，僕夫也自要人扶。',32,'全唐诗/poet.song.140000.json','["不但先生倦不蘇，僕夫也自要人扶。", "青松數了還重數，只是從前八九株。"]'),
('d1983043-c8f4-4b9b-bec8-8b521315aee5','宿靈鷲禪寺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','暑中带汗入山中，霜滿風篁雪滿松。',32,'全唐诗/poet.song.140000.json','["暑中带汗入山中，霜滿風篁雪滿松。", "只是山寒清到骨，也無霜雪也無風。"]'),
('5f0802c3-d98f-4c24-9a53-311a511e056f','宿靈鷲禪寺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','初疑夜雨忽朝晴，乃是山泉終夜鳴。',32,'全唐诗/poet.song.140000.json','["初疑夜雨忽朝晴，乃是山泉終夜鳴。", "流到前溪無半語，在山做得許多聲。"]'),
('c17f86aa-db37-438b-8590-28c13ad984cf','初五日曉寒浙人謂之蠶寒蓋麥秋寒也','楊萬里','宋','宋诗','song-poetry','','[]','歲歲春寒欲去時，麥牽蠶惹不教歸。',32,'全唐诗/poet.song.140000.json','["歲歲春寒欲去時，麥牽蠶惹不教歸。", "早知今曉猶差冷，未肯疎它舊裌衣。"]'),
('2505bca8-5f99-494d-82ba-22a683af7f7e','道傍小憩觀物化','楊萬里','宋','宋诗','song-poetry','','[]','蝴蝶新生未解飛，鬚拳粉濕睡花枝。',32,'全唐诗/poet.song.140000.json','["蝴蝶新生未解飛，鬚拳粉濕睡花枝。", "後來借得風光力，不記如癡似醉時。"]'),
('08103b78-540c-43d7-96d7-9888f6bd98d5','山行','楊萬里','宋','宋诗','song-poetry','','[]','山行兩日厭荒涼，田少山多多更長。',32,'全唐诗/poet.song.140000.json','["山行兩日厭荒涼，田少山多多更長。", "一望不曾虧碧草，半分何似借青秧。"]'),
('680896d5-4402-47e5-b36a-9976848665c9','晨炊玉田聞鶑觀鷺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','曉寒顧影惜金衣，著意聽時不肯啼。',32,'全唐诗/poet.song.140000.json','["曉寒顧影惜金衣，著意聽時不肯啼。", "飛入柳陰多去處，數聲只許落花知。"]'),
('d45a52dd-2ad8-4100-8a59-d0e7a1e5f0aa','晨炊玉田聞鶑觀鷺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','清溪欲下影先翻，隻鷺還將雙鷺看。',32,'全唐诗/poet.song.140000.json','["清溪欲下影先翻，隻鷺還將雙鷺看。", "綠玉脛長聊試淺，素瓊裳冷不禁寒。"]'),
('735fd1e5-7fbd-4b8a-b198-243842d3e9bb','過石磨嶺嶺皆創爲田直至其頂','楊萬里','宋','宋诗','song-poetry','','[]','翠带千鐶束翠巒，青梯萬級搭青天。',32,'全唐诗/poet.song.140000.json','["翠带千鐶束翠巒，青梯萬級搭青天。", "長淮見說田生棘，此地都將嶺作田。"]'),
('76386bf3-35dd-4f7a-88ed-5e3077026617','將至永豐縣','楊萬里','宋','宋诗','song-poetry','','[]','清和天氣半陰晴，下轎携筇取次行。',32,'全唐诗/poet.song.140000.json','["清和天氣半陰晴，下轎携筇取次行。", "不奈永豐山色好，雲窺霧看未分明。"]'),
('b6316bfd-a351-4d3d-80aa-4f50ecc0893a','永豐驛逢故人趙伯庭過叔','楊萬里','宋','宋诗','song-poetry','','[]','同官贛水總青春，消息中間兩不聞。',32,'全唐诗/poet.song.140000.json','["同官贛水總青春，消息中間兩不聞。", "道我未衰君莫戲，不須看我只看君。"]'),
('90dcf06a-dd89-4ad1-abe7-ddf04bb9605f','出永豐縣西石橋上聞子規二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','花愁月恨只長啼，雨夕風晨不住飛。',32,'全唐诗/poet.song.140000.json','["花愁月恨只長啼，雨夕風晨不住飛。", "自出錦江歸未得，至今猶勸別人歸。"]'),
('3c18909f-0088-484a-b92d-11289e7a0b29','出永豐縣西石橋上聞子規二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','怨笛哀箏總不如，一聲聲徹九天虛。',32,'全唐诗/poet.song.140000.json','["怨笛哀箏總不如，一聲聲徹九天虛。", "若逢雨夜如何聽，幸得花時莫管渠。"]'),
('ba90b88c-20f9-4626-982e-41b62eae0bc7','入上饒界道中野酴醾盛開二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','千朶齊開雪面皮，一芽初長紫蘭枝。',32,'全唐诗/poet.song.140000.json','["千朶齊開雪面皮，一芽初長紫蘭枝。", "一芽來歲還千朶，誰見開花似雪時。"]'),
('111a99af-9f73-455e-aa65-8616140841ee','入上饒界道中野酴醾盛開二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','走上松梢繞却它，爲它滿插一頭花。',32,'全唐诗/poet.song.140000.json','["走上松梢繞却它，爲它滿插一頭花。", "未論似得酴醾否，且是幽香野得些。"]'),
('1c7c2265-00ad-4e74-a0c8-4ae0df8b8d4c','憩冷水村道傍榴花初開','楊萬里','宋','宋诗','song-poetry','','[]','蒨羅縐薄剪薰風，已自花明蔕亦同。',32,'全唐诗/poet.song.140000.json','["蒨羅縐薄剪薰風，已自花明蔕亦同。", "不肯染時輕著色，却將密綠護深紅。"]'),
('281164cb-0ec4-4ba5-949d-07514fb3ebab','晚雲釀雨二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','昨來一雨斷人行，恰則晴時雲又生。',32,'全唐诗/poet.song.140000.json','["昨來一雨斷人行，恰則晴時雲又生。", "梅月如何休得雨，麥秋却是要它晴。"]'),
('9032775a-31da-4814-90ca-8416e0e165a9','晚雲釀雨二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','只消舊雨已驚心，莫遣新晴更作陰。',32,'全唐诗/poet.song.140000.json','["只消舊雨已驚心，莫遣新晴更作陰。", "路轉綠荷仍翠柳，眼隨白鳥度青林。"]'),
('808c2804-c966-4777-87ec-f4cb5fbc8278','詩情','楊萬里','宋','宋诗','song-poetry','','[]','只要琱詩不要名，老來也復減詩情。',32,'全唐诗/poet.song.140000.json','["只要琱詩不要名，老來也復減詩情。", "虛名滿世真何用，更把虛名賺後生。"]'),
('0844cd68-5e48-4cd9-b596-b56feefce7e3','四月十三日度鄱陽湖','楊萬里','宋','宋诗','song-poetry','','[]','泊舟番君湖，風雨至夜半。',192,'全唐诗/poet.song.140000.json','["泊舟番君湖，風雨至夜半。", "求濟敢自必，苟安固所願。", "孤愁知無益，暫忍復永歎。", "夜久忽自睡，倦極不知旦。", "舟人呼我起，順風不容緩。", "半篙已湖心，一葉恰鏡面。", "仰見雲衣開，側視帆腹滿。", "天如瑠璃鍾，下覆水晶椀。", "波光金汁瀉，日影銀柱貫。", "康山杯中蛭，廬阜帆前幔。", "豁然地無蔕，渺若海不岸。", "是身若虛空，御氣遊汗漫。", "初憂觸危濤，不意拾奇觀。", "近歲六暄涼，此水三往返。", "未涉每不寧，既濟輒復玩。", "游倦當自歸，非爲猿鶴怨。"]'),
('5bc96630-5f04-4c38-86ff-07193bc8c37a','已至湖尾望見西山三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','好風穩送五湖船，萬頃銀濤半霎間。',32,'全唐诗/poet.song.140000.json','["好風穩送五湖船，萬頃銀濤半霎間。", "已入江西猶未覺，忽然對面是西山。"]'),
('1c8c0e55-7e13-44a0-a0db-4f1836ae25c5','已至湖尾望見西山三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','蘆荻中間一港深，蔞蒿如柱不成簪。',32,'全唐诗/poet.song.140000.json','["蘆荻中間一港深，蔞蒿如柱不成簪。", "正愁半日無村落，遠有人家在樹林。"]'),
('56006ead-8f0d-4342-a93f-90145ed87d01','已至湖尾望見西山三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','千里都無半點山，如何敢望有人煙。',32,'全唐诗/poet.song.140000.json','["千里都無半點山，如何敢望有人煙。", "不教遠樹遮攔却，蘆荻生來直到天。"]'),
('18978d13-11f5-4b67-a60c-82e7045bde3c','送鄉余文明勸之以歸','楊萬里','宋','宋诗','song-poetry','','[]','一別高人又十年，霜筋雪骨健依然。',64,'全唐诗/poet.song.140000.json','["一別高人又十年，霜筋雪骨健依然。", "席門未害車多轍，斗酒尚能詩百篇。", "蒼狗白衣俱昨夢，長庚孤月自青天。", "故山松菊平安在，何日歸歟解釣船。"]'),
('cc4d8923-07bd-47c8-abca-c8bfb056cd8d','送王季山主簿省覲樞府','楊萬里','宋','宋诗','song-poetry','','[]','六館名流王季山，十年風雨短檠寒。',64,'全唐诗/poet.song.140000.json','["六館名流王季山，十年風雨短檠寒。", "不曾文字饒羣子，勉爲庭闈就一官。", "伯也騰身紫極上，叔兮著眼白雲端。", "會當再奏河東賦，姓字從頭揭牓看。"]'),
('0081cb58-348f-4b52-884a-64e25172e676','豫章光華館苦雨','楊萬里','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','阻水水不退，苦雨雨不收。',108,'全唐诗/poet.song.140000.json','["阻水水不退，苦雨雨不收。", "天不遣人行，我豈願此留。", "客間亦何娛，勝踐或銷憂。", "西山天下奇，東湖塵外幽。", "駕言欲一往，雨濕且復休。", "懷哉滕王閣，咫尺城南陬。", "舉武便可至，登臨亦無由。", "平陸幻成海，高屋瞬失樓。", "南浦水正長，何時放歸舟。"]'),
('886bef3e-0bc2-4cc8-bb27-a9f9d30f4fb5','葉教授鎬乃翁致政一百三歲屢加封仍錫朱銀取告命之詞名其堂曰介壽','楊萬里','宋','宋诗','song-poetry','','[]','蘭玉初攀桂，朱銀降自天。',48,'全唐诗/poet.song.140000.json','["蘭玉初攀桂，朱銀降自天。", "堂中有一老，物外百三年。", "紫誥行充棟，霜毛儘滿顛。", "仁人元自壽，端不羨臞仙。"]'),
('420a3098-b090-46cd-a38d-bf934a7e8ca4','秋蟲','楊萬里','宋','宋诗','song-poetry','','[]','蟬哀落日恰纔收，蛩怨黄昏正未休。',32,'全唐诗/poet.song.140000.json','["蟬哀落日恰纔收，蛩怨黄昏正未休。", "催得世人頭總白，不知替得二蟲愁。"]'),
('da946177-85df-448a-bfa7-27a74106edd0','病中感秋時初喪壽佺子','楊萬里','宋','宋诗','song-poetry','','[]','臨曉睡偏重，不知窗已明。',48,'全唐诗/poet.song.140000.json','["臨曉睡偏重，不知窗已明。", "高梧下清露，宿鳥有寒聲。", "愁豈關鬚事，秋來添雪莖。", "病身仍哭子，併作老來情。"]'),
('1894b0ef-bb05-4ee0-824e-7290d8927943','秋熱二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','多難幽懷慘不舒，秋風殘暑掃難除。',32,'全唐诗/poet.song.140000.json','["多難幽懷慘不舒，秋風殘暑掃難除。", "一生最怕西窗日，長是酴醾架子疎。"]'),
('2df7cf31-4fec-4010-8673-d5221d54281d','秋熱二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','年年極暑與秋期，日日秋陽在暮時。',32,'全唐诗/poet.song.140000.json','["年年極暑與秋期，日日秋陽在暮時。", "我自愁吟無意思，蟬聲移近入簷枝。"]'),
('a7948bf2-7595-492d-bcf5-931d1554bf64','夜坐','楊萬里','宋','宋诗','song-poetry','','[]','夜永留清坐，詩臞稱病容。',48,'全唐诗/poet.song.140000.json','["夜永留清坐，詩臞稱病容。", "溪鳴風處竹，月濕露中松。", "喜事何曾夢，燈花誑殺儂。", "欲歸歸已得，歸得却無悰。"]'),
('50bc5252-7b3b-4a9a-add9-6c8b5982cfaa','中秋病中不飲二首後一首用轆轤體  其一','楊萬里','宋','宋诗','song-poetry','','[]','去年兩浙浙西州，今夕南溪溪上頭。',64,'全唐诗/poet.song.140000.json','["去年兩浙浙西州，今夕南溪溪上頭。", "滿著玻瓈一盆水，洗開玉鏡十分秋。", "病來不飲非無酒，老去追驩總是愁。", "自笑獨醒仍苦詠，枯腸雷轉不禁搜。"]'),
('fd497ccb-625a-4dda-b453-238d7b45eda1','中秋病中不飲二首後一首用轆轤體  其二','楊萬里','宋','宋诗','song-poetry','','[]','無風無雨併無雲，今歲中秋儘十分。',64,'全唐诗/poet.song.140000.json','["無風無雨併無雲，今歲中秋儘十分。", "畢竟冰輪誰爲轉，碾穿玉宇不生痕。", "坐看兒輩紛然飲，也遣先生半欲醺。", "自是清樽負明月，不關明月負清樽。"]'),
('2aec798b-20ed-4060-86a2-40113f4fcddb','中秋月長句','楊萬里','宋','宋诗','song-poetry','','[]','西山走下丹砂丸，東山飛上黄金盤。',160,'全唐诗/poet.song.140000.json','["西山走下丹砂丸，東山飛上黄金盤。", "徑從碧海昇青天，半濕尚带波濤痕。", "初輝淡淡寒不動，月華猶輕桂華重。", "黄羅團扇暗花紋，蹙金突起雙龍鳳。", "須臾正面天中央，銀鉦退盡向來黄。", "乾坤鎔入冰壺裏，萬象都無只有光。", "平生愛月愛今夕，古人與我同此癖。", "去年中秋天漆黑，今年中秋月雪白。", "先生舊不論升斗，近來畏病不飲酒。", "月下醒眼搔白首，明年月似今宵否。"]'),
('60a551d7-6aef-4de8-ae4b-3c0173586c54','秋雨初霽','楊萬里','宋','宋诗','song-poetry','','[]','松竹陰寒分外蒼，芭蕉花濕夢中香。',64,'全唐诗/poet.song.140000.json','["松竹陰寒分外蒼，芭蕉花濕夢中香。", "抽身朱墨塵埃裏，入眼山林氣味長。", "今日更無秋熱去，曉晴猶带雨餘涼。", "却將白髮三千丈，繰作霜絲補錦囊。"]'),
('a1594c6c-824b-4f0f-bb4c-43cd00ca6403','子上弟折贈木犀數枝走筆謝之','楊萬里','宋','宋诗','song-poetry','','[]','我家殊未有秋色，君家先得秋消息。',96,'全唐诗/poet.song.140000.json','["我家殊未有秋色，君家先得秋消息。", "西風夜入小池塘，木犀漏洩月中香。", "一粒粟中香萬斛，君看一梢幾金粟。", "門前雙桂更作門，路人知是幽人屋。", "數枝寄我開愁眉，欲狀黄香無好詩。", "君到廣寒折一枝，香無兩般君自知。"]'),
('e35fda97-403e-46ec-a466-6596509fff58','西齋舊無竹予歸自毗陵齋前忽有竹滿庭蓋牆外之竹迸逸而生此也喜而賦之','楊萬里','宋','宋诗','song-poetry','','[]','平生取友孤竹君，館之山崦與卜鄰。',176,'全唐诗/poet.song.140000.json','["平生取友孤竹君，館之山崦與卜鄰。", "風衿月珮霜雪身，只談風節不論文。", "我開西齋對清潤，每嫌隔窗不相近。", "別來桃李一再花，我長在外君在家。", "歸來西齋掛窗處，此君忽在窗前住。", "繞牆檢校無來路，此君來路從何許。", "向來先生初出去，遣猿看牆鶴看戶。", "如何鶴睡眼未開，此君一夜過牆來。", "明朝穉子滿庭砌，豹文玉骨龍苗裔。", "春風吹墮錦衣裳，仰看青士冠劍長。", "先生豈惜窗前地，與君同醒復同醉。"]'),
('6c62e89b-a988-45d7-ac4c-e0af8f4e8ef5','病後覺衰','楊萬里','宋','宋诗','song-poetry','','[]','病著初無惱，安來始覺衰。',48,'全唐诗/poet.song.140000.json','["病著初無惱，安來始覺衰。", "人誰長健底，老有頓來時。", "山意淒寒日，秋光染瘦詩。", "小松能許劣，學我弄吟髭。"]'),
('addf54ea-5b8c-44ea-84c0-82d62bba2ab4','昨日訪子上不遇裴回庭砌觀木犀而歸再以七言乞數枝','楊萬里','宋','宋诗','song-poetry','','[]','昨携兒輩扣雲關，繞遍巖花恣意看。',64,'全唐诗/poet.song.140000.json','["昨携兒輩扣雲關，繞遍巖花恣意看。", "苔砌落深金布地，水沉烝透粟堆盤。", "寄詩北阮賒秋色，供我西窗當晚餐。", "小朶出叢須折却，莫教折破碧團欒。"]'),
('ccc8e9c9-2226-48a9-986f-81cbbfa743ea','芭蕉三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','骨相玲瓏透八窗，花頭倒挂紫荷香。',32,'全唐诗/poet.song.140000.json','["骨相玲瓏透八窗，花頭倒挂紫荷香。", "繞身無數青羅扇，風不來時也不涼。"]'),
('1ef84d18-191b-468b-8889-17d073acb362','芭蕉三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','蕭蕭灑灑復婷婷，一半風流一半清。',32,'全唐诗/poet.song.140000.json','["蕭蕭灑灑復婷婷，一半風流一半清。", "不爲暑窗添午蔭，却來愁枕作秋聲。"]'),
('67253915-77be-4d77-aed4-da8fb2a18d0e','芭蕉三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','簷牙窗額兩三株，只欠王維畫雪圖。',32,'全唐诗/poet.song.140000.json','["簷牙窗額兩三株，只欠王維畫雪圖。", "開卷不題元字脚，碧窗圜蠟有如無。"]'),
('2439afa5-24cf-4955-8725-ab169e8e00ea','拒霜花','楊萬里','宋','宋诗','song-poetry','','[]','木蕖何似水芙蕖，同箇聲名各自都。',64,'全唐诗/poet.song.140000.json','["木蕖何似水芙蕖，同箇聲名各自都。", "風露商量借膏沐，燕脂深淺入肌膚。", "喚回春色秋光裏，饒得紅妝翠蓋無。", "字曰拒霜渾不惡，却愁霜重要人扶。"]'),
('92d6e92c-156c-408c-9c7c-2e77c4473d44','不寐四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老來只願酒難醒，酒力纔醒夢便驚。',64,'全唐诗/poet.song.140000.json','["老來只願酒難醒，酒力纔醒夢便驚。", "露滴新寒欺病骨，宦游如夢記平生。", "深山五鼓雞吹角，落月一窗鵝打更。", "等待曉光琱好句，曉光未白句先成。"]'),
('16cadac7-ca10-4ac6-91a0-7e386ad2eda3','不寐四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','非關枕上愛哦詩，聊復銷愁片子時。',64,'全唐诗/poet.song.140000.json','["非關枕上愛哦詩，聊復銷愁片子時。", "老眼强眠終不夢，空腸暗響訴長饑。", "翻來覆去體都痛，乍暗忽明燈爲誰。", "只道晝長無那著，夜長難奈不曾知。"]'),
('0f3cad01-bb46-4af8-b90d-098a354b433d','不寐四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','暗蟲夜啼不肯停，直從黄昏啼到明。',64,'全唐诗/poet.song.140000.json','["暗蟲夜啼不肯停，直從黄昏啼到明。", "不知討論底事著，爲復怨嗟誰子生。", "至竟通宵千萬語，真實只是兩三聲。", "唧唧唧唧復唧唧，此外何言君試聽。"]'),
('6ca2db8c-8b8b-40ca-ba48-1f7af4d96df8','不寐四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','初聞一犬兩犬聲，次第遠近雞都鳴。',64,'全唐诗/poet.song.140000.json','["初聞一犬兩犬聲，次第遠近雞都鳴。", "今夕明朝何日了，南村北巷幾人行。", "忽思春雨宿茅店，最苦僕夫催去程。", "是時懶起惜殘睡，如今不眠愁獨醒。"]'),
('c1982ddc-4843-44d3-b7b7-4220f5c3758c','寄題保靜庵','楊萬里','宋','宋诗','song-poetry','','[]','洙泗九淵閟玄珠，沒人下取龍怒鬚。',112,'全唐诗/poet.song.140000.json','["洙泗九淵閟玄珠，沒人下取龍怒鬚。", "迂叟勃興章甫徒，刺手一探珠炯如。", "正心保躬四顆餘，一顆光照千乘車。", "艮齋豎起麈拂子，保靜居士一笑喜。", "試著此珠狂波底，波自拍天珠在水。", "江南江北起秋風，庵前庵後吹霜松。", "居士焚香於其中，手揮五絃送歸鴻。"]'),
('2c2ea5bc-2adf-449c-81ca-c50df70624f9','戲題常州草蟲枕屏','楊萬里','宋','宋诗','song-poetry','','[]','黄蜂作歌紫蝶舞，蜻蜓蚱蜢如風雨。',80,'全唐诗/poet.song.140000.json','["黄蜂作歌紫蝶舞，蜻蜓蚱蜢如風雨。", "先生晝眠紙帳溫，無那此輩喧夢魂。", "眼中了了華胥國，蜂催蝶喚到不得。", "覺來忽見四摺屏，野花紅白野草青。", "勾引飛蟲作許聲，何緣先生睡不驚。"]'),
('61ee551b-e9b3-49a4-99ca-1e70311ac293','子上持豫章畫扇其上牡丹三株黄白相間盛開一貓將二子戲其旁','楊萬里','宋','宋诗','song-poetry','','[]','暄風暖景政春遲，開盡好花人未知。',32,'全唐诗/poet.song.140000.json','["暄風暖景政春遲，開盡好花人未知。", "輸與狸奴得春色，牡丹香裏弄雙兒。"]'),
('886404cb-70c3-419d-adf5-a9873693c900','和李與賢投贈之韻','楊萬里','宋','宋诗','song-poetry','','[]','雲海不教鵬怒飛，玉階也合鳳來儀。',64,'全唐诗/poet.song.140000.json','["雲海不教鵬怒飛，玉階也合鳳來儀。", "如何天下李元禮，未遇人間鍾子期。", "夜誦子虛無路達，夢生春草只心知。", "願君更奏三千牘，金榜青衫染柳絲。"]'),
('058d4caa-3c6c-4525-b02d-2e5e5f226070','李與賢來訪自言所居幽勝甚似剡溪因以似剡名其庵出閑居五詠因次其韻五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','玉壺冰段露金莖，未抵閑居五詠清。',32,'全唐诗/poet.song.140000.json','["玉壺冰段露金莖，未抵閑居五詠清。", "休道曹詩成七步，不須三步已詩成。"]'),
('7dfdb809-02d1-4aab-a4a6-ce02f42148b6','李與賢來訪自言所居幽勝甚似剡溪因以似剡名其庵出閑居五詠因次其韻五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山似剡溪溪似油，人如詩句句如秋。',32,'全唐诗/poet.song.140000.json','["山似剡溪溪似油，人如詩句句如秋。", "無邊春裏花饒笑，有底忙時草喚愁。"]'),
('0353c63e-5482-4a03-af11-06e6644c0d27','李與賢來訪自言所居幽勝甚似剡溪因以似剡名其庵出閑居五詠因次其韻五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','溪上新橋是鳳林，殘風剩雨做秋陰。',32,'全唐诗/poet.song.140000.json','["溪上新橋是鳳林，殘風剩雨做秋陰。", "先生小試南風手，寫得一川山水音。"]'),
('ab3d6fb4-4d71-48b7-9f90-7a05ffe75b72','李與賢來訪自言所居幽勝甚似剡溪因以似剡名其庵出閑居五詠因次其韻五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','見說幽居繞萬松，栽梅能白杏能紅。',32,'全唐诗/poet.song.140000.json','["見說幽居繞萬松，栽梅能白杏能紅。", "人行剡曲溪山裏，家住輞川圖畫中。"]'),
('6c2419e4-9a47-4ae1-9e22-6496acbdfb02','李與賢來訪自言所居幽勝甚似剡溪因以似剡名其庵出閑居五詠因次其韻五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','漫浪江湖天一方，故人不見兩三霜。',32,'全唐诗/poet.song.140000.json','["漫浪江湖天一方，故人不見兩三霜。", "對床說盡平生話，黄葉聲中秋夜長。"]'),
('7184c061-543a-43d8-b76a-93705228d591','寄題李與賢似剡庵','楊萬里','宋','宋诗','song-poetry','','[]','四明狂客一茅屋，敕賜剡川纔一曲。',163,'全唐诗/poet.song.140000.json','["四明狂客一茅屋，敕賜剡川纔一曲。", "安福詩人李與賢，大書似剡山扉前。", "我曾著脚勾踐國，奉詔昭陵省松柏。", "是時八月欲半頭，鏡湖不是人間秋。", "稽山影落水精闕，荷花露滴波中月。", "季真茅屋荒蒼苔，古木哀猿啼禹穴。", "今君結屋阿那邊，疋似剡川若箇言。", "我到剡川君未到，似和不似然不然。", "君不見興公舊草天台賦，元不曾識天台路。", "一俛仰間已再升，何用瘦藤與芒屨。"]'),
('636fc640-323b-4275-8673-a4d6b873dcc7','試蜀中梁杲桐煙墨書玉板紙','楊萬里','宋','宋诗','song-poetry','','[]','木犀煮泉漱寒齒，殘滴更將添硯水。',88,'全唐诗/poet.song.140000.json','["木犀煮泉漱寒齒，殘滴更將添硯水。", "子規鄉裏桐花煙，浣花溪頭瓊葉紙。", "先生老去怯苦吟，琢無肝肺嘔無心。", "芙蓉在左木犀右，漫與七言真藉手。", "秋光一點入骨清，有筆如椽描不就，先生不瘦教誰瘦。"]'),
('96ea1b77-04cf-4cb0-a0b6-d658de92ffa2','蕙花初開五言','楊萬里','宋','宋诗','song-poetry','','[]','幽人非愛山，出山將何之。',156,'全唐诗/poet.song.140000.json','["幽人非愛山，出山將何之。", "山居種蘭蕙，歲寒久當知。", "初藝止百畝，餘地惜奚爲。", "先生無廣居，千巖一茅茨。", "四面祇藝蕙，中間纔置錐。", "銳綠紛宿叢，脩紫擢幼枝。", "孤榦八九花，一花破初蕤。", "西風澹無味，微度成香吹。", "燈夢得幽馥，月寫傳靜姿。", "我欲掇芳英，和露充晨炊。", "眷然惻不忍，環翫自忘饑。", "豈無衆花草，不願秋不遲。", "種時亂不擇，歲晚悔可追。"]'),
('5a39d336-bae4-445e-b7db-989c2942bca5','木犀落盡有感二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一歲秋香又一空，落英顦顇怨西風。',32,'全唐诗/poet.song.140000.json','["一歲秋香又一空，落英顦顇怨西風。", "開時占斷西風曉，豈念荷花脫病紅。"]'),
('82920a9e-7694-4344-8a7b-60f99ae3f29e','木犀落盡有感二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','姮娥收去廣寒秋，太息花中無此流。',32,'全唐诗/poet.song.140000.json','["姮娥收去廣寒秋，太息花中無此流。", "花品已高香更絕，却緣韻勝得清愁。"]'),
('4d5299ca-bb5e-44ab-843c-58e89e495496','秋蠅','楊萬里','宋','宋诗','song-poetry','','[]','秋蠅知我政哦詩，得得緣眉復入髭。',32,'全唐诗/poet.song.140000.json','["秋蠅知我政哦詩，得得緣眉復入髭。", "欲打群飛還歇去，風光乞與幾多時。"]'),
('2c6f1628-0bbd-407a-b424-bbb98b52afbe','白魚羹戲題','楊萬里','宋','宋诗','song-poetry','','[]','秋水寒魚白錦鱗，薑花棖實獻芳辛。',32,'全唐诗/poet.song.140000.json','["秋水寒魚白錦鱗，薑花棖實獻芳辛。", "東坡玉糝真窮相，得似先生此味珍。"]'),
('f5d27106-fbb5-4dd2-8909-a4143ee0fbee','松聲','楊萬里','宋','宋诗','song-poetry','','[]','哦詩口角恰微鳴，喚得風從月脇生。',32,'全唐诗/poet.song.140000.json','["哦詩口角恰微鳴，喚得風從月脇生。", "端爲先生醒醉耳，繞山搜出萬松聲。"]'),
('1d4c37dc-4ea1-48ed-ac10-905b8427efa4','寄題邵武張漢傑運幹萬卷樓','楊萬里','宋','宋诗','song-poetry','','[]','書生都將命乞書，願身化作蠹書魚。',98,'全唐诗/poet.song.140000.json','["書生都將命乞書，願身化作蠹書魚。", "蠹魚生得針來大，日啖銀鈎三萬箇。", "書生一腹無十圍，經炊史酌不曾饑。", "君家一編本黄石，積書至今與山齊。", "玉川搜腸纔一半，鄴侯插架端無羨。", "如何萬卷樓上人，却去黄鶴樓前作賓贊。"]'),
('4b8b3c3e-6c4d-40b4-9dd0-ed4df25cee4a','戲筆二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','野菊荒苔各鑄錢，金黄銅綠兩爭妍。',32,'全唐诗/poet.song.140000.json','["野菊荒苔各鑄錢，金黄銅綠兩爭妍。", "天公支與窮詩客，只買清愁不買田。"]'),
('964aad8c-de59-4407-afc7-0c4d777f2175','戲筆二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','哦詩只道更無題，物物秋來總是詩。',32,'全唐诗/poet.song.140000.json','["哦詩只道更無題，物物秋來總是詩。", "著意染鬚玄尚白，梳頭得蝨素成緇。"]'),
('32d49dc8-73cc-45c0-8159-d45248f046b0','飯罷散策遇細雨二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','秋暄團扇尚堪携，病脚朝來健似飛。',32,'全唐诗/poet.song.140000.json','["秋暄團扇尚堪携，病脚朝來健似飛。", "偶到溪頭晴喚出，未窮山頂雨催歸。"]'),
('2602811c-54d7-4a83-bf1b-c057d7aed704','飯罷散策遇細雨二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','極知秋旱已難醫，所喜陰雲忽四垂。',32,'全唐诗/poet.song.140000.json','["極知秋旱已難醫，所喜陰雲忽四垂。", "畢竟不成簷半滴，辛勤枉費雨千絲。"]'),
('eb56b8c8-8335-4035-ae90-09a6ad82585c','重九日雨仍菊花未開用轆轤體','楊萬里','宋','宋诗','song-poetry','','[]','良辰巧與賞心違，四者能并自古稀。',64,'全唐诗/poet.song.140000.json','["良辰巧與賞心違，四者能并自古稀。", "恰則今年重九日，也無黄菊兩三枝。", "閉門幸免吹烏帽，有酒何須望白衣。", "政坐滿城風雨句，平生不喜老潘詩。"]'),
('5387dd04-9212-4982-aec6-36c64224dbb2','西齋睡起','楊萬里','宋','宋诗','song-poetry','','[]','小睡西齋聽雨涼，竹雞聲裏夢難長。',32,'全唐诗/poet.song.140000.json','["小睡西齋聽雨涼，竹雞聲裏夢難長。", "開門山色都爭入，只放青蒼一冊方。"]'),
('1a0d8bd9-bfd0-47d2-8945-4ba4163cac99','讀陳蕃傳','楊萬里','宋','宋诗','song-poetry','','[]','仲舉高談亦壯哉，白頭狼狽只堪哀。',32,'全唐诗/poet.song.140000.json','["仲舉高談亦壯哉，白頭狼狽只堪哀。", "枉教一室塵如積，天下何曾掃得來。"]'),
('e2e47154-2c21-4371-b5be-973217765073','銅雀硯','楊萬里','宋','宋诗','song-poetry','','[]','摸索陶泓不忍研，阿瞞故物尚依然。',32,'全唐诗/poet.song.140000.json','["摸索陶泓不忍研，阿瞞故物尚依然。", "浪傳銅雀簷間瓦，恐是金鳬海底磚。"]'),
('9aad4b09-2a55-429d-ae0b-e8a5adedd38b','黄雀食新二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','鵝黄染線織秋衣，楊柳吹綿細細披。',32,'全唐诗/poet.song.140000.json','["鵝黄染線織秋衣，楊柳吹綿細細披。", "詩債被渠渾索盡，醉鄉邀我不容歸。"]'),
('bf4d1b44-ef28-47d7-8d31-44c17847b371','黄雀食新二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','侯門信口總稱珍，只見陳人不見新。',32,'全唐诗/poet.song.140000.json','["侯門信口總稱珍，只見陳人不見新。", "三日荔枝香味變，況開醤瓿拂蛛塵。"]'),
('541db31a-29a7-41d4-89c1-9fc0651ef6ec','夜寒獨覺','楊萬里','宋','宋诗','song-poetry','','[]','兒啼驚覺夢中身，恰則華胥政問津。',64,'全唐诗/poet.song.140000.json','["兒啼驚覺夢中身，恰則華胥政問津。", "脚到五更偏作冷，老來萬事不如人。", "若無窗月誰相伴，聽盡雞聲不肯晨。", "尚有布衾寒似鐵，無衾似鐵始言貧。"]'),
('8ed82b77-963a-4ccf-8cdc-cc38d9e290ba','雨晴得毗陵故舊書','楊萬里','宋','宋诗','song-poetry','','[]','雀聲只喜晚晴新，不管畦蔬雨未勻。',64,'全唐诗/poet.song.140000.json','["雀聲只喜晚晴新，不管畦蔬雨未勻。", "日與山光弄秋色，風將竹影掃窗塵。", "多時浙右無消息，忽有書來問老人。", "知我近來頭白盡，寒暄語外更情親。"]'),
('efd65a26-bfd1-423e-a6ae-3caf49a9d6ab','憂患感歎二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','醉裏還多感，醒來却更愁。',24,'全唐诗/poet.song.140000.json','["醉裏還多感，醒來却更愁。", "醉醒都不是，愁感幾時休。"]'),
('abd550a2-7c02-4788-8d0d-6a9fe68f8522','憂患感歎二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老去情懷已不勝，愁邊災患更相仍。',32,'全唐诗/poet.song.140000.json','["老去情懷已不勝，愁邊災患更相仍。", "胸中莫著傷心事，東處銷時西處生。"]'),
('f5ebcd10-2af9-41a1-b004-fb1f65521893','霜曉','楊萬里','宋','宋诗','song-poetry','','[]','荒荒瘦日作秋暉，稍稍微暄破曉霏。',32,'全唐诗/poet.song.140000.json','["荒荒瘦日作秋暉，稍稍微暄破曉霏。", "只有江楓偏得意，夜挼霜水染紅衣。"]'),
('d5e54a63-b52d-4b51-b8c1-3ab0c60f785b','寄題蕭邦懷步芳園','楊萬里','宋','宋诗','song-poetry','','[]','群鶑亂飛春晝長，極目千里春草香。',64,'全唐诗/poet.song.140000.json','["群鶑亂飛春晝長，極目千里春草香。", "幽人自煮蟹眼湯，茶甌影裏見山光。", "欣然藥囿聊步屧，戲隨蜜蜂與蝴蝶。", "楊花糝逕白於雪，桃花夾逕紅於襭。"]'),
('f4a2bf66-7836-40e9-9c89-a09251601e6b','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其一','楊萬里','宋','宋诗','song-poetry','','[]','晚飲西鄰大阮家，天風吹雪入簷牙。',32,'全唐诗/poet.song.140000.json','["晚飲西鄰大阮家，天風吹雪入簷牙。", "呼僮浄掃青苔地，莫遣纖塵涴玉花。"]'),
('d9346c53-bf16-4081-9847-ae4cb84911fc','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其二','楊萬里','宋','宋诗','song-poetry','','[]','長廊盡處繞梅行，過盡風聲得雪聲。',32,'全唐诗/poet.song.140000.json','["長廊盡處繞梅行，過盡風聲得雪聲。", "醉裏不愁飄濕面，自舒翠袖點瓊英。"]'),
('7e03cdeb-56bc-4d23-9213-896e7e0f99e4','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其三','楊萬里','宋','宋诗','song-poetry','','[]','老子那知鬢脚凋，忍寒拚命看珠跳。',32,'全唐诗/poet.song.140000.json','["老子那知鬢脚凋，忍寒拚命看珠跳。", "却嫌地暖無冰凍，恰則飛來恰則銷。"]'),
('4b5ea270-40df-40f4-8030-6a8f925be47a','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其四','楊萬里','宋','宋诗','song-poetry','','[]','梅花得雪更清妍，折入燈前細撚看。',32,'全唐诗/poet.song.140000.json','["梅花得雪更清妍，折入燈前細撚看。", "下却珠簾教到地，橫枝太瘦不禁寒。"]'),
('98dec125-1f0b-4886-846c-e721979c7dd4','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其五','楊萬里','宋','宋诗','song-poetry','','[]','雪政飛時梅政開，倩人和雪折庭梅。',32,'全唐诗/poet.song.140000.json','["雪政飛時梅政開，倩人和雪折庭梅。", "莫教顫脫梢頭雪，千萬輕輕折取來。"]'),
('1256734d-0101-47d5-95b3-5047803ffb27','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其六','楊萬里','宋','宋诗','song-poetry','','[]','急雪穿簾繞蠟燈，梅花微笑古銅瓶。',32,'全唐诗/poet.song.140000.json','["急雪穿簾繞蠟燈，梅花微笑古銅瓶。", "朔風惡劇驚人殺，吹倒琉璃六曲屏。"]'),
('74306104-6970-4298-b233-28f4117d7fdb','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其七','楊萬里','宋','宋诗','song-poetry','','[]','南烹北果聚君家，象箸冰盤物物佳。',32,'全唐诗/poet.song.140000.json','["南烹北果聚君家，象箸冰盤物物佳。", "只有蔗霜分不得，老夫自要嚼梅花。"]'),
('8ea8587d-d572-4f14-9520-0fa608bd3812','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其八','楊萬里','宋','宋诗','song-poetry','','[]','不是今宵雪不清，只愁清殺老書生。',32,'全唐诗/poet.song.140000.json','["不是今宵雪不清，只愁清殺老書生。", "不知落得幾多雪，做盡北風無限聲。"]'),
('85440833-402c-4e3e-9ee2-b307f2b79e69','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其九','楊萬里','宋','宋诗','song-poetry','','[]','酒香端的似梅無，小摘梅花浸酒壺。',32,'全唐诗/poet.song.140000.json','["酒香端的似梅無，小摘梅花浸酒壺。", "莫遣南枝獨醒著，一杯聊勸雪肌膚。"]'),
('9cee2393-3562-4333-87c7-e875983dc1b3','慶長叔招飲一杯未釂雪聲璀然即席走筆賦十詩  其一○','楊萬里','宋','宋诗','song-poetry','','[]','燕寧軒裏集羣仙，薄宦歸來又兩年。',32,'全唐诗/poet.song.140000.json','["燕寧軒裏集羣仙，薄宦歸來又兩年。", "梅影舞風風舞雪，勸人何苦怯金船。"]'),
('629e1d56-b2b6-4b7a-ab9b-58e290aebbde','糟蟹六言二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','霜前不落第二，糟餘也復無雙。',28,'全唐诗/poet.song.140000.json','["霜前不落第二，糟餘也復無雙。", "一腹金相玉質，兩螯明月秋江。"]'),
('76012071-7861-4106-bd5e-affcad57d741','糟蟹六言二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','別業拋離水國，失身墮在糟丘。',28,'全唐诗/poet.song.140000.json','["別業拋離水國，失身墮在糟丘。", "莫笑草泥郭索，策勳作醉鄉侯。"]');
